			public byte[] Buffer => _Buffer;

			public int Length
			{
				get
				{
					return _Length;
				}
				set
				{
					if (value > _Buffer.Length)
					{
						uint num = (uint)_Buffer.Length;
						num <<= 1;
						if (num > int.MaxValue)
						{
							num = 2147483647u;
						}
						else if ((uint)value > num)
						{
							num = (uint)value;
						}
						Array.Resize(ref _Buffer, (int)num);
					}
					_Length = value;
				}
			}

			public FlexArray(int Capacity)
			{
				_Buffer = new byte[Capacity];
				_Length = 0;
			}
		}

