		public static ExifData Empty()
		{
			ExifData exifData = new ExifData();
			exifData.SetEmptyExifBlock();
			return exifData;
		}

		public void Save(string DestFileNameWithPath = null, ExifSaveOptions SaveOptions = (ExifSaveOptions)0)
		{
			bool flag = false;
			string fileNameWithPath = _FileNameWithPath;
			if (DestFileNameWithPath != null)
			{
				DestFileNameWithPath = Path.GetFullPath(DestFileNameWithPath);
			}
			if (DestFileNameWithPath == null || string.Compare(fileNameWithPath, DestFileNameWithPath, StringComparison.OrdinalIgnoreCase) == 0)
			{
				int num = fileNameWithPath.LastIndexOf('\\');
				int num2 = fileNameWithPath.LastIndexOf('.');
				if (num2 <= num)
				{
					num2 = fileNameWithPath.Length;
				}
				DestFileNameWithPath = fileNameWithPath.Insert(num2, "~");
				flag = true;
			}
			bool flag2 = false;
			FileStream fileStream = null;
			FileStream fileStream2 = null;
			try
			{
				fileStream = File.OpenRead(fileNameWithPath);
				fileStream2 = File.Open(DestFileNameWithPath, FileMode.Create);
				flag2 = true;
				Save(fileStream, fileStream2, SaveOptions);
				fileStream.Dispose();
				fileStream = null;
				fileStream2.Dispose();
				fileStream2 = null;
				if (flag)
				{
					File.Delete(fileNameWithPath);
					File.Move(DestFileNameWithPath, fileNameWithPath);
				}
			}
			catch
			{
				fileStream?.Dispose();
				fileStream2?.Dispose();
				if (flag2)
				{
					File.Delete(DestFileNameWithPath);
				}
				throw;
			}
		}

		public void Save(Stream SourceStream, Stream DestStream, ExifSaveOptions SaveOptions = (ExifSaveOptions)0)
		{
			ImageType imageType = CheckStreamTypeAndCompatibility(SourceStream);
			if (imageType != ImageType)
			{
				throw new ExifException(ExifErrCode.ImageTypesDoNotMatch);
			}
			switch (imageType)
			{
			case ImageType.Jpeg:
				SaveJpeg(SourceStream, DestStream);
				break;
			case ImageType.Tiff:
				SaveTiff(SourceStream, DestStream);
				break;
			case ImageType.Png:
				SavePng(SourceStream, DestStream);
				break;
			}
		}

		public bool GetTagValue(ExifTag TagSpec, out string Value, StrCoding Coding)
		{
			bool result = false;
			StrCodingFormat strCodingFormat = (StrCodingFormat)(Coding & (StrCoding)(-65536));
			ushort num = (ushort)Coding;
			if (strCodingFormat == StrCodingFormat.TypeUndefinedWithIdCode)
			{
				result = GetTagValueWithIdCode(TagSpec, out Value, num);
			}
			else
			{
				Value = null;
				if (GetTagItem(TagSpec, out var t))
				{
					int num2 = t.ValueCount;
					int valueIndex = t.ValueIndex;
					if (num == 1200 || num == 1201)
					{
						while (num2 >= 2 && t.ValueData[valueIndex + num2 - 2] == 0 && t.ValueData[valueIndex + num2 - 1] == 0)
						{
							num2 -= 2;
						}
					}
					else
					{
						while (num2 >= 1 && t.ValueData[valueIndex + num2 - 1] == 0)
						{
							num2--;
						}
					}
					if (num != 0 && ((strCodingFormat == StrCodingFormat.TypeAscii && t.TagType == ExifTagType.Ascii) || (strCodingFormat == StrCodingFormat.TypeUndefined && t.TagType == ExifTagType.Undefined) || (strCodingFormat == StrCodingFormat.TypeByte && t.TagType == ExifTagType.Byte)))
					{
						Value = Encoding.GetEncoding(num).GetString(t.ValueData, valueIndex, num2);
						result = true;
					}
				}
			}
			return result;
		}

		public bool SetTagValue(ExifTag TagSpec, string Value, StrCoding Coding)
		{
			bool result = false;
			StrCodingFormat strCodingFormat = (StrCodingFormat)(Coding & (StrCoding)(-65536));
			ushort num = (ushort)Coding;
			if (strCodingFormat == StrCodingFormat.TypeUndefinedWithIdCode)
			{
				result = SetTagValueWithIdCode(TagSpec, Value, num);
			}
			else
			{
				ExifTagType exifTagType = strCodingFormat switch
				{
					StrCodingFormat.TypeUndefined => ExifTagType.Undefined, 
					StrCodingFormat.TypeByte => ExifTagType.Byte, 
					_ => ExifTagType.Ascii, 
				};
				int num2 = 0;
				if (exifTagType != ExifTagType.Undefined)
				{
					num2 = ((num != 1200 && num != 1201) ? 1 : 2);
				}
				if (num != 0)
				{
					byte[] bytes = Encoding.GetEncoding(num).GetBytes(Value);
					int num3 = bytes.Length;
					int valueCount = num3 + num2;
					TagItem tagItem = PrepareTagForCompleteWriting(TagSpec, exifTagType, valueCount);
					if (tagItem != null)
					{
						Array.Copy(bytes, 0, tagItem.ValueData, tagItem.ValueIndex, num3);
						if (num2 >= 1)
						{
							tagItem.ValueData[tagItem.ValueIndex + num3] = 0;
						}
						if (num2 >= 2)
						{
							tagItem.ValueData[tagItem.ValueIndex + num3 + 1] = 0;
						}
						result = true;
					}
				}
			}
			return result;
		}

		public bool GetTagValue(ExifTag TagSpec, out int Value, int Index = 0)
		{
			bool flag = false;
			uint Value2 = 0u;
			if (GetTagItem(TagSpec, out var t) && ReadUintElement(t, Index, out Value2))
			{
				flag = t.TagType != ExifTagType.ULong || (int)Value2 >= 0;
				if (!flag)
				{
					Value2 = 0u;
				}
			}
			Value = (int)Value2;
			return flag;
		}

		public bool SetTagValue(ExifTag TagSpec, int Value, ExifTagType TagType, int Index = 0)
		{
			bool flag = false;
			switch (TagType)
			{
			case ExifTagType.Byte:
				if (Value >= 0 && Value <= 255)
				{
					flag = true;
				}
				break;
			case ExifTagType.UShort:
				if (Value >= 0 && Value <= 65535)
				{
					flag = true;
				}
				break;
			case ExifTagType.ULong:
				if (Value >= 0)
				{
					flag = true;
				}
				break;
			case ExifTagType.SLong:
				flag = true;
				break;
			}
			if (flag)
			{
				TagItem t = PrepareTagForArrayItemWriting(TagSpec, TagType, Index);
				flag = WriteUintElement(t, Index, (uint)Value);
			}
			return flag;
		}

		public bool GetTagValue(ExifTag TagSpec, out uint Value, int Index = 0)
		{
			bool flag = false;
			uint Value2 = 0u;
			if (GetTagItem(TagSpec, out var t) && ReadUintElement(t, Index, out Value2))
			{
				flag = t.TagType != ExifTagType.SLong || (int)Value2 >= 0;
				if (!flag)
