					Value2 = 0u;
				}
			}
			Value = Value2;
			return flag;
		}

		public bool SetTagValue(ExifTag TagSpec, uint Value, ExifTagType TagType, int Index = 0)
		{
			bool flag = false;
			switch (TagType)
			{
			case ExifTagType.Byte:
				if (Value >= 0 && Value <= 255)
				{
					flag = true;
				}
				break;
			case ExifTagType.UShort:
				if (Value >= 0 && Value <= 65535)
				{
					flag = true;
				}
				break;
			case ExifTagType.ULong:
				flag = true;
				break;
			case ExifTagType.SLong:
				if ((int)Value >= 0)
				{
					flag = true;
				}
				break;
			}
			if (flag)
			{
				TagItem t = PrepareTagForArrayItemWriting(TagSpec, TagType, Index);
				flag = WriteUintElement(t, Index, Value);
			}
			return flag;
		}

		public bool GetTagValue(ExifTag TagSpec, out ExifRational Value, int Index = 0)
		{
			bool result = false;
			if (GetTagItem(TagSpec, out var t) && ReadURatElement(t, Index, out var Numer, out var Denom))
			{
				if (t.TagType == ExifTagType.URational)
				{
					Value = new ExifRational(Numer, Denom);
				}
				else
				{
					Value = new ExifRational((int)Numer, (int)Denom);
				}
				result = true;
			}
			else
			{
				Value = new ExifRational(0, 0);
			}
			return result;
		}

		public bool SetTagValue(ExifTag TagSpec, ExifRational Value, ExifTagType TagType, int Index = 0)
		{
			bool flag = false;
			switch (TagType)
			{
			case ExifTagType.SRational:
				if (Value.Numer < 2147483648u && Value.Denom < 2147483648u)
				{
					if (Value.Sign)
					{
						Value.Numer = 0 - Value.Numer;
					}
					flag = true;
				}
				else
				{
					flag = false;
				}
				break;
			case ExifTagType.URational:
				flag = !Value.IsNegative();
				break;
			}
			if (flag)
			{
				TagItem t = PrepareTagForArrayItemWriting(TagSpec, TagType, Index);
				flag = WriteURatElement(t, Index, Value.Numer, Value.Denom);
			}
			return flag;
		}

		public bool GetTagValue(ExifTag TagSpec, out DateTime Value, ExifDateFormat Format = ExifDateFormat.DateAndTime)
		{
			bool result = false;
			Value = DateTime.MinValue;
			if (GetTagItem(TagSpec, out var t) && t.TagType == ExifTagType.Ascii)
			{
				try
				{
					int valueIndex = t.ValueIndex;
					if (t.ValueCount >= 10 && t.ValueData[valueIndex + 4] == 58 && t.ValueData[valueIndex + 7] == 58)
					{
						int year = CalculateTwoDigitDecNumber(t.ValueData, valueIndex) * 100 + CalculateTwoDigitDecNumber(t.ValueData, valueIndex + 2);
						int month = CalculateTwoDigitDecNumber(t.ValueData, valueIndex + 5);
						int day = CalculateTwoDigitDecNumber(t.ValueData, valueIndex + 8);
						if (Format == ExifDateFormat.DateAndTime && t.ValueCount == 20 && t.ValueData[valueIndex + 10] == 32 && t.ValueData[valueIndex + 13] == 58 && t.ValueData[valueIndex + 16] == 58 && t.ValueData[valueIndex + 19] == 0)
						{
							int hour = CalculateTwoDigitDecNumber(t.ValueData, valueIndex + 11);
							int minute = CalculateTwoDigitDecNumber(t.ValueData, valueIndex + 14);
							int second = CalculateTwoDigitDecNumber(t.ValueData, valueIndex + 17);
							Value = new DateTime(year, month, day, hour, minute, second);
							result = true;
						}
						else if (Format == ExifDateFormat.DateOnly && t.ValueCount == 11 && t.ValueData[valueIndex + 10] == 0)
						{
							Value = new DateTime(year, month, day);
							result = true;
						}
					}
				}
				catch
				{
				}
			}
			return result;
		}

		public bool SetTagValue(ExifTag TagSpec, DateTime Value, ExifDateFormat Format = ExifDateFormat.DateAndTime)
		{
			bool result = false;
			int num = 0;
			switch (Format)
			{
			case ExifDateFormat.DateAndTime:
				num = 20;
				break;
			case ExifDateFormat.DateOnly:
				num = 11;
				break;
			}
			if (num != 0)
			{
				TagItem tagItem = PrepareTagForCompleteWriting(TagSpec, ExifTagType.Ascii, num);
				if (tagItem != null)
				{
					int Index = tagItem.ValueIndex;
					int year = Value.Year;
					ConvertTwoDigitNumberToByteArr(tagItem.ValueData, ref Index, year / 100);
					ConvertTwoDigitNumberToByteArr(tagItem.ValueData, ref Index, year % 100);
					tagItem.ValueData[Index] = 58;
					Index++;
					ConvertTwoDigitNumberToByteArr(tagItem.ValueData, ref Index, Value.Month);
					tagItem.ValueData[Index] = 58;
					Index++;
					ConvertTwoDigitNumberToByteArr(tagItem.ValueData, ref Index, Value.Day);
					if (Format == ExifDateFormat.DateAndTime)
					{
						tagItem.ValueData[Index] = 32;
						Index++;
						ConvertTwoDigitNumberToByteArr(tagItem.ValueData, ref Index, Value.Hour);
						tagItem.ValueData[Index] = 58;
						Index++;
						ConvertTwoDigitNumberToByteArr(tagItem.ValueData, ref Index, Value.Minute);
						tagItem.ValueData[Index] = 58;
						Index++;
						ConvertTwoDigitNumberToByteArr(tagItem.ValueData, ref Index, Value.Second);
					}
					tagItem.ValueData[Index] = 0;
					Index++;
					result = true;
				}
			}
			return result;
		}

