		public bool SetTagRawData(ExifTag TagSpec, ExifTagType TagType, int ValueCount, byte[] RawData, int RawDataIndex = 0)
		{
			bool result = false;
			ExifIfd exifIfd = ExtractIfd(TagSpec);
			if ((uint)exifIfd < 5u)
			{
				int tagByteCount = GetTagByteCount(TagType, ValueCount);
				Dictionary<ExifTagId, TagItem> dictionary = TagTable[(int)exifIfd];
				if (dictionary.TryGetValue(ExtractTagId(TagSpec), out var value))
				{
					value.TagType = TagType;
					value.ValueCount = ValueCount;
					value.ValueData = RawData;
					value.ValueIndex = RawDataIndex;
					value.AllocatedByteCount = tagByteCount;
				}
				else
				{
					value = new TagItem(ExtractTagId(TagSpec), TagType, ValueCount, RawData, RawDataIndex, tagByteCount);
					dictionary.Add(value.TagId, value);
				}
				result = true;
			}
			return result;
		}

