		public bool EnumerateNextTag(out ExifTag TagSpec)
		{
			bool result = false;
			if (TagEnumerator.MoveNext())
			{
				ExifTagId current = TagEnumerator.Current;
				TagSpec = ComposeTagSpec(ExifIfdForTagEnumeration, current);
				result = true;
			}
			else
			{
				TagSpec = (ExifTag)0;
			}
			return result;
		}

