		public bool GetGpsAltitude(out decimal Value)
		{
			bool result = false;
			if (GetTagValue(ExifTag.GpsAltitude, out ExifRational Value2, 0) && Value2.IsValid())
			{
				Value = ExifRational.ToDecimal(Value2);
				if (GetTagValue(ExifTag.GpsAltitudeRef, out uint Value3, 0) && Value3 == 1)
