		private int DetectPngImageBlock(Stream ImageStream, byte[] SignatureData, uint ChunkType, out ImageFileBlock BlockType)
		{
			int num = 0;
			BlockType = ImageFileBlock.Unknown;
			switch (ChunkType)
			{
			case 1700284774u:
				BlockType = ImageFileBlock.Exif;
				break;
			case 1767135348u:
			{
