				num = ImageStream.Read(SignatureData, 0, count);
				if (ArrayStartsWith(SignatureData, num, PngXmpSignature))
				{
					BlockType = ImageFileBlock.Xmp;
				}
				else if (ArrayStartsWith(SignatureData, num, PngIptcSignature))
				{
					BlockType = ImageFileBlock.Iptc;
				}
				break;
			}
			case 1950701684u:
				BlockType = ImageFileBlock.PngMetaData;
				break;
			case 1950960965u:
				BlockType = ImageFileBlock.PngDateChanged;
				break;
			}
			return num;
		}

		private static uint CalculateCrc32(byte[] Data, int StartIndex, int Length, bool Finalize = true, uint StartCrc = uint.MaxValue)
		{
			uint num = StartCrc;
			int num2 = StartIndex + Length;
			for (int i = StartIndex; i < num2; i++)
			{
				byte b = Data[i];
				num = Crc32ChecksumTable[(byte)num ^ b] ^ (num >> 8);
			}
			if (Finalize)
			{
				num = ~num;
			}
			return num;
		}

		private void UpdateImageFileBlockInfo()
