						int i;
						for (i = JpegXmpInitialSignature.Length; i < BlockContentSize2 && BlockContent[i] != 0; i++)
						{
						}
						MetaDataIndex = i + 1;
					}
				}
				else if (BlockMarker == 65517)
				{
					if (ArrayStartsWith(BlockContent, BlockContentSize2, JpegIptcSignature))
					{
						BlockType = ImageFileBlock.Iptc;
						MetaDataIndex = JpegIptcSignature.Length;
					}
				}
				else if (BlockMarker == 65534)
				{
