			SegmentByteCountTable = new uint[valueCount];
			bool flag = t.TagType == ExifTagType.UShort;
			bool flag2 = t2.TagType == ExifTagType.UShort;
			for (int i = 0; i < valueCount; i++)
			{
				uint num = ((!flag) ? exifData.ExifReadUInt32(t.ValueData, t.ValueIndex + (i << 2)) : exifData.ExifReadUInt16(t.ValueData, t.ValueIndex + (i << 1)));
				SegmentOffsetTable[i] = num;
				num = ((!flag2) ? exifData.ExifReadUInt32(t2.ValueData, t2.ValueIndex + (i << 2)) : exifData.ExifReadUInt16(t2.ValueData, t2.ValueIndex + (i << 1)));
				SegmentByteCountTable[i] = num;
			}
			return exifData;
		}

		private void SavePng(Stream SourceStream, Stream DestStream)
		{
			byte[] array = new byte[65536];
			byte[] signatureData = new byte[30];
			SourceStream.Position = 8L;
			WriteUInt32BE(array, 0, 2303741511u);
			WriteUInt32BE(array, 4, 218765834u);
			DestStream.Write(array, 0, 8);
			uint ChunkType;
			do
			{
				bool flag = true;
				long position = SourceStream.Position;
				ReadPngBlockHeader(SourceStream, array, out var BlockLength, out ChunkType);
				DetectPngImageBlock(SourceStream, signatureData, ChunkType, out var BlockType);
				if (BlockType != ImageFileBlock.Unknown && (BlockType == ImageFileBlock.Exif || ImageFileBlockInfo[(int)BlockType] == ImageFileBlockState.Removed))
				{
					flag = false;
				}
				if (flag)
				{
					SourceStream.Position = position;
					int num = BlockLength + 12;
					int num2 = array.Length;
					do
					{
						if (num2 > num)
						{
							num2 = num;
						}
						if (SourceStream.Read(array, 0, num2) == num2)
						{
							DestStream.Write(array, 0, num2);
							num -= num2;
							continue;
						}
						throw new ExifException(ExifErrCode.InternalImageStructureIsWrong);
					}
					while (num > 0);
				}
				else
				{
					SourceStream.Position = position + BlockLength + 12;
				}
				if (ChunkType == 1229472850)
				{
					CreateExifBlock(out var NewExifBlock, 8);
					int length = NewExifBlock.Length;
					if (length > 0)
					{
						CreateTiffHeader(out var TiffHeader, 8);
						uint value = (uint)(8 + length);
						WriteUInt32BE(array, 0, value);
						WriteUInt32BE(array, 4, 1700284774u);
						DestStream.Write(array, 0, 8);
						DestStream.Write(TiffHeader, 0, 8);
						DestStream.Write(NewExifBlock.Buffer, 0, length);
						uint startCrc = CalculateCrc32(array, 4, 4, Finalize: false);
						startCrc = CalculateCrc32(TiffHeader, 0, 8, Finalize: false, startCrc);
						startCrc = CalculateCrc32(NewExifBlock.Buffer, 0, length, Finalize: true, startCrc);
						WriteUInt32BE(array, 0, startCrc);
						DestStream.Write(array, 0, 4);
					}
				}
			}
			while (ChunkType != 1229278788);
		}

		private void SetEmptyExifBlock()
		{
			SourceExifBlock = new byte[14];
			ExifWriteUInt16(SourceExifBlock, 8, 0);
			ExifWriteUInt32(SourceExifBlock, 10, 0u);
			EvaluateExifBlock(8);
		}

		private void WriteTagToFlexArray(TagItem TempTagData, FlexArray WriteData, ref int TagDataIndex, int ExifBlockOffset)
		{
			int num = TagDataIndex;
			TagDataIndex += 12;
			ExifWriteUInt16(WriteData.Buffer, num, (ushort)TempTagData.TagId);
			ExifWriteUInt16(WriteData.Buffer, num + 2, (ushort)TempTagData.TagType);
			ExifWriteUInt32(WriteData.Buffer, num + 4, (uint)TempTagData.ValueCount);
			int tagByteCount = GetTagByteCount(TempTagData.TagType, TempTagData.ValueCount);
			if (tagByteCount <= 4)
			{
				WriteData.Buffer[num + 8] = TempTagData.ValueData[TempTagData.ValueIndex];
				byte b = 0;
				if (tagByteCount >= 2)
				{
					b = TempTagData.ValueData[TempTagData.ValueIndex + 1];
				}
				WriteData.Buffer[num + 9] = b;
				b = 0;
				if (tagByteCount >= 3)
				{
					b = TempTagData.ValueData[TempTagData.ValueIndex + 2];
				}
				WriteData.Buffer[num + 10] = b;
				b = 0;
				if (tagByteCount >= 4)
				{
					b = TempTagData.ValueData[TempTagData.ValueIndex + 3];
				}
				WriteData.Buffer[num + 11] = b;
			}
			else
			{
				int length = WriteData.Length;
				ExifWriteUInt32(WriteData.Buffer, num + 8, (uint)(ExifBlockOffset + length));
				WriteData.Length += tagByteCount;
				Array.Copy(TempTagData.ValueData, TempTagData.ValueIndex, WriteData.Buffer, length, tagByteCount);
				if ((tagByteCount & 1) != 0)
				{
					WriteData.Length++;
					WriteData.Buffer[WriteData.Length - 1] = 0;
				}
			}
		}

		private int CreateExifBlock(out FlexArray NewExifBlock, int CurrentExifBlockOffset)
		{
			int num = 0;
			FlexArray flexArray = (NewExifBlock = new FlexArray(65518));
			int WriteIndex = 0;
			UpdateIfdPointerTags(out var PrivateDataPointerTag, out var GpsInfoDataPointerTag, out var InteroperabilityPointerTag);
			CreateIfdPrimaryData(flexArray, ref WriteIndex, CurrentExifBlockOffset, out var PrivateDataIfdPointerIndex, out var GpsInfoDataIfdPointerIndex, out var ThumbnailDataIfdPointerIndex);
			CreateIfdPrivateData(flexArray, ref WriteIndex, CurrentExifBlockOffset, PrivateDataIfdPointerIndex, PrivateDataPointerTag, out var InteroperabilityIfdPointerIndex);
			CreateIfdGpsInfoData(flexArray, ref WriteIndex, CurrentExifBlockOffset, GpsInfoDataIfdPointerIndex, GpsInfoDataPointerTag);
			CreateIfdInteroperability(flexArray, ref WriteIndex, CurrentExifBlockOffset, InteroperabilityIfdPointerIndex, InteroperabilityPointerTag);
			if (ImageType == ImageType.Tiff)
			{
				num = ThumbnailDataIfdPointerIndex;
				ExifWriteUInt32(flexArray.Buffer, num, 0u);
			}
			else
			{
				CreateIfdThumbnailData(flexArray, ref WriteIndex, CurrentExifBlockOffset, ThumbnailDataIfdPointerIndex);
			}
			if (flexArray.Length <= 6)
			{
				flexArray.Length = 0;
			}
			return num;
		}

		private void CreateTiffHeader(out byte[] TiffHeader, int ExifBlockOffset)
		{
			TiffHeader = new byte[8];
			if (ByteOrder == ExifByteOrder.BigEndian)
			{
				WriteUInt32BE(TiffHeader, 0, 1296891946u);
			}
			else
			{
				if (ByteOrder != ExifByteOrder.LittleEndian)
				{
					throw new ExifException(ExifErrCode.InternalError);
				}
				WriteUInt32BE(TiffHeader, 0, 1229531648u);
			}
			ExifWriteUInt32(TiffHeader, 4, (uint)ExifBlockOffset);
		}

		private void UpdateIfdPointerTags(out TagItem PrivateDataPointerTag, out TagItem GpsInfoDataPointerTag, out TagItem InteroperabilityPointerTag)
		{
			Dictionary<ExifTagId, TagItem> dictionary = TagTable[1];
			Dictionary<ExifTagId, TagItem> obj = TagTable[3];
			dictionary.TryGetValue(ExifTagId.InteroperabilityIfdPointer, out InteroperabilityPointerTag);
			if (obj.Count > 0)
			{
				if (InteroperabilityPointerTag == null)
				{
					InteroperabilityPointerTag = new TagItem(ExifTag.InteroperabilityIfdPointer, ExifTagType.ULong, 1);
					dictionary.Add(ExifTagId.InteroperabilityIfdPointer, InteroperabilityPointerTag);
				}
			}
			else if (InteroperabilityPointerTag != null)
			{
				dictionary.Remove(ExifTagId.InteroperabilityIfdPointer);
			}
			Dictionary<ExifTagId, TagItem> dictionary2 = TagTable[0];
			Dictionary<ExifTagId, TagItem> obj2 = TagTable[2];
			dictionary2.TryGetValue(ExifTagId.GpsInfoIfdPointer, out GpsInfoDataPointerTag);
			if (obj2.Count > 0)
			{
				if (GpsInfoDataPointerTag == null)
				{
					GpsInfoDataPointerTag = new TagItem(ExifTag.GpsInfoIfdPointer, ExifTagType.ULong, 1);
					dictionary2.Add(ExifTagId.GpsInfoIfdPointer, GpsInfoDataPointerTag);
				}
			}
			else if (GpsInfoDataPointerTag != null)
			{
				dictionary2.Remove(ExifTagId.GpsInfoIfdPointer);
			}
			dictionary2.TryGetValue(ExifTagId.ExifIfdPointer, out PrivateDataPointerTag);
			if (dictionary.Count > 0)
			{
				if (PrivateDataPointerTag == null)
				{
					PrivateDataPointerTag = new TagItem(ExifTag.ExifIfdPointer, ExifTagType.ULong, 1);
					dictionary2.Add(ExifTagId.ExifIfdPointer, PrivateDataPointerTag);
				}
			}
			else if (PrivateDataPointerTag != null)
			{
				dictionary2.Remove(ExifTagId.ExifIfdPointer);
			}
		}

		private void CreateIfdPrimaryData(FlexArray WriteExifBlock, ref int WriteIndex, int ExifBlockOffset, out int PrivateDataIfdPointerIndex, out int GpsInfoDataIfdPointerIndex, out int ThumbnailDataIfdPointerIndex)
		{
			Dictionary<ExifTagId, TagItem> obj = TagTable[0];
			int count = obj.Count;
			PrivateDataIfdPointerIndex = -1;
			GpsInfoDataIfdPointerIndex = -1;
			int num = 2 + count * 12 + 4;
			WriteExifBlock.Length += num;
			ExifWriteUInt16(WriteExifBlock.Buffer, WriteIndex, (ushort)count);
			WriteIndex += 2;
			foreach (TagItem value in obj.Values)
			{
				if (value.TagId == ExifTagId.ExifIfdPointer)
				{
					value.TagType = ExifTagType.ULong;
					PrivateDataIfdPointerIndex = WriteIndex + 8;
				}
				else if (value.TagId == ExifTagId.GpsInfoIfdPointer)
				{
					value.TagType = ExifTagType.ULong;
					GpsInfoDataIfdPointerIndex = WriteIndex + 8;
				}
				WriteTagToFlexArray(value, WriteExifBlock, ref WriteIndex, ExifBlockOffset);
			}
			ThumbnailDataIfdPointerIndex = WriteIndex;
			WriteIndex = WriteExifBlock.Length;
		}

		private void CreateIfdPrivateData(FlexArray WriteExifBlock, ref int WriteIndex, int ExifBlockOffset, int PrivateDataIfdPointerIndex, TagItem PrivateDataPointerTag, out int InteroperabilityIfdPointerIndex)
		{
			Dictionary<ExifTagId, TagItem> dictionary = TagTable[1];
			int num = dictionary.Count;
			InteroperabilityIfdPointerIndex = -1;
			if (num <= 0)
			{
				return;
			}
			int num2 = WriteIndex;
			ExifWriteUInt32(PrivateDataPointerTag.ValueData, PrivateDataPointerTag.ValueIndex, (uint)(ExifBlockOffset + WriteIndex));
			ExifWriteUInt32(WriteExifBlock.Buffer, PrivateDataIfdPointerIndex, (uint)(ExifBlockOffset + WriteIndex));
			bool flag;
			do
			{
				int makerNoteDataPointerIndex = 0;
				int offsetSchemaValueIndex = 0;
				TagItem offsetSchemaTag = null;
				int num3 = 2 + num * 12 + 4;
				WriteExifBlock.Length += num3;
				ExifWriteUInt16(WriteExifBlock.Buffer, WriteIndex, (ushort)num);
				WriteIndex += 2;
				foreach (TagItem value2 in dictionary.Values)
				{
					if (value2.TagId == ExifTagId.InteroperabilityIfdPointer)
					{
						value2.TagType = ExifTagType.ULong;
						InteroperabilityIfdPointerIndex = WriteIndex + 8;
					}
					else if (value2.TagId == ExifTagId.MakerNote)
					{
						makerNoteDataPointerIndex = WriteIndex + 8;
					}
					else if (value2.TagId == ExifTagId.OffsetSchema)
					{
						value2.TagType = ExifTagType.SLong;
						offsetSchemaValueIndex = WriteIndex + 8;
						offsetSchemaTag = value2;
					}
					WriteTagToFlexArray(value2, WriteExifBlock, ref WriteIndex, ExifBlockOffset);
				}
				ExifWriteUInt32(WriteExifBlock.Buffer, WriteIndex, 0u);
				WriteIndex = WriteExifBlock.Length;
				flag = CheckIfMakerNoteTagHasMoved(WriteExifBlock.Buffer, makerNoteDataPointerIndex, offsetSchemaValueIndex, offsetSchemaTag);
				if (flag)
				{
					TagItem value = new TagItem(ExifTag.OffsetSchema, ExifTagType.SLong, 1);
					dictionary.Add(ExifTagId.OffsetSchema, value);
					num++;
					WriteExifBlock.Length = num2;
					WriteIndex = num2;
				}
			}
			while (flag);
		}

		private void CreateIfdGpsInfoData(FlexArray WriteExifBlock, ref int WriteIndex, int ExifBlockOffset, int GpsInfoDataIfdPointerIndex, TagItem GpsInfoDataPointerTag)
		{
			Dictionary<ExifTagId, TagItem> dictionary = TagTable[2];
			int count = dictionary.Count;
			if (count <= 0)
			{
				return;
			}
			uint value = (uint)(ExifBlockOffset + WriteIndex);
			ExifWriteUInt32(GpsInfoDataPointerTag.ValueData, GpsInfoDataPointerTag.ValueIndex, value);
			ExifWriteUInt32(WriteExifBlock.Buffer, GpsInfoDataIfdPointerIndex, value);
			int num = 2 + count * 12 + 4;
			WriteExifBlock.Length += num;
			ExifWriteUInt16(WriteExifBlock.Buffer, WriteIndex, (ushort)count);
			WriteIndex += 2;
			foreach (TagItem value2 in dictionary.Values)
			{
				WriteTagToFlexArray(value2, WriteExifBlock, ref WriteIndex, ExifBlockOffset);
			}
			ExifWriteUInt32(WriteExifBlock.Buffer, WriteIndex, 0u);
			WriteIndex = WriteExifBlock.Length;
		}

		private void CreateIfdInteroperability(FlexArray WriteExifBlock, ref int WriteIndex, int ExifBlockOffset, int InteroperabilityIfdPointerIndex, TagItem InteroperabilityPointerTag)
		{
			Dictionary<ExifTagId, TagItem> dictionary = TagTable[3];
			int count = dictionary.Count;
			if (count <= 0)
			{
				return;
			}
			uint value = (uint)(ExifBlockOffset + WriteIndex);
			ExifWriteUInt32(InteroperabilityPointerTag.ValueData, InteroperabilityPointerTag.ValueIndex, value);
			ExifWriteUInt32(WriteExifBlock.Buffer, InteroperabilityIfdPointerIndex, value);
			int num = 2 + count * 12 + 4;
			WriteExifBlock.Length += num;
			ExifWriteUInt16(WriteExifBlock.Buffer, WriteIndex, (ushort)count);
			WriteIndex += 2;
			foreach (TagItem value2 in dictionary.Values)
			{
				WriteTagToFlexArray(value2, WriteExifBlock, ref WriteIndex, ExifBlockOffset);
