		private void CreateIfdThumbnailData(FlexArray WriteExifBlock, ref int WriteIndex, int ExifBlockOffset, int ThumbnailDataIfdPointerIndex)
		{
			Dictionary<ExifTagId, TagItem> dictionary = TagTable[4];
			int count = dictionary.Count;
			if (count > 0 || ThumbnailImageExists())
			{
				ExifWriteUInt32(WriteExifBlock.Buffer, ThumbnailDataIfdPointerIndex, (uint)(ExifBlockOffset + WriteIndex));
				int num = 2 + count * 12 + 4;
				WriteExifBlock.Length += num;
				ExifWriteUInt16(WriteExifBlock.Buffer, WriteIndex, (ushort)count);
				WriteIndex += 2;
				int num2 = -1;
				TagItem tagItem = null;
				bool flag = false;
				foreach (TagItem value2 in dictionary.Values)
				{
					if (value2.TagId == ExifTagId.JpegInterchangeFormat)
					{
						value2.TagType = ExifTagType.ULong;
						tagItem = value2;
						num2 = WriteIndex + 8;
					}
					else if (value2.TagId == ExifTagId.JpegInterchangeFormatLength)
					{
						value2.TagType = ExifTagType.ULong;
						ExifWriteUInt32(value2.ValueData, value2.ValueIndex, (uint)ThumbnailByteCount);
						flag = true;
					}
					WriteTagToFlexArray(value2, WriteExifBlock, ref WriteIndex, ExifBlockOffset);
				}
				if (ThumbnailImage != null)
				{
					if (num2 < 0 || !flag)
					{
						throw new ExifException(ExifErrCode.InternalError);
					}
					int length = WriteExifBlock.Length;
					uint value = (uint)(ExifBlockOffset + length);
					ExifWriteUInt32(tagItem.ValueData, tagItem.ValueIndex, value);
					ExifWriteUInt32(WriteExifBlock.Buffer, num2, value);
					WriteExifBlock.Length += ThumbnailByteCount;
					Array.Copy(ThumbnailImage, ThumbnailStartIndex, WriteExifBlock.Buffer, length, ThumbnailByteCount);
					if ((WriteExifBlock.Length & 1) != 0)
					{
						WriteExifBlock.Length++;
						WriteExifBlock[WriteExifBlock.Length - 1] = 0;
					}
				}
				else if (num2 >= 0)
				{
					throw new ExifException(ExifErrCode.InternalError);
				}
				ExifWriteUInt32(WriteExifBlock.Buffer, WriteIndex, 0u);
			}
			else
			{
				ExifWriteUInt32(WriteExifBlock.Buffer, ThumbnailDataIfdPointerIndex, 0u);
			}
		}

		private bool CheckIfMakerNoteTagHasMoved(byte[] DataBlock, int MakerNoteDataPointerIndex, int OffsetSchemaValueIndex, TagItem OffsetSchemaTag)
		{
			bool result = false;
			if (MakerNoteOriginalOffset > 0 && MakerNoteDataPointerIndex > 0)
			{
				int num = (int)ExifReadUInt32(DataBlock, MakerNoteDataPointerIndex);
				if (MakerNoteOriginalOffset != num)
				{
					if (OffsetSchemaValueIndex > 0)
					{
						int value = num - MakerNoteOriginalOffset;
						ExifWriteUInt32(DataBlock, OffsetSchemaValueIndex, (uint)value);
						ExifWriteUInt32(OffsetSchemaTag.ValueData, OffsetSchemaTag.ValueIndex, (uint)value);
					}
					else
					{
						result = true;
					}
				}
				else if (OffsetSchemaValueIndex > 0)
				{
					ExifWriteUInt32(DataBlock, OffsetSchemaValueIndex, 0u);
					ExifWriteUInt32(OffsetSchemaTag.ValueData, OffsetSchemaTag.ValueIndex, 0u);
				}
			}
			else if (OffsetSchemaValueIndex > 0)
			{
				ExifWriteUInt32(DataBlock, OffsetSchemaValueIndex, 0u);
				ExifWriteUInt32(OffsetSchemaTag.ValueData, OffsetSchemaTag.ValueIndex, 0u);
			}
			return result;
		}

		private TagItem CreateTagWithReferenceToIfdRawData(byte[] IfdRawData, int IfdRawDataIndex)
		{
			ushort tagId = ExifReadUInt16(IfdRawData, IfdRawDataIndex);
			ExifTagType tagType = (ExifTagType)ExifReadUInt16(IfdRawData, IfdRawDataIndex + 2);
			uint num = ExifReadUInt32(IfdRawData, IfdRawDataIndex + 4);
			if (num > 268435455)
			{
				throw new ExifException(ErrCodeForIllegalExifBlock);
			}
			int tagByteCount = GetTagByteCount(tagType, (int)num);
			int TagDataIndex;
			byte[] TagData;
			int num2;
			int num3;
			if (tagByteCount <= 4)
			{
				TagDataIndex = IfdRawDataIndex + 8;
				TagData = IfdRawData;
				num2 = 4;
				num3 = 0;
			}
			else
			{
				num3 = (int)ExifReadUInt32(IfdRawData, IfdRawDataIndex + 8);
				num2 = tagByteCount;
				GetOutsourcedData(num3, num2, out TagData, out TagDataIndex);
			}
			return new TagItem((ExifTagId)tagId, tagType, (int)num, TagData, TagDataIndex, num2, num3);
		}

		private void GetOutsourcedData(int DataOffset, int DataLen, out byte[] TagData, out int TagDataIndex)
		{
			if (SourceExifBlock != null)
			{
				if ((uint)(DataOffset + DataLen) <= (uint)SourceExifBlock.Length)
				{
					TagData = SourceExifBlock;
					TagDataIndex = DataOffset;
					return;
				}
				throw new ExifException(ErrCodeForIllegalExifBlock);
			}
			TagData = new byte[DataLen];
			SourceExifStream.Position = DataOffset;
			if (SourceExifStream.Read(TagData, 0, DataLen) != DataLen)
			{
				throw new ExifException(ErrCodeForIllegalExifBlock);
			}
			TagDataIndex = 0;
		}

		private void InitIfdPrimaryData(byte[] IfdRawData, int IfdRawDataIndex, out int PrivateDataOffset, out int GpsInfoDataOffset, out int NextImageOffset)
		{
			PrivateDataOffset = 0;
			GpsInfoDataOffset = 0;
			int num = ExifReadUInt16(IfdRawData, IfdRawDataIndex);
			IfdRawDataIndex += 2;
			Dictionary<ExifTagId, TagItem> dictionary = new Dictionary<ExifTagId, TagItem>(num);
			TagTable[0] = dictionary;
			for (int i = 0; i < num; i++)
			{
				TagItem tagItem = CreateTagWithReferenceToIfdRawData(IfdRawData, IfdRawDataIndex);
				if (AddIfNotExists(dictionary, tagItem))
				{
					if (tagItem.TagId == ExifTagId.ExifIfdPointer)
					{
						PrivateDataOffset = (int)ExifReadUInt32(tagItem.ValueData, tagItem.ValueIndex);
					}
					else if (tagItem.TagId == ExifTagId.GpsInfoIfdPointer)
					{
						GpsInfoDataOffset = (int)ExifReadUInt32(tagItem.ValueData, tagItem.ValueIndex);
					}
				}
				IfdRawDataIndex += 12;
			}
			NextImageOffset = (int)ExifReadUInt32(IfdRawData, IfdRawDataIndex);
		}

		private void InitIfdPrivateData(byte[] IfdRawData, int IfdRawDataIndex, out int InteroperabilityOffset)
		{
			InteroperabilityOffset = 0;
			int num = 0;
			int num2 = 0;
			int num3 = ExifReadUInt16(IfdRawData, IfdRawDataIndex);
			IfdRawDataIndex += 2;
			Dictionary<ExifTagId, TagItem> dictionary = new Dictionary<ExifTagId, TagItem>(num3);
			TagTable[1] = dictionary;
			for (int i = 0; i < num3; i++)
			{
				TagItem tagItem = CreateTagWithReferenceToIfdRawData(IfdRawData, IfdRawDataIndex);
				if (AddIfNotExists(dictionary, tagItem))
				{
					if (tagItem.TagId == ExifTagId.InteroperabilityIfdPointer)
					{
						InteroperabilityOffset = (int)ExifReadUInt32(tagItem.ValueData, tagItem.ValueIndex);
					}
					else if (tagItem.TagId == ExifTagId.MakerNote)
					{
						num = tagItem.OriginalDataOffset;
					}
					else if (tagItem.TagId == ExifTagId.OffsetSchema)
					{
						num2 = (int)ExifReadUInt32(tagItem.ValueData, tagItem.ValueIndex);
					}
				}
				IfdRawDataIndex += 12;
			}
			if (num > 0)
			{
				MakerNoteOriginalOffset = num - num2;
			}
			else
			{
				MakerNoteOriginalOffset = 0;
			}
		}

		private void InitIfdGpsInfoData(byte[] IfdRawData, int IfdRawDataIndex)
		{
			int num = ExifReadUInt16(IfdRawData, IfdRawDataIndex);
			IfdRawDataIndex += 2;
			Dictionary<ExifTagId, TagItem> dictionary = new Dictionary<ExifTagId, TagItem>(num);
			TagTable[2] = dictionary;
			for (int i = 0; i < num; i++)
			{
				TagItem tagData = CreateTagWithReferenceToIfdRawData(IfdRawData, IfdRawDataIndex);
				AddIfNotExists(dictionary, tagData);
				IfdRawDataIndex += 12;
			}
		}

		private void InitIfdInteroperability(byte[] IfdRawData, int IfdRawDataIndex)
