				TagItem tagData = CreateTagWithReferenceToIfdRawData(IfdRawData, IfdRawDataIndex);
				AddIfNotExists(dictionary, tagData);
				IfdRawDataIndex += 12;
			}
		}

		private void InitIfdThumbnailData(byte[] IfdRawData, int IfdRawDataIndex)
		{
			int num = 0;
			ThumbnailByteCount = 0;
			ThumbnailImage = null;
			int num2 = ExifReadUInt16(IfdRawData, IfdRawDataIndex);
			IfdRawDataIndex += 2;
			Dictionary<ExifTagId, TagItem> dictionary = new Dictionary<ExifTagId, TagItem>(num2);
			TagTable[4] = dictionary;
			for (int i = 0; i < num2; i++)
			{
				TagItem tagItem = CreateTagWithReferenceToIfdRawData(IfdRawData, IfdRawDataIndex);
				if (AddIfNotExists(dictionary, tagItem))
				{
					if (tagItem.TagId == ExifTagId.JpegInterchangeFormat)
					{
						num = (int)ExifReadUInt32(tagItem.ValueData, tagItem.ValueIndex);
					}
					else if (tagItem.TagId == ExifTagId.JpegInterchangeFormatLength)
					{
						ThumbnailByteCount = (int)ExifReadUInt32(tagItem.ValueData, tagItem.ValueIndex);
					}
				}
				IfdRawDataIndex += 12;
			}
			if (num > 0)
			{
				GetOutsourcedData(num, ThumbnailByteCount, out ThumbnailImage, out ThumbnailStartIndex);
			}
		}

		private void GetNextIfd(int IfdOffset, out byte[] IfdRawData, out int IfdRawDataIndex)
		{
			if (IfdOffset == 0)
			{
				IfdRawData = new byte[2];
				IfdRawDataIndex = 0;
				return;
			}
			if (SourceExifBlock != null)
			{
				IfdRawData = SourceExifBlock;
				IfdRawDataIndex = IfdOffset;
				return;
			}
			SourceExifStream.Position = IfdOffset;
			IfdRawDataIndex = 0;
			byte[] array = new byte[2];
			if (SourceExifStream.Read(array, 0, 2) == 2)
			{
				int num = ExifReadUInt16(array, 0);
				int num2 = 2 + num * 12 + 4;
				IfdRawData = new byte[num2];
				IfdRawData[0] = array[0];
				IfdRawData[1] = array[1];
				if (SourceExifStream.Read(IfdRawData, 2, num2 - 2) == num2 - 2)
				{
					return;
				}
				throw new ExifException(ExifErrCode.InternalImageStructureIsWrong);
			}
			throw new ExifException(ExifErrCode.InternalImageStructureIsWrong);
		}

		private int EvaluateExifBlock(int PrimaryDataOffset)
		{
			int result = 0;
			TagTable = new Dictionary<ExifTagId, TagItem>[5];
			GetNextIfd(PrimaryDataOffset, out var IfdRawData, out var IfdRawDataIndex);
			InitIfdPrimaryData(IfdRawData, IfdRawDataIndex, out var PrivateDataOffset, out var GpsInfoDataOffset, out var NextImageOffset);
			GetNextIfd(PrivateDataOffset, out IfdRawData, out IfdRawDataIndex);
			InitIfdPrivateData(IfdRawData, IfdRawDataIndex, out var InteroperabilityOffset);
			GetNextIfd(GpsInfoDataOffset, out IfdRawData, out IfdRawDataIndex);
			InitIfdGpsInfoData(IfdRawData, IfdRawDataIndex);
			GetNextIfd(InteroperabilityOffset, out IfdRawData, out IfdRawDataIndex);
			InitIfdInteroperability(IfdRawData, IfdRawDataIndex);
			if (ImageType == ImageType.Tiff)
			{
				IfdRawData = new byte[2];
				InitIfdThumbnailData(IfdRawData, 0);
				result = NextImageOffset;
			}
			else
			{
				GetNextIfd(NextImageOffset, out IfdRawData, out IfdRawDataIndex);
				InitIfdThumbnailData(IfdRawData, IfdRawDataIndex);
			}
			return result;
		}

