		private bool ReadUintElement(TagItem t, int ElementIndex, out uint Value)
		{
			bool result = false;
			if (ElementIndex >= 0 && ElementIndex < t.ValueCount)
			{
				switch (t.TagType)
				{
				case ExifTagType.Byte:
					Value = t.ValueData[t.ValueIndex + ElementIndex];
					result = true;
					break;
				case ExifTagType.UShort:
					Value = ExifReadUInt16(t.ValueData, t.ValueIndex + (ElementIndex << 1));
					result = true;
					break;
				case ExifTagType.ULong:
				case ExifTagType.SLong:
					Value = ExifReadUInt32(t.ValueData, t.ValueIndex + (ElementIndex << 2));
					result = true;
					break;
				default:
					Value = 0u;
					break;
				}
			}
			else
			{
				Value = 0u;
			}
			return result;
		}

		private bool WriteUintElement(TagItem t, int ElementIndex, uint Value)
		{
			bool result = false;
			if (t != null)
			{
				if (t.TagType == ExifTagType.Byte)
				{
					t.ValueData[t.ValueIndex + ElementIndex] = (byte)Value;
				}
				else if (t.TagType == ExifTagType.UShort)
				{
					ExifWriteUInt16(t.ValueData, t.ValueIndex + (ElementIndex << 1), (ushort)Value);
				}
				else
				{
					ExifWriteUInt32(t.ValueData, t.ValueIndex + (ElementIndex << 2), Value);
				}
				result = true;
			}
			return result;
		}

		private bool GetTagValueWithIdCode(ExifTag TagSpec, out string Value, ushort CodePage)
		{
			bool result = false;
			bool flag = false;
			bool flag2 = false;
			Value = null;
			if (GetTagItem(TagSpec, out var t) && t.TagType == ExifTagType.Undefined && t.ValueCount >= 8)
			{
				if (CompareArrays(t.ValueData, t.ValueIndex, IdCodeUtf16))
				{
					flag = true;
				}
				else if (CompareArrays(t.ValueData, t.ValueIndex, IdCodeAscii) || CompareArrays(t.ValueData, t.ValueIndex, IdCodeDefault))
				{
					flag2 = true;
				}
				int num = t.ValueCount - 8;
				int num2 = t.ValueIndex + 8;
				if (flag)
				{
					while (num >= 2 && t.ValueData[num2 + num - 2] == 0 && t.ValueData[num2 + num - 1] == 0)
					{
						num -= 2;
					}
					CodePage = (ushort)((ByteOrder != ExifByteOrder.BigEndian) ? 1200 : 1201);
					Value = Encoding.GetEncoding(CodePage).GetString(t.ValueData, num2, num);
					result = true;
				}
				else if (flag2)
				{
					while (num >= 1 && t.ValueData[num2 + num - 1] == 0)
					{
						num--;
					}
					if (CodePage == 1200 || CodePage == 1201)
					{
						CodePage = 20127;
					}
					Value = Encoding.GetEncoding(CodePage).GetString(t.ValueData, num2, num);
					result = true;
				}
			}
			return result;
		}

		private bool SetTagValueWithIdCode(ExifTag TagSpec, string Value, ushort CodePage)
		{
			bool result = false;
			if (CodePage == 1200 && ByteOrder == ExifByteOrder.BigEndian)
			{
				CodePage = 1201;
			}
			if (CodePage == 1201 && ByteOrder == ExifByteOrder.LittleEndian)
			{
				CodePage = 1200;
			}
			byte[] bytes = Encoding.GetEncoding(CodePage).GetBytes(Value);
			int num = bytes.Length;
			int valueCount = 8 + num;
			TagItem tagItem = PrepareTagForCompleteWriting(TagSpec, ExifTagType.Undefined, valueCount);
			if (tagItem != null)
			{
				byte[] sourceArray = ((CodePage != 1200 && CodePage != 1201) ? IdCodeAscii : IdCodeUtf16);
				Array.Copy(sourceArray, 0, tagItem.ValueData, tagItem.ValueIndex, 8);
				Array.Copy(bytes, 0, tagItem.ValueData, tagItem.ValueIndex + 8, num);
				result = true;
			}
			return result;
		}

		private bool ReadURatElement(TagItem t, int ElementIndex, out uint Numer, out uint Denom)
		{
			bool result = false;
			if (ElementIndex >= 0 && ElementIndex < t.ValueCount)
			{
				if (t.TagType == ExifTagType.SRational || t.TagType == ExifTagType.URational)
				{
					int num = t.ValueIndex + (ElementIndex << 3);
					Numer = ExifReadUInt32(t.ValueData, num);
					Denom = ExifReadUInt32(t.ValueData, num + 4);
					result = true;
				}
				else
				{
					Numer = 0u;
					Denom = 0u;
				}
			}
			else
			{
				Numer = 0u;
				Denom = 0u;
			}
			return result;
		}

		private bool WriteURatElement(TagItem t, int ElementIndex, uint Numer, uint Denom)
		{
			bool result = false;
			if (t != null)
			{
				int num = t.ValueIndex + (ElementIndex << 3);
				ExifWriteUInt32(t.ValueData, num, Numer);
				ExifWriteUInt32(t.ValueData, num + 4, Denom);
				result = true;
			}
			return result;
		}

		private bool GetTagItem(ExifTag TagSpec, out TagItem t)
		{
			ExifIfd exifIfd = ExtractIfd(TagSpec);
			if ((uint)exifIfd < 5u)
			{
				return TagTable[(int)exifIfd].TryGetValue(ExtractTagId(TagSpec), out t);
			}
			t = null;
			return false;
		}

		private TagItem PrepareTagForArrayItemWriting(ExifTag TagSpec, ExifTagType TagType, int ArrayIndex)
		{
			TagItem value = null;
			ExifIfd exifIfd = ExtractIfd(TagSpec);
			if ((uint)exifIfd < 5u && (uint)ArrayIndex < 268435455u)
			{
				Dictionary<ExifTagId, TagItem> dictionary = TagTable[(int)exifIfd];
				if (dictionary.TryGetValue(ExtractTagId(TagSpec), out value))
				{
					int num = value.ValueCount;
					if (ArrayIndex >= num)
					{
						num = ArrayIndex + 1;
					}
					value.SetTagTypeAndValueCount(TagType, num, KeepExistingData: true);
				}
				else
				{
					int valueCount = ArrayIndex + 1;
					value = new TagItem(TagSpec, TagType, valueCount);
					dictionary.Add(value.TagId, value);
				}
			}
			return value;
		}

		private TagItem PrepareTagForCompleteWriting(ExifTag TagSpec, ExifTagType TagType, int ValueCount)
		{
			TagItem value = null;
			ExifIfd exifIfd = ExtractIfd(TagSpec);
			if ((uint)exifIfd < 5u && (uint)ValueCount <= 268435455u)
			{
				Dictionary<ExifTagId, TagItem> dictionary = TagTable[(int)exifIfd];
				if (dictionary.TryGetValue(ExtractTagId(TagSpec), out value))
				{
					value.SetTagTypeAndValueCount(TagType, ValueCount, KeepExistingData: false);
				}
				else
				{
					value = new TagItem(TagSpec, TagType, ValueCount);
					dictionary.Add(value.TagId, value);
				}
			}
			return value;
		}

		private static int CalculateTwoDigitDecNumber(byte[] ByteArr, int Index)
		{
			int result = -1;
			int num = ByteArr[Index];
			int num2 = ByteArr[Index + 1];
			if (num >= 48 && num <= 57 && num2 >= 48 && num2 <= 57)
			{
				result = (num - 48) * 10 + (num2 - 48);
			}
			return result;
		}

		private static void ConvertTwoDigitNumberToByteArr(byte[] ByteArr, ref int Index, int Value)
		{
			ByteArr[Index] = (byte)(Value / 10 + 48);
			Index++;
			ByteArr[Index] = (byte)(Value % 10 + 48);
			Index++;
		}

		private void ClearIfd_Unchecked(ExifIfd Ifd)
		{
			TagTable[(int)Ifd].Clear();
		}

		private void RemoveAllTagsFromIfdPrimaryData()
		{
			if (ImageType == ImageType.Tiff)
			{
				Dictionary<ExifTagId, TagItem> dictionary = TagTable[0];
				List<ExifTagId> list = new List<ExifTagId>(dictionary.Count);
				foreach (ExifTagId key in dictionary.Keys)
				{
					if (!IsInternalTiffTag(key) && !IsMetaDataTiffTag(key))
					{
						list.Add(key);
					}
				}
				{
					foreach (ExifTagId item in list)
					{
						dictionary.Remove(item);
					}
					return;
				}
			}
			ClearIfd_Unchecked(ExifIfd.PrimaryData);
		}

