		private bool GetGpsCoordinateHelper(out GeoCoordinate Value, ExifTag ValueTag, ExifTag RefTag, char Cp1, char Cp2)
		{
			bool result = false;
			if (GetTagValue(ValueTag, out ExifRational Value2, 0) && Value2.IsValid() && GetTagValue(ValueTag, out ExifRational Value3, 1) && Value3.IsValid() && GetTagValue(ValueTag, out ExifRational Value4, 2) && Value4.IsValid() && GetTagValue(RefTag, out var Value5, StrCoding.Utf8) && Value5.Length == 1)
			{
				char c = Value5[0];
				if (c == Cp1 || c == Cp2)
				{
					Value.Degree = ExifRational.ToDecimal(Value2);
					Value.Minute = ExifRational.ToDecimal(Value3);
					Value.Second = ExifRational.ToDecimal(Value4);
					Value.CardinalPoint = c;
					result = true;
				}
				else
				{
					Value = default(GeoCoordinate);
				}
			}
			else
			{
				Value = default(GeoCoordinate);
			}
			return result;
		}

		private bool SetGpsCoordinateHelper(GeoCoordinate Value, ExifTag ValueTag, ExifTag RefTag, char Cp1, char Cp2)
		{
			bool result = false;
			ExifRational value = ExifRational.FromDecimal(Value.Degree);
			ExifRational value2 = ExifRational.FromDecimal(Value.Minute);
			ExifRational value3 = ExifRational.FromDecimal(Value.Second);
			if (SetTagValue(ValueTag, value, ExifTagType.URational) && SetTagValue(ValueTag, value2, ExifTagType.URational, 1) && SetTagValue(ValueTag, value3, ExifTagType.URational, 2) && (Value.CardinalPoint == Cp1 || Value.CardinalPoint == Cp2) && SetTagValue(RefTag, Value.CardinalPoint.ToString(), StrCoding.Utf8))
			{
				result = true;
			}
			return result;
		}

		private bool GetDateAndTimeWithMillisecHelper(out DateTime Value, ExifTag DateAndTimeTag, ExifTag MillisecTag)
		{
			bool result = false;
			if (GetTagValue(DateAndTimeTag, out Value, ExifDateFormat.DateAndTime))
			{
				result = true;
				if (GetTagValue(MillisecTag, out var Value2, StrCoding.Utf8))
				{
					string text = Value2;
					int length = text.Length;
					if (length > 3)
					{
						text = text.Substring(0, 3);
					}
					if (int.TryParse(text, out var result2) && result2 >= 0)
					{
						switch (length)
						{
						case 1:
							result2 *= 100;
							break;
						case 2:
							result2 *= 10;
							break;
						}
						Value = Value.AddMilliseconds(result2);
					}
				}
			}
			return result;
		}

		private bool SetDateAndTimeWithMillisecHelper(DateTime Value, ExifTag DateAndTimeTag, ExifTag MillisecTag)
		{
			bool flag = false;
			if (SetTagValue(DateAndTimeTag, Value))
			{
				flag = true;
				int millisecond = Value.Millisecond;
				if (millisecond != 0 || TagExists(MillisecTag))
				{
					string value = millisecond.ToString("000");
					flag = flag && SetTagValue(MillisecTag, value, StrCoding.Utf8);
				}
			}
			return flag;
		}

		private static void InitInternalTiffTags()
		{
			InternalTiffTagsBitArray = new BitArray(533, defaultValue: false);
			int num = InternalTiffTagsBitArray.Length;
			ExifTagId[] internalTiffTags = InternalTiffTags;
			for (int i = 0; i < internalTiffTags.Length; i++)
			{
				int num2 = (int)internalTiffTags[i];
				if (num2 >= num)
				{
					num <<= 1;
					if (num2 >= num)
					{
						num = num2 + 1;
					}
					InternalTiffTagsBitArray.Length = num;
				}
				InternalTiffTagsBitArray.Set(num2, value: true);
			}
		}

		private static bool IsInternalTiffTag(ExifTagId TagId)
		{
			if (InternalTiffTagsBitArray == null)
			{
				InitInternalTiffTags();
			}
			if ((int)TagId < InternalTiffTagsBitArray.Length)
			{
				return InternalTiffTagsBitArray.Get((int)TagId);
			}
			return false;
		}

		private static bool IsMetaDataTiffTag(ExifTagId TagId)
		{
			if (TagId != ExifTagId.XmpMetadata)
			{
				return TagId == ExifTagId.IptcMetadata;
			}
			return true;
		}

		private void SwapByteOrderOfTagData(ExifIfd Ifd, TagItem t)
		{
			switch (Ifd)
			{
			case ExifIfd.PrimaryData:
				if (IsMetaDataTiffTag(t.TagId))
				{
					return;
				}
				break;
			case ExifIfd.PrivateData:
				if (t.TagId == ExifTagId.UserComment && t.TagType == ExifTagType.Undefined)
				{
					int num = t.ValueIndex + 8;
					int num2 = (t.ValueCount - 8) / 2;
					for (int i = 0; i < num2; i++)
					{
						Swap2ByteValue(t.ValueData, num);
						num += 2;
					}
					return;
				}
				break;
			}
			switch (t.TagType)
			{
			case ExifTagType.UShort:
			case ExifTagType.SShort:
			{
				int num3 = t.ValueIndex;
				for (int m = 0; m < t.ValueCount; m++)
				{
					Swap2ByteValue(t.ValueData, num3);
					num3 += 2;
				}
				break;
			}
			case ExifTagType.ULong:
			case ExifTagType.SLong:
			case ExifTagType.Float:
			{
				int num3 = t.ValueIndex;
				for (int k = 0; k < t.ValueCount; k++)
				{
					Swap4ByteValue(t.ValueData, num3);
					num3 += 4;
				}
				break;
			}
			case ExifTagType.URational:
			case ExifTagType.SRational:
			{
				int num3 = t.ValueIndex;
				for (int l = 0; l < t.ValueCount; l++)
				{
					Swap4ByteValue(t.ValueData, num3);
					num3 += 4;
					Swap4ByteValue(t.ValueData, num3);
					num3 += 4;
				}
				break;
			}
			case ExifTagType.Double:
			{
				int num3 = t.ValueIndex;
				for (int j = 0; j < t.ValueCount; j++)
				{
					Array.Reverse(t.ValueData, num3, 8);
					num3 += 8;
				}
				break;
			}
			case ExifTagType.SByte:
			case ExifTagType.Undefined:
				break;
			}
		}

		private void Swap2ByteValue(byte[] b, int i)
		{
			byte b2 = b[i];
			b[i] = b[i + 1];
			b[i + 1] = b2;
		}

		private void Swap4ByteValue(byte[] b, int i)
		{
			byte b2 = b[i];
			b[i] = b[i + 3];
			b[i + 3] = b2;
			b2 = b[i + 1];
			b[i + 1] = b[i + 2];
			b[i + 2] = b2;
		}

		private TagItem CopyTagItemDeeply(ExifIfd Ifd, TagItem TagItemToBeCopied, bool SwapByteOrder)
		{
			TagItem tagItem = new TagItem(TagItemToBeCopied.TagId, TagItemToBeCopied.TagType, TagItemToBeCopied.ValueCount);
			Array.Copy(TagItemToBeCopied.ValueData, TagItemToBeCopied.ValueIndex, tagItem.ValueData, 0, tagItem.ByteCount);
			if (SwapByteOrder)
			{
				SwapByteOrderOfTagData(Ifd, tagItem);
			}
			return tagItem;
		}
