	public struct ExifRational
	{
		public uint Numer;

		public uint Denom;

		public bool Sign;

		public ExifRational(int _Numer, int _Denom)
		{
			if (_Numer < 0)
			{
				Numer = (uint)(-_Numer);
				Sign = true;
			}
			else
			{
				Numer = (uint)_Numer;
				Sign = false;
			}
			if (_Denom < 0)
			{
				Denom = (uint)(-_Denom);
				Sign = !Sign;
			}
			else
			{
				Denom = (uint)_Denom;
			}
		}

		public ExifRational(uint _Numer, uint _Denom, bool _Sign = false)
		{
			Numer = _Numer;
			Denom = _Denom;
			Sign = _Sign;
		}

		public bool IsNegative()
		{
			if (Sign)
			{
				return Numer != 0;
			}
			return false;
		}

		public bool IsPositive()
		{
			if (!Sign)
			{
				return Numer != 0;
			}
			return false;
		}

		public bool IsZero()
		{
			return Numer == 0;
		}

		public bool IsValid()
		{
			return Denom != 0;
		}

		public new string ToString()
		{
			string text = "";
			if (IsNegative())
			{
				text = "-";
			}
			return text + Numer + "/" + Denom;
		}

		public static decimal ToDecimal(ExifRational Value)
		{
			decimal num = (decimal)Value.Numer / (decimal)Value.Denom;
			if (Value.Sign)
			{
				num = -num;
			}
			return num;
		}

		public static ExifRational FromDecimal(decimal Value)
		{
			uint num = 1u;
			ExifRational result = default(ExifRational);
			decimal num2;
			if (Value >= 0m)
			{
				num2 = Value;
				result.Sign = false;
			}
			else
			{
				num2 = -Value;
				result.Sign = true;
			}
			if (num2 >= 1000000000m)
			{
				num2 = Math.Truncate(num2 + 0.5m);
				if (!(num2 <= 4294967295m))
				{
					throw new OverflowException();
				}
				result.Numer = (uint)num2;
			}
			else
			{
				while (num2 != decimal.Truncate(num2))
				{
					decimal num3 = num2 * 10m;
					if (num > 100000000 || !(decimal.Truncate(num3 + 0.5m) < 1000000000m))
					{
						break;
					}
					num2 = num3;
					num *= 10;
				}
				result.Numer = (uint)decimal.Truncate(num2 + 0.5m);
			}
			result.Denom = num;
			while (result.Denom >= 10 && result.Numer % 10 == 0)
			{
				result.Numer /= 10u;
				result.Denom /= 10u;
			}
			return result;
		}
	}
	public struct GeoCoordinate
	{
		public decimal Degree;

		public decimal Minute;

		public decimal Second;

		public char CardinalPoint;

		public static decimal ToDecimal(GeoCoordinate Value)
		{
			decimal num = Value.Degree + Value.Minute / 60m + Value.Second / 3600m;
			if (Value.CardinalPoint == 'S' || Value.CardinalPoint == 'W')
			{
				num = -num;
			}
			return num;
		}

		public static GeoCoordinate FromDecimal(decimal Value, bool IsLatitude)
		{
			GeoCoordinate result = default(GeoCoordinate);
			decimal num;
			if (Value >= 0m)
			{
				result.CardinalPoint = (IsLatitude ? 'N' : 'E');
				num = Value;
			}
			else
			{
				result.CardinalPoint = (IsLatitude ? 'S' : 'W');
				num = -Value;
			}
			result.Degree = decimal.Truncate(num);
			decimal num2 = (num - result.Degree) * 60m;
			result.Minute = decimal.Truncate(num2);
			result.Second = (num2 - result.Minute) * 60m;
			return result;
		}
	}
