namespace ProperVersion
{
	public class SemVer : IComparable<SemVer>, IEquatable<SemVer>
	{
		private static readonly string[] PART_LOOKUP = new string[5] { "MAJOR", "MINOR", "PATCH", "PRE_RELEASE", "BUILD_METADATA" };

		public int Major { get; }

		public int Minor { get; }

		public int Patch { get; }

		public string[] PreReleaseIdentifiers { get; }

		public string[] BuildMetadataIdentifiers { get; }

		public string PreRelease => string.Join(".", PreReleaseIdentifiers);

		public string BuildMetadata => string.Join(".", BuildMetadataIdentifiers);

		public SemVer(int major, int minor, int patch)
			: this(major, minor, patch, Array.Empty<string>(), null, Array.Empty<string>(), null)
		{
		}

		public SemVer(int major, int minor, int patch, string preRelease = "", string buildMetadata = "")
			: this(major, minor, patch, SplitIdentifiers(preRelease), "preRelease", SplitIdentifiers(buildMetadata), "buildMetadata")
		{
		}

		public SemVer(int major, int minor, int patch, string[] preReleaseIdentifiers = null, string[] buildMetadataIdentifiers = null)
			: this(major, minor, patch, preReleaseIdentifiers, "preReleaseIdentifiers", buildMetadataIdentifiers, "buildMetadataIdentifiers")
		{
		}

		private SemVer(int major, int minor, int patch, string[] preReleaseIdentifiers, string preReleaseParamName, string[] buildMetadataIdentifiers, string buildMetadataParamName)
		{
			if (major < 0)
			{
				throw new ArgumentOutOfRangeException("major", major, "Major value must be 0 or positive");
			}
			if (minor < 0)
			{
				throw new ArgumentOutOfRangeException("minor", minor, "Minor value must be 0 or positive");
			}
			if (patch < 0)
			{
				throw new ArgumentOutOfRangeException("patch", patch, "Patch value must be 0 or positive");
			}
			if (preReleaseIdentifiers == null)
			{
				preReleaseIdentifiers = Array.Empty<string>();
			}
			for (int i = 0; i < preReleaseIdentifiers.Length; i++)
			{
				string text = preReleaseIdentifiers[i];
				if (text == null)
				{
					throw new ArgumentException($"{preReleaseParamName} contains null element at index {i}", preReleaseParamName);
				}
				if (text.Length == 0)
				{
					throw new ArgumentException($"{preReleaseParamName} contains empty identifier at index {i}", preReleaseParamName);
				}
				if (!IsValidIdentifier(text))
				{
					throw new ArgumentException($"{preReleaseParamName} contains invalid identifier ('{text}') at index {i}", preReleaseParamName);
				}
				if (IsNumericIdent(text) && text[0] == '0' && text.Length > 1)
				{
					throw new ArgumentException($"{preReleaseParamName} contains numeric identifier with leading zero(es) at index {i}", preReleaseParamName);
				}
			}
			if (buildMetadataIdentifiers == null)
			{
				buildMetadataIdentifiers = Array.Empty<string>();
			}
			for (int j = 0; j < buildMetadataIdentifiers.Length; j++)
			{
				string text2 = buildMetadataIdentifiers[j];
				if (text2 == null)
				{
					throw new ArgumentException($"{buildMetadataParamName} contains null element at index {j}", buildMetadataParamName);
				}
				if (text2.Length == 0)
				{
					throw new ArgumentException($"{buildMetadataParamName} contains empty identifier at index {j}", buildMetadataParamName);
				}
				if (!IsValidIdentifier(text2))
				{
					throw new ArgumentException($"{buildMetadataParamName} contains invalid identifier ('{text2}') at index {j}", buildMetadataParamName);
				}
			}
			Major = major;
			Minor = minor;
			Patch = patch;
			PreReleaseIdentifiers = preReleaseIdentifiers;
			BuildMetadataIdentifiers = buildMetadataIdentifiers;
		}

		public static SemVer Parse(string s)
		{
			TryParse(s, out var result, throwException: true);
			return result;
		}

		public static bool TryParse(string s, out SemVer result)
		{
			string error;
			return TryParse(s, out result, out error);
		}

		public static bool TryParse(string s, out SemVer result, out string error)
		{
			error = TryParse(s, out result, throwException: false);
			return error == null;
		}

		private static string TryParse(string s, out SemVer result, bool throwException)
		{
			if (s == null)
			{
				throw new ArgumentNullException("s");
			}
			StringBuilder stringBuilder = new StringBuilder();
			string error = null;
			int mode = 0;
			int index = 0;
			char? chr = null;
			int[] array = new int[3];
			List<string>[] array2 = new List<string>[2]
			{
				new List<string>(),
				new List<string>()
			};
			for (; index <= s.Length; index++)
			{
				chr = ((index < s.Length) ? new char?(s[index]) : ((char?)null));
				if (mode <= 2)
				{
					if (chr >= '0' && chr <= '9')
					{
						stringBuilder.Append(chr);
						if (stringBuilder.Length == 2 && stringBuilder[0] == '0')
						{
							Error("{0} version contains leading zero");
						}
						continue;
					}
					if (stringBuilder.Length == 0)
					{
						Error("Expected {0} version number, found {1}");
					}
					else
					{
						array[mode] = int.Parse(stringBuilder.ToString());
					}
					stringBuilder.Clear();
					if (chr == '.')
					{
						if (mode == 2)
						{
							Error("Expected PRE_RELEASE or BUILD_METADATA, found {1}");
						}
						mode++;
						continue;
					}
					if (mode != 2)
					{
						Error("Expected {0} version, found {1}", nextMode: true);
					}
					if (chr == '-')
					{
						mode = 3;
					}
					else if (chr == '+')
					{
						mode = 4;
					}
					else if (chr.HasValue)
					{
						Error("Expected PRE_RELEASE or BUILD_METADATA, found {1}");
						mode = 3;
						index--;
					}
					continue;
				}
				if (chr.HasValue && IsValidIdentifierChar(chr.Value))
				{
					stringBuilder.Append(chr);
					continue;
				}
				if (chr != '.' && chr.HasValue && (chr != '+' || mode != 3))
				{
					Error("Unexpected character {1} in {0} identifier");
					continue;
				}
				if (stringBuilder.Length == 0)
				{
					Error("Expected {0} identifier, found {1}");
				}
				else
				{
					string text = stringBuilder.ToString();
					if (mode == 3 && IsNumericIdent(text) && text[0] == '0' && text.Length > 1)
					{
						Error("{0} numeric identifier contains leading zero");
						text = text.TrimStart('0');
					}
					array2[mode - 3].Add(text);
				}
				stringBuilder.Clear();
				if (chr == '+' && mode == 3)
				{
					mode++;
				}
			}
			result = new SemVer(array[0], array[1], array[2], array2[0].ToArray(), array2[1].ToArray());
			return error;
			void Error(string message, bool nextMode = false)
			{
				if (error == null)
				{
					error = $"Failed parsing version string '{s}' at index {index}: " + string.Format(message, PART_LOOKUP[nextMode ? (mode + 1) : mode], chr.HasValue ? $"'{chr}'" : "end of string");
					if (throwException)
					{
						throw new FormatException(error);
					}
				}
			}
		}

		public override string ToString()
		{
			StringBuilder stringBuilder = new StringBuilder().Append(Major).Append('.').Append(Minor)
				.Append('.')
				.Append(Patch);
			if (PreReleaseIdentifiers.Length != 0)
			{
				stringBuilder.Append('-').Append(PreRelease);
			}
			if (BuildMetadataIdentifiers.Length != 0)
			{
				stringBuilder.Append('+').Append(BuildMetadata);
			}
			return stringBuilder.ToString();
		}

		public static bool operator ==(SemVer left, SemVer right)
		{
			if ((object)left != right)
			{
				return left?.Equals(right) ?? false;
			}
			return true;
		}

		public static bool operator !=(SemVer left, SemVer right)
		{
			return !(left == right);
		}

		public static bool operator >(SemVer left, SemVer right)
		{
			if (left != null && right != null)
			{
				return Compare(left, right) > 0;
			}
			return false;
		}

		public static bool operator <(SemVer left, SemVer right)
		{
			if (left != null && right != null)
			{
				return Compare(left, right) < 0;
			}
			return false;
		}

		public static bool operator >=(SemVer left, SemVer right)
		{
			if (left != null && right != null)
			{
				return Compare(left, right) >= 0;
			}
			return false;
		}

		public static bool operator <=(SemVer left, SemVer right)
		{
			if (left != null && right != null)
			{
				return Compare(left, right) <= 0;
			}
			return false;
		}

		public int CompareTo(SemVer other)
		{
			return Compare(this, other);
		}

		public static int Compare(SemVer left, SemVer right)
		{
			if ((object)left == right)
			{
				return 0;
			}
			if ((object)left == null)
			{
				return -1;
			}
			if ((object)right == null)
			{
				return 1;
			}
			int num = left.Major.CompareTo(right.Major);
			if (num != 0)
			{
				return num;
			}
			int num2 = left.Minor.CompareTo(right.Minor);
			if (num2 != 0)
			{
				return num2;
			}
			int num3 = left.Patch.CompareTo(right.Patch);
			if (num3 != 0)
			{
				return num3;
			}
			bool flag = left.PreReleaseIdentifiers.Length != 0;
			bool flag2 = right.PreReleaseIdentifiers.Length != 0;
			if (flag != flag2)
			{
				if (!flag)
				{
					return 1;
				}
				return -1;
			}
			int num4 = Math.Min(left.PreReleaseIdentifiers.Length, right.PreReleaseIdentifiers.Length);
			for (int i = 0; i < num4; i++)
			{
				string text = left.PreReleaseIdentifiers[i];
				string text2 = right.PreReleaseIdentifiers[i];
				bool flag3 = IsNumericIdent(text);
				bool flag4 = IsNumericIdent(text2);
				if (flag3 != flag4)
				{
					if (!flag3)
					{
						return 1;
					}
					return -1;
				}
				int num5 = (flag3 ? int.Parse(text).CompareTo(int.Parse(text2)) : string.CompareOrdinal(text, text2));
				if (num5 != 0)
				{
					return num5;
				}
			}
			return left.PreReleaseIdentifiers.Length - right.PreReleaseIdentifiers.Length;
		}

		public bool Equals(SemVer other)
		{
			if (other != null && Major == other.Major && Minor == other.Minor && Patch == other.Patch && PreRelease == other.PreRelease)
			{
				return BuildMetadata == other.BuildMetadata;
			}
			return false;
		}

		public override bool Equals(object obj)
		{
			return Equals(obj as SemVer);
		}

		public override int GetHashCode()
		{
			return Major ^ (Minor << 8) ^ (Patch << 16) ^ PreRelease.GetHashCode() ^ (BuildMetadata.GetHashCode() << 6);
		}

		private static bool IsValidIdentifier(string ident)
		{
			for (int i = 0; i < ident.Length; i++)
			{
				if (!IsValidIdentifierChar(ident[i]))
				{
					return false;
				}
			}
			return true;
		}

		private static bool IsValidIdentifierChar(char chr)
		{
			if ((chr < '0' || chr > '9') && (chr < 'A' || chr > 'Z') && (chr < 'a' || chr > 'z'))
			{
				return chr == '-';
			}
			return true;
		}

		private static bool IsNumericIdent(string ident)
		{
			for (int i = 0; i < ident.Length; i++)
			{
				if (ident[i] < '0' || ident[i] > '9')
				{
					return false;
				}
			}
			return true;
		}

		private static string[] SplitIdentifiers(string str)
		{
			if (string.IsNullOrEmpty(str))
			{
				return Array.Empty<string>();
			}
			return str.Split('.');
		}
	}
}
