				}
			}

			public int ToRgba(uint light, int lightSat)
			{
				byte b = blockLightlevelsByte[(light >> 5) & 0x1F];
				byte b2 = sunLightlevelsByte[light & 0x1F];
				if (lightSat == 0)
				{
					return (b2 << 24) | (b << 16) | (b << 8) | b;
				}
				byte num = hueLevels[light >> 10];
				byte b3 = satLevels[lightSat];
