	public class Crc32Algorithm : HashAlgorithm
	{
		private uint _currentCrc;

		private static readonly SafeProxy _proxy = new SafeProxy();

		public Crc32Algorithm()
		{
			HashSizeValue = 32;
		}

		public static uint Append(uint initial, byte[] input, int offset, int length)
		{
			if (input == null)
			{
				throw new ArgumentNullException();
			}
			if (offset < 0 || length < 0 || offset + length > input.Length)
			{
				throw new ArgumentOutOfRangeException("Selected range is outside the bounds of the input array");
			}
			return AppendInternal(initial, input, offset, length);
		}

		public static uint Append(uint initial, byte[] input)
		{
			if (input == null)
			{
				throw new ArgumentNullException();
			}
			return AppendInternal(initial, input, 0, input.Length);
		}

		public static uint Compute(byte[] input, int offset, int length)
		{
			return Append(0u, input, offset, length);
		}

		public static uint Compute(byte[] input)
		{
			return Append(0u, input);
		}

		public override void Initialize()
		{
			_currentCrc = 0u;
		}

		protected override void HashCore(byte[] input, int offset, int length)
		{
			_currentCrc = AppendInternal(_currentCrc, input, offset, length);
		}

		protected override byte[] HashFinal()
		{
			return new byte[4]
			{
				(byte)(_currentCrc >> 24),
				(byte)(_currentCrc >> 16),
				(byte)(_currentCrc >> 8),
				(byte)_currentCrc
			};
		}

		private static uint AppendInternal(uint initial, byte[] input, int offset, int length)
		{
			if (length > 0)
			{
				return _proxy.Append(initial, input, offset, length);
			}
			return initial;
		}
	}
	internal class SafeProxy
	{
		private const uint Poly = 3988292384u;

		private static readonly uint[] _table;

		static SafeProxy()
		{
			_table = new uint[4096];
			for (uint num = 0u; num < 256; num++)
			{
				uint num2 = num;
				for (int i = 0; i < 16; i++)
				{
					for (int j = 0; j < 8; j++)
					{
						num2 = (((num2 & 1) == 1) ? (0xEDB88320u ^ (num2 >> 1)) : (num2 >> 1));
					}
					_table[i * 256 + num] = num2;
				}
			}
		}

		public uint Append(uint crc, byte[] input, int offset, int length)
		{
			uint num = 0xFFFFFFFFu ^ crc;
			uint[] table = _table;
			while (length >= 16)
			{
				num = table[3840 + ((num ^ input[offset]) & 0xFF)] ^ table[3584 + (((num >> 8) ^ input[offset + 1]) & 0xFF)] ^ table[3328 + (((num >> 16) ^ input[offset + 2]) & 0xFF)] ^ table[3072 + (((num >> 24) ^ input[offset + 3]) & 0xFF)] ^ table[2816 + input[offset + 4]] ^ table[2560 + input[offset + 5]] ^ table[2304 + input[offset + 6]] ^ table[2048 + input[offset + 7]] ^ table[1792 + input[offset + 8]] ^ table[1536 + input[offset + 9]] ^ table[1280 + input[offset + 10]] ^ table[1024 + input[offset + 11]] ^ table[768 + input[offset + 12]] ^ table[512 + input[offset + 13]] ^ table[256 + input[offset + 14]] ^ table[input[offset + 15]];
				offset += 16;
				length -= 16;
			}
			while (--length >= 0)
			{
				num = table[(num ^ input[offset++]) & 0xFF] ^ (num >> 8);
			}
			return num ^ 0xFFFFFFFFu;
		}
	}
	public class Cuboidd : ICuboid<double, Cuboidd>, IEquatable<Cuboidd>
	{
		private const double epsilon = 1.6E-05;

		public double X1;

		public double Y1;

		public double Z1;

		public double X2;

		public double Y2;

		public double Z2;

		public double Width => MaxX - MinX;

		public double Height => MaxY - MinY;

		public double Length => MaxZ - MinZ;

		public double MinX => Math.Min(X1, X2);

		public double MinY => Math.Min(Y1, Y2);

		public double MinZ => Math.Min(Z1, Z2);

		public double MaxX => Math.Max(X1, X2);

		public double MaxY => Math.Max(Y1, Y2);

		public double MaxZ => Math.Max(Z1, Z2);

		public Vec3d Start => new Vec3d(MinX, MinY, MinZ);

		public Vec3d End => new Vec3d(MaxX, MaxY, MaxZ);

		public Cuboidd()
		{
		}

		public Cuboidd(double x1, double y1, double z1, double x2, double y2, double z2)
		{
			Set(x1, y1, z1, x2, y2, z2);
		}

		public Cuboidd(Vec3d start, Vec3d end)
		{
			X1 = start.X;
			Y1 = start.Y;
			Z1 = start.Z;
			X2 = end.X;
			Y2 = end.Y;
			Z2 = end.Z;
		}

		public Cuboidd Set(double x1, double y1, double z1, double x2, double y2, double z2)
		{
			X1 = x1;
			Y1 = y1;
			Z1 = z1;
			X2 = x2;
			Y2 = y2;
			Z2 = z2;
			return this;
		}

		public Cuboidd Set(IVec3 min, IVec3 max)
		{
			Set(min.XAsDouble, min.YAsDouble, min.ZAsDouble, max.XAsDouble, max.YAsDouble, max.ZAsDouble);
			return this;
		}

		public Cuboidd Set(Cuboidf selectionBox)
		{
			X1 = selectionBox.X1;
			Y1 = selectionBox.Y1;
			Z1 = selectionBox.Z1;
			X2 = selectionBox.X2;
			Y2 = selectionBox.Y2;
			Z2 = selectionBox.Z2;
			return this;
		}

		public void Set(Cuboidd other)
		{
			X1 = other.X1;
			Y1 = other.Y1;
			Z1 = other.Z1;
			X2 = other.X2;
			Y2 = other.Y2;
			Z2 = other.Z2;
		}

		public Cuboidd SetAndTranslate(Cuboidf selectionBox, Vec3d vec)
		{
			X1 = (double)selectionBox.X1 + vec.X;
			Y1 = (double)selectionBox.Y1 + vec.Y;
			Z1 = (double)selectionBox.Z1 + vec.Z;
			X2 = (double)selectionBox.X2 + vec.X;
			Y2 = (double)selectionBox.Y2 + vec.Y;
			Z2 = (double)selectionBox.Z2 + vec.Z;
			return this;
		}

		public Cuboidd SetAndTranslate(Cuboidf selectionBox, double dX, double dY, double dZ)
		{
			X1 = (double)selectionBox.X1 + dX;
			Y1 = (double)selectionBox.Y1 + dY;
			Z1 = (double)selectionBox.Z1 + dZ;
			X2 = (double)selectionBox.X2 + dX;
			Y2 = (double)selectionBox.Y2 + dY;
			Z2 = (double)selectionBox.Z2 + dZ;
			return this;
		}

		public void RemoveRoundingErrors()
		{
			double num = X1 * 16.0;
			double num2 = Z1 * 16.0;
			double num3 = X2 * 16.0;
			double num4 = Z2 * 16.0;
			if (Math.Ceiling(num) - num < 1.6E-05)
			{
				X1 = Math.Ceiling(num) / 16.0;
			}
			if (Math.Ceiling(num2) - num2 < 1.6E-05)
			{
				Z1 = Math.Ceiling(num2) / 16.0;
			}
			if (num3 - Math.Floor(num3) < 1.6E-05)
			{
				X2 = Math.Floor(num3) / 16.0;
			}
			if (num4 - Math.Floor(num4) < 1.6E-05)
			{
				Z2 = Math.Floor(num4) / 16.0;
			}
		}

		public Cuboidd Translate(IVec3 vec)
		{
			Translate(vec.XAsDouble, vec.YAsDouble, vec.ZAsDouble);
			return this;
		}

		public Cuboidd Translate(double posX, double posY, double posZ)
		{
			X1 += posX;
			Y1 += posY;
			Z1 += posZ;
			X2 += posX;
			Y2 += posY;
			Z2 += posZ;
			return this;
		}

		public Cuboidd GrowBy(double dx, double dy, double dz)
		{
			X1 -= dx;
			Y1 -= dy;
			Z1 -= dz;
			X2 += dx;
			Y2 += dy;
			Z2 += dz;
			return this;
		}

		public bool ContainsOrTouches(double x, double y, double z)
		{
			if (x >= X1 && x <= X2 && y >= Y1 && y <= Y2 && z >= Z1)
			{
				return z <= Z2;
			}
			return false;
		}

		public bool Contains(double x, double y, double z)
		{
			if (x > X1 && x < X2 && y > Y1 && y < Y2 && z > Z1)
			{
				return z < Z2;
			}
			return false;
		}

		public bool ContainsOrTouches(IVec3 vec)
		{
