		}

		public Cuboidd GrowToInclude(int x, int y, int z)
		{
			X1 = Math.Min(X1, x);
			Y1 = Math.Min(Y1, y);
			Z1 = Math.Min(Z1, z);
			X2 = Math.Max(X2, x + 1);
			Y2 = Math.Max(Y2, y + 1);
			Z2 = Math.Max(Z2, z + 1);
			return this;
		}

		public Cuboidd GrowToInclude(IVec3 vec)
