					int leftBottom = map.Data[(j + 1 + topLeftPadding) * map.Size + i + topLeftPadding];
					int rightBottom = map.Data[(j + 1 + topLeftPadding) * map.Size + i + 1 + topLeftPadding];
					for (int k = 0; k < zoom; k++)
