		public static void Shuffle<T>(Random rand, T[] array)
		{
			int num = array.Length;
			while (num > 1)
			{
				int num2 = rand.Next(num);
				num--;
				T val = array[num];
				array[num] = array[num2];
				array[num2] = val;
			}
		}

		public static void Shuffle<T>(Random rand, List<T> array)
		{
