			float num5 = a[2];
			float num6 = a[3];
			float num7 = a[4];
			float num8 = a[5];
			float num9 = a[6];
			float num10 = a[7];
			if (a != output)
			{
				output[8] = a[8];
				output[9] = a[9];
				output[10] = a[10];
				output[11] = a[11];
				output[12] = a[12];
				output[13] = a[13];
				output[14] = a[14];
				output[15] = a[15];
			}
			output[0] = num3 * num2 + num7 * num;
			output[1] = num4 * num2 + num8 * num;
			output[2] = num5 * num2 + num9 * num;
			output[3] = num6 * num2 + num10 * num;
			output[4] = num7 * num2 - num3 * num;
			output[5] = num8 * num2 - num4 * num;
			output[6] = num9 * num2 - num5 * num;
