			array[6] = right[2];
			array[1] = up[0];
			array[4] = up[1];
			array[7] = up[2];
			array[2] = view[0];
			array[5] = view[1];
			array[8] = view[2];
			return Normalize(output, FromMat3(output, array));
		}

