			double num5 = GameMath.Sin(rad);
			double num6 = GameMath.Cos(rad);
			output[0] = num * num6 + num2 * num5;
			output[1] = num2 * num6 - num * num5;
			output[2] = num3 * num6 + num4 * num5;
			output[3] = num4 * num6 - num3 * num5;
