			output[0] = num;
			output[1] = num2;
			output[2] = num3;
			double num4 = 1.0;
			output[3] = 0f - GameMath.Sqrt(Math.Abs(num4 - num * num - num2 * num2 - num3 * num3));
			return output;
		}

