						}
						flag3 = flag3 || direction != EnumPushDirection.None;
					}
					collidedVertically = flag3;
				}
				for (int num8 = 0; num8 < collBoxCount; num8++)
				{
					entityBox[num8].Translate(num, 0.0, 0.0);
				}
				for (int num9 = 0; num9 < num4; num9++)
