				orderedOctaveEntries = new OctaveEntry[num2];
				double num7 = 0.0;
				for (int num8 = num2 - 1; num8 >= 0; num8--)
				{
					int num9 = array2[num8];
					num7 += array[num9];
					double num10 = terrainNoise.frequencies[num9];
					orderedOctaveEntries[num8] = new OctaveEntry
					{
