	public class HorRectanglei
	{
		public int X1;

		public int Z1;

		public int X2;

		public int Z2;

		public int MinX => Math.Min(X1, X2);

		public int MaxX => Math.Max(X1, X2);

		public int MaxZ => Math.Max(Z1, Z2);

		public int MinZ => Math.Min(Z1, Z2);

		public HorRectanglei()
		{
		}

		public HorRectanglei(int x1, int z1, int x2, int z2)
		{
			X1 = x1;
			Z1 = z1;
			X2 = x2;
			Z2 = z2;
		}
	}
	public struct Rectanglei
	{
		private int X;

		private int Y;

		private int Width;

		private int Height;

		public int X1 => X;

		public int Y1 => Y;

		public int X2 => X + Width;

		public int Y2 => Y + Height;

		public int Bottom()
		{
			return Y + Height;
		}

		public Rectanglei(int X, int Y, int width, int height)
		{
			this.X = X;
			this.Y = Y;
			Width = width;
			Height = height;
		}

		public Rectanglei GrowBy(int size)
		{
			return new Rectanglei(X - size, Y - size, Width + size * 2, Height + size * 2);
		}

		[Obsolete("Rectanglei is a struct and there is no point cloning a struct")]
		public Rectanglei Clone()
		{
			return new Rectanglei(X, Y, Width, Height);
		}

		public bool PointInside(int x, int y)
		{
			if (x >= X && y >= Y && x <= X + Width)
			{
				return y <= Y + Height;
			}
			return false;
		}

		public bool PointInside(Vec2i pos)
		{
			if (pos.X >= X && pos.Y >= Y && pos.X <= X + Width)
			{
				return pos.Y <= Y + Height;
			}
			return false;
		}

		public bool Intersects(Rectanglei with)
		{
			if (with.X2 <= X1 || with.X1 >= X2)
			{
				return false;
			}
			if (with.Y2 <= Y1 || with.Y1 >= Y2)
			{
				return false;
			}
			return true;
		}

		public bool IntersectsOrTouches(Rectanglei with)
		{
			if (with.X2 < X1)
			{
				return false;
			}
			if (with.X1 >= X2)
			{
				return false;
			}
			if (with.Y2 < Y1)
			{
				return false;
			}
			if (with.Y1 >= Y2)
			{
				return false;
			}
			return true;
		}

		public bool IntersectsOrTouches(int withX1, int withY1, int withX2, int withY2)
		{
			if (withX2 < X1)
			{
				return false;
			}
			if (withX1 >= X2)
			{
				return false;
			}
			if (withY2 < Y1)
			{
				return false;
			}
			if (withY1 >= Y2)
			{
				return false;
			}
			return true;
		}

		public bool Contains(Vec2i pos)
		{
			if (pos.X >= X1 && pos.X < X2 && pos.Y >= Y1)
			{
				return pos.Y < Y2;
			}
			return false;
		}

		public bool Contains(int x, int y)
		{
			if (x >= X1 && x < X2 && y >= Y1)
			{
				return y < Y2;
			}
			return false;
		}
	}
	public static class ShapeUtil
