			for (int i = 1; i < MaxShells; i++)
			{
				cubicShellNormalizedVectors[i] = new Vec3f[(2 * i + 1) * (2 * i + 1) * 6];
				int num = 0;
				BlockFacing[] aLLFACES = BlockFacing.ALLFACES;
				foreach (BlockFacing blockFacing in aLLFACES)
				{
					array[0] = -i;
					while (array[0] <= i)
					{
						array[1] = -i;
