		public bool Equals(IWorldAccessor worldForResolve, IAttribute attr)
		{
			return Equals(worldForResolve, attr, null);
		}

		internal bool Equals(IWorldAccessor worldForResolve, IAttribute attr, string[] ignorePaths)
		{
			if (!(attr is ItemstackAttribute))
			{
				return false;
			}
			ItemstackAttribute itemstackAttribute = (ItemstackAttribute)attr;
			if (itemstackAttribute.value != null || value != null)
			{
				if (itemstackAttribute.value != null)
				{
					return itemstackAttribute.value.Equals(worldForResolve, value, ignorePaths);
				}
				return false;
			}
			return true;
		}

