		static TreeAttribute()
		{
			AttributeIdMapping = new Dictionary<int, Type>();
			RegisterAttribute(1, typeof(IntAttribute));
			RegisterAttribute(2, typeof(LongAttribute));
			RegisterAttribute(3, typeof(DoubleAttribute));
