				{
					return false;
				}
			}
			if (num2 >= array.Length)
			{
				array = expandArray(num);
			}
			array[num2++] = value;
			sizes[num] = num2;
			count++;
			return true;
		}

		private long[] expandArray(int j)
		{
			long[] array = buckets[j];
			long[] array2 = new long[array.Length * 3 / 2 + 1];
			for (int i = 0; i < array.Length; i++)
			{
