			}
			buckets[j] = array2;
			return array2;
		}

		public IEnumerator<long> GetEnumerator()
		{
			for (int j = 0; j < buckets.Length; j++)
			{
				int size = sizes[j];
				long[] set = buckets[j];
				for (int i = 0; i < size; i++)
				{
					yield return set[i];
				}
			}
		}

