				for (int i = num; i < num2; i++)
				{
					if ((array[i] & 0xFFFFFF) == num3)
					{
						ReplaceIfLarger(i, v);
						return;
					}
				}
			}
			else
			{
				for (int j = 0; j < num2; j++)
				{
					if ((array[j] & 0xFFFFFF) == num3)
					{
						ReplaceIfLarger(j, v);
						return;
					}
				}
				for (int k = num; k < array.Length; k++)
				{
					if ((array[k] & 0xFFFFFF) == num3)
					{
						ReplaceIfLarger(k, v);
						return;
					}
				}
			}
			Enqueue(v);
		}

		private void ReplaceIfLarger(int i, int v)
		{
			if ((array[i] & 0x1F000000) < (v & 0x1F000000))
			{
				array[i] = v;
			}
		}

		public int Dequeue()
		{
			Count--;
			return array[head++ % maxSize];
		}

		public int DequeueLIFO()
		{
			Count--;
			int result = array[tail-- % maxSize];
			if (tail < 0)
			{
				tail += maxSize;
			}
			return result;
		}

		private void expandArray()
		{
			head %= maxSize;
			int num = maxSize;
			maxSize = maxSize * 2 + 1;
			int[] dest = new int[maxSize];
			if (head == 0)
			{
				ArrayCopy(array, 0, dest, 0, num);
			}
			else
			{
				num -= head;
				ArrayCopy(array, head, dest, 0, num);
				ArrayCopy(array, 0, dest, num, head);
			}
			array = dest;
			head = 0;
			tail = Count;
		}

		private void ArrayCopy(int[] src, int srcOffset, int[] dest, int destOffset, int len)
		{
			if (len > 128)
			{
				Array.Copy(src, srcOffset, dest, destOffset, len);
				return;
			}
			int num = srcOffset;
			int num2 = destOffset;
			int num3 = len / 4 * 4 + srcOffset;
			while (num < num3)
			{
				dest[num2] = src[num];
				dest[num2 + 1] = src[num + 1];
				dest[num2 + 2] = src[num + 2];
				dest[num2 + 3] = src[num + 3];
				num += 4;
				num2 += 4;
			}
			len += srcOffset;
			while (num < len)
			{
				dest[num2++] = src[num++];
			}
		}
	}
	public class RingArray<T> : IEnumerable<T>, IEnumerable
	{
		private T[] elements;

		private int cursor;

		public T this[int index]
		{
			get
			{
				return elements[index];
			}
			set
			{
				elements[index] = value;
			}
		}

		public int EndPosition
		{
			get
			{
				return cursor;
			}
			set
			{
				cursor = value;
			}
		}

		public T[] Values => elements;

		public int Length => elements.Length;

		public RingArray(int capacity)
		{
			elements = new T[capacity];
		}

		public RingArray(int capacity, T[] initialvalues)
		{
			elements = new T[capacity];
			if (initialvalues != null)
			{
				for (int i = 0; i < initialvalues.Length; i++)
				{
					Add(initialvalues[i]);
				}
			}
		}

		public void Add(T elem)
		{
			elements[cursor] = elem;
			cursor = (cursor + 1) % elements.Length;
		}

		public IEnumerator<T> GetEnumerator()
		{
			for (int i = 0; i < elements.Length; i++)
			{
				yield return elements[(cursor + i) % elements.Length];
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}

		public void Clear()
		{
			for (int i = 0; i < elements.Length; i++)
			{
				elements[i] = default(T);
			}
			cursor = 0;
		}

		public void ResizeTo(int size)
		{
			T[] array = new T[size];
			for (int i = 0; i < elements.Length; i++)
			{
				array[size - 1] = elements[GameMath.Mod(EndPosition - i, elements.Length)];
				size--;
				if (size <= 0)
				{
					break;
				}
			}
			elements = array;
		}
	}
