	public struct SmallBoolArray : IEquatable<int>
	{
		public const int OnAllSides = 63;

		private int bits;

		public bool this[int i]
		{
			get
			{
				return (bits & (1 << i)) != 0;
			}
			set
			{
				if (value)
				{
					bits |= 1 << i;
				}
				else
				{
					bits &= ~(1 << i);
				}
			}
		}

		public bool Any => bits != 0;

		public bool All
		{
			get
			{
				return bits == 63;
			}
			set
			{
				bits = (value ? 63 : 0);
			}
		}

		public bool SidesAndBase => (bits & 0x2F) == 47;

		public bool Horizontals => (bits & 0xF) == 15;

		public bool Verticals => (bits & 0x30) == 48;

		public static implicit operator int(SmallBoolArray a)
		{
			return a.bits;
		}

		public SmallBoolArray(int values)
		{
			bits = values;
		}

		public SmallBoolArray(int[] values)
		{
			bits = 0;
			for (int i = 0; i < values.Length; i++)
			{
				if (values[i] != 0)
				{
					bits |= 1 << i;
				}
			}
		}

		public SmallBoolArray(bool[] values)
		{
			bits = 0;
			for (int i = 0; i < values.Length; i++)
			{
				if (values[i])
				{
					bits |= 1 << i;
				}
			}
		}

		public bool Equals(int other)
		{
			return bits == other;
		}

		public override bool Equals(object o)
		{
			if (o is int num)
			{
				return bits == num;
			}
			if (o is SmallBoolArray smallBoolArray)
			{
				return bits == smallBoolArray.bits;
			}
			return false;
		}

		public static bool operator ==(SmallBoolArray left, int right)
		{
			return right == left.bits;
		}

		public static bool operator !=(SmallBoolArray left, int right)
		{
			return right != left.bits;
		}

		public void Fill(bool b)
		{
			bits = (b ? 63 : 0);
		}

		public int[] ToIntArray(int size)
		{
			int[] array = new int[size];
			int num = bits;
			for (int i = 0; i < array.Length; i++)
			{
				array[i] = num & 1;
				num >>= 1;
			}
			return array;
		}

		public bool Opposite(int i)
		{
			return (bits & (1 << (i ^ (2 - i / 4)))) != 0;
		}

		public bool OnSide(BlockFacing face)
		{
			return (bits & (1 << face.Index)) != 0;
		}

		public int Value()
		{
			return bits;
		}

		public override int GetHashCode()
		{
			return 1537853281 + bits.GetHashCode();
		}
	}
	public class SortableQueue<T> where T : IComparable<T>
	{
		public int Count;

		public int maxSize = 27;

		protected int tail;

		protected int head;

		protected T[] array;

		public SortableQueue()
		{
			array = new T[maxSize];
		}

		public void Clear()
		{
			Count = 0;
			head = 0;
			tail = 0;
			Array.Clear(array, 0, maxSize);
		}

		public void Enqueue(T v)
		{
			if (Count == maxSize)
			{
				expandArray();
			}
			array[tail++ % maxSize] = v;
			Count++;
		}

		public void EnqueueOrMerge(T v)
		{
			if (head % maxSize > tail % maxSize)
			{
				for (int i = head % maxSize; i < maxSize; i++)
				{
					if (((IMergeable<T>)(object)array[i]).MergeIfEqual(v))
					{
						return;
					}
				}
				for (int j = 0; j < tail % maxSize; j++)
				{
					if (((IMergeable<T>)(object)array[j]).MergeIfEqual(v))
					{
						return;
					}
				}
			}
			else
			{
				for (int k = head % maxSize; k < tail % maxSize; k++)
				{
					if (((IMergeable<T>)(object)array[k]).MergeIfEqual(v))
					{
						return;
					}
				}
			}
			Enqueue(v);
		}

		public T Dequeue()
		{
			Count--;
			int num = head++ % maxSize;
			T result = array[num];
			array[num] = default(T);
			return result;
		}

		public void Sort()
		{
			if (head % maxSize > tail % maxSize)
			{
				T[] dest = new T[maxSize];
				int num = maxSize - head % maxSize;
				ArrayCopy(array, head % maxSize, dest, 0, num);
				ArrayCopy(array, 0, dest, num, tail % maxSize);
				Array.Clear(array, 0, maxSize);
				array = dest;
				head = 0;
				tail = tail % maxSize + num;
			}
			int num2 = head % maxSize;
			Array.Sort(array, num2, tail % maxSize - num2);
		}

		public void RunForEach(Action<T> action)
		{
			if (head % maxSize > tail % maxSize)
			{
				for (int i = head % maxSize; i < maxSize; i++)
				{
					action(array[i]);
				}
				for (int j = 0; j < tail % maxSize; j++)
				{
					action(array[j]);
				}
			}
			else
			{
				for (int k = head % maxSize; k < tail % maxSize; k++)
				{
					action(array[k]);
				}
			}
		}

		public T DequeueLIFO()
		{
			Count--;
			T result = array[tail-- % maxSize];
			if (tail < 0)
			{
				tail += maxSize;
			}
			return result;
		}

		private void expandArray()
		{
			head %= maxSize;
			int num = maxSize;
			maxSize = maxSize * 2 + 1;
			T[] dest = new T[maxSize];
			if (head == 0)
			{
				ArrayCopy(array, 0, dest, 0, num);
			}
			else
			{
				num -= head;
				ArrayCopy(array, head, dest, 0, num);
				ArrayCopy(array, 0, dest, num, head);
			}
			array = dest;
			head = 0;
			tail = Count;
		}

		private void ArrayCopy(T[] src, int srcOffset, T[] dest, int destOffset, int len)
		{
			if (len > 128)
			{
				Array.Copy(src, srcOffset, dest, destOffset, len);
				return;
			}
			int num = srcOffset;
			int num2 = destOffset;
			int num3 = len / 4 * 4 + srcOffset;
			while (num < num3)
			{
				dest[num2] = src[num];
				dest[num2 + 1] = src[num + 1];
				dest[num2 + 2] = src[num + 2];
				dest[num2 + 3] = src[num + 3];
				num += 4;
				num2 += 4;
			}
			len += srcOffset;
			while (num < len)
			{
				dest[num2++] = src[num++];
			}
		}
	}
	public class StackMatrix4
	{
		private double[][] values;

		private const int max = 1024;

		private int count;

		public double[] Top => values[count - 1];

		public int Count => count;

		public StackMatrix4(int max = 1024)
		{
			values = new double[max][];
			for (int i = 0; i < max; i++)
			{
				values[i] = Mat4d.Create();
			}
		}

		public void PushIdentity()
		{
			Mat4d.Identity(values[count]);
			count++;
			if (count >= values.Length)
			{
				throw new Exception("Stack matrix overflow");
			}
		}

		public void Push(double[] p)
		{
			Mat4d.Copy(values[count], p);
			count++;
			if (count >= values.Length)
			{
				throw new Exception("Stack matrix overflow");
			}
		}

		public void Push()
		{
			Mat4d.Copy(values[count], Top);
			count++;
			if (count >= values.Length)
			{
				throw new Exception("Stack matrix overflow");
			}
		}

		public double[] Pop()
		{
			double[] result = values[count - 1];
			count--;
			if (count < 0)
			{
				throw new Exception("Stack matrix underflow");
			}
			return result;
		}

		public void Clear()
		{
			count = 0;
		}

		public void Rotate(double rad, double x, double y, double z)
		{
			Mat4d.Rotate(Top, Top, rad, x, y, z);
		}

		public void Translate(double x, double y, double z)
		{
			Mat4d.Translate(Top, Top, x, y, z);
		}

		public void Scale(double x, double y, double z)
		{
			Mat4d.Scale(Top, x, y, z);
		}

		public void Translate(double[] rotationOrigin)
		{
			Mat4d.Translate(Top, Top, rotationOrigin);
		}
	}
	public readonly struct EntityTagArray
	{
		public readonly ulong BitMask1;

		public readonly ulong BitMask2;

		public const byte MasksNumber = 2;

		public const int Size = 128;

		public static readonly EntityTagArray Empty = new EntityTagArray();

		public EntityTagArray(IEnumerable<ushort> tags)
		{
			BitMask1 = 0uL;
			BitMask2 = 0uL;
			foreach (ushort tag in tags)
			{
				WriteTagToBitMasks(tag, ref BitMask1, ref BitMask2);
			}
		}

		public EntityTagArray(ushort tag)
		{
			BitMask1 = 0uL;
			BitMask2 = 0uL;
			WriteTagToBitMasks(tag, ref BitMask1, ref BitMask2);
		}

		public EntityTagArray()
		{
			BitMask1 = 0uL;
			BitMask2 = 0uL;
		}

		public EntityTagArray(ulong bitMask1, ulong bitMask2)
		{
			BitMask1 = bitMask1;
			BitMask2 = bitMask2;
		}

		public IEnumerable<ushort> ToArray()
		{
			for (ushort index = 0; index < 64; index++)
			{
				if ((BitMask1 & (ulong)(1L << (int)index)) != 0L)
				{
					yield return (ushort)(index + 1);
				}
			}
			for (ushort index = 0; index < 64; index++)
			{
				if ((BitMask2 & (ulong)(1L << (int)index)) != 0L)
				{
					yield return (ushort)(index + 64 + 1);
				}
			}
		}

		public IEnumerable<string> ToArray(ICoreAPI api)
		{
			return ToArray().Select(api.TagRegistry.EntityTagIdToTag);
		}

		public bool ContainsAll(EntityTagArray other)
		{
			if ((BitMask1 & other.BitMask1) == other.BitMask1)
			{
				return (BitMask2 & other.BitMask2) == other.BitMask2;
			}
			return false;
		}

		public bool IntersectsWithEach(EntityTagArray[] tags)
		{
			foreach (EntityTagArray second in tags)
			{
				if (!Intersect(this, second))
				{
					return false;
				}
			}
			return true;
		}

		public bool ContainsAllFromAtLeastOne(EntityTagArray[] tags)
		{
			foreach (EntityTagArray other in tags)
			{
				if (ContainsAll(other))
				{
					return true;
				}
			}
			return false;
		}

		public static bool Intersect(EntityTagArray first, EntityTagArray second)
		{
			ulong num = first.BitMask1 & second.BitMask1;
			ulong num2 = first.BitMask2 & second.BitMask2;
			return (num | num2) != 0;
		}

		public bool Intersect(EntityTagArray other)
		{
			return Intersect(this, other);
		}

		public EntityTagArray Remove(EntityTagArray other)
		{
			return new EntityTagArray(BitMask1 & ~other.BitMask1, BitMask2 & ~other.BitMask2);
		}

		public static EntityTagArray And(EntityTagArray first, EntityTagArray second)
		{
			return new EntityTagArray(first.BitMask1 & second.BitMask1, first.BitMask2 & second.BitMask2);
		}

		public static EntityTagArray Or(EntityTagArray first, EntityTagArray second)
		{
			return new EntityTagArray(first.BitMask1 | second.BitMask1, first.BitMask2 | second.BitMask2);
		}

		public static EntityTagArray Not(EntityTagArray value)
		{
			return new EntityTagArray(~value.BitMask1, ~value.BitMask2);
		}

		public static EntityTagArray operator &(EntityTagArray first, EntityTagArray second)
		{
			return And(first, second);
		}

		public static EntityTagArray operator |(EntityTagArray first, EntityTagArray second)
		{
			return Or(first, second);
		}

		public static EntityTagArray operator ~(EntityTagArray value)
		{
			return Not(value);
		}

		public static bool operator ==(EntityTagArray first, EntityTagArray second)
		{
			if (first.BitMask1 == second.BitMask1)
			{
				return first.BitMask2 == second.BitMask2;
			}
			return false;
		}

		public static bool operator !=(EntityTagArray first, EntityTagArray second)
		{
			return !(first == second);
		}

		public override bool Equals(object? obj)
		{
			if (obj is EntityTagArray entityTagArray)
			{
				return this == entityTagArray;
			}
			return false;
		}

		public override int GetHashCode()
		{
			return (int)(BitMask1 ^ BitMask2);
		}

		public override string ToString()
		{
			return PrintBitMask(BitMask2) + ":" + PrintBitMask(BitMask1);
		}

		public void ToBytes(BinaryWriter writer)
		{
			writer.Write(BitMask1);
			writer.Write(BitMask2);
		}

		public static EntityTagArray FromBytes(BinaryReader reader)
		{
			ulong bitMask = reader.ReadUInt64();
			ulong bitMask2 = reader.ReadUInt64();
			return new EntityTagArray(bitMask, bitMask2);
		}

		private static void WriteTagToBitMasks(ushort tag, ref ulong bitMask1, ref ulong bitMask2)
		{
			if (tag != 0)
			{
				int num = (tag - 1) % 64;
				switch ((tag - 1) / 64)
				{
				case 0:
					bitMask1 |= (ulong)(1L << num);
					break;
				case 1:
					bitMask2 |= (ulong)(1L << num);
					break;
				}
			}
		}

		private static string PrintBitMask(ulong bitMask)
		{
			return (from chunk in $"{bitMask:X16}".Chunk(4)
				select new string(chunk)).Aggregate((string first, string second) => first + "." + second);
		}
	}
	public readonly struct EntityTagRule
	{
		public readonly EntityTagArray TagsThatShouldBePresent;

		public readonly EntityTagArray TagsThatShouldBeAbsent;

		public const string NotPrefix = "not-";

		public static readonly EntityTagRule Empty = new EntityTagRule(EntityTagArray.Empty, EntityTagArray.Empty);

		public EntityTagRule(EntityTagArray tagsThatShouldBePresent, EntityTagArray tagsThatShouldBeAbsent)
		{
			TagsThatShouldBePresent = tagsThatShouldBePresent;
			TagsThatShouldBeAbsent = tagsThatShouldBeAbsent;
		}

		public EntityTagRule(ICoreAPI api, IEnumerable<string> tags)
		{
			List<string> list = new List<string>();
			List<string> list2 = new List<string>();
			foreach (string tag in tags)
			{
				if (tag.StartsWith("not-"))
				{
					string text = tag;
					int length = "not-".Length;
					list2.Add(text.Substring(length, text.Length - length));
				}
				else
				{
					list.Add(tag);
				}
			}
			TagsThatShouldBePresent = api.TagRegistry.EntityTagsToTagArray(list.ToArray());
			TagsThatShouldBeAbsent = api.TagRegistry.EntityTagsToTagArray(list2.ToArray());
		}

		public bool Intersects(EntityTagArray tags)
		{
			if (TagsThatShouldBePresent != EntityTagArray.Empty && !tags.Intersect(TagsThatShouldBePresent))
			{
				return false;
			}
			if (TagsThatShouldBeAbsent != EntityTagArray.Empty && tags.ContainsAll(TagsThatShouldBeAbsent))
			{
				return false;
			}
			return true;
		}

		public static bool IntersectsWithEach(EntityTagArray entityTag, EntityTagRule[] rules)
		{
			for (int i = 0; i < rules.Length; i++)
			{
				EntityTagRule entityTagRule = rules[i];
				if ((entityTagRule.TagsThatShouldBePresent != EntityTagArray.Empty && !entityTag.Intersect(entityTagRule.TagsThatShouldBePresent)) || (entityTagRule.TagsThatShouldBeAbsent != EntityTagArray.Empty && entityTag.ContainsAll(entityTagRule.TagsThatShouldBeAbsent)))
				{
					return false;
				}
			}
			return true;
		}

		public static bool ContainsAllFromAtLeastOne(EntityTagArray entityTag, EntityTagRule[] rules)
		{
			for (int i = 0; i < rules.Length; i++)
			{
				EntityTagRule entityTagRule = rules[i];
				if (entityTag.ContainsAll(entityTagRule.TagsThatShouldBePresent) && (!(entityTagRule.TagsThatShouldBeAbsent != EntityTagArray.Empty) || !entityTag.Intersect(entityTagRule.TagsThatShouldBeAbsent)))
				{
					return true;
				}
			}
			return false;
		}

		public static bool operator ==(EntityTagRule first, EntityTagRule second)
		{
			if (first.TagsThatShouldBePresent == second.TagsThatShouldBePresent)
			{
				return first.TagsThatShouldBeAbsent == second.TagsThatShouldBeAbsent;
			}
			return false;
		}

		public static bool operator !=(EntityTagRule first, EntityTagRule second)
		{
			return !(first == second);
