	public static class Lang
	{
		public static Dictionary<string, ITranslationService> AvailableLanguages { get; } = new Dictionary<string, ITranslationService>();

		public static string CurrentLocale { get; private set; }

		public static string DefaultLocale { get; set; } = "en";

		public static void Load(ILogger logger, IAssetManager assetManager, string language = "en")
		{
			CurrentLocale = language;
			JsonObject[] array = JsonObject.FromJson(File.ReadAllText(Path.Combine(GamePaths.AssetsPath, "game", "lang", "languages.json"))).AsArray();
			foreach (JsonObject jsonObject in array)
			{
				string text = jsonObject["code"].AsString();
				EnumLinebreakBehavior lbBehavior = (EnumLinebreakBehavior)Enum.Parse(typeof(EnumLinebreakBehavior), jsonObject["linebreakBehavior"].AsString("AfterWord"));
				LoadLanguage(logger, assetManager, text, text != CurrentLocale, lbBehavior);
			}
			if (!AvailableLanguages.ContainsKey(language))
			{
				logger.Error("Language '{0}' not found. Will default to english.", language);
				CurrentLocale = "en";
			}
		}

		public static void ChangeLanguage(string languageCode)
		{
			CurrentLocale = languageCode;
		}

		public static void LoadLanguage(ILogger logger, IAssetManager assetManager, string languageCode = "en", bool lazyLoad = false, EnumLinebreakBehavior lbBehavior = EnumLinebreakBehavior.AfterWord)
		{
			if (AvailableLanguages.ContainsKey(languageCode))
			{
				AvailableLanguages[languageCode].UseAssetManager(assetManager);
				AvailableLanguages[languageCode].Load(lazyLoad);
			}
			else
			{
				TranslationService translationService = new TranslationService(languageCode, logger, assetManager, lbBehavior);
				translationService.Load(lazyLoad);
				AvailableLanguages.Add(languageCode, translationService);
			}
		}

		public static void PreLoad(ILogger logger, string assetsPath, string defaultLanguage = "en")
		{
			CurrentLocale = defaultLanguage;
			JsonObject[] array = JsonObject.FromJson(File.ReadAllText(Path.Combine(GamePaths.AssetsPath, "game", "lang", "languages.json"))).AsArray();
			bool flag = false;
			JsonObject[] array2 = array;
			foreach (JsonObject jsonObject in array2)
			{
				string text = jsonObject["code"].AsString();
				EnumLinebreakBehavior lbBehavior = (EnumLinebreakBehavior)Enum.Parse(typeof(EnumLinebreakBehavior), jsonObject["linebreakBehavior"].AsString("AfterWord"));
				TranslationService translationService = new TranslationService(text, logger, null, lbBehavior);
				bool lazyLoad = text != defaultLanguage;
				translationService.PreLoad(assetsPath, lazyLoad);
				AvailableLanguages[text] = translationService;
				if (text == defaultLanguage)
				{
					flag = true;
				}
			}
			if (defaultLanguage != "en" && !flag)
			{
				logger.Error("Language '{0}' not found. Will default to english.", defaultLanguage);
				AvailableLanguages["en"].PreLoad(assetsPath);
				CurrentLocale = "en";
			}
		}

		public static void PreLoadModWorldConfig(string modPath, string modDomain, string defaultLanguage = "en")
		{
			JsonObject[] array = JsonObject.FromJson(File.ReadAllText(Path.Combine(GamePaths.AssetsPath, "game", "lang", "languages.json"))).AsArray();
			foreach (JsonObject jsonObject in array)
			{
				string text = jsonObject["code"].AsString();
				_ = (EnumLinebreakBehavior)Enum.Parse(typeof(EnumLinebreakBehavior), jsonObject["linebreakBehavior"].AsString("AfterWord"));
				bool lazyLoad = text != defaultLanguage;
				AvailableLanguages[text].PreLoadModWorldConfig(modPath, modDomain, lazyLoad);
			}
		}

		public static string GetIfExists(string key, params object[] args)
		{
			if (!HasTranslation(key))
			{
				return AvailableLanguages[DefaultLocale].GetIfExists(key, args);
			}
			return AvailableLanguages[CurrentLocale].GetIfExists(key, args);
		}

		public static string GetL(string langcode, string key, params object[] args)
		{
			if (!AvailableLanguages.TryGetValue(langcode, out var value) || !value.HasTranslation(key, findWildcarded: false))
			{
				return AvailableLanguages[DefaultLocale].Get(key, args);
			}
			return value.Get(key, args);
		}

		public static string GetMatchingL(string langcode, string key, params object[] args)
		{
			if (!AvailableLanguages.TryGetValue(langcode, out var value) || !value.HasTranslation(key))
			{
				return AvailableLanguages[DefaultLocale].GetMatching(key, args);
			}
			return value.GetMatching(key, args);
		}

		public static string Get(string key, params object[] args)
		{
			if (!HasTranslation(key, findWildcarded: false))
			{
				return AvailableLanguages[DefaultLocale].Get(key, args);
			}
			return AvailableLanguages[CurrentLocale].Get(key, args);
		}

		public static string GetWithFallback(string key, string fallbackKey, params object[] args)
		{
			if (!HasTranslation(key, findWildcarded: false))
			{
				if (!HasTranslation(fallbackKey, findWildcarded: false))
				{
					return AvailableLanguages[DefaultLocale].Get(key, args);
				}
				return AvailableLanguages[CurrentLocale].Get(fallbackKey, args);
			}
			return AvailableLanguages[CurrentLocale].Get(key, args);
		}

		public static string GetUnformatted(string key)
		{
			if (!HasTranslation(key))
			{
				return AvailableLanguages[DefaultLocale].GetUnformatted(key);
			}
			return AvailableLanguages[CurrentLocale].GetUnformatted(key);
		}

		public static string GetMatching(string key, params object[] args)
		{
			if (!HasTranslation(key))
			{
				return AvailableLanguages[DefaultLocale].GetMatching(key, args);
			}
			return AvailableLanguages[CurrentLocale].GetMatching(key, args);
		}

		public static string GetMatchingIfExists(string key, params object[] args)
		{
			if (!HasTranslation(key, findWildcarded: true, logErrors: false))
			{
				return AvailableLanguages[DefaultLocale].GetMatchingIfExists(key, args);
			}
			return AvailableLanguages[CurrentLocale].GetMatchingIfExists(key, args);
		}

		public static IDictionary<string, string> GetAllEntries()
		{
			Dictionary<string, string> source = AvailableLanguages[DefaultLocale].GetAllEntries().ToDictionary((KeyValuePair<string, string> p) => p.Key, (KeyValuePair<string, string> p) => p.Value);
			Dictionary<string, string> currentEntries = AvailableLanguages[CurrentLocale].GetAllEntries().ToDictionary((KeyValuePair<string, string> p) => p.Key, (KeyValuePair<string, string> p) => p.Value);
			foreach (KeyValuePair<string, string> item in source.Where((KeyValuePair<string, string> entry) => !currentEntries.ContainsKey(entry.Key)))
			{
				currentEntries.Add(item.Key, item.Value);
			}
			return currentEntries;
		}

		public static bool HasTranslation(string key, bool findWildcarded = true, bool logErrors = true)
		{
			return AvailableLanguages[CurrentLocale].HasTranslation(key, findWildcarded, logErrors);
		}

		public static void InitialiseSearch()
		{
			AvailableLanguages[CurrentLocale].InitialiseSearch();
		}

		public static string GetNamePlaceHolder(AssetLocation code)
		{
			string text = "";
			string[] array = code.Path.Split('-');
			for (int i = 0; i < array.Length; i++)
			{
				if (!(array[i] == "north") && !(array[i] == "east") && !(array[i] == "west") && !(array[i] == "south") && !(array[i] == "up") && !(array[i] == "down"))
				{
					if (i > 0)
					{
						text += " ";
					}
					if (i > 0 && i == array.Length - 1)
					{
						text += "(";
					}
					text = ((i != 0) ? (text + array[i]) : (text + array[i].First().ToString().ToUpper() + array[i].Substring(1)));
					if (i > 0 && i == array.Length - 1)
					{
						text += ")";
					}
				}
			}
			return text;
		}

		public static bool UsesNonLatinCharacters(string lang)
		{
			if (!(lang == "ar") && !lang.StartsWithOrdinal("zh-"))
			{
				switch (lang)
				{
				default:
					return lang == "ru";
				case "ja":
				case "ko":
				case "th":
				case "uk":
					break;
				}
			}
			return true;
		}
	}
	public class TranslationService : ITranslationService
	{
		internal Dictionary<string, string> entryCache = new Dictionary<string, string>();

		private Dictionary<string, KeyValuePair<Regex, string>> regexCache = new Dictionary<string, KeyValuePair<Regex, string>>();

		private Dictionary<string, string> wildcardCache = new Dictionary<string, string>();

		private HashSet<string> notFound = new HashSet<string>();

		private IAssetManager assetManager;

		private readonly ILogger logger;

		internal bool loaded;

		private string preLoadAssetsPath;

		private Dictionary<string, string> preLoadModPaths = new Dictionary<string, string>();

		private bool modWorldConfig;

		public EnumLinebreakBehavior LineBreakBehavior { get; set; }

		public string LanguageCode { get; }

		public TranslationService(string languageCode, ILogger logger, IAssetManager assetManager = null, EnumLinebreakBehavior lbBehavior = EnumLinebreakBehavior.AfterWord)
		{
			LanguageCode = languageCode;
			this.logger = logger;
			this.assetManager = assetManager;
			LineBreakBehavior = lbBehavior;
		}

		public void Load(bool lazyLoad = false)
		{
			preLoadAssetsPath = null;
			if (lazyLoad)
			{
				return;
			}
			loaded = true;
			Dictionary<string, string> dictionary = new Dictionary<string, string>();
			Dictionary<string, KeyValuePair<Regex, string>> dictionary2 = new Dictionary<string, KeyValuePair<Regex, string>>();
			Dictionary<string, string> dictionary3 = new Dictionary<string, string>();
			foreach (IAsset item in assetManager.Origins.SelectMany((IAssetOrigin p) => from a in p.GetAssets(AssetCategory.lang)
				where a.Name.Equals(LanguageCode + ".json") || a.Name.Equals("worldconfig-" + LanguageCode + ".json")
				select a))
			{
				try
				{
					string text = item.ToText();
					LoadEntries(dictionary, dictionary2, dictionary3, JsonConvert.DeserializeObject<Dictionary<string, string>>(text), item.Location.Domain);
				}
				catch (Exception e)
				{
					logger.Error("Failed to load language file: " + item.Name);
					logger.Error(e);
				}
			}
			entryCache = dictionary;
			regexCache = dictionary2;
			wildcardCache = dictionary3;
		}

		public void PreLoad(string assetsPath, bool lazyLoad = false)
		{
			preLoadAssetsPath = assetsPath;
			if (lazyLoad)
			{
				return;
			}
			loaded = true;
			Dictionary<string, string> dictionary = new Dictionary<string, string>();
			Dictionary<string, KeyValuePair<Regex, string>> dictionary2 = new Dictionary<string, KeyValuePair<Regex, string>>();
			Dictionary<string, string> dictionary3 = new Dictionary<string, string>();
			foreach (FileInfo item in new DirectoryInfo(Path.Combine(assetsPath, "game", "lang")).EnumerateFiles(LanguageCode + ".json", SearchOption.AllDirectories))
			{
				try
				{
					string text = File.ReadAllText(item.FullName);
					LoadEntries(dictionary, dictionary2, dictionary3, JsonConvert.DeserializeObject<Dictionary<string, string>>(text));
				}
				catch (Exception e)
				{
					logger.Error("Failed to load language file: " + item.Name);
					logger.Error(e);
				}
			}
			entryCache = dictionary;
			regexCache = dictionary2;
			wildcardCache = dictionary3;
		}

		public void PreLoadModWorldConfig(string modPath = null, string modDomain = null, bool lazyLoad = false)
		{
			modWorldConfig = true;
			if (modPath != null && modDomain != null && !preLoadModPaths.ContainsKey(modDomain))
			{
				preLoadModPaths.Add(modDomain, modPath);
			}
			if (lazyLoad || modPath == null || modDomain == null)
			{
				return;
			}
			Dictionary<string, string> entryCache = new Dictionary<string, string>();
			Dictionary<string, KeyValuePair<Regex, string>> regexCache = new Dictionary<string, KeyValuePair<Regex, string>>();
			Dictionary<string, string> wildcardCache = new Dictionary<string, string>();
			Dictionary<string, string> dictionary = new Dictionary<string, string>();
			if (modPath == null && modDomain == null)
			{
				dictionary = preLoadModPaths;
			}
			else
			{
				dictionary.Add(modDomain, modPath);
			}
			dictionary.Foreach(delegate(KeyValuePair<string, string> mod)
			{
				DirectoryInfo directoryInfo = new DirectoryInfo(Path.Combine(mod.Value, "assets", "game", "lang"));
				try
				{
					foreach (FileInfo item in directoryInfo.EnumerateFiles("worldconfig-" + LanguageCode + ".json", SearchOption.AllDirectories))
					{
						try
						{
							string text = File.ReadAllText(item.FullName);
							LoadEntries(entryCache, regexCache, wildcardCache, JsonConvert.DeserializeObject<Dictionary<string, string>>(text));
						}
						catch (Exception e)
						{
							logger.Error("Failed to load language file: " + item.Name);
							logger.Error(e);
						}
					}
				}
				catch
				{
					logger.Error("Failed to find language folder: " + directoryInfo.FullName);
				}
			});
			this.entryCache.AddRange(entryCache);
			this.regexCache.AddRange(regexCache);
			this.wildcardCache.AddRange(wildcardCache);
		}

		protected void EnsureLoaded()
		{
			if (loaded)
			{
				return;
			}
			if (preLoadAssetsPath != null)
			{
				PreLoad(preLoadAssetsPath);
				if (modWorldConfig)
				{
					PreLoadModWorldConfig();
				}
			}
			else
			{
				Load();
			}
		}

		public void Invalidate()
		{
			loaded = false;
		}

		protected string Format(string value, params object[] args)
		{
			if (value.ContainsFast("{p"))
			{
				return PluralFormat(value, args);
			}
			return TryFormat(value, args);
		}

		private string TryFormat(string value, params object[] args)
		{
			string result;
			try
			{
				result = string.Format(value, args);
			}
			catch (Exception e)
			{
				logger.Error(e);
				result = value;
				if (logger != null)
				{
					StringBuilder stringBuilder = new StringBuilder();
					stringBuilder.Append("Translation string format exception thrown for: \"");
					foreach (char c in value)
					{
						stringBuilder.Append(c);
						if (c == '{' || c == '}')
						{
							stringBuilder.Append(c);
						}
					}
					stringBuilder.Append("\"\n   Args were: ");
					for (int j = 0; j < args.Length; j++)
					{
						if (j > 0)
						{
							stringBuilder.Append(", ");
						}
						stringBuilder.Append(args[j].ToString());
					}
					try
					{
						logger.Warning(stringBuilder.ToString());
					}
					catch (Exception e2)
					{
						logger.Error("Exception thrown when trying to print exception message for an incorrect translation entry. Exception: ");
						logger.Error(e2);
					}
				}
			}
			return result;
		}

		private string PluralFormat(string value, object[] args)
		{
			int num = value.IndexOfOrdinal("{p");
			if (value.Length < num + 5)
			{
				return TryFormat(value, args);
			}
			int num2 = num + 4;
			int num3 = value.IndexOf('}', num2);
			char c = value[num + 2];
			if (c < '0' || c > '9')
			{
				return TryFormat(value, args);
			}
			if (num3 < 0)
			{
				return TryFormat(value, args);
			}
			int num4 = c - 48;
			if ((c = value[num + 3]) != ':')
			{
				if (value[num + 4] != ':' || c < '0' || c > '9')
				{
					return TryFormat(value, args);
				}
				num4 = num4 * 10 + c - 48;
				num2++;
			}
			if (num4 >= args.Length)
			{
				throw new IndexOutOfRangeException("Index out of range: Plural format {p#:...} referenced an argument " + num4 + " but only " + args.Length + " arguments were available in the code");
			}
			float n = 0f;
			try
			{
				n = float.Parse(args[num4].ToString());
			}
			catch (Exception)
			{
			}
			string value2 = value.Substring(0, num);
			string input = value.Substring(num2, num3 - num2);
			string value3 = value.Substring(num3 + 1);
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append(TryFormat(value2, args));
			stringBuilder.Append(BuildPluralFormat(input, n));
			stringBuilder.Append(Format(value3, args));
			return stringBuilder.ToString();
		}

		internal static string BuildPluralFormat(string input, float n)
		{
			string[] array = input.Split('|');
			int round = 3;
			if (array.Length >= 2)
			{
				if (!TryGuessRounding(array[1], out round))
				{
					TryGuessRounding(array[^1], out round);
				}
				if (round < 0 || round > 15)
				{
					round = 3;
				}
			}
			int num = (int)Math.Ceiling(Math.Round(n, round));
			if (num < 0 || num >= array.Length)
			{
				num = array.Length - 1;
			}
			if (array.Length >= 2)
			{
				if (n == 1f)
				{
					num = 1;
				}
				else if (n < 1f)
				{
					num = 0;
				}
			}
			return WithNumberFormatting(array[num], n);
		}

		private static bool TryGuessRounding(string entry, out int round)
		{
			string partB;
			string numberFormattingFrom = GetNumberFormattingFrom(entry, out partB);
			if (numberFormattingFrom.IndexOf('.') > 0)
			{
				round = numberFormattingFrom.Length - numberFormattingFrom.IndexOf('.') - 1;
				return true;
			}
			if (numberFormattingFrom.Length > 0)
			{
				round = 0;
				return true;
			}
			round = 3;
			return false;
		}

		internal static string GetNumberFormattingFrom(string rawResult, out string partB)
		{
			int startIndexOfNumberFormat = GetStartIndexOfNumberFormat(rawResult);
			if (startIndexOfNumberFormat >= 0)
			{
				int num = startIndexOfNumberFormat;
				while (++num < rawResult.Length)
				{
					char c = rawResult[num];
					if (c != '#' && c != '.' && c != '0' && c != ',')
					{
						break;
					}
				}
				partB = rawResult.Substring(num);
				return rawResult.Substring(startIndexOfNumberFormat, num - startIndexOfNumberFormat);
			}
			partB = rawResult;
			return "";
		}

		private static int GetStartIndexOfNumberFormat(string rawResult)
		{
			int num = rawResult.IndexOf('#');
			int num2 = rawResult.IndexOf('0');
			int result = -1;
			if (num >= 0 && num2 >= 0)
			{
				result = Math.Min(num, num2);
			}
			else if (num >= 0)
			{
				result = num;
			}
			else if (num2 >= 0)
			{
				result = num2;
			}
			return result;
		}

		internal static string WithNumberFormatting(string rawResult, float n)
		{
			int startIndexOfNumberFormat = GetStartIndexOfNumberFormat(rawResult);
			if (startIndexOfNumberFormat < 0)
			{
				return rawResult;
			}
			string text = rawResult.Substring(0, startIndexOfNumberFormat);
			string partB;
			string numberFormattingFrom = GetNumberFormattingFrom(rawResult, out partB);
			string text2;
			try
			{
				text2 = ((numberFormattingFrom.Length != 1 || n != 0f) ? n.ToString(numberFormattingFrom, GlobalConstants.DefaultCultureInfo) : "0");
			}
			catch (Exception)
			{
				text2 = n.ToString(GlobalConstants.DefaultCultureInfo);
			}
			return text + text2 + partB;
		}

		public string GetIfExists(string key, params object[] args)
		{
			EnsureLoaded();
			if (!entryCache.TryGetValue(KeyWithDomain(key), out var value))
			{
				return null;
			}
			return Format(value, args);
		}

		public string Get(string key, params object[] args)
		{
			return Format(GetUnformatted(key), args);
		}

		public IDictionary<string, string> GetAllEntries()
		{
			EnsureLoaded();
			return entryCache;
		}

		public string GetUnformatted(string key)
		{
			EnsureLoaded();
			if (!entryCache.TryGetValue(KeyWithDomain(key), out var value))
			{
				return key;
			}
			return value;
		}

		public string GetMatching(string key, params object[] args)
		{
			EnsureLoaded();
			string matchingIfExists = GetMatchingIfExists(KeyWithDomain(key), args);
			if (!string.IsNullOrEmpty(matchingIfExists))
			{
				return matchingIfExists;
			}
			return Format(key, args);
		}

		public bool HasTranslation(string key, bool findWildcarded = true)
		{
			return HasTranslation(key, findWildcarded, logErrors: true);
		}

		public bool HasTranslation(string key, bool findWildcarded, bool logErrors)
		{
			EnsureLoaded();
			string validKey = KeyWithDomain(key);
			if (entryCache.ContainsKey(validKey))
			{
				return true;
			}
			if (findWildcarded)
			{
				if (!key.Contains(":"))
				{
					key = "game:" + key;
				}
				bool flag = wildcardCache.Any((KeyValuePair<string, string> pair) => key.StartsWithFast(pair.Key));
				if (!flag)
				{
					flag = regexCache.Values.Any((KeyValuePair<Regex, string> pair) => pair.Key.IsMatch(validKey));
				}
				if (!flag && logErrors && !key.Contains("desc-") && notFound.Add(key))
				{
					logger.VerboseDebug("Lang key not found: " + key.Replace("{", "{{").Replace("}", "}}"));
				}
				return flag;
			}
			return false;
		}

		public void UseAssetManager(IAssetManager assetManager)
		{
			this.assetManager = assetManager;
		}

		public string GetMatchingIfExists(string key, params object[] args)
		{
			EnsureLoaded();
			string validKey = KeyWithDomain(key);
			if (entryCache.TryGetValue(validKey, out var value))
			{
				return Format(value, args);
			}
			using (IEnumerator<KeyValuePair<string, string>> enumerator = wildcardCache.Where((KeyValuePair<string, string> pair) => validKey.StartsWithFast(pair.Key)).GetEnumerator())
			{
				if (enumerator.MoveNext())
				{
					return Format(enumerator.Current.Value, args);
				}
			}
			return (from pair in regexCache.Values
				where pair.Key.IsMatch(validKey)
				select Format(pair.Value, args)).FirstOrDefault();
		}

		private void LoadEntries(Dictionary<string, string> entryCache, Dictionary<string, KeyValuePair<Regex, string>> regexCache, Dictionary<string, string> wildcardCache, Dictionary<string, string> entries, string domain = "game")
		{
			foreach (KeyValuePair<string, string> entry in entries)
			{
				LoadEntry(entryCache, regexCache, wildcardCache, entry, domain);
			}
		}

		private void LoadEntry(Dictionary<string, string> entryCache, Dictionary<string, KeyValuePair<Regex, string>> regexCache, Dictionary<string, string> wildcardCache, KeyValuePair<string, string> entry, string domain = "game")
		{
			string text = KeyWithDomain(entry.Key, domain);
			switch (text.CountChars('*'))
			{
			case 0:
				entryCache[text] = entry.Value;
				return;
			case 1:
				if (text.EndsWith('*'))
				{
					wildcardCache[text.TrimEnd('*')] = entry.Value;
					return;
				}
				break;
			}
			Regex key = new Regex("^" + text.Replace("*", "(.*)") + "$", RegexOptions.Compiled);
			regexCache[text] = new KeyValuePair<Regex, string>(key, entry.Value);
		}

		private static string KeyWithDomain(string key, string domain = "game")
		{
			if (key.Contains(':'))
			{
				return key;
			}
			return new StringBuilder(domain).Append(':').Append(key).ToString();
		}

		public void InitialiseSearch()
		{
			regexCache.Values.Any((KeyValuePair<Regex, string> pair) => pair.Key.IsMatch("nonsense_value_and_fairly_longgg"));
		}
	}
}
namespace Vintagestory.API.Util
{
	public enum EnumTalkType
	{
		Meet,
		Idle,
		Hurt,
		Hurt2,
		Death,
		Purchase,
		Complain,
		Goodbye,
		IdleShort,
		Laugh,
		Thrust,
		Shrug
	}
	public class SlidingPitchSound
	{
		public EnumTalkType TalkType;

		public ILoadedSound sound;

		public float startPitch;

		public float endPitch;

		public float length;

		public long startMs;

		public float StartVolumne;

		public float EndVolumne;

		public bool Vibrato;
	}
	public class EntityTalkUtil
	{
		public const int TalkPacketId = 1231;

		protected int lettersLeftToTalk;

		protected int totalLettersToTalk;

		protected int currentLetterInWord;

		protected int totalLettersTalked;

		protected float chordDelay;

		protected bool LongNote;

		protected Dictionary<EnumTalkType, float> TalkSpeed;

		protected EnumTalkType talkType;

		protected ICoreServerAPI sapi;

		protected ICoreClientAPI capi;

		protected Entity entity;

		public AssetLocation soundName = new AssetLocation("sounds/voice/saxophone");

		public float soundLength = -1f;

		protected List<SlidingPitchSound> slidingPitchSounds = new List<SlidingPitchSound>();

		protected List<SlidingPitchSound> stoppedSlidingSounds = new List<SlidingPitchSound>();

		public float chordDelayMul = 1f;

		public float pitchModifier = 1f;

		public float volumneModifier = 1f;

		public float idleTalkChance = 0.0005f;

		public bool AddSoundLengthChordDelay;

		public bool IsMultiSoundVoice;

		public bool ShouldDoIdleTalk = true;

		private List<IAsset> sounds;

		protected virtual Random Rand => capi.World.Rand;

		public EntityTalkUtil(ICoreAPI api, Entity atEntity, bool isMultiSoundVoice)
		{
			sapi = api as ICoreServerAPI;
			capi = api as ICoreClientAPI;
			entity = atEntity;
			IsMultiSoundVoice = isMultiSoundVoice;
			TalkSpeed = defaultTalkSpeeds();
			capi?.Event.RegisterRenderer(new DummyRenderer
			{
				action = OnRenderTick
			}, EnumRenderStage.Before, "talkfasttilk");
		}

		protected AssetLocation GetSoundLocation(float pitch, out float pitchOffset)
		{
			if (soundLength < 0f)
			{
				float pitchOffset2;
				SoundParams param = new SoundParams
				{
					Location = getSoundLocOnly(pitch, out pitchOffset2),
					DisposeOnFinish = true,
					ShouldLoop = false
				};
				ILoadedSound loadedSound = capi.World.LoadSound(param);
				soundLength = loadedSound?.SoundLengthSeconds ?? 0.1f;
				loadedSound?.Dispose();
			}
			return getSoundLocOnly(pitch, out pitchOffset);
		}

		private AssetLocation getSoundLocOnly(float pitch, out float pitchOffset)
		{
			if (IsMultiSoundVoice)
			{
				if (sounds == null)
				{
					sounds = capi.Assets.GetMany(soundName.Path, soundName.Domain, loadAsset: false);
				}
				int count = sounds.Count;
				int num = (int)GameMath.Clamp((pitch - 0.65f) * (float)count, 0f, count - 1);
				float num2 = 1f / (float)count;
				float num3 = (float)num * num2 + 0.65f;
				pitchOffset = pitch - num3;
				return sounds[num].Location;
			}
			pitchOffset = pitch;
			return soundName;
		}

		private void OnRenderTick(float dt)
		{
			for (int i = 0; i < slidingPitchSounds.Count; i++)
			{
				SlidingPitchSound slidingPitchSound = slidingPitchSounds[i];
				if (slidingPitchSound.sound.HasStopped)
				{
					stoppedSlidingSounds.Add(slidingPitchSound);
					continue;
				}
				float num = (float)(capi.World.ElapsedMilliseconds - slidingPitchSound.startMs) / 1000f;
				float length = slidingPitchSound.length;
				float t = GameMath.Min(1f, num / length);
				float num2 = GameMath.Lerp(slidingPitchSound.startPitch, slidingPitchSound.endPitch, t);
				float num3 = GameMath.Lerp(slidingPitchSound.StartVolumne, slidingPitchSound.EndVolumne, t);
				if (num > length)
				{
					num3 -= (num - slidingPitchSound.length) * 5f;
				}
				slidingPitchSound.Vibrato = slidingPitchSound.TalkType == EnumTalkType.Death || slidingPitchSound.TalkType == EnumTalkType.Thrust;
				if (slidingPitchSound.TalkType == EnumTalkType.Thrust && (double)num > 0.15)
				{
					slidingPitchSound.sound.Stop();
					continue;
				}
				if (num3 <= 0f)
				{
					slidingPitchSound.sound.FadeOutAndStop(0f);
					continue;
				}
				slidingPitchSound.sound.SetPitch(num2 + (slidingPitchSound.Vibrato ? ((float)Math.Sin(num * 8f) * 0.05f) : 0f));
				slidingPitchSound.sound.FadeTo(num3, 0.1f, delegate
				{
				});
			}
			foreach (SlidingPitchSound stoppedSlidingSound in stoppedSlidingSounds)
			{
				slidingPitchSounds.Remove(stoppedSlidingSound);
			}
		}

		public virtual void SetModifiers(float chordDelayMul = 1f, float pitchModifier = 1f, float volumneModifier = 1f)
		{
			this.chordDelayMul = chordDelayMul;
			this.pitchModifier = pitchModifier;
			this.volumneModifier = volumneModifier;
			TalkSpeed = defaultTalkSpeeds();
			EnumTalkType[] array = TalkSpeed.Keys.ToArray();
			foreach (EnumTalkType key in array)
			{
				TalkSpeed[key] = Math.Max(0.06f, TalkSpeed[key] * chordDelayMul);
			}
		}

		public virtual void OnGameTick(float dt)
		{
			float num = 0.1f + (float)(capi.World.Rand.NextDouble() * capi.World.Rand.NextDouble()) / 2f;
			if (lettersLeftToTalk > 0)
			{
				chordDelay -= dt * (IsMultiSoundVoice ? 0.6f : 1f);
				if (!(chordDelay < 0f))
				{
					return;
				}
				chordDelay = TalkSpeed[talkType];
				switch (talkType)
				{
				case EnumTalkType.Purchase:
				{
					float startPitch2 = 1.5f;
					float endPitch3 = ((totalLettersTalked > 0) ? 0.9f : 1.5f);
					PlaySound(startPitch2, endPitch3, 1f, 0.8f, num);
					chordDelay = 0.3f * chordDelayMul;
					break;
				}
				case EnumTalkType.Goodbye:
				{
					float num7 = 1.25f - 0.6f * (float)totalLettersTalked / (float)totalLettersToTalk;
					PlaySound(num7, num7 * 0.9f, 0.7f, 0.6f, num);
					chordDelay = 0.25f * chordDelayMul;
					break;
				}
				case EnumTalkType.Death:
					num = 2.3f;
					PlaySound(0.75f, 0.3f, 1f, 0.2f, num);
					break;
				case EnumTalkType.Thrust:
					num = 0.12f;
					PlaySound(0.5f, 0.8f, 0.4f, 1f, num);
					break;
				case EnumTalkType.Shrug:
					num = 0.6f;
					PlaySound(0.9f, 1.5f, 0.8f, 0.8f, num);
					break;
				case EnumTalkType.Meet:
				{
					float num6 = 0.75f + 0.5f * (float)Rand.NextDouble() + (float)totalLettersTalked / (float)totalLettersToTalk / 3f;
					PlaySound(num6, num6 * 1.5f, 0.75f, 0.75f, num);
					if (currentLetterInWord > 1 && capi.World.Rand.NextDouble() < 0.35)
					{
						chordDelay = 0.15f * chordDelayMul;
						currentLetterInWord = 0;
					}
					break;
				}
				case EnumTalkType.Complain:
				{
					float num2 = 0.75f + 0.5f * (float)Rand.NextDouble();
					float num3 = num2 + 0.15f;
					num = 0.05f;
					PlaySound(num2, num3, num2, num3, num);
					if (currentLetterInWord > 1 && capi.World.Rand.NextDouble() < 0.35)
					{
						chordDelay = 0.45f * chordDelayMul;
						currentLetterInWord = 0;
					}
					break;
				}
				case EnumTalkType.Idle:
				case EnumTalkType.IdleShort:
				{
					float startPitch = 0.75f + 0.25f * (float)Rand.NextDouble();
					float endPitch2 = 0.75f + 0.25f * (float)Rand.NextDouble();
					PlaySound(startPitch, endPitch2, 0.75f, 0.75f, num);
					if (currentLetterInWord > 1 && capi.World.Rand.NextDouble() < 0.35)
					{
						chordDelay = 0.35f * chordDelayMul;
						currentLetterInWord = 0;
					}
					break;
				}
				case EnumTalkType.Laugh:
				{
					float num8 = (float)Rand.NextDouble() * 0.1f;
					float num9 = (float)Math.Pow(Math.Min(1f, 1f / pitchModifier), 2.0);
					num = 0.1f;
					float num10 = num8 + 1.5f - (float)currentLetterInWord / (20f / num9);
					float endPitch = num10 - 0.05f;
					PlaySound(num10, endPitch, 1f, 0.8f, num);
					chordDelay = 0.2f * chordDelayMul * num9;
					break;
				}
				case EnumTalkType.Hurt:
				{
					float num4 = 0.75f + 0.5f * (float)Rand.NextDouble() + (1f - (float)totalLettersTalked / (float)totalLettersToTalk);
					num /= 4f;
					float num5 = 0.5f + (1f - (float)totalLettersTalked / (float)totalLettersToTalk);
					PlaySound(num4, num4 - 0.2f, num5, num5, num);
					if (currentLetterInWord > 1 && capi.World.Rand.NextDouble() < 0.35)
					{
						chordDelay = 0.25f * chordDelayMul;
						currentLetterInWord = 0;
					}
					break;
				}
				case EnumTalkType.Hurt2:
				{
					float startpitch = 0.75f + 0.4f * (float)Rand.NextDouble() + (1f - (float)totalLettersTalked / (float)totalLettersToTalk);
					PlaySound(startpitch, 0.5f + (1f - (float)totalLettersTalked / (float)totalLettersToTalk) / 1.25f, num);
					if (currentLetterInWord > 1 && capi.World.Rand.NextDouble() < 0.35)
					{
						chordDelay = 0.2f * chordDelayMul;
						currentLetterInWord = 0;
					}
					chordDelay = 0f;
					break;
				}
				}
				if (AddSoundLengthChordDelay)
				{
					chordDelay += Math.Min(soundLength, num) * chordDelayMul;
				}
				lettersLeftToTalk--;
				currentLetterInWord++;
				totalLettersTalked++;
			}
			else if (lettersLeftToTalk == 0 && capi.World.Rand.NextDouble() < (double)idleTalkChance && entity.Alive && ShouldDoIdleTalk)
			{
				Talk(EnumTalkType.Idle);
			}
		}

		protected virtual void PlaySound(float startpitch, float volume, float length)
		{
			PlaySound(startpitch, startpitch, volume, volume, length);
		}

		protected virtual void PlaySound(float startPitch, float endPitch, float startvolume, float endvolumne, float length)
		{
			startPitch *= pitchModifier;
			endPitch *= pitchModifier;
			startvolume *= volumneModifier;
			endvolumne *= volumneModifier;
			float pitchOffset;
			AssetLocation soundLocation = GetSoundLocation(startPitch, out pitchOffset);
			SoundParams param = new SoundParams
			{
				Location = soundLocation,
				DisposeOnFinish = true,
				Pitch = (IsMultiSoundVoice ? pitchOffset : startPitch),
				Volume = startvolume,
				Position = entity.Pos.XYZ.ToVec3f().Add(0f, (float)entity.LocalEyePos.Y, 0f),
				ShouldLoop = false,
				Range = 8f
			};
			ILoadedSound loadedSound = capi.World.LoadSound(param);
			slidingPitchSounds.Add(new SlidingPitchSound
			{
				TalkType = talkType,
				startPitch = (IsMultiSoundVoice ? (1f + pitchOffset) : startPitch),
				endPitch = (IsMultiSoundVoice ? (1f + (endPitch - startPitch) + pitchOffset) : endPitch),
				sound = loadedSound,
				startMs = capi.World.ElapsedMilliseconds,
				length = length,
				StartVolumne = startvolume,
				EndVolumne = endvolumne
			});
			loadedSound.Start();
		}

		public virtual void Talk(EnumTalkType talkType)
		{
			if (sapi != null)
			{
				sapi.Network.BroadcastEntityPacket(entity.EntityId, 1231, SerializerUtil.Serialize(talkType));
				return;
			}
			IClientWorldAccessor world = capi.World;
			this.talkType = talkType;
			totalLettersTalked = 0;
			currentLetterInWord = 0;
			chordDelay = TalkSpeed[talkType];
			LongNote = false;
			if (talkType == EnumTalkType.Meet)
			{
				lettersLeftToTalk = 2 + world.Rand.Next(10);
			}
			if (talkType == EnumTalkType.Hurt || talkType == EnumTalkType.Hurt2)
			{
				lettersLeftToTalk = 2 + world.Rand.Next(3);
			}
			if (talkType == EnumTalkType.Idle)
			{
				lettersLeftToTalk = 3 + world.Rand.Next(12);
			}
			if (talkType == EnumTalkType.IdleShort)
			{
				lettersLeftToTalk = 3 + world.Rand.Next(4);
			}
			if (talkType == EnumTalkType.Laugh)
			{
				lettersLeftToTalk = (int)((float)(4 + world.Rand.Next(4)) * Math.Max(1f, pitchModifier));
			}
			if (talkType == EnumTalkType.Purchase)
			{
				lettersLeftToTalk = 2 + world.Rand.Next(2);
			}
			if (talkType == EnumTalkType.Complain)
			{
				lettersLeftToTalk = 10 + world.Rand.Next(12);
			}
			if (talkType == EnumTalkType.Goodbye)
			{
				lettersLeftToTalk = 2 + world.Rand.Next(2);
			}
			if (talkType == EnumTalkType.Death)
			{
				lettersLeftToTalk = 1;
			}
			if (talkType == EnumTalkType.Shrug)
			{
				lettersLeftToTalk = 1;
			}
			if (talkType == EnumTalkType.Thrust)
			{
				lettersLeftToTalk = 1;
			}
			totalLettersToTalk = lettersLeftToTalk;
		}

		private Dictionary<EnumTalkType, float> defaultTalkSpeeds()
		{
			return new Dictionary<EnumTalkType, float>
			{
				{
					EnumTalkType.Meet,
					0.13f
				},
				{
					EnumTalkType.Death,
					0.3f
				},
				{
					EnumTalkType.Idle,
					0.1f
				},
				{
					EnumTalkType.IdleShort,
					0.1f
				},
				{
					EnumTalkType.Laugh,
					0.2f
				},
				{
					EnumTalkType.Hurt,
					0.07f
				},
				{
					EnumTalkType.Hurt2,
					0.07f
				},
				{
					EnumTalkType.Goodbye,
					0.07f
				},
				{
					EnumTalkType.Complain,
					0.09f
				},
				{
					EnumTalkType.Purchase,
					0.15f
				},
				{
					EnumTalkType.Thrust,
					0.15f
				},
				{
					EnumTalkType.Shrug,
					0.15f
				}
			};
		}
	}
	public class RelaxedReadOnlyDictionary<T, K> : IDictionary<T, K>, ICollection<KeyValuePair<T, K>>, IEnumerable<KeyValuePair<T, K>>, IEnumerable
	{
		private IDictionary<T, K> dict;

		public K this[T key]
		{
			get
			{
				if (!dict.TryGetValue(key, out var value))
				{
					value = default(K);
				}
				return value;
			}
			set
			{
				throw new InvalidOperationException("May not be modified");
			}
		}

		public ICollection<T> Keys => dict.Keys;

		public ICollection<K> Values => dict.Values;

		public int Count => dict.Count;

		public bool IsReadOnly => true;

		public RelaxedReadOnlyDictionary(IDictionary<T, K> values)
		{
			dict = values;
		}

		public void Add(T key, K value)
		{
			throw new InvalidOperationException("May not be modified");
		}

		public void Add(KeyValuePair<T, K> item)
		{
			throw new InvalidOperationException("May not be modified");
		}

		public void Clear()
		{
			throw new InvalidOperationException("May not be modified");
		}

		public bool Contains(KeyValuePair<T, K> item)
		{
			return dict.Contains(item);
		}

		public bool ContainsKey(T key)
		{
			return dict.ContainsKey(key);
		}

		public void CopyTo(KeyValuePair<T, K>[] array, int arrayIndex)
		{
			dict.CopyTo(array, arrayIndex);
		}

		public IEnumerator<KeyValuePair<T, K>> GetEnumerator()
		{
			return dict.GetEnumerator();
		}

		public bool Remove(T key)
		{
			throw new InvalidOperationException("May not be modified");
		}

		public bool Remove(KeyValuePair<T, K> item)
		{
			throw new InvalidOperationException("May not be modified");
		}

		public bool TryGetValue(T key, out K value)
		{
			return dict.TryGetValue(key, out value);
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return dict.GetEnumerator();
		}
	}
	public delegate T fillCallback<T>(int index);
	public static class ArrayUtil
	{
		public static T[] CreateFilled<T>(int quantity, fillCallback<T> fillCallback)
		{
			T[] array = new T[quantity];
			for (int i = 0; i < quantity; i++)
			{
				array[i] = fillCallback(i);
			}
			return array;
		}

		public static T[] CreateFilled<T>(int quantity, T with)
		{
			T[] array = new T[quantity];
			for (int i = 0; i < quantity; i++)
			{
				array[i] = with;
			}
			return array;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static T[] FastCopy<T>(this T[] src, int count)
		{
			T[] array = new T[count];
			if (count > 127)
			{
				Array.Copy(src, 0, array, 0, count);
			}
			else
			{
				for (int i = 0; i < array.Length; i++)
				{
					array[i] = src[i];
				}
			}
			return array;
		}

		public static T[] Slice<T>(this T[] src, int index, int count)
		{
			T[] array = new T[count];
			for (int i = 0; i < count; i++)
			{
				array[i] = src[index + i];
			}
			return array;
		}
	}
	public static class EnumerableExtensions
	{
		public static int IndexOf<T>(this IEnumerable<T> source, ActionBoolReturn<T> onelem)
		{
			int num = 0;
			foreach (T item in source)
			{
				if (onelem(item))
				{
					return num;
				}
				num++;
			}
			return -1;
		}

		public static void Foreach<T>(this IEnumerable<T> array, Action<T> onelement)
		{
			foreach (T item in array)
			{
				onelement(item);
			}
		}

		public static T Nearest<T>(this IEnumerable<T> array, System.Func<T, double> getDistance)
		{
			double num = double.MaxValue;
			T result = default(T);
			foreach (T item in array)
			{
				double num2 = getDistance(item);
				if (num2 < num)
				{
					num = num2;
					result = item;
				}
			}
			return result;
		}

		public static double NearestDistance<T>(this IEnumerable<T> array, System.Func<T, double> getDistance)
		{
			double num = double.MaxValue;
			foreach (T item in array)
			{
				double num2 = getDistance(item);
				if (num2 < num)
				{
					num = num2;
				}
			}
			return num;
		}
	}
