		public static T[] Shuffle<T>(this T[] array, Random rand)
		{
			int num = array.Length;
			while (num > 1)
			{
				int num2 = rand.Next(num);
				num--;
				T val = array[num];
				array[num] = array[num2];
				array[num2] = val;
			}
			return array;
		}

