		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static Block GetBlockBelow(this IBlockAccessor accessor, BlockPos pos, int dy = 1, int layer = 0)
		{
			pos.Y -= dy;
			Block block = accessor.GetBlock(pos, layer);
			pos.Y += dy;
			return block;
		}

