			for (int num = reference.Length - 1; num >= 0; num--)
			{
				char c;
				char c2;
				if ((c = value[num]) != (c2 = reference[num]) && ((c & 0xFFDF) != (c2 & 0xFFDF) || (c & 0xFFDF) < 65 || (c & 0xFFDF) > 90))
				{
					return false;
				}
