	public class MeshDataPool
	{
		public int MaxPartsPerPool;

		public int VerticesPoolSize;

		public int IndicesPoolSize;

		internal MeshRef modelRef;

		internal int poolId;

		internal List<ModelDataPoolLocation> poolLocations = new List<ModelDataPoolLocation>();

		public int[] indicesStartsByte;

		public int[] indicesSizes;

		public int indicesGroupsCount;

		public int indicesPosition;

		public int verticesPosition;

		public float CurrentFragmentation;

		public int UsedVertices;

		internal Vec3i poolOrigin;

		internal int dimensionId;

		public int RenderedTriangles;

		public int AllocatedTris;

		private MeshDataPool(int verticesPoolSize, int indicesPoolSize, int maxPartsPerPool)
		{
			MaxPartsPerPool = maxPartsPerPool;
			IndicesPoolSize = indicesPoolSize;
			VerticesPoolSize = verticesPoolSize;
		}

		public static MeshDataPool AllocateNewPool(ICoreClientAPI capi, int verticesPoolSize, int indicesPoolSize, int maxPartsPerPool, CustomMeshDataPartFloat customFloats = null, CustomMeshDataPartShort customShorts = null, CustomMeshDataPartByte customBytes = null, CustomMeshDataPartInt customInts = null)
		{
			MeshDataPool obj = new MeshDataPool(verticesPoolSize, indicesPoolSize, maxPartsPerPool)
			{
				indicesStartsByte = new int[maxPartsPerPool * 2],
				indicesSizes = new int[maxPartsPerPool]
			};
			customFloats?.SetAllocationSize(verticesPoolSize * customFloats.InterleaveStride / 4);
			customShorts?.SetAllocationSize(verticesPoolSize * customShorts.InterleaveStride / 2);
			customBytes?.SetAllocationSize(verticesPoolSize * customBytes.InterleaveStride);
			customInts?.SetAllocationSize(verticesPoolSize * customInts.InterleaveStride / 4);
			obj.modelRef = capi.Render.AllocateEmptyMesh(12 * verticesPoolSize, 0, 8 * verticesPoolSize, 4 * verticesPoolSize, 4 * verticesPoolSize, 4 * indicesPoolSize, customFloats, customShorts, customBytes, customInts, EnumDrawMode.Triangles, staticDraw: false);
			return obj;
		}

		public ModelDataPoolLocation TryAdd(ICoreClientAPI capi, MeshData modeldata, Vec3i modelOrigin, int dimension, Sphere frustumCullSphere)
		{
			if (poolLocations.Count >= MaxPartsPerPool || dimension != dimensionId)
			{
				return null;
			}
			if (poolOrigin != null)
			{
				if (poolLocations.Count == 0)
				{
					poolOrigin.Set(modelOrigin);
				}
				if (modelOrigin.SquareDistanceTo(poolOrigin) > 25000000)
				{
					return null;
				}
			}
			if (CurrentFragmentation > 0.03f)
			{
				ModelDataPoolLocation modelDataPoolLocation = TrySqueezeInbetween(capi, modeldata, modelOrigin, frustumCullSphere);
				if (modelDataPoolLocation != null)
				{
					return modelDataPoolLocation;
				}
			}
			return TryAppend(capi, modeldata, modelOrigin, frustumCullSphere);
		}

		private ModelDataPoolLocation TrySqueezeInbetween(ICoreClientAPI capi, MeshData modeldata, Vec3i modelOrigin, Sphere frustumCullSphere)
		{
			int num = 0;
			int num2 = 0;
			for (int i = 0; i < poolLocations.Count; i++)
			{
				ModelDataPoolLocation modelDataPoolLocation = poolLocations[i];
				if (modelDataPoolLocation.IndicesStart - num2 > modeldata.IndicesCount && modelDataPoolLocation.VerticesStart - num > modeldata.VerticesCount)
				{
					return InsertAt(capi, modeldata, modelOrigin, frustumCullSphere, num2, num, i);
				}
				num2 = modelDataPoolLocation.IndicesEnd;
				num = modelDataPoolLocation.VerticesEnd;
			}
			return null;
		}

		private ModelDataPoolLocation TryAppend(ICoreClientAPI capi, MeshData modeldata, Vec3i modelOrigin, Sphere frustumCullSphere)
		{
			if (modeldata.IndicesCount + indicesPosition > IndicesPoolSize || modeldata.VerticesCount + verticesPosition > VerticesPoolSize)
			{
				return null;
			}
			ModelDataPoolLocation result = InsertAt(capi, modeldata, modelOrigin, frustumCullSphere, indicesPosition, verticesPosition, -1);
			indicesPosition += modeldata.IndicesCount;
			verticesPosition += modeldata.VerticesCount;
			return result;
		}

		private ModelDataPoolLocation InsertAt(ICoreClientAPI capi, MeshData modeldata, Vec3i modelOrigin, Sphere frustumCullSphere, int indexPosition, int vertexPosition, int listPosition)
		{
			if (vertexPosition > 0)
			{
				for (int i = 0; i < modeldata.IndicesCount; i++)
				{
					modeldata.Indices[i] += vertexPosition;
				}
			}
			if (poolOrigin != null)
			{
				int num = modelOrigin.X - poolOrigin.X;
				int num2 = modelOrigin.Y - poolOrigin.Y;
				int num3 = modelOrigin.Z - poolOrigin.Z;
				for (int j = 0; j < modeldata.VerticesCount; j++)
				{
					modeldata.xyz[3 * j] += num;
					modeldata.xyz[3 * j + 1] += num2;
					modeldata.xyz[3 * j + 2] += num3;
				}
			}
			modeldata.XyzOffset = vertexPosition * 12;
			modeldata.NormalsOffset = vertexPosition * 4;
			modeldata.RgbaOffset = vertexPosition * 4;
			modeldata.Rgba2Offset = vertexPosition * 4;
			modeldata.UvOffset = vertexPosition * 8;
			modeldata.FlagsOffset = vertexPosition * 4;
			modeldata.IndicesOffset = indexPosition * 4;
			if (modeldata.CustomFloats != null)
			{
				modeldata.CustomFloats.BaseOffset = vertexPosition * modeldata.CustomFloats.InterleaveStride;
			}
			if (modeldata.CustomShorts != null)
			{
				modeldata.CustomShorts.BaseOffset = vertexPosition * modeldata.CustomShorts.InterleaveStride;
			}
			if (modeldata.CustomBytes != null)
			{
				modeldata.CustomBytes.BaseOffset = vertexPosition * modeldata.CustomBytes.InterleaveStride;
			}
			if (modeldata.CustomInts != null)
			{
				modeldata.CustomInts.BaseOffset = vertexPosition * modeldata.CustomInts.InterleaveStride;
			}
			capi.Render.UpdateChunkMesh(modelRef, modeldata);
			ModelDataPoolLocation modelDataPoolLocation = new ModelDataPoolLocation
			{
				IndicesStart = indexPosition,
				IndicesEnd = indexPosition + modeldata.IndicesCount,
				VerticesStart = vertexPosition,
				VerticesEnd = vertexPosition + modeldata.VerticesCount,
				PoolId = poolId,
				FrustumCullSphere = frustumCullSphere
			};
			if (listPosition != -1)
			{
				poolLocations.Insert(listPosition, modelDataPoolLocation);
			}
			else
			{
				poolLocations.Add(modelDataPoolLocation);
			}
			CalcFragmentation();
			return modelDataPoolLocation;
		}

		public void RemoveLocation(ModelDataPoolLocation location)
		{
			if (location.PoolId != poolId)
			{
				throw new Exception("invalid call");
			}
			if (!poolLocations.Remove(location))
			{
				throw new InvalidOperationException("Tried to remove mesh that does not exist. This shouldn't happen");
			}
			if (poolLocations.Count == 0)
			{
				indicesPosition = 0;
				verticesPosition = 0;
			}
			else if (location.IndicesEnd == indicesPosition && location.VerticesEnd == verticesPosition)
			{
				indicesPosition = poolLocations[poolLocations.Count - 1].IndicesEnd;
				verticesPosition = poolLocations[poolLocations.Count - 1].VerticesEnd;
			}
			CalcFragmentation();
		}

		public void Draw(ICoreClientAPI capi, FrustumCulling frustumCuller, EnumFrustumCullMode frustumCullMode)
		{
			FrustumCull(frustumCuller, frustumCullMode);
			capi.Render.RenderMesh(modelRef, indicesStartsByte, indicesSizes, indicesGroupsCount);
		}

		public void FrustumCull(FrustumCulling frustumCuller, EnumFrustumCullMode frustumCullMode)
		{
			indicesGroupsCount = 0;
			RenderedTriangles = 0;
			AllocatedTris = 0;
			for (int i = 0; i < poolLocations.Count; i++)
			{
				ModelDataPoolLocation modelDataPoolLocation = poolLocations[i];
				int num = modelDataPoolLocation.IndicesEnd - modelDataPoolLocation.IndicesStart;
				if (modelDataPoolLocation.IsVisible(frustumCullMode, frustumCuller))
				{
					indicesStartsByte[indicesGroupsCount * 2] = modelDataPoolLocation.IndicesStart * 4;
					indicesSizes[indicesGroupsCount] = num;
					RenderedTriangles += num / 3;
					indicesGroupsCount++;
				}
				AllocatedTris += num / 3;
			}
		}

		public void SetFullyVisible()
		{
			indicesGroupsCount = 0;
			RenderedTriangles = 0;
			AllocatedTris = 0;
			for (int i = 0; i < poolLocations.Count; i++)
			{
				ModelDataPoolLocation modelDataPoolLocation = poolLocations[i];
				int num = modelDataPoolLocation.IndicesEnd - modelDataPoolLocation.IndicesStart;
				indicesStartsByte[indicesGroupsCount * 2] = modelDataPoolLocation.IndicesStart * 4;
				indicesSizes[indicesGroupsCount] = num;
				RenderedTriangles += num / 3;
				indicesGroupsCount++;
				AllocatedTris += num / 3;
			}
		}

		public bool IsEmpty()
		{
			return poolLocations.Count == 0;
		}

		public void Dispose(ICoreClientAPI capi)
		{
			capi.Render.DeleteMesh(modelRef);
		}

		public void CalcFragmentation()
		{
			int num = 0;
			int num2 = 0;
			UsedVertices = 0;
			if (verticesPosition == 0)
			{
				CurrentFragmentation = 0f;
				return;
			}
			foreach (ModelDataPoolLocation poolLocation in poolLocations)
			{
				UsedVertices += poolLocation.VerticesEnd - poolLocation.VerticesStart;
				num2 += Math.Max(0, poolLocation.VerticesStart - num);
				num = poolLocation.VerticesEnd;
			}
			CurrentFragmentation = (float)num2 / (float)verticesPosition;
		}

		public float GetFragmentation()
		{
			return CurrentFragmentation;
		}

		public void RenderMesh(IRenderAPI render)
		{
			render.RenderMesh(modelRef, indicesStartsByte, indicesSizes, indicesGroupsCount);
		}
	}
	public class ModelDataPoolLocation
	{
		public static int VisibleBufIndex;

		public int PoolId;

		public int IndicesStart;

		public int IndicesEnd;

		public int VerticesStart;

		public int VerticesEnd;

		public Sphere FrustumCullSphere;

		public bool FrustumVisible;

		public Bools CullVisible = new Bools(a: true, b: true);

		public int LodLevel;

		public bool Hide;

		public int TransitionCounter;

		private bool UpdateVisibleFlag(bool inFrustum)
		{
			FrustumVisible = inFrustum;
			return FrustumVisible;
		}

		public bool IsVisible(EnumFrustumCullMode mode, FrustumCulling culler)
		{
			switch (mode)
			{
			case EnumFrustumCullMode.CullInstant:
				if (!Hide && CullVisible[VisibleBufIndex])
				{
					return culler.InFrustum(FrustumCullSphere);
				}
				return false;
			case EnumFrustumCullMode.CullInstantShadowPassNear:
				if (!Hide && CullVisible[VisibleBufIndex])
				{
					return culler.InFrustumShadowPass(FrustumCullSphere);
				}
				return false;
			case EnumFrustumCullMode.CullInstantShadowPassFar:
				if (!Hide && CullVisible[VisibleBufIndex] && culler.InFrustumShadowPass(FrustumCullSphere))
				{
					return LodLevel >= 1;
				}
				return false;
			case EnumFrustumCullMode.CullNormal:
				if (!Hide && CullVisible[VisibleBufIndex])
				{
					return UpdateVisibleFlag(culler.InFrustumAndRange(FrustumCullSphere, FrustumVisible, LodLevel));
				}
				return false;
			default:
				return !Hide;
			}
		}
	}
	public delegate bool VisibleTestDelegate(FrustumCulling culler);
	public class MeshDataPoolManager
	{
		private List<MeshDataPool> pools = new List<MeshDataPool>();

		internal FrustumCulling frustumCuller;

		private ICoreClientAPI capi;

		private MeshDataPoolMasterManager masterPool;

		private CustomMeshDataPartFloat customFloats;

		private CustomMeshDataPartShort customShorts;

		private CustomMeshDataPartByte customBytes;

		private CustomMeshDataPartInt customInts;

		private int defaultVertexPoolSize;

		private int defaultIndexPoolSize;

		private int maxPartsPerPool;

		private Vec3f tmp = new Vec3f();

		public MeshDataPoolManager(MeshDataPoolMasterManager masterPool, FrustumCulling frustumCuller, ICoreClientAPI capi, int defaultVertexPoolSize, int defaultIndexPoolSize, int maxPartsPerPool, CustomMeshDataPartFloat customFloats = null, CustomMeshDataPartShort customShorts = null, CustomMeshDataPartByte customBytes = null, CustomMeshDataPartInt customInts = null)
		{
			this.masterPool = masterPool;
			this.frustumCuller = frustumCuller;
			this.capi = capi;
			this.customFloats = customFloats;
			this.customBytes = customBytes;
			this.customInts = customInts;
			this.customShorts = customShorts;
			this.defaultIndexPoolSize = defaultIndexPoolSize;
			this.defaultVertexPoolSize = defaultVertexPoolSize;
			this.maxPartsPerPool = maxPartsPerPool;
		}

		public ModelDataPoolLocation AddModel(MeshData modeldata, Vec3i modelOrigin, int dimension, Sphere frustumCullSphere)
		{
			ModelDataPoolLocation modelDataPoolLocation = null;
			for (int i = 0; i < pools.Count; i++)
			{
				modelDataPoolLocation = pools[i].TryAdd(capi, modeldata, modelOrigin, dimension, frustumCullSphere);
				if (modelDataPoolLocation != null)
				{
					break;
				}
			}
			if (modelDataPoolLocation == null)
			{
				int num = Math.Max(modeldata.VerticesCount, defaultVertexPoolSize);
				int indicesPoolSize = Math.Max(modeldata.IndicesCount, defaultIndexPoolSize);
				if (num > defaultVertexPoolSize)
				{
					capi.World.Logger.Warning("Chunk (or some other mesh source at origin: {0}) exceeds default geometric complexity maximum of {1} vertices and {2} indices. You must be loading some very complex objects (#v = {3}, #i = {4}). Adjusted Pool size accordingly.", modelOrigin, defaultVertexPoolSize, defaultIndexPoolSize, modeldata.VerticesCount, modeldata.IndicesCount);
				}
				MeshDataPool meshDataPool = MeshDataPool.AllocateNewPool(capi, num, indicesPoolSize, maxPartsPerPool, customFloats, customShorts, customBytes, customInts);
				meshDataPool.poolOrigin = modelOrigin.Clone();
				meshDataPool.dimensionId = dimension;
				masterPool.AddModelDataPool(meshDataPool);
				pools.Add(meshDataPool);
				modelDataPoolLocation = meshDataPool.TryAdd(capi, modeldata, modelOrigin, dimension, frustumCullSphere);
			}
			if (modelDataPoolLocation == null)
			{
				capi.World.Logger.Fatal("Can't add modeldata (probably a tesselated chunk @{0}) to the model data pool list, blocks will likely be invisible. Potential reasons are the parts per pool were exceeded, or other code reasons, please report this. Default pool size is {1} vertices and {2} indices. Mesh size (#v = {3}, #i = {4}). Try increasing MaxVertexSize and MaxIndexSize.", modelOrigin, defaultVertexPoolSize, defaultIndexPoolSize, modeldata.VerticesCount, modeldata.IndicesCount);
			}
			return modelDataPoolLocation;
		}

		public void Render(Vec3d playerpos, string originUniformName, EnumFrustumCullMode frustumCullMode = EnumFrustumCullMode.CullNormal)
		{
			int count = pools.Count;
			for (int i = 0; i < count; i++)
			{
				MeshDataPool meshDataPool = pools[i];
				if (meshDataPool.dimensionId == 1)
				{
					bool flag = false;
					bool flag2 = false;
					bool flag3 = false;
					if (!capi.World.TryGetMiniDimension(meshDataPool.poolOrigin, out var dimension) || dimension.selectionTrackingOriginalPos == null)
					{
						continue;
					}
					meshDataPool.SetFullyVisible();
					if (meshDataPool.indicesGroupsCount == 0)
					{
						continue;
					}
					FastVec3d renderOffset = dimension.GetRenderOffset(masterPool.currentDt);
					IShaderProgram currentActiveShader = capi.Render.CurrentActiveShader;
					if (currentActiveShader.HasUniform("modelViewMatrix"))
					{
						currentActiveShader.UniformMatrix("modelViewMatrix", dimension.GetRenderTransformMatrix(masterPool.currentModelViewMatrix, playerpos));
						flag = true;
						if (currentActiveShader.HasUniform("forcedTransparency"))
						{
							currentActiveShader.Uniform("forcedTransparency", capi.Settings.Float["previewTransparency"]);
							flag3 = true;
						}
					}
					else if (currentActiveShader.HasUniform("mvpMatrix"))
					{
						currentActiveShader.UniformMatrix("mvpMatrix", dimension.GetRenderTransformMatrix(masterPool.shadowMVPMatrix, playerpos));
						flag2 = true;
					}
					currentActiveShader.Uniform(originUniformName, tmp.Set((float)((double)meshDataPool.poolOrigin.X + renderOffset.X - playerpos.X), (float)((double)meshDataPool.poolOrigin.Y + renderOffset.Y - playerpos.Y), (float)((double)meshDataPool.poolOrigin.Z + renderOffset.Z - playerpos.Z)));
					try
					{
						meshDataPool.RenderMesh(capi.Render);
					}
					finally
					{
						if (flag)
						{
							capi.Render.CurrentActiveShader.UniformMatrix("modelViewMatrix", masterPool.currentModelViewMatrix);
						}
						if (flag2)
						{
							capi.Render.CurrentActiveShader.UniformMatrix("mvpMatrix", masterPool.shadowMVPMatrix);
						}
						if (flag3)
						{
							capi.Render.CurrentActiveShader.Uniform("forcedTransparency", 0f);
						}
					}
				}
				else
				{
					meshDataPool.FrustumCull(frustumCuller, frustumCullMode);
					if (meshDataPool.indicesGroupsCount != 0)
					{
						capi.Render.CurrentActiveShader.Uniform(originUniformName, tmp.Set((float)((double)meshDataPool.poolOrigin.X - playerpos.X), (float)((double)(meshDataPool.poolOrigin.Y + meshDataPool.dimensionId * 32768) - playerpos.Y), (float)((double)meshDataPool.poolOrigin.Z - playerpos.Z)));
						meshDataPool.RenderMesh(capi.Render);
					}
				}
			}
		}

		public void GetStats(ref long usedVideoMemory, ref long renderedTris, ref long allocatedTris)
		{
			long num = (capi.Render.UseSSBOs ? 16 : 28) + ((customFloats != null) ? customFloats.InterleaveStride : 0) + ((customShorts != null) ? customShorts.InterleaveStride : 0) + ((customBytes != null) ? customBytes.InterleaveStride : 0) + ((customInts != null) ? customInts.InterleaveStride : 0);
			int num2 = ((!capi.Render.UseSSBOs) ? 4 : 0);
			int num3 = 0;
			for (int i = 0; i < pools.Count; i++)
			{
				MeshDataPool meshDataPool = pools[i];
				usedVideoMemory += meshDataPool.VerticesPoolSize * num + meshDataPool.IndicesPoolSize * num2;
				renderedTris += meshDataPool.RenderedTriangles;
				allocatedTris += meshDataPool.AllocatedTris;
				if (meshDataPool.IndicesPoolSize > num3)
				{
					num3 = meshDataPool.IndicesPoolSize;
				}
			}
			if (capi.Render.UseSSBOs)
			{
				usedVideoMemory += num3 * 4;
			}
		}
	}
	public class MeshDataPoolMasterManager
	{
		private List<MeshDataPool> modelPools = new List<MeshDataPool>();

		private ICoreClientAPI capi;

		public float currentDt;

		public float[] currentModelViewMatrix;

		public float[] shadowMVPMatrix;

		public bool DelayedPoolLocationRemoval;

		private Queue<ModelDataPoolLocation[]>[] removalQueue = new Queue<ModelDataPoolLocation[]>[4]
		{
			new Queue<ModelDataPoolLocation[]>(),
			new Queue<ModelDataPoolLocation[]>(),
			new Queue<ModelDataPoolLocation[]>(),
			new Queue<ModelDataPoolLocation[]>()
		};

		public MeshDataPoolMasterManager(ICoreClientAPI capi)
		{
			this.capi = capi;
		}

		public void RemoveDataPoolLocations(ModelDataPoolLocation[] locations)
		{
			if (DelayedPoolLocationRemoval)
			{
				for (int i = 0; i < locations.Length; i++)
				{
					locations[i].Hide = true;
				}
				removalQueue[0].Enqueue(locations);
			}
			else
			{
				RemoveLocationsNow(locations);
			}
		}

		public void OnFrame(float dt, float[] modelviewMatrix, float[] shadowMVPMatrix)
		{
			currentDt = dt;
			currentModelViewMatrix = modelviewMatrix;
			this.shadowMVPMatrix = shadowMVPMatrix;
			while (removalQueue[3].Count > 0)
			{
				RemoveLocationsNow(removalQueue[3].Dequeue());
			}
			while (removalQueue[2].Count > 0)
			{
				removalQueue[3].Enqueue(removalQueue[2].Dequeue());
			}
			while (removalQueue[1].Count > 0)
			{
				removalQueue[2].Enqueue(removalQueue[1].Dequeue());
			}
			while (removalQueue[0].Count > 0)
			{
				removalQueue[1].Enqueue(removalQueue[0].Dequeue());
			}
		}

		private void RemoveLocationsNow(ModelDataPoolLocation[] locations)
		{
			for (int i = 0; i < locations.Length; i++)
			{
				if (locations[i] == null || modelPools[locations[i].PoolId] == null)
				{
					capi.World.Logger.Error("Could not remove model data from the master pool. Something wonky is happening. Ignoring for now.");
				}
				else
				{
					modelPools[locations[i].PoolId].RemoveLocation(locations[i]);
				}
			}
		}

		public void AddModelDataPool(MeshDataPool pool)
		{
			pool.poolId = modelPools.Count;
			modelPools.Add(pool);
		}

		public void DisposeAllPools(ICoreClientAPI capi)
		{
			for (int i = 0; i < modelPools.Count; i++)
			{
				modelPools[i].Dispose(capi);
			}
		}

		public float CalcFragmentation()
		{
			long num = 0L;
			long num2 = 0L;
			for (int i = 0; i < modelPools.Count; i++)
			{
				num += modelPools[i].UsedVertices;
				num2 += modelPools[i].VerticesPoolSize;
			}
			return (float)(1.0 - (double)num / (double)num2);
		}

		public int QuantityModelDataPools()
		{
			return modelPools.Count;
		}
	}
	public class MeshDataRecycler
	{
		public const int MinimumSizeForRecycling = 4096;

		public const int TTL = 15000;

		private const int smallLimit = 368;

		private const int mediumLimit = 3072;

		private const int Four = 4;

		private SortedList<float, MeshData> smallSizes = new SortedList<float, MeshData>();

		private SortedList<float, MeshData> mediumSizes = new SortedList<float, MeshData>();

		private SortedList<float, MeshData> largeSizes = new SortedList<float, MeshData>();

		private IClientWorldAccessor game;

		private bool disposed;

		private ConcurrentQueue<MeshData> forRecycling = new ConcurrentQueue<MeshData>();

		private FieldInfo keysAccessor;

		public MeshDataRecycler(IClientWorldAccessor clientMain)
		{
			game = clientMain;
			Type typeFromHandle = typeof(SortedList<float, MeshData>);
			keysAccessor = typeFromHandle.GetField("keys", BindingFlags.Instance | BindingFlags.NonPublic);
		}

		public MeshData GetOrCreateMesh(int minimumVertices)
		{
			minimumVertices = (minimumVertices + 4 - 1) / 4 * 4;
			MeshData meshData = (disposed ? null : GetRecycled(minimumVertices));
			if (meshData == null)
			{
				if (!disposed)
				{
					minimumVertices = (minimumVertices * 41 / 40 + 4 - 1) / 4 * 4;
				}
				meshData = new MeshData(minimumVertices);
			}
			else if (meshData.IndicesMax != meshData.VerticesMax * 6 / 4)
			{
				meshData.Indices = new int[meshData.VerticesMax * 6 / 4];
				meshData.IndicesMax = meshData.Indices.Length;
			}
			meshData.Recyclable = true;
			return meshData;
		}

		public void DoRecycling()
		{
			if (disposed)
			{
				forRecycling.Clear();
				smallSizes.Clear();
				mediumSizes.Clear();
				largeSizes.Clear();
			}
			if (forRecycling.IsEmpty)
			{
				return;
			}
			ControlSizeOfLists();
			MeshData result;
			while (!forRecycling.IsEmpty && forRecycling.TryDequeue(out result))
			{
				int num = result.VerticesMax / 4;
				if (num < 368)
				{
					TryAdd(smallSizes, num, result);
				}
				else if (num < 3072)
				{
					TryAdd(mediumSizes, num, result);
				}
				else
				{
					TryAdd(largeSizes, num, result);
				}
				result.RecyclingTime = game.ElapsedMilliseconds;
			}
		}

		public void Recycle(MeshData meshData)
		{
			if (!disposed)
			{
				forRecycling.Enqueue(meshData);
			}
		}

		public void Dispose()
		{
			disposed = true;
		}

		private void ControlSizeOfLists()
		{
			RemoveOldest(smallSizes, 300000);
			RemoveOldest(mediumSizes, 900000);
			RemoveOldest(largeSizes, 2240000);
		}

		private void RemoveOldest(SortedList<float, MeshData> list, int maxSize)
		{
			if (list.Count == 0)
			{
				return;
			}
			int num = 0;
			int index = 0;
			long recyclingTime = list.GetValueAtIndex(0).RecyclingTime;
			int num2 = 0;
			foreach (KeyValuePair<float, MeshData> item in list)
			{
				num += (int)item.Key;
				if (item.Value.RecyclingTime < recyclingTime)
				{
					index = num2;
					recyclingTime = item.Value.RecyclingTime;
				}
				num2++;
			}
			if (num > maxSize || recyclingTime < game.ElapsedMilliseconds - 15000)
			{
				list.GetValueAtIndex(index).DisposeBasicData();
				list.RemoveAt(index);
			}
		}

		private MeshData GetRecycled(int minimumCapacity)
		{
			if (disposed)
			{
				return null;
			}
			int num = minimumCapacity / 4;
			if (num < 368)
			{
				return TryGet(smallSizes, num);
			}
			if (num < 3072)
			{
				return TryGet(mediumSizes, num);
			}
			return TryGet(largeSizes, num);
		}

		private void TryAdd(SortedList<float, MeshData> list, int intkey, MeshData entry)
		{
			float num = intkey;
			while (num < (float)(intkey + 1))
			{
				if (list.TryAdd(num, entry))
				{
					return;
				}
				float num2 = num + 0.25f;
				if (num2 == num)
				{
					num2 = num + 0.5f;
				}
				if (num2 == num)
				{
					break;
				}
				num = num2;
			}
			entry.DisposeBasicData();
		}

		private MeshData TryGet(SortedList<float, MeshData> list, int entrySize)
		{
			if (list.Count == 0)
			{
				return null;
			}
			int num = Array.BinarySearch((float[])keysAccessor.GetValue(list), 0, list.Count, entrySize, null);
			if (num < 0)
			{
				num = ~num;
				if (num >= list.Count)
				{
					return null;
				}
				if ((int)list.GetKeyAtIndex(num) > entrySize * 5 / 4 + 64)
				{
					return null;
				}
			}
			MeshData valueAtIndex = list.GetValueAtIndex(num);
			list.RemoveAt(num);
			return valueAtIndex;
		}
	}
