		public void AddPackedUV(float u, float v, bool isU2, bool isV2)
		{
			Add((short)(ushort)((int)(u * 32768f + 0.5f) + (isU2 ? 1 : 0)));
			Add((short)(ushort)((int)(v * 32768f + 0.5f) + (isV2 ? 1 : 0)));
		}
	}
