		public MeshData WithTexPos(TextureAtlasPosition texPos)
		{
			MeshData meshData = Clone();
			meshData.SetTexPos(texPos);
			return meshData;
		}

		public void SetTexPos(TextureAtlasPosition texPos)
		{
			float num = texPos.x2 - texPos.x1;
			float num2 = texPos.y2 - texPos.y1;
			for (int i = 0; i < Uv.Length; i++)
			{
				Uv[i] = ((i % 2 == 0) ? (Uv[i] * num + texPos.x1) : (Uv[i] * num2 + texPos.y1));
			}
			byte textureIndex = getTextureIndex(texPos.atlasTextureId);
			for (int j = 0; j < TextureIndices.Length; j++)
			{
				TextureIndices[j] = textureIndex;
			}
		}

		public MeshData[] SplitByTextureId()
		{
			MeshData[] array = new MeshData[TextureIds.Length];
			if (array.Length == 1)
			{
				array[0] = this;
			}
			else
			{
				int i;
				for (i = 0; i < array.Length; i++)
				{
					MeshData obj = (array[i] = EmptyClone());
					obj.AddMeshData(this, (int faceindex) => TextureIndices[faceindex] == i);
					obj.CompactBuffers();
				}
			}
			return array;
		}
	}
	public static class MeshUtil
	{
		public static void SetWindFlag(this MeshData sourceMesh, float waveFlagMinY = 0.5625f, int flag = 67108864)
		{
			int verticesCount = sourceMesh.VerticesCount;
			float[] xyz = sourceMesh.xyz;
			int[] flags = sourceMesh.Flags;
			for (int i = 0; i < verticesCount; i++)
			{
				if (xyz[i * 3 + 1] > waveFlagMinY)
				{
					flags[i] |= flag;
				}
				else
				{
					flags[i] &= -503316481;
				}
			}
		}

		public static void ClearWindFlags(this MeshData sourceMesh)
		{
			int verticesCount = sourceMesh.VerticesCount;
			int[] flags = sourceMesh.Flags;
			for (int i = 0; i < verticesCount; i++)
			{
				flags[i] &= -503316481;
			}
		}

		public static void ToggleWindModeSetWindData(this MeshData sourceMesh, int leavesNoShearTileSide, bool enableWind, int groundOffsetTop)
		{
			int num = 33554431;
			int verticesCount = sourceMesh.VerticesCount;
			int[] flags = sourceMesh.Flags;
			if (!enableWind)
			{
				for (int i = 0; i < verticesCount; i++)
				{
					flags[i] &= num;
				}
				return;
			}
			float[] xyz = sourceMesh.xyz;
			for (int j = 0; j < verticesCount; j++)
			{
				int num2 = (int)(sourceMesh.xyz[j * 3 + 1] - 1.5f) >> 1;
				if (leavesNoShearTileSide != 0)
				{
					int num3 = (int)(xyz[j * 3] - 1.5f) >> 1;
					int num4 = (int)(xyz[j * 3 + 2] - 1.5f) >> 1;
					int num5 = (1 << 4 - num2) | (4 + num4 * 3) | (2 - num3 * 6);
					if ((leavesNoShearTileSide & num5) != 0)
					{
						VertexFlags.ReplaceWindData(ref flags[j], 0);
						continue;
					}
				}
				int windData = ((groundOffsetTop == 8) ? 7 : (groundOffsetTop + num2));
				VertexFlags.ReplaceWindData(ref flags[j], windData);
			}
		}
	}
	public static class NormalUtil
	{
		public static int NegBit = 512;

		public static int tenBitMask = 1023;

		public static int nineBitMask = 511;

		public static int tenthBitMask = 512;

		public static void FromPackedNormal(int normal, ref Vec4f toFill)
		{
			int num = normal >> 10;
			int num2 = normal >> 20;
			bool flag = (tenthBitMask & normal) > 0;
			bool flag2 = (tenthBitMask & num) > 0;
			bool flag3 = (tenthBitMask & num2) > 0;
			toFill.X = (float)(flag ? (~normal & nineBitMask) : (normal & nineBitMask)) / 512f;
			toFill.Y = (float)(flag2 ? (~num & nineBitMask) : (num & nineBitMask)) / 512f;
			toFill.Z = (float)(flag3 ? (~num2 & nineBitMask) : (num2 & nineBitMask)) / 512f;
			toFill.W = normal >> 30;
		}

		public static void FromPackedNormal(int normal, ref float[] toFill)
		{
			int num = normal >> 10;
			int num2 = normal >> 20;
			bool flag = (tenthBitMask & normal) > 0;
			bool flag2 = (tenthBitMask & num) > 0;
			bool flag3 = (tenthBitMask & num2) > 0;
			toFill[0] = (float)(flag ? (~normal & nineBitMask) : (normal & nineBitMask)) / 512f;
			toFill[1] = (float)(flag2 ? (~num & nineBitMask) : (num & nineBitMask)) / 512f;
			toFill[2] = (float)(flag3 ? (~num2 & nineBitMask) : (num2 & nineBitMask)) / 512f;
			toFill[3] = normal >> 30;
		}

		public static int PackNormal(Vec4f normal)
		{
			bool num = normal.X < 0f;
			bool flag = normal.Y < 0f;
			bool flag2 = normal.Z < 0f;
			int num2 = (int)Math.Abs(normal.X * 511f);
			int num3 = (int)Math.Abs(normal.Y * 511f);
			int num4 = (int)Math.Abs(normal.Z * 511f);
			return (num ? (NegBit | (~num2 & nineBitMask)) : num2) | ((flag ? (NegBit | (~num3 & nineBitMask)) : num3) << 10) | ((flag2 ? (NegBit | (~num4 & nineBitMask)) : num4) << 20) | ((int)normal.W << 30);
		}

		public static int PackNormal(float x, float y, float z)
		{
			bool num = x < 0f;
			bool flag = y < 0f;
			bool flag2 = z < 0f;
			int num2 = (num ? (NegBit | (~(int)Math.Abs(x * 511f) & nineBitMask)) : ((int)(x * 511f) & nineBitMask));
			int num3 = (flag ? (NegBit | (~(int)Math.Abs(y * 511f) & nineBitMask)) : ((int)(y * 511f) & nineBitMask));
			int num4 = (flag2 ? (NegBit | (~(int)Math.Abs(z * 511f) & nineBitMask)) : ((int)(z * 511f) & nineBitMask));
			return num2 | (num3 << 10) | (num4 << 20);
		}

		internal static int PackNormal(float[] normal)
		{
			bool num = normal[0] < 0f;
			bool flag = normal[1] < 0f;
			bool flag2 = normal[2] < 0f;
			int num2 = (int)Math.Abs(normal[0] * 511f);
			int num3 = (int)Math.Abs(normal[1] * 511f);
			int num4 = (int)Math.Abs(normal[2] * 511f);
			return (num ? (NegBit | (~num2 & nineBitMask)) : num2) | ((flag ? (NegBit | (~num3 & nineBitMask)) : num3) << 10) | ((flag2 ? (NegBit | (~num4 & nineBitMask)) : num4) << 20) | ((int)normal[3] << 30);
		}

		internal static void FromPackedNormal(int normal, ref double[] toFill)
		{
			int num = normal >> 10;
			int num2 = normal >> 20;
			bool flag = (tenthBitMask & normal) > 0;
			bool flag2 = (tenthBitMask & num) > 0;
			bool flag3 = (tenthBitMask & num2) > 0;
			toFill[0] = (float)(flag ? (~normal & nineBitMask) : (normal & nineBitMask)) / 512f;
			toFill[1] = (float)(flag2 ? (~num & nineBitMask) : (num & nineBitMask)) / 512f;
			toFill[2] = (float)(flag3 ? (~num2 & nineBitMask) : (num2 & nineBitMask)) / 512f;
			toFill[3] = normal >> 30;
		}

		internal static int PackNormal(double[] normal)
		{
			bool num = normal[0] < 0.0;
			bool flag = normal[1] < 0.0;
			bool flag2 = normal[2] < 0.0;
			int num2 = (int)Math.Abs(normal[0] * 512.0);
			int num3 = (int)Math.Abs(normal[1] * 512.0);
			int num4 = (int)Math.Abs(normal[2] * 512.0);
			return (num ? (NegBit | (~num2 & tenBitMask)) : num2) | ((flag ? (NegBit | (~num3 & tenBitMask)) : num3) << 10) | ((flag2 ? (NegBit | (~num4 & tenBitMask)) : num4) << 20) | ((int)normal[3] << 30);
		}
	}
	public class QuadMeshUtil
	{
		private static int[] quadVertices = new int[12]
		{
			-1, -1, 0, 1, -1, 0, 1, 1, 0, -1,
			1, 0
		};

		private static int[] quadTextureCoords = new int[8] { 0, 0, 1, 0, 1, 1, 0, 1 };

		private static int[] quadVertexIndices = new int[6] { 0, 1, 2, 0, 2, 3 };

		public static MeshData GetQuad()
		{
			MeshData meshData = new MeshData();
			float[] array = new float[12];
			for (int i = 0; i < 12; i++)
			{
				array[i] = quadVertices[i];
			}
			meshData.SetXyz(array);
			float[] array2 = new float[8];
			for (int j = 0; j < array2.Length; j++)
			{
				array2[j] = quadTextureCoords[j];
			}
			meshData.SetUv(array2);
			meshData.SetVerticesCount(4);
			meshData.SetIndices(quadVertexIndices);
			meshData.SetIndicesCount(6);
			return meshData;
		}

		public static MeshData GetCustomQuadModelData(float x, float y, float z, float dw, float dh)
		{
			MeshData meshData = new MeshData(4, 6, withNormals: false, withUv: true, withRgba: false, withFlags: false);
			for (int i = 0; i < 4; i++)
			{
				meshData.AddVertex(x + ((quadVertices[i * 3] > 0) ? dw : 0f), y + ((quadVertices[i * 3 + 1] > 0) ? dh : 0f), z, quadTextureCoords[i * 2], quadTextureCoords[i * 2 + 1]);
			}
			for (int j = 0; j < 6; j++)
			{
				meshData.AddIndex(quadVertexIndices[j]);
			}
			return meshData;
		}

		public static MeshData GetCustomQuad(float x, float y, float z, float width, float height, byte r, byte g, byte b, byte a)
		{
			MeshData meshData = new MeshData();
			meshData.SetXyz(new float[12]
			{
				x,
				y,
				z,
				x + width,
				y,
				z,
				x + width,
				y + height,
				z,
				x,
				y + height,
				z
			});
			float[] array = new float[8];
			for (int i = 0; i < array.Length; i += 2)
			{
				array[i] = (float)quadTextureCoords[i] * width;
				array[i + 1] = (float)quadTextureCoords[i + 1] * height;
			}
			meshData.SetUv(array);
			byte[] array2 = new byte[16];
			for (int j = 0; j < 4; j++)
			{
				array2[j * 4] = r;
				array2[j * 4 + 1] = g;
				array2[j * 4 + 2] = b;
				array2[j * 4 + 3] = a;
			}
			meshData.SetRgba(array2);
			meshData.SetVerticesCount(4);
			meshData.SetIndices(quadVertexIndices);
			meshData.SetIndicesCount(6);
			return meshData;
		}

		public static MeshData GetCustomQuadHorizontal(float x, float y, float z, float width, float length, byte r, byte g, byte b, byte a)
		{
			MeshData meshData = new MeshData();
			meshData.SetXyz(new float[12]
			{
				x,
				y,
				z,
				x + width,
				y,
				z,
				x + width,
				y,
				z + length,
				x,
				y,
				z + length
			});
			float[] array = new float[8];
			for (int i = 0; i < array.Length; i += 2)
			{
				array[i] = (float)quadTextureCoords[i] * width;
				array[i + 1] = (float)quadTextureCoords[i + 1] * length;
			}
			meshData.SetUv(array);
			byte[] array2 = new byte[16];
			for (int j = 0; j < 4; j++)
			{
				array2[j * 4] = r;
				array2[j * 4 + 1] = g;
				array2[j * 4 + 2] = b;
				array2[j * 4 + 3] = a;
			}
			meshData.SetRgba(array2);
			meshData.SetVerticesCount(4);
			meshData.SetIndices(quadVertexIndices);
			meshData.SetIndicesCount(6);
			return meshData;
		}

		public static MeshData GetCustomQuadModelData(float u, float v, float u2, float v2, float dx, float dy, float dw, float dh, byte r, byte g, byte b, byte a)
		{
			MeshData meshData = new MeshData();
			meshData.SetXyz(new float[12]
			{
				dx,
				dy,
				0f,
				dx + dw,
				dy,
				0f,
				dx + dw,
				dy + dh,
				0f,
				dx,
				dy + dh,
				0f
			});
			meshData.SetUv(new float[8] { u, v, u2, v, u2, v2, u, v2 });
			byte[] array = new byte[16];
			for (int i = 0; i < 4; i++)
			{
				array[i * 4] = r;
				array[i * 4 + 1] = g;
				array[i * 4 + 2] = b;
				array[i * 4 + 3] = a;
			}
			meshData.SetRgba(array);
			meshData.SetVerticesCount(4);
			meshData.SetIndices(quadVertexIndices);
			meshData.SetIndicesCount(6);
			return meshData;
		}
	}
