	public class ModelCubeUtilExt : CubeMeshUtil
	{
		public enum EnumShadeMode
		{
			Off,
			On,
			Gradient
		}

		private static int[] gradientNormalMixedFlags;

		static ModelCubeUtilExt()
		{
			gradientNormalMixedFlags = new int[6];
			for (int i = 0; i < 6; i++)
			{
				Vec3f vec3f = new Vec3f(0f, 1f, 0f).Mul(0.33f) + BlockFacing.ALLFACES[i].Normalf.Clone().Mul(0.66f);
				vec3f.Normalize();
				gradientNormalMixedFlags[i] = VertexFlags.PackNormal(vec3f);
			}
		}

		public static void AddFace(MeshData modeldata, BlockFacing face, Vec3f centerXyz, Vec3f sizeXyz, Vec2f originUv, Vec2f sizeUv, int textureId, int color, EnumShadeMode shade, int[] vertexFlags, float brightness = 1f, int uvRotation = 0, byte climateColorMapId = 0, byte seasonColorMapId = 0, short renderPass = -1)
		{
			int num = face.Index * 12;
			int num2 = face.Index * 8;
			int verticesCount = modeldata.VerticesCount;
			int color2 = ColorUtil.ColorMultiply3(color, brightness);
			if (shade == EnumShadeMode.Gradient)
			{
				float num3 = sizeXyz.Y / 2f;
				int normalPackedFlags = BlockFacing.UP.NormalPackedFlags;
				int num4 = gradientNormalMixedFlags[face.Index];
				for (int i = 0; i < 4; i++)
				{
					float x = centerXyz.X + sizeXyz.X * (float)CubeMeshUtil.CubeVertices[num++] / 2f;
					float num5 = centerXyz.Y + sizeXyz.Y * (float)CubeMeshUtil.CubeVertices[num++] / 2f;
					int num6 = 2 * ((uvRotation + i) % 4) + num2;
					modeldata.AddWithFlagsVertex(x, num5, centerXyz.Z + sizeXyz.Z * (float)CubeMeshUtil.CubeVertices[num++] / 2f, originUv.X + sizeUv.X * (float)CubeMeshUtil.CubeUvCoords[num6], originUv.Y + sizeUv.Y * (float)CubeMeshUtil.CubeUvCoords[num6 + 1], color2, vertexFlags[i] | ((num5 > num3) ? normalPackedFlags : num4));
				}
			}
			else
			{
				for (int j = 0; j < 4; j++)
				{
					int num7 = 2 * ((uvRotation + j) % 4) + num2;
					modeldata.AddWithFlagsVertex(centerXyz.X + sizeXyz.X * (float)CubeMeshUtil.CubeVertices[num++] / 2f, centerXyz.Y + sizeXyz.Y * (float)CubeMeshUtil.CubeVertices[num++] / 2f, centerXyz.Z + sizeXyz.Z * (float)CubeMeshUtil.CubeVertices[num++] / 2f, originUv.X + sizeUv.X * (float)CubeMeshUtil.CubeUvCoords[num7], originUv.Y + sizeUv.Y * (float)CubeMeshUtil.CubeUvCoords[num7 + 1], color2, vertexFlags[j]);
				}
			}
			modeldata.AddIndex(verticesCount);
			modeldata.AddIndex(verticesCount + 1);
			modeldata.AddIndex(verticesCount + 2);
			modeldata.AddIndex(verticesCount);
			modeldata.AddIndex(verticesCount + 2);
			modeldata.AddIndex(verticesCount + 3);
			if (modeldata.XyzFacesCount >= modeldata.XyzFaces.Length)
			{
				Array.Resize(ref modeldata.XyzFaces, modeldata.XyzFaces.Length + 32);
			}
			if (modeldata.TextureIndicesCount >= modeldata.TextureIndices.Length)
			{
				Array.Resize(ref modeldata.TextureIndices, modeldata.TextureIndices.Length + 32);
			}
			modeldata.TextureIndices[modeldata.TextureIndicesCount++] = modeldata.getTextureIndex(textureId);
			modeldata.XyzFaces[modeldata.XyzFacesCount++] = (byte)((shade != EnumShadeMode.Off) ? face.MeshDataIndex : 0);
			if (modeldata.ClimateColorMapIds != null)
			{
				if (modeldata.ColorMapIdsCount >= modeldata.ClimateColorMapIds.Length)
				{
					Array.Resize(ref modeldata.ClimateColorMapIds, modeldata.ClimateColorMapIds.Length + 32);
					Array.Resize(ref modeldata.SeasonColorMapIds, modeldata.SeasonColorMapIds.Length + 32);
				}
				modeldata.ClimateColorMapIds[modeldata.ColorMapIdsCount] = climateColorMapId;
				modeldata.SeasonColorMapIds[modeldata.ColorMapIdsCount++] = seasonColorMapId;
			}
			if (modeldata.RenderPassesAndExtraBits != null)
			{
				if (modeldata.RenderPassCount >= modeldata.RenderPassesAndExtraBits.Length)
				{
					Array.Resize(ref modeldata.RenderPassesAndExtraBits, modeldata.RenderPassesAndExtraBits.Length + 32);
				}
				modeldata.RenderPassesAndExtraBits[modeldata.RenderPassCount++] = renderPass;
			}
		}

		public static void AddFaceSkipTex(MeshData modeldata, BlockFacing face, Vec3f centerXyz, Vec3f sizeXyz, int color, float brightness = 1f)
		{
			int num = face.Index * 12;
			int verticesCount = modeldata.VerticesCount;
			for (int i = 0; i < 4; i++)
			{
				float[] array = new float[3]
				{
					centerXyz.X + sizeXyz.X * (float)CubeMeshUtil.CubeVertices[num++] / 2f,
					centerXyz.Y + sizeXyz.Y * (float)CubeMeshUtil.CubeVertices[num++] / 2f,
					centerXyz.Z + sizeXyz.Z * (float)CubeMeshUtil.CubeVertices[num++] / 2f
				};
				modeldata.AddVertexSkipTex(array[0], array[1], array[2], ColorUtil.ColorMultiply3(color, brightness));
			}
			modeldata.AddIndex(verticesCount);
			modeldata.AddIndex(verticesCount + 1);
			modeldata.AddIndex(verticesCount + 2);
			modeldata.AddIndex(verticesCount);
			modeldata.AddIndex(verticesCount + 2);
			modeldata.AddIndex(verticesCount + 3);
		}
	}
	public class DamagedPerceptionEffect : PerceptionEffect
	{
		private long damageVignettingUntil;

		private float strength;

		private int duration;

		private readonly NormalizedSimplexNoise noiseGenerator;

		public DamagedPerceptionEffect(ICoreClientAPI capi)
			: base(capi)
		{
			noiseGenerator = NormalizedSimplexNoise.FromDefaultOctaves(4, 1.0, 0.9, 123L);
		}

		public override void OnOwnPlayerDataReceived(EntityPlayer player)
		{
			player.WatchedAttributes.RegisterModifiedListener("onHurt", OnHurt);
		}

		private void OnHurt()
		{
			EntityPlayer entity = capi.World.Player.Entity;
			strength = entity.WatchedAttributes.GetFloat("onHurt");
			if (strength != 0f && capi.World.Player.Entity.RemainingActivityTime("invulnerable") > 0)
			{
				duration = GameMath.Clamp(200 + (int)(strength * 10f), 200, 600) * 3;
				damageVignettingUntil = capi.ElapsedMilliseconds + duration;
				float num = entity.WatchedAttributes.GetFloat("onHurtDir");
				if (num < -99f)
				{
					capi.Render.ShaderUniforms.DamageVignettingSide = 0f;
					return;
				}
				float num2 = GameMath.AngleRadDistance(entity.Pos.Yaw - (float)Math.PI / 2f, num);
				capi.Render.ShaderUniforms.DamageVignettingSide = GameMath.Clamp(num2 / ((float)Math.PI / 2f), -1f, 1f);
			}
		}

		public override void OnBeforeGameRender(float dt)
		{
			if (!capi.IsGamePaused)
			{
				HandleDamageEffects(Math.Min(dt, 1f));
			}
		}

		private void HandleDamageEffects(float dt)
		{
			if (!capi.World.Player.Entity.Alive)
			{
				ApplyDeathEffects(dt);
				return;
			}
			float healthThreshold = CalculateHealthThreshold();
			float elapsedSeconds = (float)capi.InWorldEllapsedMilliseconds / 1000f;
			ApplyDamageSepiaEffect(healthThreshold, elapsedSeconds);
			ApplyDamageVignette(elapsedSeconds, healthThreshold);
			ApplyMotionEffects(healthThreshold, elapsedSeconds);
		}

		private void ApplyDeathEffects(float dt)
		{
			capi.Render.ShaderUniforms.ExtraSepia += (2f - capi.Render.ShaderUniforms.ExtraSepia) * Math.Min(1f, dt * 5f);
			capi.Render.ShaderUniforms.DamageVignetting += (1.25f - capi.Render.ShaderUniforms.DamageVignetting) * Math.Min(1f, dt * 5f);
			capi.Render.ShaderUniforms.DamageVignettingSide += (0f - capi.Render.ShaderUniforms.DamageVignettingSide) * Math.Min(1f, dt * 5f);
		}

		private float CalculateHealthThreshold()
		{
			ITreeAttribute treeAttribute = capi.World.Player.Entity.WatchedAttributes.GetTreeAttribute("health");
			float num = (treeAttribute?.GetFloat("currenthealth") / treeAttribute?.GetFloat("maxhealth")) ?? 1f;
			return Math.Max(0f, (0.23f - num) * 1f / 0.18f);
		}

		private void ApplyDamageSepiaEffect(float healthThreshold, float elapsedSeconds)
		{
			capi.Render.ShaderUniforms.ExtraSepia = ((healthThreshold <= 0f) ? 0f : GameMath.Clamp(healthThreshold * (float)noiseGenerator.Noise(0.0, elapsedSeconds / 3f) * 1.2f, 0f, 1.2f));
		}

		private void ApplyDamageVignette(float elapsedSeconds, float healthThreshold)
		{
			int num = GameMath.Clamp((int)(damageVignettingUntil - capi.ElapsedMilliseconds), 0, duration);
			float num2 = (float)noiseGenerator.Noise(12412.0, elapsedSeconds / 2f) * 0.5f + (float)Math.Pow(Math.Abs(GameMath.Sin(elapsedSeconds * 1f / 0.7f)), 30.0) * 0.5f;
			float num3 = Math.Min(healthThreshold * 1.5f, 1f) * (num2 * 0.75f + 0.5f);
			capi.Render.ShaderUniforms.DamageVignetting = GameMath.Clamp(GameMath.Clamp(strength / 2f, 0.5f, 3.5f) * ((float)num / (float)Math.Max(1, duration)) + num3, 0f, 1.5f);
		}

		private void ApplyMotionEffects(float healthThreshold, float elapsedSeconds)
		{
			if (!(healthThreshold <= 0f))
			{
				if (capi.World.Rand.NextDouble() < 0.01)
				{
					capi.World.AddCameraShake(0.15f * healthThreshold);
				}
				capi.Input.MouseYaw += healthThreshold * (float)(noiseGenerator.Noise(76.0, elapsedSeconds / 50f) - 0.5) * 0.003f;
				float num = healthThreshold * (float)(noiseGenerator.Noise(elapsedSeconds / 50f, 987.0) - 0.5) * 0.003f;
				capi.World.Player.Entity.Pos.Pitch += num;
				capi.Input.MousePitch += num;
			}
		}
	}
	public class DrunkPerceptionEffect : PerceptionEffect
	{
		private NormalizedSimplexNoise noisegen = NormalizedSimplexNoise.FromDefaultOctaves(4, 1.0, 0.9, 123L);

		private float accum;

		private float accum1s;

		private float targetIntensity;

		public DrunkPerceptionEffect(ICoreClientAPI capi)
			: base(capi)
		{
		}

		public override void OnBeforeGameRender(float dt)
		{
			if (!capi.IsGamePaused && capi.World.Player.Entity.AnimManager.HeadController != null)
			{
				capi.Render.ShaderUniforms.PerceptionEffectIntensity = Intensity;
				accum1s += dt;
				if (accum1s > 1f)
				{
					accum1s = 0f;
					targetIntensity = capi.World.Player.Entity.WatchedAttributes.GetFloat("intoxication");
				}
				Intensity += (targetIntensity - Intensity) * dt / 3f;
				accum = (float)((double)capi.InWorldEllapsedMilliseconds / 3000.0 % 100.0 * Math.PI);
				float num = Intensity / 250f;
				float num2 = (float)(Math.Cos((double)accum / 1.15) + Math.Cos(accum / 1.35f)) * num / 2f;
				capi.World.Player.Entity.Pos.Pitch += num2;
				capi.Input.MousePitch += num2;
				capi.Input.MouseYaw += (float)(Math.Sin((double)accum / 1.1) + Math.Sin(accum / 1.5f) + Math.Sin(accum / 5f) * 0.20000000298023224) * num;
				if (!capi.Input.MouseGrabbed)
				{
					capi.World.Player.Entity.Pos.Yaw = capi.Input.MouseYaw;
				}
				EntityHeadController headController = capi.World.Player.Entity.AnimManager.HeadController;
				headController.yawOffset = (float)(Math.Cos((double)accum / 1.12) + Math.Cos(accum / 1.2f) + Math.Cos(accum / 4f) * 0.20000000298023224) * num * 60f;
				accum /= 2f;
				headController.pitchOffset = (float)(Math.Sin((double)accum / 1.12) + Math.Sin(accum / 1.2f) + Math.Sin(accum / 4f) * 0.20000000298023224) * num * 30f;
				headController.pitchOffset = (float)(Math.Sin((double)accum / 1.12) + Math.Sin(accum / 1.2f) + Math.Sin(accum / 4f) * 0.20000000298023224) * num * 30f;
				double num3 = (float)((double)capi.InWorldEllapsedMilliseconds / 9000.0 % 100.0 * Math.PI);
				float perceptionEffectIntensity = capi.Render.ShaderUniforms.PerceptionEffectIntensity;
				capi.Render.ShaderUniforms.AmbientBloomLevelAdd[1] = GameMath.Clamp((float)Math.Abs(Math.Cos(num3 / 1.12) + Math.Sin(num3 / 2.2) + Math.Cos(num3 * 2.3)) * perceptionEffectIntensity * 2f, perceptionEffectIntensity / 3f, 1.8f);
			}
		}

		public override void ApplyToFpHand(Matrixf modelMat)
		{
			float num = Intensity / 10f;
			modelMat.Translate(GameMath.Sin(accum) * num, (double)GameMath.Sin(accum) * 1.2 * (double)num, 0.0);
			modelMat.RotateX(GameMath.Cos(accum * 0.8f) * num);
			modelMat.RotateZ(GameMath.Cos(accum * 1.1f) * num);
		}

		public override void ApplyToTpPlayer(EntityPlayer entityPlr, float[] modelMatrix, float? playerIntensity = null)
		{
			if (entityPlr.Player is IClientPlayer clientPlayer && entityPlr.AnimManager.Animator != null && (clientPlayer.CameraMode != EnumCameraMode.FirstPerson || clientPlayer.ImmersiveFpMode))
			{
				float num = ((!playerIntensity.HasValue) ? Intensity : playerIntensity.Value);
				ElementPose posebyName = entityPlr.AnimManager.Animator.GetPosebyName("root");
				posebyName.degOffX = GameMath.Sin(accum) / 5f * num * (180f / (float)Math.PI);
				posebyName.degOffZ = GameMath.Sin(accum * 1.2f) / 5f * num * (180f / (float)Math.PI);
			}
		}

		public override void NowActive(float intensity)
		{
			base.NowActive(intensity);
			capi.Render.ShaderUniforms.PerceptionEffectId = 2;
		}
	}
	public class FreezingPerceptionEffect : PerceptionEffect
	{
		private float currentStrength;

		private readonly NormalizedSimplexNoise noiseGenerator;

		public FreezingPerceptionEffect(ICoreClientAPI capi)
			: base(capi)
		{
			noiseGenerator = NormalizedSimplexNoise.FromDefaultOctaves(4, 1.0, 0.9, 123L);
		}

		public override void OnBeforeGameRender(float dt)
		{
			if (!capi.IsGamePaused)
			{
				HandleFreezingEffects(Math.Min(dt, 1f));
			}
		}

		private void HandleFreezingEffects(float dt)
		{
			float num = capi.World.Player.Entity.WatchedAttributes.GetFloat("freezingEffectStrength");
			currentStrength += (num - currentStrength) * dt;
			ApplyFrostVignette(currentStrength);
			if ((double)currentStrength > 0.1 && capi.World.Player.CameraMode == EnumCameraMode.FirstPerson)
			{
				ApplyMotionEffects(currentStrength);
			}
		}

		private void ApplyFrostVignette(float strength)
		{
			capi.Render.ShaderUniforms.FrostVignetting = strength;
		}

		private void ApplyMotionEffects(float strength)
		{
			float num = (float)capi.InWorldEllapsedMilliseconds / 1000f;
			capi.Input.MouseYaw += capi.Settings.Float["cameraShakeStrength"] * (float)(Math.Max(0.0, noiseGenerator.Noise(num, 12.0) - 0.4000000059604645) * Math.Sin(num * 90f) * 0.01) * GameMath.Clamp(strength * 3f, 0f, 1f);
		}
	}
	public abstract class PerceptionEffect
	{
		public string Code;

		public int PerceptionEffectId;

		public float Intensity;

		public double DurationHours;

		protected ICoreClientAPI capi;

		public PerceptionEffect(ICoreClientAPI capi)
		{
			this.capi = capi;
		}

		public virtual void OnBeforeGameRender(float dt)
		{
			if (PerceptionEffectId > 0)
			{
				capi.Render.ShaderUniforms.PerceptionEffectId = PerceptionEffectId;
				capi.Render.ShaderUniforms.PerceptionEffectIntensity = Intensity;
			}
		}

		public virtual void OnOwnPlayerDataReceived(EntityPlayer eplr)
		{
		}

		public virtual void ApplyToFpHand(Matrixf modelMat)
		{
		}

		public virtual void ApplyToTpPlayer(EntityPlayer entityPlr, float[] modelMatrix, float? playerIntensity = null)
		{
		}

		public virtual void NowDisabled()
		{
		}

		public virtual void NowActive(float intensity)
		{
			Intensity = intensity;
		}
	}
	public class PerceptionEffects
	{
		private ICoreClientAPI capi;

		private int nextPerceptionEffectId = 1;

		private Dictionary<string, PerceptionEffect> registeredPerceptionEffects = new Dictionary<string, PerceptionEffect>();

		private Dictionary<string, PerceptionEffect> activePerceptionEffects = new Dictionary<string, PerceptionEffect>();

		public ICollection<string> RegisteredEffects => registeredPerceptionEffects.Keys;

		public PerceptionEffects(ICoreClientAPI capi)
		{
			this.capi = capi;
			RegisterPerceptionEffect(new DamagedPerceptionEffect(capi), "damaged");
			RegisterPerceptionEffect(new FreezingPerceptionEffect(capi), "freezing");
			RegisterPerceptionEffect(new DrunkPerceptionEffect(capi), "drunk");
		}

		public void RegisterPerceptionEffect(PerceptionEffect effect, string code)
		{
			effect.PerceptionEffectId = nextPerceptionEffectId++;
			effect.Code = code;
			registeredPerceptionEffects[code] = effect;
		}

		public void TriggerEffect(string code, float intensity, bool? on = null)
		{
			if ((!on.HasValue) ? (!activePerceptionEffects.ContainsKey(code)) : on.Value)
			{
				activePerceptionEffects[code] = registeredPerceptionEffects[code];
				activePerceptionEffects[code].NowActive(intensity);
			}
			else if (activePerceptionEffects.ContainsKey(code))
			{
				activePerceptionEffects[code].NowDisabled();
				activePerceptionEffects.Remove(code);
				capi.Render.ShaderUniforms.PerceptionEffectId = 0;
			}
		}

		public void OnBeforeGameRender(float dt)
		{
			foreach (KeyValuePair<string, PerceptionEffect> activePerceptionEffect in activePerceptionEffects)
			{
				activePerceptionEffect.Value.OnBeforeGameRender(dt);
			}
		}

		public void OnOwnPlayerDataReceived(EntityPlayer eplr)
		{
			TriggerEffect("damaged", 1f, true);
			TriggerEffect("freezing", 1f, true);
			TriggerEffect("drunk", 0f, true);
			foreach (KeyValuePair<string, PerceptionEffect> activePerceptionEffect in activePerceptionEffects)
			{
				activePerceptionEffect.Value.OnOwnPlayerDataReceived(eplr);
			}
		}

		public void ApplyToFpHand(Matrixf modelMat)
		{
			foreach (KeyValuePair<string, PerceptionEffect> activePerceptionEffect in activePerceptionEffects)
			{
				activePerceptionEffect.Value.ApplyToFpHand(modelMat);
			}
		}

		public void ApplyToTpPlayer(EntityPlayer entityPlr, float[] modelMatrix, float? playerIntensity = null)
		{
			foreach (KeyValuePair<string, PerceptionEffect> activePerceptionEffect in activePerceptionEffects)
			{
				activePerceptionEffect.Value.ApplyToTpPlayer(entityPlr, modelMatrix, playerIntensity);
			}
		}
	}
