	public interface ITexPositionSource
	{
		TextureAtlasPosition this[string textureCode] { get; }

		Size2i AtlasSize { get; }
	}
	public class ContainedTextureSource : ITexPositionSource
	{
		private ITextureAtlasAPI targetAtlas;

		private ICoreClientAPI capi;

		public Dictionary<string, AssetLocation> Textures = new Dictionary<string, AssetLocation>();

		private string sourceForErrorLogging;

		public Size2i AtlasSize => targetAtlas.Size;

		public TextureAtlasPosition this[string textureCode] => getOrCreateTexPos(Textures[textureCode]);

		public ContainedTextureSource(ICoreClientAPI capi, ITextureAtlasAPI targetAtlas, Dictionary<string, AssetLocation> textures, string sourceForErrorLogging)
		{
			this.capi = capi;
			this.targetAtlas = targetAtlas;
			Textures = textures;
			this.sourceForErrorLogging = sourceForErrorLogging;
		}

		protected TextureAtlasPosition getOrCreateTexPos(AssetLocation texturePath)
		{
			TextureAtlasPosition texPos = targetAtlas[texturePath];
			if (texPos == null)
			{
				IAsset texAsset = capi.Assets.TryGet(texturePath.Clone().WithPathPrefixOnce("textures/").WithPathAppendixOnce(".png"));
				if (texAsset != null)
				{
					targetAtlas.GetOrInsertTexture(texturePath, out var _, out texPos, () => texAsset.ToBitmap(capi));
					if (texPos == null)
					{
						capi.World.Logger.Error("{0}, require texture {1} which exists, but unable to upload it or allocate space", sourceForErrorLogging, texturePath);
						texPos = targetAtlas.UnknownTexturePosition;
					}
				}
				else
				{
					capi.World.Logger.Error("{0}, require texture {1}, but no such texture found.", sourceForErrorLogging, texturePath);
					texPos = targetAtlas.UnknownTexturePosition;
				}
			}
			return texPos;
		}
	}
	public class LoadedTexture : IDisposable
	{
		public int TextureId;

		public int Width;

		public int Height;

		protected bool disposed;

		protected string trace;

		protected ICoreClientAPI capi;

		public bool Disposed => disposed;

		public bool IgnoreUndisposed { get; set; }

		public LoadedTexture(ICoreClientAPI capi)
		{
			this.capi = capi;
			if (RuntimeEnv.DebugTextureDispose)
			{
				trace = Environment.StackTrace;
			}
		}

		public LoadedTexture(ICoreClientAPI capi, int textureId, int width, int height)
		{
			this.capi = capi;
			TextureId = textureId;
			Width = width;
			Height = height;
			if (RuntimeEnv.DebugTextureDispose)
			{
				trace = Environment.StackTrace;
			}
		}

		public virtual void Dispose()
		{
			disposed = true;
			if (TextureId != 0)
			{
				capi.Gui.DeleteTexture(TextureId);
				TextureId = 0;
			}
		}

		~LoadedTexture()
		{
			if (IgnoreUndisposed || (TextureId == 0 || disposed))
			{
				return;
			}
			ICoreClientAPI coreClientAPI = capi;
			if (coreClientAPI == null || !coreClientAPI.IsShuttingDown)
			{
				if (trace == null)
				{
					capi?.Logger.Debug("Texture with texture id {0} is leaking memory, missing call to Dispose. Set env var TEXTURE_DEBUG_DISPOSE to get allocation trace.", TextureId);
				}
				else
				{
					capi?.Logger.Debug("Texture with texture id {0} is leaking memory, missing call to Dispose. Allocated at {1}.", TextureId, trace);
				}
			}
		}
	}
	public delegate ITexPositionSource TextureSourceBuilder(Shape shape, string name);
	public delegate string TexturePathUpdater(string path);
	public class ShapeTextureSource : ITexPositionSource
	{
		private ICoreClientAPI capi;

		private Shape shape;

		private string filenameForLogging;

		public Dictionary<string, CompositeTexture> textures = new Dictionary<string, CompositeTexture>();

		public TextureAtlasPosition? firstTexPos;

		private HashSet<AssetLocation> missingTextures = new HashSet<AssetLocation>();

		public TextureAtlasPosition this[string textureCode]
		{
			get
			{
				int textureSubId;
				TextureAtlasPosition texPos;
				if (textures.TryGetValue(textureCode, out CompositeTexture value))
				{
					capi.BlockTextureAtlas.GetOrInsertTexture(value, out textureSubId, out texPos);
				}
				else
				{
					shape.Textures.TryGetValue(textureCode, out var value2);
					if (value2 == null)
					{
						if (!missingTextures.Contains(value2))
						{
							capi.Logger.Warning("Shape {0} has an element using texture code {1}, but no such texture exists", filenameForLogging, textureCode);
							missingTextures.Add(value2);
						}
						return capi.BlockTextureAtlas.UnknownTexturePosition;
					}
					capi.BlockTextureAtlas.GetOrInsertTexture(value2, out textureSubId, out texPos);
				}
				if (texPos == null)
				{
					return capi.BlockTextureAtlas.UnknownTexturePosition;
				}
				if (firstTexPos == null)
				{
					firstTexPos = texPos;
				}
				return texPos;
			}
		}

		public Size2i AtlasSize => capi.BlockTextureAtlas.Size;

		public ShapeTextureSource(ICoreClientAPI capi, Shape shape, string filenameForLogging)
		{
			this.capi = capi;
			this.shape = shape;
			this.filenameForLogging = filenameForLogging;
		}

		public ShapeTextureSource(ICoreClientAPI capi, Shape shape, string filenameForLogging, IDictionary<string, CompositeTexture> texturesSource, TexturePathUpdater pathUpdater)
			: this(capi, shape, filenameForLogging)
		{
			foreach (KeyValuePair<string, CompositeTexture> item in texturesSource)
			{
				CompositeTexture compositeTexture = item.Value.Clone();
				compositeTexture.Base.Path = pathUpdater(compositeTexture.Base.Path);
				compositeTexture.Bake(capi.Assets);
				textures[item.Key] = compositeTexture;
			}
		}
	}
