		public virtual bool IsInRangeOf(Vec3d pos)
		{
			Vec3d pos2 = capi.World.Player.Entity.Pos.XYZ.Add(capi.World.Player.Entity.LocalEyePos);
			return (double)pos.DistanceTo(pos2) <= (double)capi.World.Player.WorldData.PickingRange + 0.5;
		}

		public EnumPosFlag GetFreePos(string code)
		{
			Array values = Enum.GetValues(typeof(EnumPosFlag));
			posFlagDict().TryGetValue(code, out var value);
			foreach (EnumPosFlag item in values)
			{
				if ((int)((uint)value & (uint)item) <= 0)
				{
					return item;
				}
			}
			return (EnumPosFlag)0;
		}

		public void OccupyPos(string code, EnumPosFlag pos)
		{
			posFlagDict().TryGetValue(code, out var value);
			posFlagDict()[code] = value | (int)pos;
		}

		public void FreePos(string code, EnumPosFlag pos)
		{
			posFlagDict().TryGetValue(code, out var value);
			posFlagDict()[code] = value & (int)(~pos);
		}

		private Dictionary<string, int> posFlagDict()
		{
			capi.ObjectCache.TryGetValue("dialogCount", out var value);
			Dictionary<string, int> dictionary = value as Dictionary<string, int>;
			if (dictionary == null)
			{
				dictionary = (Dictionary<string, int>)(capi.ObjectCache["dialogCount"] = new Dictionary<string, int>());
			}
			return dictionary;
		}

		protected bool IsRight(EnumPosFlag flag)
		{
			if (flag != EnumPosFlag.RightBot && flag != EnumPosFlag.RightMid && flag != EnumPosFlag.RightTop && flag != EnumPosFlag.Right2Top && flag != EnumPosFlag.Right2Mid && flag != EnumPosFlag.Right2Bot && flag != EnumPosFlag.Right3Top && flag != EnumPosFlag.Right3Mid)
			{
				return flag == EnumPosFlag.Right3Bot;
			}
			return true;
		}

		protected float YOffsetMul(EnumPosFlag flag)
		{
			switch (flag)
			{
			case EnumPosFlag.RightTop:
			case EnumPosFlag.LeftTop:
			case EnumPosFlag.Right2Top:
			case EnumPosFlag.Left2Top:
			case EnumPosFlag.Right3Top:
			case EnumPosFlag.Left3Top:
				return -1f;
			case EnumPosFlag.RightBot:
			case EnumPosFlag.LeftBot:
			case EnumPosFlag.Right2Bot:
			case EnumPosFlag.Left2Bot:
			case EnumPosFlag.Right3Bot:
			case EnumPosFlag.Left3Bot:
				return 1f;
			default:
				return 0f;
			}
		}

		protected float XOffsetMul(EnumPosFlag flag)
		{
			switch (flag)
			{
			case EnumPosFlag.Right2Mid:
			case EnumPosFlag.Right2Top:
			case EnumPosFlag.Right2Bot:
				return -1f;
			case EnumPosFlag.Left2Mid:
			case EnumPosFlag.Left2Top:
			case EnumPosFlag.Left2Bot:
				return 1f;
			case EnumPosFlag.Right3Mid:
			case EnumPosFlag.Right3Top:
			case EnumPosFlag.Right3Bot:
				return -2f;
			case EnumPosFlag.Left3Mid:
			case EnumPosFlag.Left3Top:
			case EnumPosFlag.Left3Bot:
				return 2f;
			default:
				return 0f;
			}
		}
	}
	public abstract class GuiDialogBlockEntity : GuiDialogGeneric
	{
		public bool IsDuplicate { get; }

		public InventoryBase Inventory { get; }

		public BlockPos BlockEntityPosition { get; }

		public virtual AssetLocation OpenSound { get; set; }

		public virtual AssetLocation CloseSound { get; set; }

		protected virtual double FloatyDialogPosition => 0.75;

		protected virtual double FloatyDialogAlign => 0.75;

		public override bool PrefersUngrabbedMouse => false;

		public GuiDialogBlockEntity(string dialogTitle, InventoryBase inventory, BlockPos blockEntityPos, ICoreClientAPI capi)
			: base(dialogTitle, capi)
		{
			IsDuplicate = capi.World.Player.InventoryManager.Inventories.ContainsValue(inventory);
			if (!IsDuplicate)
			{
				Inventory = inventory;
				BlockEntityPosition = blockEntityPos;
			}
		}

		public GuiDialogBlockEntity(string dialogTitle, BlockPos blockEntityPos, ICoreClientAPI capi)
			: base(dialogTitle, capi)
		{
			IsDuplicate = capi.OpenedGuis.FirstOrDefault((object dlg) => (dlg as GuiDialogBlockEntity)?.BlockEntityPosition == blockEntityPos) != null;
			if (!IsDuplicate)
			{
				BlockEntityPosition = blockEntityPos;
			}
		}

		public override void OnFinalizeFrame(float dt)
		{
			base.OnFinalizeFrame(dt);
			if (!IsInRangeOfBlock(BlockEntityPosition))
			{
				capi.Event.EnqueueMainThreadTask(delegate
				{
					TryClose();
				}, "closedlg");
			}
		}

		public override void OnRenderGUI(float deltaTime)
		{
			if (capi.Settings.Bool["immersiveMouseMode"])
			{
				Vec3d vec3d = MatrixToolsd.Project(new Vec3d((double)BlockEntityPosition.X + 0.5, (double)BlockEntityPosition.Y + FloatyDialogPosition, (double)BlockEntityPosition.Z + 0.5), capi.Render.PerspectiveProjectionMat, capi.Render.PerspectiveViewMat, capi.Render.FrameWidth, capi.Render.FrameHeight);
				if (vec3d.Z < 0.0)
				{
					return;
				}
				base.SingleComposer.Bounds.Alignment = EnumDialogArea.None;
				base.SingleComposer.Bounds.fixedOffsetX = 0.0;
				base.SingleComposer.Bounds.fixedOffsetY = 0.0;
				base.SingleComposer.Bounds.absFixedX = vec3d.X - base.SingleComposer.Bounds.OuterWidth / 2.0;
				base.SingleComposer.Bounds.absFixedY = (double)capi.Render.FrameHeight - vec3d.Y - base.SingleComposer.Bounds.OuterHeight * FloatyDialogAlign;
				base.SingleComposer.Bounds.absMarginX = 0.0;
				base.SingleComposer.Bounds.absMarginY = 0.0;
			}
			base.OnRenderGUI(deltaTime);
		}

		protected void DoSendPacket(object p)
		{
			capi.Network.SendBlockEntityPacket(BlockEntityPosition.X, BlockEntityPosition.InternalY, BlockEntityPosition.Z, p);
		}

		protected void OnNewScrollbarvalue(float value)
		{
			ElementBounds bounds = base.SingleComposer.GetSlotGrid("slotgrid").Bounds;
			bounds.fixedY = 10.0 - GuiElementItemSlotGridBase.unscaledSlotPadding - (double)value;
			bounds.CalcWorldBounds();
		}

		protected void CloseIconPressed()
		{
			TryClose();
		}

		public override void OnGuiOpened()
		{
			if (Inventory != null)
			{
				capi.World.Player.InventoryManager.OpenInventory(Inventory);
			}
			capi.Gui.PlaySound(OpenSound, randomizePitch: true);
		}

		public override bool TryOpen()
		{
			if (IsDuplicate)
			{
				return false;
			}
			return base.TryOpen();
		}

		public override void OnGuiClosed()
		{
			if (Inventory != null)
			{
				capi.World.Player.InventoryManager.CloseInventoryAndSync(Inventory);
			}
			capi.Network.SendBlockEntityPacket(BlockEntityPosition, 1001);
			capi.Gui.PlaySound(CloseSound, randomizePitch: true);
		}

		public void ReloadValues()
		{
		}
	}
	public enum EnumBlockEntityPacketId
	{
		Open = 1000,
		Close
	}
	public class GuiDialogBlockEntityInventory : GuiDialogBlockEntity
	{
		private int cols;

		private EnumPosFlag screenPos;

		public override double DrawOrder => 0.2;

		public GuiDialogBlockEntityInventory(string dialogTitle, InventoryBase inventory, BlockPos blockEntityPos, int cols, ICoreClientAPI capi)
			: base(dialogTitle, inventory, blockEntityPos, capi)
		{
			if (base.IsDuplicate)
			{
				return;
			}
			this.cols = cols;
			double elementToDialogPadding = GuiStyle.ElementToDialogPadding;
			double unscaledSlotPadding = GuiElementItemSlotGridBase.unscaledSlotPadding;
			int num = (int)Math.Ceiling((float)inventory.Count / (float)cols);
			int num2 = Math.Min(num, 7);
			ElementBounds elementBounds = ElementStdBounds.SlotGrid(EnumDialogArea.None, unscaledSlotPadding, unscaledSlotPadding, cols, num2);
			ElementBounds elementBounds2 = ElementStdBounds.SlotGrid(EnumDialogArea.None, 0.0, 0.0, cols, num);
			ElementBounds elementBounds3 = elementBounds.ForkBoundingParent(6.0, 6.0, 6.0, 6.0);
			screenPos = GetFreePos("smallblockgui");
			if (num2 < num)
			{
				ElementBounds elementBounds4 = elementBounds.CopyOffsetedSibling();
				elementBounds4.fixedHeight -= 3.0;
				ElementBounds elementBounds5 = elementBounds3.ForkBoundingParent(elementToDialogPadding, elementToDialogPadding + 30.0, elementToDialogPadding + 20.0, elementToDialogPadding).WithFixedAlignmentOffset(IsRight(screenPos) ? (0.0 - GuiStyle.DialogToScreenPadding) : GuiStyle.DialogToScreenPadding, 0.0).WithAlignment(IsRight(screenPos) ? EnumDialogArea.RightMiddle : EnumDialogArea.LeftMiddle);
				if (!capi.Settings.Bool["immersiveMouseMode"])
				{
					elementBounds5.fixedOffsetY += (elementBounds5.fixedHeight + 10.0) * (double)YOffsetMul(screenPos);
					elementBounds5.fixedOffsetX += (elementBounds5.fixedWidth + 10.0) * (double)XOffsetMul(screenPos);
				}
				ElementBounds bounds = ElementStdBounds.VerticalScrollbar(elementBounds3).WithParent(elementBounds5);
				base.SingleComposer = capi.Gui.CreateCompo("blockentityinventory" + blockEntityPos, elementBounds5).AddShadedDialogBG(ElementBounds.Fill).AddDialogTitleBar(dialogTitle, base.CloseIconPressed)
					.AddInset(elementBounds3)
					.AddVerticalScrollbar(base.OnNewScrollbarvalue, bounds, "scrollbar")
					.BeginClip(elementBounds4)
					.AddItemSlotGrid(inventory, base.DoSendPacket, cols, elementBounds2, "slotgrid")
					.EndClip()
					.Compose();
