		public virtual bool IsPositionInside(int posX, int posY)
		{
			if (Bounds.PointInside(posX, posY))
			{
				if (InsideClipBounds != null)
				{
					return InsideClipBounds.PointInside(posX, posY);
				}
				return true;
			}
			return false;
		}

