			{
				ctx.NewPath();
				ctx.SetSourceRGBA(0.0, 0.0, 0.0, 0.5);
				double num10 = Bounds.InnerWidth * (double)i / (double)num9;
				ctx.MoveTo(num10, 0.0);
				ctx.LineTo(num10, Math.Max(3.0, Bounds.InnerHeight - 1.0));
