			RenderTextSelection();
			api.Render.Render2DTexturePremultipliedAlpha(textTexture.TextureId, Bounds);
			base.RenderInteractiveElements(deltaTime);
		}

		public override void Dispose()
		{
			base.Dispose();
			highlightTexture.Dispose();
		}

