			bool flag = false;
			while (!flag)
			{
				flag = true;
				int count = queue.Count;
				while (count-- > 0)
				{
					GridRecipe gridRecipe = queue.Dequeue();
					Dictionary<int, ItemStack[]> dictionary = null;
					bool flag2 = true;
					for (int l = 0; l < gridRecipe.resolvedIngredients.Length; l++)
					{
