							Recipe = gridRecipe,
							unnamedIngredients = dictionary
						});
					}
				}
			}
			resolveCache.Clear();
			GridRecipesAndUnIn = list.ToArray();
			GridRecipesAndUnIn.Shuffle(rand);
			bool flag3 = false;
			for (int num2 = 0; num2 < GridRecipesAndUnIn.Length; num2++)
