			this.onStackClicked = onStackClicked;
		}

		public SlideshowItemstackTextComponent(ICoreClientAPI capi, ItemStack itemstackgroup, List<ItemStack> allstacks, double unscaleSize, EnumFloat floatType, Action<ItemStack> onStackClicked = null)
			: base(capi)
		{
			initSlot();
			this.onStackClicked = onStackClicked;
			unscaledSize = unscaleSize;
			string[] array = itemstackgroup.Collectible.Attributes?["handbook"]?["groupBy"]?.AsArray<string>();
			List<ItemStack> list = new List<ItemStack>();
			List<ItemStack> list2 = new List<ItemStack>();
			list.Add(itemstackgroup);
			list2.Add(itemstackgroup);
			if (allstacks != null)
			{
				if (array != null)
				{
					AssetLocation[] array2 = new AssetLocation[array.Length];
					for (int i = 0; i < array.Length; i++)
					{
						if (!array[i].Contains(":"))
						{
							array2[i] = new AssetLocation(itemstackgroup.Collectible.Code.Domain, array[i]);
						}
						else
						{
							array2[i] = new AssetLocation(array[i]);
						}
					}
					foreach (ItemStack allstack in allstacks)
					{
						JsonObject attributes = allstack.Collectible.Attributes;
						if (attributes != null && attributes["handbook"]?["isDuplicate"].AsBool() == true)
						{
							list.Add(allstack);
							continue;
						}
						for (int j = 0; j < array2.Length; j++)
						{
							if (allstack.Collectible.WildCardMatch(array2[j]))
							{
								list2.Add(allstack);
								list.Add(allstack);
								break;
							}
						}
					}
				}
				foreach (ItemStack item in list)
				{
					allstacks.Remove(item);
				}
			}
			Itemstacks = list2.ToArray();
			Float = floatType;
			BoundsPerLine = new LineRectangled[1]
			{
				new LineRectangled(0.0, 0.0, GuiElement.scaled(unscaleSize), GuiElement.scaled(unscaleSize))
			};
		}

		private void initSlot()
		{
			dummyInv = new DummyInventory(capi);
			dummyInv.OnAcquireTransitionSpeed += (EnumTransitionType transType, ItemStack stack, float mul) => 0f;
			slot = new DummySlot(null, dummyInv);
		}

		public override EnumCalcBoundsResult CalcBounds(TextFlowPath[] flowPath, double currentLineHeight, double offsetX, double lineY, out double nextOffsetX)
		{
			TextFlowPath currentFlowPathSection = GetCurrentFlowPathSection(flowPath, lineY);
			offsetX += GuiElement.scaled(PaddingLeft);
			bool flag = offsetX + BoundsPerLine[0].Width > currentFlowPathSection.X2;
			BoundsPerLine[0].X = (flag ? 0.0 : offsetX);
			BoundsPerLine[0].Y = lineY + (flag ? currentLineHeight : 0.0);
			BoundsPerLine[0].Width = GuiElement.scaled(unscaledSize) + GuiElement.scaled(PaddingRight);
			nextOffsetX = (flag ? 0.0 : offsetX) + BoundsPerLine[0].Width;
			if (!flag)
			{
				return EnumCalcBoundsResult.Continue;
			}
			return EnumCalcBoundsResult.Nextline;
		}

		public override void ComposeElements(Context ctx, ImageSurface surface)
		{
			if (Background)
			{
				ctx.SetSourceRGBA(1.0, 1.0, 1.0, 0.2);
				ctx.Rectangle(BoundsPerLine[0].X, BoundsPerLine[0].Y, BoundsPerLine[0].Width, BoundsPerLine[0].Height);
				ctx.Fill();
			}
		}

		protected override string OnRequireInfoText(ItemSlot slot)
		{
			return base.OnRequireInfoText(slot) + ExtraTooltipText;
		}

		public override void RenderInteractiveElements(float deltaTime, double renderX, double renderY, double renderZ)
		{
			int num = (int)((double)api.Input.MouseX - renderX + (double)renderOffset.X);
			int num2 = (int)((double)api.Input.MouseY - renderY + (double)renderOffset.Y);
			LineRectangled lineRectangled = BoundsPerLine[0];
			bool num3 = lineRectangled.PointInside(num, num2);
			ItemStack itemstack = Itemstacks[curItemIndex];
			if (!num3 && (secondsVisible -= deltaTime) <= 0f)
			{
				secondsVisible = 1f;
				curItemIndex = (curItemIndex + 1) % Itemstacks.Length;
			}
			if (overrideCurrentItemStack != null)
			{
				itemstack = overrideCurrentItemStack();
			}
			slot.Itemstack = itemstack;
			ElementBounds elementBounds = ElementBounds.FixedSize((int)(lineRectangled.Width / (double)RuntimeEnv.GUIScale), (int)(lineRectangled.Height / (double)RuntimeEnv.GUIScale));
			elementBounds.ParentBounds = capi.Gui.WindowBounds;
			elementBounds.CalcWorldBounds();
			elementBounds.absFixedX = renderX + lineRectangled.X + (double)renderOffset.X;
			elementBounds.absFixedY = renderY + lineRectangled.Y + (double)renderOffset.Y;
			elementBounds.absInnerWidth *= renderSize / 0.58f;
			elementBounds.absInnerHeight *= renderSize / 0.58f;
			api.Render.PushScissor(elementBounds, stacking: true);
			api.Render.RenderItemstackToGui(slot, renderX + lineRectangled.X + lineRectangled.Width * 0.5 + (double)renderOffset.X + offX, renderY + lineRectangled.Y + lineRectangled.Height * 0.5 + (double)renderOffset.Y + offY, 100f + renderOffset.Z, (float)lineRectangled.Width * renderSize, -1, shading: true, rotate: false, ShowStackSize);
			api.Render.PopScissor();
			if (num3 && ShowTooltip)
			{
				RenderItemstackTooltip(slot, renderX + (double)num, renderY + (double)num2, deltaTime);
			}
		}

		public override void OnMouseDown(MouseEvent args)
		{
			if (slot.Itemstack == null)
			{
				return;
			}
			LineRectangled[] boundsPerLine = BoundsPerLine;
			for (int i = 0; i < boundsPerLine.Length; i++)
			{
				if (boundsPerLine[i].PointInside(args.X, args.Y))
				{
					onStackClicked?.Invoke(slot.Itemstack);
				}
			}
		}
	}
	public class LinkTextComponent : RichTextComponent
	{
		private Action<LinkTextComponent> onLinkClicked;

		public string Href;

		private bool clickable = true;

		private LoadedTexture normalText;

		private LoadedTexture hoverText;

		private double leftMostX;

		private double topMostY;

		private bool isHover;

		private bool wasMouseDown;

		public bool Clickable
		{
			get
			{
				return clickable;
			}
			set
			{
				clickable = value;
				base.MouseOverCursor = (clickable ? "linkselect" : null);
			}
		}

		public LinkTextComponent(string href)
			: base(null, "", null)
		{
			Href = href;
		}

		public LinkTextComponent(ICoreClientAPI api, string displayText, CairoFont font, Action<LinkTextComponent> onLinkClicked)
			: base(api, displayText, font)
		{
			this.onLinkClicked = onLinkClicked;
			base.MouseOverCursor = "linkselect";
			Font = Font.Clone().WithColor(GuiStyle.ActiveButtonTextColor);
			hoverText = new LoadedTexture(api);
			normalText = new LoadedTexture(api);
		}

		public override EnumCalcBoundsResult CalcBounds(TextFlowPath[] flowPath, double currentLineHeight, double offsetX, double lineY, out double nextOffsetX)
		{
			return base.CalcBounds(flowPath, currentLineHeight, offsetX, lineY, out nextOffsetX);
		}

		public override void ComposeElements(Context ctxStatic, ImageSurface surfaceStatic)
		{
			//IL_00e7: Unknown result type (might be due to invalid IL or missing references)
			//IL_00ed: Expected O, but got Unknown
			//IL_00ee: Unknown result type (might be due to invalid IL or missing references)
			//IL_00f4: Expected O, but got Unknown
			leftMostX = 999999.0;
			topMostY = 999999.0;
			double num = 0.0;
			double num2 = 0.0;
			for (int i = 0; i < Lines.Length; i++)
			{
				TextLine textLine = Lines[i];
				leftMostX = Math.Min(leftMostX, textLine.Bounds.X);
				topMostY = Math.Min(topMostY, textLine.Bounds.Y);
				num = Math.Max(num, textLine.Bounds.X + textLine.Bounds.Width);
				num2 = Math.Max(num2, textLine.Bounds.Y + textLine.Bounds.Height);
			}
			ImageSurface val = new ImageSurface((Format)0, (int)(num - leftMostX), (int)(num2 - topMostY));
			Context val2 = new Context((Surface)(object)val);
			val2.SetSourceRGBA(0.0, 0.0, 0.0, 0.0);
			val2.Paint();
			val2.Save();
			Matrix matrix = val2.Matrix;
			matrix.Translate((double)(int)(0.0 - leftMostX), (double)(int)(0.0 - topMostY));
			val2.Matrix = matrix;
			CairoFont font = Font;
			ComposeFor(val2, val);
			api.Gui.LoadOrUpdateCairoTexture(val, linearMag: false, ref normalText);
			val2.Operator = (Operator)0;
			val2.SetSourceRGBA(0.0, 0.0, 0.0, 0.0);
			val2.Paint();
			val2.Operator = (Operator)2;
			Font = Font.Clone();
			Font.Color[0] = Math.Min(1.0, Font.Color[0] * 1.2);
			Font.Color[1] = Math.Min(1.0, Font.Color[1] * 1.2);
			Font.Color[2] = Math.Min(1.0, Font.Color[2] * 1.2);
			ComposeFor(val2, val);
			Font = font;
			val2.Restore();
			api.Gui.LoadOrUpdateCairoTexture(val, linearMag: false, ref hoverText);
			((Surface)val).Dispose();
			val2.Dispose();
		}

		private void ComposeFor(Context ctx, ImageSurface surface)
		{
			textUtil.DrawMultilineText(ctx, Font, Lines);
			ctx.LineWidth = 1.0;
			ctx.SetSourceRGBA(Font.Color);
			for (int i = 0; i < Lines.Length; i++)
			{
				TextLine textLine = Lines[i];
				ctx.MoveTo(textLine.Bounds.X, textLine.Bounds.Y + textLine.Bounds.AscentOrHeight + 2.0);
				ctx.LineTo(textLine.Bounds.X + textLine.Bounds.Width, textLine.Bounds.Y + textLine.Bounds.AscentOrHeight + 2.0);
				ctx.Stroke();
			}
		}

		public override void RenderInteractiveElements(float deltaTime, double renderX, double renderY, double renderZ)
		{
			base.RenderInteractiveElements(deltaTime, renderX, renderY, renderZ);
			isHover = false;
			double fontOrientOffsetX = GetFontOrientOffsetX();
			if (clickable)
			{
				LineRectangled[] boundsPerLine = BoundsPerLine;
				for (int i = 0; i < boundsPerLine.Length; i++)
				{
					if (boundsPerLine[i].PointInside((double)api.Input.MouseX - renderX - fontOrientOffsetX, (double)api.Input.MouseY - renderY))
					{
						isHover = true;
						break;
					}
				}
			}
			api.Render.Render2DTexturePremultipliedAlpha(isHover ? hoverText.TextureId : normalText.TextureId, (int)(renderX + leftMostX + fontOrientOffsetX), (int)(renderY + topMostY), hoverText.Width, hoverText.Height, (float)renderZ + 50f);
		}

		public override bool UseMouseOverCursor(ElementBounds richtextBounds)
		{
			return isHover;
		}

		public override void OnMouseDown(MouseEvent args)
		{
			if (!clickable)
			{
				return;
			}
			double fontOrientOffsetX = GetFontOrientOffsetX();
			wasMouseDown = false;
			LineRectangled[] boundsPerLine = BoundsPerLine;
			for (int i = 0; i < boundsPerLine.Length; i++)
			{
				if (boundsPerLine[i].PointInside((double)args.X - fontOrientOffsetX, args.Y))
				{
					wasMouseDown = true;
				}
			}
		}

		public override void OnMouseUp(MouseEvent args)
		{
			if (!clickable || !wasMouseDown)
			{
				return;
			}
			double fontOrientOffsetX = GetFontOrientOffsetX();
			LineRectangled[] boundsPerLine = BoundsPerLine;
			for (int i = 0; i < boundsPerLine.Length; i++)
			{
				if (boundsPerLine[i].PointInside((double)args.X - fontOrientOffsetX, args.Y))
				{
					args.Handled = true;
					Trigger();
				}
			}
		}

		public LinkTextComponent SetHref(string href)
		{
			Href = href;
			return this;
		}

		public void Trigger()
		{
			if (onLinkClicked == null)
			{
				if (Href != null)
				{
					HandleLink();
				}
			}
			else
			{
				onLinkClicked(this);
			}
		}

		public void HandleLink()
		{
			if (Href.StartsWithOrdinal("hotkey://"))
			{
				api.Input.GetHotKeyByCode(Href.Substring("hotkey://".Length))?.Handler?.Invoke(null);
				return;
			}
			string[] array = Href.Split(new string[1] { "://" }, StringSplitOptions.RemoveEmptyEntries);
			if (array.Length != 0 && api.LinkProtocols != null && api.LinkProtocols.ContainsKey(array[0]))
			{
				api.LinkProtocols[array[0]](this);
			}
			else if (array.Length != 0 && array[0].StartsWithOrdinal("http"))
			{
				api.Gui.OpenLink(Href);
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			hoverText?.Dispose();
			normalText?.Dispose();
		}
	}
