	public class ItemRenderInfo
	{
		public MultiTextureMeshRef ModelRef;

		public ModelTransform Transform;

		public bool CullFaces;

		public int TextureId;

		public Size2i TextureSize = new Size2i();

		public float AlphaTest;

		public bool HalfTransparent;

		public bool NormalShaded;

		public bool ApplyColor;

		public LoadedTexture OverlayTexture;

		public float OverlayOpacity;

		public float DamageEffect;

		public ItemSlot InSlot;

		public float dt;

		public void SetRotOverlay(ICoreClientAPI capi, float opacity)
		{
			if (OverlayTexture == null)
			{
				OverlayTexture = new LoadedTexture(capi);
			}
			capi.Render.GetOrLoadTexture(new AssetLocation("textures/gui/rot.png"), ref OverlayTexture);
			OverlayOpacity = opacity;
		}
	}
	public delegate void OnValueSetDelegate(string elementCode, string newValue);
	public delegate string OnValueGetDelegate(string elementCode);
	public enum EnumDialogElementType
	{
		Select,
		Input,
		Slider,
		Switch,
		NumberInput,
		Button,
		Text,
		DynamicSelect
	}
	public enum EnumDialogElementMode
	{
		DropDown,
		Buttons
	}
	public class JsonDialogSettings
	{
		public string Code;

		public EnumDialogArea Alignment;

		public float PosX;

		public float PosY;

		public DialogRow[] Rows;

		public double SizeMultiplier = 1.0;

		public double Padding = 10.0;

		public bool DisableWorldInteract = true;

		public OnValueSetDelegate OnSet;

		public OnValueGetDelegate OnGet;

		public void ToBytes(BinaryWriter writer)
		{
			writer.Write(Code);
			writer.Write((int)Alignment);
			writer.Write(PosX);
			writer.Write(PosY);
			writer.Write(Rows.Length);
			for (int i = 0; i < Rows.Length; i++)
			{
				Rows[i].ToBytes(writer);
			}
			writer.Write(SizeMultiplier);
		}

		public void FromBytes(BinaryReader reader)
		{
			Code = reader.ReadString();
			Alignment = (EnumDialogArea)reader.ReadInt32();
			PosX = reader.ReadSingle();
			PosY = reader.ReadSingle();
			Rows = new DialogRow[reader.ReadInt32()];
			for (int i = 0; i < Rows.Length; i++)
			{
				Rows[i] = new DialogRow();
				Rows[i].FromBytes(reader);
			}
			SizeMultiplier = reader.ReadSingle();
		}
	}
	public class DialogRow
	{
		public DialogElement[] Elements;

		public float BottomPadding = 10f;

		public float TopPadding;

		public DialogRow()
		{
		}

		public DialogRow(params DialogElement[] elements)
		{
			Elements = elements;
		}

		internal void FromBytes(BinaryReader reader)
		{
			Elements = new DialogElement[reader.ReadInt32()];
			for (int i = 0; i < Elements.Length; i++)
			{
				Elements[i] = new DialogElement();
				Elements[i].FromBytes(reader);
			}
			TopPadding = reader.ReadInt16();
			BottomPadding = reader.ReadInt16();
		}

		internal void ToBytes(BinaryWriter writer)
		{
			writer.Write(Elements.Length);
			for (int i = 0; i < Elements.Length; i++)
			{
				Elements[i].ToBytes(writer);
			}
			writer.Write((short)TopPadding);
			writer.Write((short)BottomPadding);
		}
	}
	public class DialogElement
	{
		public string Code;

		public int Width = 150;

		public int Height = 30;

		public int PaddingLeft;

		public EnumDialogElementType Type;

		public EnumDialogElementMode Mode;

		public string Label;

		public string Icon;

		public string Text;

		public string Tooltip;

		public float FontSize = 14f;

		public string[] Icons;

		public string[] Values;

		public string[] Names;

		public string[] Tooltips;

		public int MinValue;

		public int MaxValue;

		public int Step;

		public string Param;

		internal void FromBytes(BinaryReader reader)
		{
			Code = reader.ReadString();
			Width = reader.ReadInt32();
			Height = reader.ReadInt32();
			Type = (EnumDialogElementType)reader.ReadInt32();
			Mode = (EnumDialogElementMode)reader.ReadInt32();
			Label = reader.ReadString();
			Icons = reader.ReadStringArray();
			Values = reader.ReadStringArray();
			Names = reader.ReadStringArray();
			Tooltips = reader.ReadStringArray();
			Param = reader.ReadString();
			MinValue = reader.ReadInt32();
			MaxValue = reader.ReadInt32();
			Step = reader.ReadInt32();
			Icon = reader.ReadString();
			Text = reader.ReadString();
			FontSize = reader.ReadSingle();
		}

		internal void ToBytes(BinaryWriter writer)
		{
			writer.Write(Code);
			writer.Write(Width);
			writer.Write(Height);
			writer.Write((int)Type);
			writer.Write((int)Mode);
			writer.Write(Label);
			writer.WriteArray(Icons);
			writer.WriteArray(Values);
			writer.WriteArray(Names);
			writer.WriteArray(Tooltips);
			writer.Write(Param);
			writer.Write(MinValue);
			writer.Write(MaxValue);
			writer.Write(Step);
			writer.Write(Icon);
			writer.Write(Text);
			writer.Write(FontSize);
		}
	}
	public class TextBackground
	{
		public int HorPadding;

		public int VerPadding;

		public double Radius;

		public double[] FillColor = new double[4];

		public double[] BorderColor = GuiStyle.DialogBorderColor;

		public double BorderWidth;

		public bool Shade;

		public double[] ShadeColor = new double[4]
		{
			GuiStyle.DialogLightBgColor[0] * 1.4,
			GuiStyle.DialogStrongBgColor[1] * 1.4,
			GuiStyle.DialogStrongBgColor[2] * 1.4,
			1.0
		};

		public int Padding
		{
			set
			{
				HorPadding = value;
				VerPadding = value;
			}
		}

		public TextBackground Clone()
		{
			return new TextBackground
			{
				HorPadding = HorPadding,
				VerPadding = VerPadding,
				Radius = Radius,
				FillColor = (double[])FillColor.Clone(),
				BorderColor = (double[])BorderColor.Clone(),
				ShadeColor = (double[])ShadeColor.Clone(),
				Shade = Shade,
				BorderWidth = BorderWidth
			};
		}
	}
	public enum EnumLinebreakBehavior
	{
		Default,
		AfterWord,
		AfterCharacter,
		None
	}
	public class TextFlowPath
	{
		public double X1;

		public double Y1;

		public double X2;

		public double Y2;

		public TextFlowPath()
		{
		}

		public TextFlowPath(double boxWidth)
		{
			X1 = 0.0;
			Y1 = 0.0;
			X2 = boxWidth;
			Y2 = 99999.0;
		}

		public TextFlowPath(double x1, double y1, double x2, double y2)
		{
			X1 = x1;
			Y1 = y1;
			X2 = x2;
			Y2 = y2;
		}
	}
	public class TextLine
	{
		public string Text;

		public LineRectangled Bounds;

		public double LeftSpace;

		public double RightSpace;

		public double NextOffsetX;
	}
	public class LineRectangled : Rectangled
	{
		public double Ascent;

		public double AscentOrHeight
		{
			get
			{
				if (!(Ascent > 0.0))
				{
					return Height;
				}
				return Ascent;
			}
		}

		public LineRectangled(double X, double Y, double width, double height)
			: base(X, Y, width, height)
		{
		}

		public LineRectangled()
		{
		}
	}
	public class TextDrawUtil
	{
		private int caretPos;

		private bool gotLinebreak;

		private bool gotSpace;

		public TextLine[] Lineize(Context ctx, string text, double boxwidth, double lineHeightMultiplier = 1.0, EnumLinebreakBehavior linebreak = EnumLinebreakBehavior.Default, bool keepLinebreakChar = false)
		{
			return Lineize(ctx, text, linebreak, new TextFlowPath[1]
			{
				new TextFlowPath(boxwidth)
			}, 0.0, 0.0, lineHeightMultiplier, keepLinebreakChar);
		}

		public int GetQuantityTextLines(CairoFont font, string text, double boxWidth, EnumLinebreakBehavior linebreak = EnumLinebreakBehavior.Default)
		{
			return GetQuantityTextLines(font, text, linebreak, new TextFlowPath[1]
			{
				new TextFlowPath(boxWidth)
			});
		}

		public double GetMultilineTextHeight(CairoFont font, string text, double boxWidth, EnumLinebreakBehavior linebreak = EnumLinebreakBehavior.Default)
		{
			return (double)GetQuantityTextLines(font, text, boxWidth, linebreak) * GetLineHeight(font);
		}

		public TextLine[] Lineize(CairoFont font, string fulltext, double boxWidth, EnumLinebreakBehavior linebreak = EnumLinebreakBehavior.Default, bool keepLinebreakChar = false)
