			gotLinebreak = false;
			gotSpace = false;
			bool flag = linebreakBh != EnumLinebreakBehavior.None;
			while (caretPos < fulltext.Length)
			{
				char c = fulltext[caretPos];
				caretPos++;
				if (c == ' ' && flag)
				{
					gotSpace = true;
					break;
				}
				switch (c)
				{
				case '\t':
					if (stringBuilder.Length > 0)
					{
						caretPos--;
						break;
					}
					return "  ";
				case '\r':
					gotLinebreak = true;
					if (caretPos <= fulltext.Length - 1 && fulltext[caretPos] == '\n')
					{
						caretPos++;
					}
					break;
				case '\n':
					gotLinebreak = true;
					break;
