	public abstract class ArgumentParserBase : ICommandArgumentParser
	{
		protected string lastErrorMessage;

		protected bool isMandatoryArg;

		protected int argCount = 1;

		protected string argName;

		public string LastErrorMessage => lastErrorMessage;

		public string ArgumentName => argName;

		public bool IsMandatoryArg => isMandatoryArg;

		public bool IsMissing { get; set; }

		public int ArgCount => argCount;

		protected ArgumentParserBase(string argName, bool isMandatoryArg)
		{
			this.argName = argName;
			this.isMandatoryArg = isMandatoryArg;
		}

		public virtual string[] GetValidRange(CmdArgs args)
		{
			return null;
		}

		public abstract object GetValue();

		public abstract void SetValue(object data);

		public virtual string GetSyntax()
		{
			if (!isMandatoryArg)
			{
				return "<i>[" + argName + "]</i>";
			}
			return "<i>&lt;" + argName + "&gt;</i>";
		}

		public virtual string GetSyntaxUnformatted()
		{
			if (!isMandatoryArg)
			{
				return "[" + argName + "]";
			}
			return "&lt;" + argName + "&gt;";
		}

		public virtual string GetSyntaxExplanation(string indent)
		{
			return null;
		}

		public virtual string GetLastError()
		{
			return lastErrorMessage;
		}

		public abstract EnumParseResult TryProcess(TextCommandCallingArgs args, Action<AsyncParseResults> onReady = null);

		protected Dictionary<string, string> parseSubArgs(string strargs)
		{
			Dictionary<string, string> dictionary = new Dictionary<string, string>();
			if (strargs.Length == 0)
			{
				return dictionary;
			}
			StringBuilder stringBuilder = new StringBuilder();
			bool flag = false;
			foreach (char c in strargs)
			{
				switch (c)
				{
				case '[':
					flag = true;
					continue;
				default:
					if (flag)
					{
						stringBuilder.Append(c);
					}
					continue;
				case ']':
					break;
				}
				break;
			}
			string[] array = stringBuilder.ToString().Split(',');
			foreach (string text in array)
			{
				if (text.Length != 0)
				{
					string[] array2 = text.Split('=');
					if (array2.Length < 2)
					{
						lastErrorMessage = "Invalid syntax. Needs to be a key=value pair, only single value found";
						return null;
					}
					dictionary[array2[0].ToLowerInvariant().Trim()] = array2[1].Trim();
				}
			}
			return dictionary;
		}

		public virtual void PreProcess(TextCommandCallingArgs args)
		{
			IsMissing = args.RawArgs.Length == 0;
		}
	}
	public abstract class PositionArgumentParserBase : ArgumentParserBase
	{
		protected PositionArgumentParserBase(string argName, bool isMandatoryArg)
			: base(argName, isMandatoryArg)
		{
		}

		protected EnumParseResult tryGetPositionBySelector(char v, TextCommandCallingArgs args, ref Vec3d pos, ICoreAPI api)
		{
			string text = args.RawArgs.PopWord();
			Dictionary<string, string> dictionary = parseSubArgs(text);
			if (dictionary == null)
			{
				return EnumParseResult.Bad;
			}
			Vec3d pos2 = args.Caller.Pos;
			Entity entity = args.Caller.Entity;
			float? num = null;
			if (dictionary.TryGetValue("range", out var value))
			{
				num = value.ToFloat();
			}
			AssetLocation assetLocation = null;
			if (dictionary.TryGetValue("type", out var value2))
			{
				assetLocation = new AssetLocation(value2);
			}
			dictionary.TryGetValue("name", out var value3);
			bool? flag = null;
			if (dictionary.TryGetValue("alive", out var value4))
			{
				flag = value4.ToBool();
			}
			if (num.HasValue && pos2 == null)
			{
				lastErrorMessage = "Can't use range argument without source position";
				return EnumParseResult.Bad;
			}
			switch (v)
			{
			case 'p':
			{
				IPlayer player = null;
				IPlayer[] allOnlinePlayers = api.World.AllOnlinePlayers;
				foreach (IPlayer player2 in allOnlinePlayers)
				{
					if ((num.HasValue && player2.Entity.Pos.DistanceTo(pos2) > (double?)num) || (value3 != null && !WildcardUtil.Match(value3, player2.PlayerName)) || (flag.HasValue && player2.Entity.Alive != flag))
					{
						continue;
					}
					if (player == null)
					{
						player = player2;
						continue;
					}
					if (pos2 == null)
					{
						lastErrorMessage = "Two matching players found. Can't get nearest player without source position";
						return EnumParseResult.Bad;
					}
					if (player.Entity.Pos.DistanceTo(pos2) > player2.Entity.Pos.DistanceTo(pos2))
					{
						player = player2;
					}
				}
				pos = player?.Entity.Pos.XYZ;
				return EnumParseResult.Good;
			}
			case 'e':
			{
				ICollection<Entity> collection = ((api.Side != EnumAppSide.Server) ? (api as ICoreClientAPI).World.LoadedEntities.Values : (api as ICoreServerAPI).World.LoadedEntities.Values);
				Entity entity2 = null;
				if (!num.HasValue && assetLocation == null && !flag.HasValue && value3 == null && !text.Equals("[!]"))
				{
					lastErrorMessage = "No selector defined, use e[!] to select all entities";
					return EnumParseResult.Bad;
				}
				foreach (Entity item in collection)
				{
					if ((num.HasValue && item.Pos.DistanceTo(pos2) > (double?)num) || (assetLocation != null && !WildcardUtil.Match(assetLocation, item.Code)) || (flag.HasValue && item.Alive != flag) || (value3 != null && !WildcardUtil.Match(value3, item.GetName())))
					{
						continue;
					}
					if (entity2 == null)
					{
						entity2 = item;
						continue;
					}
					if (pos2 == null)
					{
						lastErrorMessage = "Two matching entities found. Can't get nearest entity without source position";
						return EnumParseResult.Bad;
					}
					if (entity2.Pos.DistanceTo(pos2) > item.Pos.DistanceTo(pos2))
					{
						entity2 = item;
					}
				}
				pos = entity2?.Pos.XYZ;
				return EnumParseResult.Good;
			}
			case 'l':
				if (!(entity is EntityPlayer entityPlayer))
				{
					lastErrorMessage = "Can't use 'l' without source player";
					return EnumParseResult.Bad;
				}
				if (entityPlayer.Player.CurrentEntitySelection == null && entityPlayer.Player.CurrentBlockSelection == null)
				{
					lastErrorMessage = "Not looking at an entity or block";
					return EnumParseResult.Bad;
				}
				pos = entityPlayer.Player.CurrentEntitySelection?.Entity.Pos.XYZ ?? entityPlayer.Player.CurrentBlockSelection.Position.ToVec3d();
				return EnumParseResult.Good;
			case 's':
				pos = entity.Pos.XYZ;
				return EnumParseResult.Good;
			default:
				lastErrorMessage = "Wrong selector, needs to be p,e,l or s";
				return EnumParseResult.Bad;
			}
		}
	}
	public class UnparsedArg : ArgumentParserBase
	{
		private string[] validRange;

		public UnparsedArg(string argName, params string[] validRange)
			: base(argName, isMandatoryArg: false)
		{
			this.validRange = validRange;
			argCount = -1;
		}

		public override object GetValue()
		{
			return null;
		}

		public override string[] GetValidRange(CmdArgs args)
		{
			return validRange;
		}

		public override void SetValue(object data)
		{
		}

		public override EnumParseResult TryProcess(TextCommandCallingArgs args, Action<AsyncParseResults> onReady = null)
		{
			return EnumParseResult.Good;
		}
	}
	public class StringArgParser : ArgumentParserBase
	{
		private string value;

		public StringArgParser(string argName, bool isMandatoryArg)
			: base(argName, isMandatoryArg)
		{
			argCount = -1;
		}

		public override object GetValue()
		{
			if (!isMandatoryArg && base.IsMissing)
			{
				return null;
			}
			return value;
		}

		public override void SetValue(object data)
		{
			value = (string)data;
		}

		public override void PreProcess(TextCommandCallingArgs args)
		{
			base.PreProcess(args);
			value = null;
		}

		public override EnumParseResult TryProcess(TextCommandCallingArgs args, Action<AsyncParseResults> onReady = null)
		{
			value = args.RawArgs.PopAll();
			return EnumParseResult.Good;
		}
	}
	public class EntityTypeArgParser : ArgumentParserBase
	{
		private ICoreAPI api;

		private EntityProperties type;

		public EntityTypeArgParser(string argName, ICoreAPI api, bool isMandatoryArg)
			: base(argName, isMandatoryArg)
		{
			this.api = api;
		}

		public override string GetSyntaxExplanation(string indent)
		{
			return indent + GetSyntax() + " is one of the registered entityTypes";
		}

		public override object GetValue()
		{
			return type;
		}

		public override void PreProcess(TextCommandCallingArgs args)
		{
			base.PreProcess(args);
			type = null;
		}

		public override EnumParseResult TryProcess(TextCommandCallingArgs args, Action<AsyncParseResults> onReady = null)
		{
			string text = args.RawArgs.PopWord();
			if (text == null)
			{
				lastErrorMessage = "Missing";
				return EnumParseResult.Bad;
			}
			type = api.World.GetEntityType(new AssetLocation(text));
			if (type == null)
			{
				lastErrorMessage = "No such entity type exists";
				return EnumParseResult.Bad;
			}
			return EnumParseResult.Good;
		}

		public override string[] GetValidRange(CmdArgs args)
		{
			return api.World.EntityTypes.Select((EntityProperties t) => t.Code.ToShortString()).ToArray();
		}

		public override void SetValue(object data)
		{
			type = (EntityProperties)data;
		}
	}
	public class EntitiesArgParser : ArgumentParserBase
	{
		private Entity[] entities;

		private ICoreAPI api;

		public EntitiesArgParser(string argName, ICoreAPI api, bool isMandatoryArg)
			: base(argName, isMandatoryArg)
		{
			this.api = api;
		}

		public override string GetSyntaxExplanation(string indent)
		{
			return indent + GetSyntax() + " is either a player name, or else one of the following selection codes:\n" + indent + "  s[] for self\n" + indent + "  l[] for the entity currently looked at\n" + indent + "  p[] for all players\n" + indent + "  e[] with filters for entities, or e[!] for all entities.\n" + indent + "  Inside the square brackets, one or more filters can be added, to be more selective. Filters include name, type, class, tag, alive, range. Type can have wildcards. For example, <code>e[type=gazelle*,range=3,alive=true]</code>. The filters minx/miny/minz/maxx/maxy/maxz can also be used to specify a volume to search, coordinates are relative to the command caller's position.\n" + indent + "  This argument may be omitted if the remainder of the command makes sense, in which case it will be interpreted as self.";
		}

		public override object GetValue()
		{
			return entities;
		}

		public override void SetValue(object data)
		{
			entities = (Entity[])data;
		}

		public override void PreProcess(TextCommandCallingArgs args)
		{
			entities = null;
			base.PreProcess(args);
			if (base.IsMissing)
			{
				entities = new Entity[1] { args.Caller.Entity };
			}
		}

		public override EnumParseResult TryProcess(TextCommandCallingArgs args, Action<AsyncParseResults> onReady = null)
		{
			string maybeplayername = args.RawArgs.PeekWord();
			IPlayer player = api.World.AllOnlinePlayers.FirstOrDefault((IPlayer p) => p.PlayerName.Equals(maybeplayername, StringComparison.InvariantCultureIgnoreCase));
			if (player != null)
			{
				args.RawArgs.PopWord();
				entities = new Entity[1] { player.Entity };
				return EnumParseResult.Good;
			}
			string text = maybeplayername;
			char c = ((text != null && text.Length > 0) ? maybeplayername[0] : ' ');
			if (c != 'p' && c != 'e' && c != 'l' && c != 's')
			{
				lastErrorMessage = Lang.Get("Not a player name and not a selector p, e, l or s: {0}'", maybeplayername);
				entities = new Entity[1] { args.Caller.Entity };
				return EnumParseResult.DependsOnSubsequent;
			}
			c = args.RawArgs.PopChar() ?? ' ';
			if (maybeplayername.Equals("e[!]") && c == 'e')
			{
				args.RawArgs.PopWord();
				if (api.Side == EnumAppSide.Server)
				{
					entities = (api as ICoreServerAPI).World.LoadedEntities.Values.ToArray();
				}
				else
				{
					entities = (api as ICoreClientAPI).World.LoadedEntities.Values.ToArray();
				}
				return EnumParseResult.Good;
			}
			Dictionary<string, string> dictionary;
			if (args.RawArgs.PeekChar() == '[')
			{
				string parseErrorMsg;
				string strargs = args.RawArgs.PopCodeBlock('[', ']', out parseErrorMsg);
				if (parseErrorMsg != null)
				{
					lastErrorMessage = parseErrorMsg;
					return EnumParseResult.Bad;
				}
				dictionary = parseSubArgs(strargs);
				if (dictionary == null)
				{
					return EnumParseResult.Bad;
				}
			}
			else
			{
				if (args.RawArgs.PeekChar() != ' ')
				{
					lastErrorMessage = "Invalid selector, needs to be p,e,l,s followed by [";
					return EnumParseResult.Bad;
				}
				args.RawArgs.PopWord();
				dictionary = new Dictionary<string, string>();
			}
			Vec3d sourcePos = args.Caller.Pos;
			Entity entity = args.Caller.Entity;
			if (dictionary.Count == 0 && c == 'e')
			{
				lastErrorMessage = "No selector defined, use e[!] to select all entities";
				return EnumParseResult.Bad;
			}
			float? range = null;
			if (dictionary.TryGetValue("range", out var value))
			{
				range = value.ToFloat();
				dictionary.Remove("range");
			}
			AssetLocation type = null;
			if (dictionary.TryGetValue("type", out var value2))
			{
				type = new AssetLocation(value2);
				dictionary.Remove("type");
			}
			if (dictionary.TryGetValue("class", out var classstr))
			{
				classstr = classstr.ToLowerInvariant();
				dictionary.Remove("class");
			}
			if (dictionary.TryGetValue("tag", out var tagstr))
			{
				tagstr = tagstr.ToLowerInvariant();
				dictionary.Remove("tag");
			}
			if (dictionary.TryGetValue("name", out var name))
			{
				dictionary.Remove("name");
			}
			bool? alive = null;
			if (dictionary.TryGetValue("alive", out var value3))
			{
				alive = value3.ToBool();
				dictionary.Remove("alive");
			}
			long? id = null;
			if (dictionary.TryGetValue("id", out var value4))
			{
				id = value4.ToLong(0L);
				dictionary.Remove("id");
			}
			Cuboidi box = null;
			if (sourcePos != null)
			{
				bool flag = false;
				string[] array = new string[6] { "minx", "miny", "minz", "maxx", "maxy", "maxz" };
				int[] array2 = new int[6];
				for (int num = 0; num < array.Length; num++)
				{
					if (dictionary.TryGetValue(array[num], out var value5))
					{
						array2[num] = value5.ToInt() + num / 3;
						dictionary.Remove(array[num]);
						flag = true;
					}
				}
				if (flag)
				{
					BlockPos asBlockPos = sourcePos.AsBlockPos;
					box = new Cuboidi(array2).Translate(asBlockPos.X, asBlockPos.Y, asBlockPos.Z);
				}
			}
			if (dictionary.Count > 0)
			{
				lastErrorMessage = "Unknown selector '" + string.Join(", ", dictionary.Keys) + "'";
				return EnumParseResult.Bad;
			}
			List<Entity> list = new List<Entity>();
			if (range.HasValue && sourcePos == null)
			{
				lastErrorMessage = "Can't use range argument without source pos";
				return EnumParseResult.Bad;
			}
			switch (c)
			{
			case 'p':
			{
				IPlayer[] allOnlinePlayers = api.World.AllOnlinePlayers;
				foreach (IPlayer player2 in allOnlinePlayers)
				{
					if (entityMatches(player2.Entity, sourcePos, type, classstr, tagstr, range, box, name, alive, id))
					{
						list.Add(player2.Entity);
					}
				}
				entities = list.ToArray();
				return EnumParseResult.Good;
			}
			case 'e':
				if (!range.HasValue)
				{
					ICollection<Entity> collection = ((api.Side != EnumAppSide.Server) ? (api as ICoreClientAPI).World.LoadedEntities.Values : (api as ICoreServerAPI).World.LoadedEntities.Values);
					foreach (Entity item in collection)
					{
						if (entityMatches(item, sourcePos, type, classstr, tagstr, range, box, name, alive, id))
						{
							list.Add(item);
						}
					}
					entities = list.ToArray();
				}
				else
				{
					float num2 = range.Value;
					entities = api.World.GetEntitiesAround(sourcePos, num2, num2, (Entity e) => entityMatches(e, sourcePos, type, classstr, tagstr, range, box, name, alive, id));
				}
				return EnumParseResult.Good;
			case 'l':
			{
				if (!(entity is EntityPlayer entityPlayer))
				{
					lastErrorMessage = "Can't use 'l' without source player";
					return EnumParseResult.Bad;
				}
				if (entityPlayer.Player.CurrentEntitySelection == null)
				{
					lastErrorMessage = "Not looking at an entity";
					return EnumParseResult.Bad;
				}
				Entity entity2 = entityPlayer.Player.CurrentEntitySelection.Entity;
				if (entityMatches(entity2, sourcePos, type, classstr, tagstr, range, box, name, alive, id))
				{
					entities = new Entity[1] { entity2 };
				}
				else
				{
					entities = Array.Empty<Entity>();
				}
				return EnumParseResult.Good;
			}
			case 's':
				if (entityMatches(entity, sourcePos, type, classstr, tagstr, range, box, name, alive, id))
				{
					entities = new Entity[1] { entity };
				}
				else
				{
					entities = Array.Empty<Entity>();
				}
				return EnumParseResult.Good;
			default:
				lastErrorMessage = "Wrong selector, needs to be a player name or p,e,l or s";
				return EnumParseResult.Bad;
			}
		}

		private bool entityMatches(Entity e, Vec3d sourcePos, AssetLocation type, string classstr, string tagstr, float? range, Cuboidi box, string name, bool? alive, long? id)
		{
			if (id.HasValue && e.EntityId != id)
			{
				return false;
			}
			if (range.HasValue && e.SidedPos.DistanceTo(sourcePos) > (double?)range)
			{
				return false;
			}
			if (box != null && !box.ContainsOrTouches(e.SidedPos))
			{
				return false;
			}
			if (classstr != null && classstr != e.Class.ToLowerInvariant())
			{
				return false;
			}
			if (type != null && !WildcardUtil.Match(type, e.Code))
			{
				return false;
			}
			if (alive.HasValue && e.Alive != alive)
			{
				return false;
			}
			if (name != null && !WildcardUtil.Match(name, e.GetName()))
			{
				return false;
			}
			if (tagstr != null && !e.HasTags(tagstr))
			{
				return false;
			}
			return true;
		}
	}
	public class CollectibleArgParser : ArgumentParserBase
	{
		private EnumItemClass itemclass;

		private ICoreAPI api;

		private ItemStack stack;

		public CollectibleArgParser(string argName, ICoreAPI api, EnumItemClass itemclass, bool isMandatoryArg)
			: base(argName, isMandatoryArg)
		{
			this.api = api;
			this.itemclass = itemclass;
		}

		public override string GetSyntaxExplanation(string indent)
		{
			return indent + Lang.Get("{0} is a precise {1} name, optionally immediately followed by braces {{}} containing attributes for the {1}", GetSyntax(), itemclass);
		}

		public override string[] GetValidRange(CmdArgs args)
		{
			string text = args.PeekWord();
			if (text.Length == 0)
			{
				return null;
			}
			if (text.Contains("{"))
			{
				text = text.Split(new string[1] { "{" }, 1, StringSplitOptions.None)[0];
			}
			if (itemclass == EnumItemClass.Block)
			{
				return (from b in api.World.SearchBlocks(new AssetLocation(text))
					select b.Code.ToShortString()).ToArray();
			}
			return (from i in api.World.SearchItems(new AssetLocation(text))
				select i.Code.ToShortString()).ToArray();
		}

		public override object GetValue()
		{
			return stack;
		}

		public override void SetValue(object data)
		{
			stack = (ItemStack)data;
		}

		public override void PreProcess(TextCommandCallingArgs args)
		{
			base.PreProcess(args);
			stack = null;
		}

		public override EnumParseResult TryProcess(TextCommandCallingArgs args, Action<AsyncParseResults> onReady = null)
		{
			string text = args.RawArgs.PeekWord();
			if (text == null)
			{
				lastErrorMessage = "Missing";
				return EnumParseResult.Bad;
			}
			string text2 = null;
			if (text.Contains("{"))
			{
				text = args.RawArgs.PopUntil('{');
				if (text.Length == 0)
				{
					lastErrorMessage = "Missing Item/Block Code";
					return EnumParseResult.Bad;
				}
				text2 = args.RawArgs.PopCodeBlock('{', '}', out var parseErrorMsg);
				if (parseErrorMsg != null)
				{
					lastErrorMessage = parseErrorMsg;
					return EnumParseResult.Bad;
				}
			}
			else
			{
				args.RawArgs.PopWord();
			}
			if (itemclass == EnumItemClass.Block)
			{
				Block block = api.World.GetBlock(new AssetLocation(text));
				if (block == null)
				{
					lastErrorMessage = "No such block exists";
					return EnumParseResult.Bad;
				}
				stack = new ItemStack(block);
			}
			else
			{
				Item item = api.World.GetItem(new AssetLocation(text));
				if (item == null)
				{
					lastErrorMessage = "No such item exists";
					return EnumParseResult.Bad;
				}
				stack = new ItemStack(item);
			}
			if (text2 != null)
			{
				try
				{
					stack.Attributes = JsonObject.FromJson(text2).ToAttribute() as ITreeAttribute;
				}
				catch (Exception ex)
				{
					lastErrorMessage = "Unable to json parse attributes, likely invalid syntax: " + ex.Message;
					return EnumParseResult.Bad;
				}
			}
			return EnumParseResult.Good;
		}
	}
	public class WorldPositionArgParser : PositionArgumentParserBase
	{
		private Vec3d pos;

		private PositionProviderDelegate mapmiddlePosProvider;

		private ICoreAPI api;

		public WorldPositionArgParser(string argName, ICoreAPI api, bool isMandatoryArg)
			: base(argName, isMandatoryArg)
		{
			this.api = api;
			mapmiddlePosProvider = () => new Vec3d(api.World.DefaultSpawnPosition.X, 0.0, api.World.DefaultSpawnPosition.Z);
			argCount = 3;
		}

		public override string GetSyntaxExplanation(string indent)
		{
			return indent + GetSyntax() + " is a world position. A world position can be either 3 coordinates, or a target selector.\n" + indent + "&nbsp;&nbsp;3 coordinates are specified as in the following examples:\n" + indent + "&nbsp;&nbsp;&nbsp;&nbsp;<code>100 150 -180</code> means 100 blocks East and 180 blocks North from the map center, with height 150 blocks\n" + indent + "&nbsp;&nbsp;&nbsp;&nbsp;<code>~-5 ~0 ~4</code> means 5 blocks West and 4 blocks South from the caller's position\n" + indent + "&nbsp;&nbsp;&nbsp;&nbsp;<code>=512100 =150 =511880</code> means the absolute x,y,z position specified (at default settings this is near the map center)\n\n" + indent + "&nbsp;&nbsp;A target selector is either a player's name (meaning that player's current position), or one of: <code>s[]</code> for self, <code>l[]</code> for looked-at entity or block, <code>p[]</code> for players, <code>e[]</code> for entities.\n" + indent + "One or more filters can be specified inside the brackets. For p[] or e[], the target will be the nearest player or entity which passes all the filters.\n" + indent + "Filters include name, type, class, alive, range. Type can use wildcards. For example, <code>e[type=gazelle*,range=3,alive=true]</code>. The filters minx/miny/minz/maxx/maxy/maxz can also be used to specify a volume to search, coordinates are relative to the command caller's position.\n";
		}

		public override string[] GetValidRange(CmdArgs args)
		{
			return null;
		}

		public override object GetValue()
		{
			return pos;
		}

		public override void SetValue(object data)
		{
			pos = (Vec3d)data;
		}

		public override void PreProcess(TextCommandCallingArgs args)
		{
			pos = args.Caller.Pos?.Clone();
			base.PreProcess(args);
		}

		public override EnumParseResult TryProcess(TextCommandCallingArgs args, Action<AsyncParseResults> onReady = null)
		{
			string maybeplayername = args.RawArgs.PeekWord();
			IPlayer player = api.World.AllOnlinePlayers.FirstOrDefault((IPlayer p) => p.PlayerName.Equals(maybeplayername, StringComparison.InvariantCultureIgnoreCase));
			if (player != null)
			{
				args.RawArgs.PopWord();
				pos = player.Entity.Pos.XYZ;
				return EnumParseResult.Good;
			}
			char? c = args.RawArgs.PeekChar();
			if (c == 'p' || c == 'e' || c == 'l' || c == 's')
			{
				args.RawArgs.PopChar();
				return tryGetPositionBySelector(c.Value, args, ref pos, api);
			}
			if (args.RawArgs.Length < 3)
			{
				lastErrorMessage = "World position must be either 3 coordinates or a target selector beginning with p (nearest player), e (nearest entity), l (looked at entity/block) or s (executing entity)";
				return EnumParseResult.Bad;
			}
			pos = args.RawArgs.PopFlexiblePos(args.Caller.Pos, mapmiddlePosProvider());
			if (pos == null)
			{
				lastErrorMessage = Lang.Get("Invalid position, must be 3 numbers");
			}
			if (!(pos == null))
			{
				return EnumParseResult.Good;
			}
			return EnumParseResult.Bad;
		}
	}
	public class WorldPosition2DArgParser : PositionArgumentParserBase
	{
		private Vec2i pos;

		private PositionProviderDelegate mapmiddlePosProvider;

		private ICoreAPI api;

		public WorldPosition2DArgParser(string argName, ICoreAPI api, bool isMandatoryArg)
			: base(argName, isMandatoryArg)
		{
			this.api = api;
			mapmiddlePosProvider = () => api.World.DefaultSpawnPosition.XYZ;
			argCount = 3;
		}

		public override string[] GetValidRange(CmdArgs args)
		{
			return null;
		}

		public override object GetValue()
		{
			return pos;
		}

		public override void SetValue(object data)
		{
			pos = (Vec2i)data;
		}

		public override void PreProcess(TextCommandCallingArgs args)
		{
			pos = posTo2D(args.Caller.Pos?.Clone());
			base.PreProcess(args);
		}

		private Vec2i posTo2D(Vec3d callerPos)
		{
			if (!(callerPos == null))
			{
				return new Vec2i(callerPos);
			}
			return null;
		}

		public override EnumParseResult TryProcess(TextCommandCallingArgs args, Action<AsyncParseResults> onReady = null)
		{
			if (args.RawArgs.Length == 1)
			{
				string maybeplayername = args.RawArgs.PeekWord();
				IPlayer player = api.World.AllOnlinePlayers.FirstOrDefault((IPlayer p) => p.PlayerName.Equals(maybeplayername, StringComparison.InvariantCultureIgnoreCase));
				if (player != null)
				{
					args.RawArgs.PopWord();
					pos = new Vec2i(player.Entity.Pos.XYZ);
					return EnumParseResult.Good;
				}
				char? c = args.RawArgs.PopChar();
				if (c == 'p' || c == 'e' || c == 'l' || c == 's')
				{
					Vec3d callerPos = new Vec3d();
					EnumParseResult result = tryGetPositionBySelector(c.Value, args, ref callerPos, api);
					pos = posTo2D(callerPos);
					return result;
				}
				lastErrorMessage = "World position 2D must be either 2 coordinates or a target selector beginning with p (nearest player), e (nearest entity), l (looked at entity) or s (executing entity)";
				return EnumParseResult.Bad;
			}
			if (args.RawArgs.Length < 2)
			{
				lastErrorMessage = "Need 2 values";
				return EnumParseResult.Good;
			}
			pos = args.RawArgs.PopFlexiblePos2D(args.Caller.Pos, mapmiddlePosProvider());
			if (pos == null)
			{
				lastErrorMessage = Lang.Get("Invalid position, must be 2 numbers");
			}
			if (!(pos == null))
			{
				return EnumParseResult.Good;
			}
			return EnumParseResult.Bad;
		}
	}
