	public enum EnumCallerType
	{
		Player,
		Entity,
		Block,
		Console,
		Unknown
	}
	public class Caller
	{
		public EnumCallerType Type;

		public string[] CallerPrivileges;

		public string CallerRole;

		public int FromChatGroupId;

		public Vec3d Pos;

		private IPlayer player;

		private Entity entity;

		public IPlayer Player
		{
			get
			{
				return player;
			}
			set
			{
				player = value;
				Entity = value.Entity;
				Type = EnumCallerType.Player;
			}
		}

		public Entity Entity
		{
			get
			{
				return entity;
			}
			set
			{
				entity = value;
				Pos = entity?.Pos.XYZ;
			}
		}

		public bool HasPrivilege(string privilege)
		{
			if (Player != null && Player.HasPrivilege(privilege))
			{
				return true;
			}
			if (CallerPrivileges != null && (Enumerable.Contains(CallerPrivileges, privilege) || Enumerable.Contains(CallerPrivileges, "*")))
			{
				return true;
			}
			return false;
		}

		public IPlayerRole GetRole(ICoreServerAPI sapi)
		{
			if (Player is IServerPlayer serverPlayer)
			{
				return serverPlayer.Role;
			}
			return sapi.Permissions.GetRole(CallerRole);
		}

		public string GetName()
		{
			if (player != null)
			{
				return "Player " + player.PlayerName;
			}
			if (Type == EnumCallerType.Console)
			{
				return "Console Admin";
			}
			if (Type == EnumCallerType.Block)
			{
				return "Block @" + Pos;
			}
			if (Type == EnumCallerType.Entity)
			{
				return string.Concat("Entity ", entity.Code, " @", Pos?.ToString());
			}
			return "Unknown caller";
		}
	}
	public class TextCommandCallingArgs
	{
		public string LanguageCode;

		public IChatCommand Command;

		public string SubCmdCode;

		public Caller Caller;

		public CmdArgs RawArgs;

		public List<ICommandArgumentParser> Parsers = new List<ICommandArgumentParser>();

		public int ArgCount
		{
			get
			{
				int num = 0;
				foreach (ICommandArgumentParser parser in Parsers)
				{
					int argCount = parser.ArgCount;
					if (argCount < 0)
					{
						return -1;
					}
					num += argCount;
				}
				return num;
			}
		}

		public object this[int index] => Parsers[index].GetValue();

		public object LastArg => Parsers[Parsers.Count - 1].GetValue();
	}
