			: base(domain, path)
		{
			Source = new SourceStringComponents(message, sourceDomain, sourcePath, alternateNo);
		}

		public AssetLocationAndSource(AssetLocation loc, SourceStringComponents source)
			: base(loc.Domain, loc.Path)
