				for (int i = 0; i < BlockBehaviors.Length; i++)
				{
					Type type2 = BlockBehaviors[i].GetType();
					if (type2 == type || type.IsAssignableFrom(type2))
					{
						return BlockBehaviors[i];
					}
				}
				return null;
