		public virtual bool OnTesselation(ITerrainMeshPool mesher, ITesselatorAPI tessThreadTesselator)
		{
			bool flag = false;
			for (int i = 0; i < Behaviors.Count; i++)
			{
				flag |= Behaviors[i].OnTesselation(mesher, tessThreadTesselator);
			}
			return flag;
