		public float LevelFrom;

		[DocumentAsJson]
		public float LevelTo;

		[DocumentAsJson]
		public float StartScaleY;

		[DocumentAsJson]
		public float EndScaleY;

		[DocumentAsJson]
		public string ResultCode;

		[DocumentAsJson]
		public string InitialCode;

		[DocumentAsJson]
		public bool LargeItem;

		public static BakingProperties ReadFrom(ItemStack stack)
		{
			if (stack == null)
			{
				return null;
			}
			BakingProperties bakingProperties = stack.Collectible?.Attributes?["bakingProperties"]?.AsObject<BakingProperties>();
			if (bakingProperties == null)
			{
				return null;
			}
			if (!bakingProperties.Temp.HasValue || bakingProperties.Temp == 0f)
			{
				CombustibleProperties combustibleProps = stack.Collectible.CombustibleProps;
				if (combustibleProps != null)
				{
					bakingProperties.Temp = combustibleProps.MeltingPoint - 40;
				}
			}
			return bakingProperties;
		}
	}
	[DocumentAsJson]
	public class CreativeTabAndStackList
	{
		[DocumentAsJson]
		public string[] Tabs;

		[DocumentAsJson]
		public JsonItemStack[] Stacks;

		public void FromBytes(BinaryReader reader, IClassRegistryAPI registry)
		{
			Tabs = new string[reader.ReadInt32()];
			for (int i = 0; i < Tabs.Length; i++)
			{
				Tabs[i] = reader.ReadString();
			}
			Stacks = new JsonItemStack[reader.ReadInt32()];
			for (int j = 0; j < Stacks.Length; j++)
			{
				Stacks[j] = new JsonItemStack();
				Stacks[j].FromBytes(reader, registry);
			}
		}

		public void ToBytes(BinaryWriter writer, IClassRegistryAPI registry)
		{
			writer.Write(Tabs.Length);
			for (int i = 0; i < Tabs.Length; i++)
			{
				writer.Write(Tabs[i]);
			}
			writer.Write(Stacks.Length);
			for (int j = 0; j < Stacks.Length; j++)
			{
				Stacks[j].ToBytes(writer);
			}
		}
	}
