	public class Item : CollectibleObject
	{
		public ItemTagArray Tags = ItemTagArray.Empty;

		public int ItemId;

		public CompositeShape Shape;

		public Dictionary<string, CompositeTexture> Textures = new Dictionary<string, CompositeTexture>();

		public override int Id => ItemId;

		public override EnumItemClass ItemClass => EnumItemClass.Item;

		public CompositeTexture FirstTexture
		{
			get
			{
				if (Textures != null && Textures.Count != 0)
				{
					return Textures.First().Value;
				}
				return null;
			}
		}

		public Item()
		{
		}

		public Item(int itemId)
		{
			ItemId = itemId;
			MaxStackSize = 1;
		}

		public override int GetRandomColor(ICoreClientAPI capi, ItemStack stack)
		{
			if (Textures == null || Textures.Count == 0)
			{
				return 0;
			}
			BakedCompositeTexture bakedCompositeTexture = Textures?.First().Value?.Baked;
			if (bakedCompositeTexture != null)
			{
				return capi.ItemTextureAtlas.GetRandomColor(bakedCompositeTexture.TextureSubId);
			}
			return 0;
		}

		public Item Clone()
		{
			Item item = (Item)MemberwiseClone();
			item.Code = Code.Clone();
			if (MiningSpeed != null)
			{
				item.MiningSpeed = new Dictionary<EnumBlockMaterial, float>(MiningSpeed);
			}
			item.Textures = new Dictionary<string, CompositeTexture>();
			if (Textures != null)
			{
				foreach (KeyValuePair<string, CompositeTexture> texture in Textures)
				{
					item.Textures[texture.Key] = texture.Value.Clone();
				}
			}
			if (Shape != null)
			{
				item.Shape = Shape.Clone();
			}
			if (Attributes != null)
			{
				item.Attributes = Attributes.Clone();
			}
			if (CombustibleProps != null)
			{
				item.CombustibleProps = CombustibleProps.Clone();
			}
			if (NutritionProps != null)
			{
				item.NutritionProps = NutritionProps.Clone();
			}
			if (GrindingProps != null)
			{
				item.GrindingProps = GrindingProps.Clone();
			}
			return item;
		}

		internal void CheckTextures(ILogger logger)
		{
			List<string> list = null;
			int num = 0;
			foreach (KeyValuePair<string, CompositeTexture> texture in Textures)
			{
				if (texture.Value.Base == null)
				{
					logger.Error("The texture definition {0} for #{2} in item with code {1} is invalid. The base property is null. Will skip.", num, Code, texture.Key);
					if (list == null)
					{
						list = new List<string>();
					}
					list.Add(texture.Key);
				}
				num++;
			}
			if (list == null)
			{
				return;
			}
			foreach (string item in list)
			{
				Textures.Remove(item);
			}
		}

		public virtual void FreeRAMServer()
		{
			Textures = null;
			GuiTransform = null;
			FpHandTransform = null;
			TpHandTransform = null;
			TpOffHandTransform = null;
			GroundTransform = null;
		}

		public override void GetHeldItemInfo(ItemSlot inSlot, StringBuilder dsc, IWorldAccessor world, bool withDebugInfo)
		{
			if (world.Api is ICoreClientAPI coreClientAPI && coreClientAPI.Settings.Bool["extendedDebugInfo"])
			{
				IEnumerable<string> source = GetTags(inSlot.Itemstack).ToArray().Select(coreClientAPI.TagRegistry.ItemTagIdToTag).Order();
				if (source.Any())
				{
					StringBuilder.AppendInterpolatedStringHandler handler = new StringBuilder.AppendInterpolatedStringHandler(35, 1, dsc);
					handler.AppendLiteral("<font color=\"#bbbbbb\">Tags: ");
					handler.AppendFormatted(source.Aggregate((string first, string second) => first + ", " + second));
					handler.AppendLiteral("</font>");
					dsc.AppendLine(ref handler);
				}
			}
			base.GetHeldItemInfo(inSlot, dsc, world, withDebugInfo);
		}

		public virtual ItemTagArray GetTags(ItemStack stack)
		{
			return Tags;
		}
	}
	[DocumentAsJson]
	[ProtoContract]
	public class JsonItemStack : IRecipeOutput
	{
		[ProtoMember(1)]
		[DocumentAsJson]
		public EnumItemClass Type;

		[ProtoMember(2)]
		[DocumentAsJson]
		public AssetLocation Code;

		[ProtoMember(3)]
		[DocumentAsJson]
		public int StackSize = 1;

		[JsonProperty]
		[JsonConverter(typeof(JsonAttributesConverter))]
		[ProtoMember(4)]
		public JsonObject Attributes;

		public ItemStack ResolvedItemstack;

		[DocumentAsJson]
		public int Quantity
		{
			get
			{
				return StackSize;
			}
			set
			{
				StackSize = value;
			}
		}

		public static JsonItemStack FromString(string jsonItemstack)
		{
			return JsonObject.FromJson(jsonItemstack).AsObject<JsonItemStack>();
		}

		public bool Resolve(IWorldAccessor resolver, string sourceForErrorLogging, AssetLocation assetLoc, bool printWarningOnError = true)
		{
			if (Type == EnumItemClass.Block)
			{
				Block block = resolver.GetBlock(Code);
				if (block == null || block.IsMissing)
				{
					if (printWarningOnError)
					{
						resolver.Logger.Warning("Failed resolving a blocks blockdrop or smeltedstack with code {0} in {1}", Code, sourceForErrorLogging + assetLoc);
					}
					return false;
				}
				ResolvedItemstack = new ItemStack(block, StackSize);
			}
			else
			{
				Item item = resolver.GetItem(Code);
				if (item == null || item.IsMissing)
				{
					if (printWarningOnError)
					{
						resolver.Logger.Warning("Failed resolving a blocks itemdrop or smeltedstack with code {0} in {1}", Code, sourceForErrorLogging + assetLoc);
					}
					return false;
				}
				ResolvedItemstack = new ItemStack(item, StackSize);
			}
			if (Attributes != null)
			{
				IAttribute attribute = Attributes.ToAttribute();
				if (attribute is ITreeAttribute)
				{
					ResolvedItemstack.Attributes = (ITreeAttribute)attribute;
				}
			}
			return true;
		}

		public bool Resolve(IWorldAccessor resolver, string sourceForErrorLogging, bool printWarningOnError = true)
		{
			if (Type == EnumItemClass.Block)
			{
				Block block = resolver.GetBlock(Code);
				if (block == null || block.IsMissing)
				{
					if (printWarningOnError)
					{
						resolver.Logger.Warning("Failed resolving a blocks blockdrop or smeltedstack with code {0} in {1}", Code, sourceForErrorLogging);
					}
					return false;
				}
				ResolvedItemstack = new ItemStack(block, StackSize);
			}
			else
			{
				Item item = resolver.GetItem(Code);
				if (item == null || item.IsMissing)
				{
					if (printWarningOnError)
					{
						resolver.Logger.Warning("Failed resolving a blocks itemdrop or smeltedstack with code {0} in {1}", Code, sourceForErrorLogging);
					}
					return false;
				}
				ResolvedItemstack = new ItemStack(item, StackSize);
			}
			if (Attributes != null)
			{
				IAttribute attribute = Attributes.ToAttribute();
				if (attribute is ITreeAttribute)
				{
					ResolvedItemstack.Attributes = (ITreeAttribute)attribute;
				}
			}
			return true;
		}

		public bool Matches(IWorldAccessor worldForResolve, ItemStack inputStack)
		{
			return ResolvedItemstack.Equals(worldForResolve, inputStack, GlobalConstants.IgnoredStackAttributes);
		}

		public JsonItemStack Clone()
		{
			JsonItemStack jsonItemStack = new JsonItemStack
			{
				Code = Code.Clone(),
				ResolvedItemstack = ResolvedItemstack?.Clone(),
				StackSize = StackSize,
				Type = Type
			};
			if (Attributes != null)
			{
				jsonItemStack.Attributes = Attributes.Clone();
			}
			return jsonItemStack;
		}

		public virtual void FromBytes(BinaryReader reader, IClassRegistryAPI instancer)
		{
			Type = (EnumItemClass)reader.ReadInt16();
			Code = new AssetLocation(reader.ReadString());
			StackSize = reader.ReadInt32();
			if (reader.ReadBoolean())
			{
				ResolvedItemstack = new ItemStack(reader);
			}
		}

		public virtual void ToBytes(BinaryWriter writer)
		{
			writer.Write((short)Type);
			writer.Write(Code.ToShortString());
			writer.Write(StackSize);
			writer.Write(ResolvedItemstack != null);
			if (ResolvedItemstack != null)
			{
				ResolvedItemstack.ToBytes(writer);
			}
		}

		public void FillPlaceHolder(string key, string value)
		{
			Code = Code.CopyWithPath(Code.Path.Replace("{" + key + "}", value));
			Attributes?.FillPlaceHolder(key, value);
		}
	}
	[DocumentAsJson]
	[JsonObject(/*Could not decode attribute arguments.*/)]
	public class ModelTransformNoDefaults
	{
		public static readonly FastVec3f defaultTf = new FastVec3f(-9.9E-05f, -9.9E-05f, -9.9E-05f);

		[JsonProperty]
		public FastVec3f Translation = defaultTf;

		[JsonProperty]
		public FastVec3f Rotation = defaultTf;

		[JsonProperty]
		public FastVec3f Origin = new FastVec3f(0.5f, 0.5f, 0.5f);

		[JsonProperty]
		public bool Rotate = true;

		[JsonProperty]
		public FastVec3f ScaleXYZ = new FastVec3f(1f, 1f, 1f);

		[JsonProperty]
		public float Scale
		{
			set
			{
				ScaleXYZ.Set(value, value, value);
			}
		}

		public float[] AsMatrix
		{
			get
			{
				float[] array = Mat4f.Create();
				Mat4f.Translate(array, array, Translation.X, Translation.Y, Translation.Z);
				Mat4f.Translate(array, array, Origin.X, Origin.Y, Origin.Z);
				if (Rotation.X != 0f || Rotation.Y != 0f || Rotation.Z != 0f)
				{
					Mat4f.RotateX(array, array, Rotation.X * ((float)Math.PI / 180f));
					Mat4f.RotateY(array, array, Rotation.Y * ((float)Math.PI / 180f));
					Mat4f.RotateZ(array, array, Rotation.Z * ((float)Math.PI / 180f));
				}
				Mat4f.Scale(array, array, ScaleXYZ.X, ScaleXYZ.Y, ScaleXYZ.Z);
				Mat4f.Translate(array, array, 0f - Origin.X, 0f - Origin.Y, 0f - Origin.Z);
				return array;
			}
		}

		public void Clear()
		{
			Rotation.Set(0f, 0f, 0f);
			Translation.Set(0f, 0f, 0f);
			Origin.Set(0f, 0f, 0f);
			Scale = 1f;
		}
	}
