	public class InventoryGeneric : InventoryBase
	{
		protected ItemSlot[] slots;

		private NewSlotDelegate onNewSlot;

		public GetSuitabilityDelegate OnGetSuitability;

		public GetAutoPushIntoSlotDelegate OnGetAutoPushIntoSlot;

		public GetAutoPullFromSlotDelegate OnGetAutoPullFromSlot;

		public Dictionary<EnumTransitionType, float> TransitionableSpeedMulByType { get; set; }

		public Dictionary<EnumFoodCategory, float> PerishableFactorByFoodCategory { get; set; }

		public float BaseWeight
		{
			get
			{
				return baseWeight;
			}
			set
			{
				baseWeight = value;
			}
		}

		public override int Count => slots.Length;

		public override ItemSlot this[int slotId]
		{
			get
			{
				if (slotId < 0 || slotId >= Count)
				{
					throw new ArgumentOutOfRangeException("slotId", "Index was " + ((slotId < 0) ? "negative: " : "too large: ") + slotId + "/" + Count + " for " + className + " at " + Pos);
				}
				return slots[slotId];
			}
			set
			{
				if (slotId < 0 || slotId >= Count)
				{
					throw new ArgumentOutOfRangeException("slotId", "Index was " + ((slotId < 0) ? "negative: " : "too large: ") + slotId + "/" + Count + " for " + className + " at " + Pos);
				}
				slots[slotId] = value ?? throw new ArgumentNullException("value");
			}
		}

		public InventoryGeneric(ICoreAPI api)
			: base("-", api)
		{
		}

		public void Init(int quantitySlots, string className, string instanceId, NewSlotDelegate onNewSlot = null)
		{
			instanceID = instanceId;
			base.className = className;
			OnGetSuitability = (ItemSlot s, ItemSlot t, bool isMerge) => (!isMerge) ? (baseWeight + 1f) : (baseWeight + 3f);
			this.onNewSlot = onNewSlot;
			slots = GenEmptySlots(quantitySlots);
		}

		public InventoryGeneric(int quantitySlots, string className, string instanceId, ICoreAPI api, NewSlotDelegate onNewSlot = null)
			: base(className, instanceId, api)
		{
			Init(quantitySlots, className, instanceId, onNewSlot);
		}

		public InventoryGeneric(int quantitySlots, string invId, ICoreAPI api, NewSlotDelegate onNewSlot = null)
			: base(invId, api)
		{
			OnGetSuitability = (ItemSlot s, ItemSlot t, bool isMerge) => (!isMerge) ? (baseWeight + 1f) : (baseWeight + 3f);
			this.onNewSlot = onNewSlot;
			slots = GenEmptySlots(quantitySlots);
		}

		public override float GetSuitability(ItemSlot sourceSlot, ItemSlot targetSlot, bool isMerge)
		{
			return OnGetSuitability(sourceSlot, targetSlot, isMerge);
		}

		public override void FromTreeAttributes(ITreeAttribute treeAttribute)
		{
			int num = slots.Length;
			slots = SlotsFromTreeAttributes(treeAttribute, slots);
			int amount = num - slots.Length;
			AddSlots(amount);
		}

		public void AddSlots(int amount)
		{
			while (amount-- > 0)
			{
				slots = slots.Append(NewSlot(slots.Length));
			}
		}

		public override void ToTreeAttributes(ITreeAttribute invtree)
		{
			SlotsToTreeAttributes(slots, invtree);
		}

		protected override ItemSlot NewSlot(int slotId)
		{
			if (onNewSlot != null)
			{
				return onNewSlot(slotId, this);
			}
			return new ItemSlotSurvival(this);
		}

		public override float GetTransitionSpeedMul(EnumTransitionType transType, ItemStack stack)
		{
			float value = GetDefaultTransitionSpeedMul(transType);
			if (transType == EnumTransitionType.Perish && PerishableFactorByFoodCategory != null && stack.Collectible.NutritionProps != null)
			{
				if (!PerishableFactorByFoodCategory.TryGetValue(stack.Collectible.NutritionProps.FoodCategory, out value))
				{
					value = GetDefaultTransitionSpeedMul(transType);
				}
			}
			else if (TransitionableSpeedMulByType != null && !TransitionableSpeedMulByType.TryGetValue(transType, out value))
			{
				value = GetDefaultTransitionSpeedMul(transType);
			}
			return InvokeTransitionSpeedDelegates(transType, stack, value);
		}

		public override ItemSlot GetAutoPullFromSlot(BlockFacing atBlockFace)
		{
			if (OnGetAutoPullFromSlot != null)
			{
				return OnGetAutoPullFromSlot(atBlockFace);
			}
			return base.GetAutoPullFromSlot(atBlockFace);
		}

		public override ItemSlot GetAutoPushIntoSlot(BlockFacing atBlockFace, ItemSlot fromSlot)
		{
			if (OnGetAutoPushIntoSlot != null)
			{
				return OnGetAutoPushIntoSlot(atBlockFace, fromSlot);
			}
			return base.GetAutoPushIntoSlot(atBlockFace, fromSlot);
		}
	}
	public class InventoryPerPlayer : InventoryGeneric
	{
		public Dictionary<string, int[]> PlayerQuantities;

		public int[] Quantities;

		public override bool PutLocked { get; set; } = true;

		public InventoryPerPlayer(int quantitySlots, string? invId, ICoreAPI? api, NewSlotDelegate? onNewSlot = null)
			: base(quantitySlots, invId, api, onNewSlot)
		{
			PlayerQuantities = new Dictionary<string, int[]>();
			Quantities = new int[quantitySlots];
		}

		public bool CanTake(ItemSlot fromSlot, ItemStackMoveOperation op)
		{
			return GetPlayerRemaining(op.ActingPlayer.PlayerUID, GetSlotId(fromSlot)) > 0;
		}

		public void AddPlayerUsage(string playerUid, int slotId, int value)
		{
			if (PlayerQuantities.TryGetValue(playerUid, out int[] value2))
			{
				value2[slotId] += value;
			}
		}

		public int GetPlayerRemaining(string playerUid, int slotId)
		{
			if (PlayerQuantities.TryGetValue(playerUid, out int[] value))
			{
				return Math.Max(0, Quantities[slotId] - value[slotId]);
			}
			value = new int[Quantities.Length];
			PlayerQuantities.Add(playerUid, value);
			return Math.Max(0, Quantities[slotId] - value[slotId]);
		}

		public override void MarkSlotDirty(int slotId)
		{
		}

		public void MarkDirty()
		{
			if (Api is ICoreServerAPI coreServerAPI)
			{
				coreServerAPI.World.BlockAccessor.GetBlockEntity(Pos).MarkDirty();
			}
		}

		protected override ItemSlot NewSlot(int slotId)
		{
			return new ItemSlotPerPlayer(this, slotId);
		}

		public void OnPlacementBySchematic()
		{
			for (int i = 0; i < slots.Length; i++)
			{
				Quantities[i] = this[i].StackSize;
			}
		}

		public override void FromTreeAttributes(ITreeAttribute treeAttribute)
		{
			base.FromTreeAttributes(treeAttribute);
			if (treeAttribute["PlayerQuantities"] is TreeAttribute treeAttribute2)
			{
				if (treeAttribute2.Count > 0)
				{
					foreach (var (key, attribute2) in treeAttribute2)
					{
						PlayerQuantities[key] = (attribute2 as IntArrayAttribute)?.value ?? new int[Count];
					}
				}
				else
				{
					PlayerQuantities.Clear();
				}
			}
			Quantities = (treeAttribute["Quantities"] as IntArrayAttribute)?.value ?? new int[Count];
			if (!(Api is ICoreClientAPI coreClientAPI) || !PlayerQuantities.ContainsKey(coreClientAPI.World.Player.PlayerUID))
			{
				return;
			}
			for (int i = 0; i < Quantities.Length; i++)
			{
				if (this[i].Itemstack == null)
				{
					continue;
				}
				int playerRemaining = GetPlayerRemaining(coreClientAPI.World.Player.PlayerUID, i);
				if (playerRemaining == 0)
				{
					if (coreClientAPI.World.Player.WorldData.CurrentGameMode == EnumGameMode.Survival)
					{
						this[i].Itemstack = null;
					}
				}
				else
				{
					this[i].Itemstack.StackSize = playerRemaining;
				}
			}
		}

		public override void ToTreeAttributes(ITreeAttribute invtree)
		{
			TreeAttribute treeAttribute = new TreeAttribute();
			foreach (KeyValuePair<string, int[]> playerQuantity in PlayerQuantities)
			{
				playerQuantity.Deconstruct(out var key, out var value);
				string key2 = key;
				int[] value2 = value;
				treeAttribute[key2] = new IntArrayAttribute(value2);
			}
			invtree["PlayerQuantities"] = treeAttribute;
			invtree["Quantities"] = new IntArrayAttribute(Quantities);
			base.ToTreeAttributes(invtree);
		}
	}
