	[ProtoContract]
	public class LandClaim
	{
		[ProtoMember(1)]
		public List<Cuboidi> Areas = new List<Cuboidi>();

		[ProtoMember(2)]
		public int ProtectionLevel;

		[ProtoMember(3)]
		public long OwnedByEntityId;

		[ProtoMember(4)]
		public string OwnedByPlayerUid;

		[ProtoMember(5)]
		public uint OwnedByPlayerGroupUid;

		[ProtoMember(6)]
		public string LastKnownOwnerName;

		[ProtoMember(7)]
		public string Description;

		[ProtoMember(8)]
		public Dictionary<int, EnumBlockAccessFlags> PermittedPlayerGroupIds = new Dictionary<int, EnumBlockAccessFlags>();

		[ProtoMember(9)]
		public Dictionary<string, EnumBlockAccessFlags> PermittedPlayerUids = new Dictionary<string, EnumBlockAccessFlags>();

		[ProtoMember(10)]
		public Dictionary<string, string> PermittedPlayerLastKnownPlayerName = new Dictionary<string, string>();

		[ProtoMember(11)]
		public bool AllowUseEveryone;

		[ProtoMember(12)]
		public bool AllowTraverseEveryone;

		public BlockPos Center
		{
			get
			{
				if (Areas.Count == 0)
				{
					return new BlockPos(0, 0, 0);
				}
				Vec3d vec3d = new Vec3d();
				int num = 0;
				foreach (Cuboidi area in Areas)
				{
					_ = area.Center;
					num += area.SizeXYZ;
				}
				foreach (Cuboidi area2 in Areas)
				{
					Vec3i center = area2.Center;
					Vec3d vec3d2 = new Vec3d(center.X, center.Y, center.Z);
					vec3d += vec3d2 * ((double)area2.SizeXYZ / (double)num);
				}
				return new BlockPos((int)(vec3d.X / (double)Areas.Count), (int)(vec3d.Y / (double)Areas.Count), (int)(vec3d.Z / (double)Areas.Count));
			}
		}

		public int SizeXZ
		{
			get
			{
				int num = 0;
				foreach (Cuboidi area in Areas)
				{
					_ = area.Center;
					num += area.SizeXZ;
				}
				return num;
			}
		}

		public int SizeXYZ
		{
			get
			{
				int num = 0;
				foreach (Cuboidi area in Areas)
				{
					_ = area.Center;
					num += area.SizeXYZ;
				}
				return num;
			}
		}

		public static LandClaim CreateClaim(IPlayer player, int protectionLevel = 1)
		{
			return new LandClaim
			{
				OwnedByPlayerUid = player.PlayerUID,
				ProtectionLevel = protectionLevel,
				LastKnownOwnerName = Lang.Get("Player " + player.PlayerName)
			};
		}

		public static LandClaim CreateClaim(EntityAgent entity, int protectionLevel = 1)
		{
			string name = entity.GetName();
			return new LandClaim
			{
				OwnedByEntityId = entity.EntityId,
				ProtectionLevel = protectionLevel,
				LastKnownOwnerName = Lang.Get("item-creature-" + entity.Code) + ((name == null) ? "" : (" " + name))
			};
		}

		public static LandClaim CreateClaim(string ownerName, int protectionLevel = 1)
		{
			return new LandClaim
			{
				ProtectionLevel = protectionLevel,
				LastKnownOwnerName = ownerName
			};
		}

		public EnumPlayerAccessResult TestPlayerAccess(IPlayer player, EnumBlockAccessFlags claimFlag)
		{
			if (player.PlayerUID.Equals(OwnedByPlayerUid))
			{
				return EnumPlayerAccessResult.OkOwner;
			}
			if (OwnedByPlayerGroupUid != 0 && player.Groups.Any((PlayerGroupMembership ms) => ms.GroupUid == OwnedByPlayerGroupUid))
			{
				return EnumPlayerAccessResult.OkGroup;
			}
			if (player.Role.PrivilegeLevel > ProtectionLevel && player.WorldData.CurrentGameMode == EnumGameMode.Creative)
			{
				return EnumPlayerAccessResult.OkPrivilege;
			}
			if (PermittedPlayerUids.TryGetValue(player.PlayerUID, out var value) && (value & claimFlag) > EnumBlockAccessFlags.None)
			{
				return EnumPlayerAccessResult.OkGrantedPlayer;
			}
			PlayerGroupMembership[] groups = player.Groups;
			foreach (PlayerGroupMembership playerGroupMembership in groups)
			{
				if (PermittedPlayerGroupIds.TryGetValue(playerGroupMembership.GroupUid, out value) && (value & claimFlag) > EnumBlockAccessFlags.None)
				{
					return EnumPlayerAccessResult.OkGrantedGroup;
				}
			}
			return EnumPlayerAccessResult.Denied;
		}

		public bool PositionInside(Vec3d position)
		{
			for (int i = 0; i < Areas.Count; i++)
			{
				if (Areas[i].Contains(position))
				{
					return true;
				}
			}
			return false;
		}

		public bool PositionInside(BlockPos position)
		{
			for (int i = 0; i < Areas.Count; i++)
			{
				if (Areas[i].Contains(position))
				{
					return true;
				}
			}
			return false;
		}

		public EnumClaimError AddArea(Cuboidi cuboidi)
		{
			if (Areas.Count == 0)
			{
				Areas.Add(cuboidi);
				return EnumClaimError.NoError;
			}
			for (int i = 0; i < Areas.Count; i++)
			{
				if (Areas[i].Intersects(cuboidi))
				{
					return EnumClaimError.Overlapping;
				}
			}
			for (int j = 0; j < Areas.Count; j++)
			{
				if (Areas[j].IsAdjacent(cuboidi))
				{
					Areas.Add(cuboidi);
					return EnumClaimError.NoError;
				}
			}
			return EnumClaimError.NotAdjacent;
		}

		public bool Intersects(Cuboidi cuboidi)
		{
			for (int i = 0; i < Areas.Count; i++)
			{
				if (Areas[i].Intersects(cuboidi))
				{
					return true;
				}
			}
			return false;
		}

		public bool Intersects2d(HorRectanglei rec)
		{
			for (int i = 0; i < Areas.Count; i++)
			{
				if (Areas[i].Intersects(rec))
				{
					return true;
				}
			}
			return false;
		}

		public LandClaim Clone()
		{
			List<Cuboidi> list = new List<Cuboidi>();
			for (int i = 0; i < Areas.Count; i++)
			{
				list.Add(Areas[i].Clone());
			}
			return new LandClaim
			{
				Areas = list,
				Description = Description,
				LastKnownOwnerName = LastKnownOwnerName,
				OwnedByEntityId = OwnedByEntityId,
				OwnedByPlayerGroupUid = OwnedByPlayerGroupUid,
				OwnedByPlayerUid = OwnedByPlayerUid,
				PermittedPlayerGroupIds = new Dictionary<int, EnumBlockAccessFlags>(PermittedPlayerGroupIds),
				PermittedPlayerUids = new Dictionary<string, EnumBlockAccessFlags>(PermittedPlayerUids),
				ProtectionLevel = ProtectionLevel
			};
		}
	}
	public class AnimatableRenderer : IRenderer, IDisposable
	{
		protected Vec3d pos;

		protected ICoreClientAPI capi;

		protected AnimatorBase animator;

		protected Dictionary<string, AnimationMetaData> activeAnimationsByAnimCode = new Dictionary<string, AnimationMetaData>();

		public MultiTextureMeshRef mtmeshref;

		public MeshRef meshref;

		public int textureId;

		public float[] ModelMat = Mat4f.Create();

		public float[] CustomTransform;

		public bool ShouldRender;

		public bool StabilityAffected = true;

		public bool LightAffected = true;

		public float FogAffectedness = 1f;

		public Vec3f rotationDeg;

		public float ScaleX = 1f;

		public float ScaleY = 1f;

		public float ScaleZ = 1f;

		public Vec4f renderColor = ColorUtil.WhiteArgbVec.Clone();

		public bool backfaceCulling = true;

		public double RenderOrder => 1.0;

		public int RenderRange => 99;

		[Obsolete("Use constructor with MultiTextureMeshRef instead, the standard MeshRef texturing breaks when there is multiple texture atlasses")]
		public AnimatableRenderer(ICoreClientAPI capi, Vec3d pos, Vec3f rotationDeg, AnimatorBase animator, Dictionary<string, AnimationMetaData> activeAnimationsByAnimCode, MeshRef meshref, int textureId, EnumRenderStage renderStage = EnumRenderStage.Opaque)
		{
			AnimatableRenderer renderer = this;
			this.pos = pos;
			this.capi = capi;
			this.animator = animator;
			this.activeAnimationsByAnimCode = activeAnimationsByAnimCode;
			this.meshref = meshref;
			this.rotationDeg = rotationDeg;
			this.textureId = textureId;
			if (rotationDeg == null)
			{
				this.rotationDeg = new Vec3f();
			}
			capi.Event.EnqueueMainThreadTask(delegate
			{
				capi.Event.RegisterRenderer(renderer, renderStage, "animatable");
				capi.Event.RegisterRenderer(renderer, EnumRenderStage.ShadowFar, "animatable");
				capi.Event.RegisterRenderer(renderer, EnumRenderStage.ShadowNear, "animatable");
			}, "registerrenderers");
		}

		public AnimatableRenderer(ICoreClientAPI capi, Vec3d pos, Vec3f rotationDeg, AnimatorBase animator, Dictionary<string, AnimationMetaData> activeAnimationsByAnimCode, MultiTextureMeshRef meshref, EnumRenderStage renderStage = EnumRenderStage.Opaque)
		{
			AnimatableRenderer renderer = this;
			this.pos = pos;
			this.capi = capi;
			this.animator = animator;
			this.activeAnimationsByAnimCode = activeAnimationsByAnimCode;
			mtmeshref = meshref;
			this.rotationDeg = rotationDeg;
			if (rotationDeg == null)
			{
				this.rotationDeg = new Vec3f();
			}
			capi.Event.EnqueueMainThreadTask(delegate
			{
				capi.Event.RegisterRenderer(renderer, renderStage, "animatable");
				capi.Event.RegisterRenderer(renderer, EnumRenderStage.ShadowFar, "animatable");
				capi.Event.RegisterRenderer(renderer, EnumRenderStage.ShadowNear, "animatable");
			}, "registerrenderers");
		}

		public void OnRenderFrame(float dt, EnumRenderStage stage)
		{
			if (!ShouldRender || (mtmeshref != null && (mtmeshref.Disposed || !mtmeshref.Initialized)) || (meshref != null && (meshref.Disposed || !meshref.Initialized)))
			{
				return;
			}
			bool flag = stage != EnumRenderStage.Opaque;
			capi.Render.GLDepthMask(on: true);
			EntityPlayer entity = capi.World.Player.Entity;
			Mat4f.Identity(ModelMat);
			Mat4f.Translate(ModelMat, ModelMat, (float)(pos.X - entity.CameraPos.X), (float)(pos.Y - entity.CameraPos.Y), (float)(pos.Z - entity.CameraPos.Z));
			if (CustomTransform != null)
			{
				Mat4f.Multiply(ModelMat, ModelMat, CustomTransform);
			}
			else
			{
				Mat4f.Translate(ModelMat, ModelMat, 0.5f, 0f, 0.5f);
				Mat4f.Scale(ModelMat, ModelMat, ScaleX, ScaleY, ScaleZ);
				Mat4f.RotateY(ModelMat, ModelMat, rotationDeg.Y * ((float)Math.PI / 180f));
				Mat4f.Translate(ModelMat, ModelMat, -0.5f, 0f, -0.5f);
			}
			IRenderAPI render = capi.Render;
			IShaderProgram currentActiveShader = render.CurrentActiveShader;
			currentActiveShader?.Stop();
			capi.Render.GlDisableCullFace();
			IShaderProgram engineShader = render.GetEngineShader(flag ? EnumShaderProgram.Shadowmapentityanimated : EnumShaderProgram.Entityanimated);
			engineShader.Use();
			Vec4f value = (LightAffected ? capi.World.BlockAccessor.GetLightRGBs((int)pos.X, (int)pos.Y, (int)pos.Z) : ColorUtil.WhiteArgbVec);
			render.GlToggleBlend(blend: true);
			if (!flag)
			{
				engineShader.Uniform("extraGlow", 0);
				engineShader.Uniform("rgbaAmbientIn", render.AmbientColor);
				engineShader.Uniform("rgbaFogIn", render.FogColor);
				engineShader.Uniform("fogMinIn", render.FogMin * FogAffectedness);
				engineShader.Uniform("fogDensityIn", render.FogDensity * FogAffectedness);
				engineShader.Uniform("rgbaLightIn", value);
				engineShader.Uniform("renderColor", renderColor);
				engineShader.Uniform("alphaTest", 0.1f);
				engineShader.UniformMatrix("modelMatrix", ModelMat);
				engineShader.UniformMatrix("viewMatrix", render.CameraMatrixOriginf);
				engineShader.Uniform("windWaveIntensity", 0f);
				engineShader.Uniform("glitchEffectStrength", 0f);
				engineShader.Uniform("frostAlpha", 0f);
				if (!StabilityAffected)
				{
					engineShader.Uniform("globalWarpIntensity", 0f);
					engineShader.Uniform("glitchWaviness", 0f);
				}
			}
			else
			{
				engineShader.UniformMatrix("modelViewMatrix", Mat4f.Mul(new float[16], capi.Render.CurrentModelviewMatrix, ModelMat));
			}
			engineShader.UniformMatrix("projectionMatrix", render.CurrentProjectionMatrix);
			engineShader.Uniform("addRenderFlags", 0);
			engineShader.UBOs["Animation"].Update((object)animator.Matrices, 0, animator.MaxJointId * 16 * 4);
			if ((stage == EnumRenderStage.Opaque || stage == EnumRenderStage.ShadowNear) && !backfaceCulling)
			{
				capi.Render.GlDisableCullFace();
			}
			if (meshref != null)
			{
				engineShader.BindTexture2D("entityTex", textureId, 0);
				capi.Render.RenderMesh(meshref);
			}
			else
			{
				capi.Render.RenderMultiTextureMesh(mtmeshref, "entityTex");
			}
			if ((stage == EnumRenderStage.Opaque || stage == EnumRenderStage.ShadowNear) && !backfaceCulling)
			{
				capi.Render.GlEnableCullFace();
			}
			engineShader.Stop();
			currentActiveShader?.Use();
		}

		public void Dispose()
		{
			capi.Event.UnregisterRenderer(this, EnumRenderStage.Opaque);
			capi.Event.UnregisterRenderer(this, EnumRenderStage.ShadowFar);
			capi.Event.UnregisterRenderer(this, EnumRenderStage.ShadowNear);
			mtmeshref?.Dispose();
			meshref?.Dispose();
		}
	}
