				Code = Animation;
			}
			CodeCrc32 = GetCrc32(Code);
		}

		public static uint GetCrc32(string animcode)
		{
			int num = int.MaxValue;
			return (uint)(GameMath.Crc32(animcode.ToLowerInvariant()) & num);
		}

		public bool Matches(int currentActivities)
		{
			AnimationTrigger triggeredBy = TriggeredBy;
			bool flag;
			if (triggeredBy != null && triggeredBy.MatchExact)
			{
				flag = currentActivities == withActivitiesMerged;
			}
			else
			{
				flag = (currentActivities & withActivitiesMerged) > 0;
				if (flag && (withActivitiesMerged & 0x90) != 0 && (currentActivities & 0x4000) != 0)
				{
					flag = false;
				}
			}
			return flag;
		}

		public AnimationMetaData Clone()
		{
			return new AnimationMetaData
			{
				Code = Code,
				Animation = Animation,
				AnimationSound = AnimationSound,
				Weight = Weight,
				Attributes = Attributes,
				ClientSide = ClientSide,
				ElementWeight = ElementWeight,
				AnimationSpeed = AnimationSpeed,
				MulWithWalkSpeed = MulWithWalkSpeed,
				EaseInSpeed = EaseInSpeed,
				EaseOutSpeed = EaseOutSpeed,
				TriggeredBy = TriggeredBy,
				AdjustCollisionBox = AdjustCollisionBox,
				BlendMode = BlendMode,
				ElementBlendMode = ElementBlendMode,
				withActivitiesMerged = withActivitiesMerged,
				CodeCrc32 = CodeCrc32,
				WasStartedFromTrigger = WasStartedFromTrigger,
				HoldEyePosAfterEasein = HoldEyePosAfterEasein,
				StartFrameOnce = StartFrameOnce,
				SupressDefaultAnimation = SupressDefaultAnimation,
				WeightCapFactor = WeightCapFactor
			};
		}

		public override bool Equals(object obj)
		{
			if (obj is AnimationMetaData animationMetaData && animationMetaData.Animation == Animation && animationMetaData.AnimationSpeed == AnimationSpeed)
			{
				return animationMetaData.BlendMode == BlendMode;
			}
			return false;
		}

		public override int GetHashCode()
		{
			return Animation.GetHashCode() ^ AnimationSpeed.GetHashCode() ^ BlendMode.GetHashCode();
		}

		public void ToBytes(BinaryWriter writer)
		{
			writer.Write(Code);
			writer.Write(Animation);
			writer.Write(Weight);
			writer.Write(ElementWeight.Count);
			foreach (KeyValuePair<string, float> item in ElementWeight)
			{
				writer.Write(item.Key);
				writer.Write(item.Value);
			}
			writer.Write(AnimationSpeed);
			writer.Write(EaseInSpeed);
			writer.Write(EaseOutSpeed);
			writer.Write(TriggeredBy != null);
			if (TriggeredBy != null)
			{
				writer.Write(TriggeredBy.MatchExact);
				EnumEntityActivity[] onControls = TriggeredBy.OnControls;
				if (onControls != null)
				{
					writer.Write(onControls.Length);
					for (int i = 0; i < onControls.Length; i++)
					{
						writer.Write((int)onControls[i]);
					}
				}
				else
				{
					writer.Write(0);
				}
				writer.Write(TriggeredBy.DefaultAnim);
			}
			writer.Write((int)BlendMode);
			writer.Write(ElementBlendMode.Count);
			foreach (KeyValuePair<string, EnumAnimationBlendMode> item2 in ElementBlendMode)
			{
				writer.Write(item2.Key);
				writer.Write((int)item2.Value);
			}
			writer.Write(MulWithWalkSpeed);
			writer.Write(StartFrameOnce);
			writer.Write(HoldEyePosAfterEasein);
			writer.Write(ClientSide);
			writer.Write(Attributes?.ToString() ?? "");
			writer.Write(WeightCapFactor);
			writer.Write(AnimationSound != null);
			if (AnimationSound != null)
			{
				writer.Write(AnimationSound.Location.ToShortString());
				writer.Write(AnimationSound.Range);
				writer.Write(AnimationSound.Frame);
				writer.Write(AnimationSound.RandomizePitch);
			}
			writer.Write(AdjustCollisionBox);
		}

		public static AnimationMetaData FromBytes(BinaryReader reader, string version)
		{
			AnimationMetaData animationMetaData = new AnimationMetaData();
			animationMetaData.Code = reader.ReadString().DeDuplicate();
			animationMetaData.Animation = reader.ReadString();
			animationMetaData.Weight = reader.ReadSingle();
			int num = reader.ReadInt32();
			for (int i = 0; i < num; i++)
			{
				animationMetaData.ElementWeight[reader.ReadString().DeDuplicate()] = reader.ReadSingle();
			}
			animationMetaData.AnimationSpeed = reader.ReadSingle();
			animationMetaData.EaseInSpeed = reader.ReadSingle();
			animationMetaData.EaseOutSpeed = reader.ReadSingle();
			if (reader.ReadBoolean())
			{
				animationMetaData.TriggeredBy = new AnimationTrigger();
				animationMetaData.TriggeredBy.MatchExact = reader.ReadBoolean();
				num = reader.ReadInt32();
				animationMetaData.TriggeredBy.OnControls = new EnumEntityActivity[num];
				for (int j = 0; j < num; j++)
				{
					animationMetaData.TriggeredBy.OnControls[j] = (EnumEntityActivity)reader.ReadInt32();
				}
				animationMetaData.TriggeredBy.DefaultAnim = reader.ReadBoolean();
			}
			animationMetaData.BlendMode = (EnumAnimationBlendMode)reader.ReadInt32();
			num = reader.ReadInt32();
			for (int k = 0; k < num; k++)
			{
				animationMetaData.ElementBlendMode[reader.ReadString().DeDuplicate()] = (EnumAnimationBlendMode)reader.ReadInt32();
			}
			animationMetaData.MulWithWalkSpeed = reader.ReadBoolean();
			if (GameVersion.IsAtLeastVersion(version, "1.12.5-dev.1"))
			{
				animationMetaData.StartFrameOnce = reader.ReadSingle();
			}
			if (GameVersion.IsAtLeastVersion(version, "1.13.0-dev.3"))
			{
				animationMetaData.HoldEyePosAfterEasein = reader.ReadSingle();
			}
			if (GameVersion.IsAtLeastVersion(version, "1.17.0-dev.18"))
			{
				animationMetaData.ClientSide = reader.ReadBoolean();
			}
			if (GameVersion.IsAtLeastVersion(version, "1.19.0-dev.20"))
			{
				string text = reader.ReadString();
				if (text != "")
				{
					animationMetaData.Attributes = new JsonObject(JToken.Parse(text));
				}
				else
				{
					animationMetaData.Attributes = new JsonObject(JToken.Parse("{}"));
				}
			}
			if (GameVersion.IsAtLeastVersion(version, "1.19.0-rc.6"))
			{
				animationMetaData.WeightCapFactor = reader.ReadSingle();
			}
			if (GameVersion.IsAtLeastVersion(version, "1.20.0-dev.13") && reader.ReadBoolean())
			{
				animationMetaData.AnimationSound = new AnimationSound
				{
					Location = AssetLocation.Create(reader.ReadString()),
					Range = reader.ReadSingle(),
					Frame = reader.ReadInt32(),
					RandomizePitch = reader.ReadBoolean()
				};
			}
			if (GameVersion.IsAtLeastVersion(version, "1.21.0-dev.1"))
			{
				animationMetaData.AdjustCollisionBox = reader.ReadBoolean();
			}
			animationMetaData.Init();
			return animationMetaData;
		}

		internal void DeDuplicate()
		{
			Code = Code.DeDuplicate();
			Dictionary<string, float> dictionary = new Dictionary<string, float>(ElementWeight.Count);
			foreach (KeyValuePair<string, float> item in ElementWeight)
			{
				dictionary[item.Key.DeDuplicate()] = item.Value;
			}
			ElementWeight = dictionary;
			Dictionary<string, EnumAnimationBlendMode> dictionary2 = new Dictionary<string, EnumAnimationBlendMode>(ElementBlendMode.Count);
			foreach (KeyValuePair<string, EnumAnimationBlendMode> item2 in ElementBlendMode)
			{
				dictionary2[item2.Key.DeDuplicate()] = item2.Value;
			}
			ElementBlendMode = dictionary2;
		}
	}
	public class AnimationUtil : IRenderer, IDisposable
	{
		public AnimatorBase animator;

		public AnimatableRenderer renderer;

		public Dictionary<string, AnimationMetaData> activeAnimationsByAnimCode = new Dictionary<string, AnimationMetaData>();

		protected ICoreAPI api;

		protected bool stopRenderTriggered;

		protected ICoreClientAPI capi;

		protected Vec3d position;

		[Obsolete]
		protected virtual int RenderTextureId => capi.BlockTextureAtlas.AtlasTextures[0].TextureId;

		public double RenderOrder => 1.0;

		public int RenderRange => 99;

		public AnimationUtil(ICoreAPI api, Vec3d position)
		{
			this.api = api;
			this.position = position;
			capi = api as ICoreClientAPI;
			(api as ICoreClientAPI)?.Event.RegisterRenderer(this, EnumRenderStage.Opaque, "beanimutil");
		}

		public virtual void InitializeShapeAndAnimator(string cacheDictKey, Shape shape, ITexPositionSource texSource, Vec3f rotation, out MeshData meshdata)
		{
			Dictionary<string, ShapeElement> elementsByName = shape.CollectAndResolveReferences(api.World.Logger, cacheDictKey);
			shape.CacheInvTransforms();
			shape.ResolveAndFindJoints(api.World.Logger, cacheDictKey, elementsByName);
			TesselationMetaData meta = new TesselationMetaData
			{
				TexSource = texSource,
				WithJointIds = true,
				WithDamageEffect = true,
				TypeForLogging = cacheDictKey,
				Rotation = rotation
			};
			capi.Tesselator.TesselateShape(meta, shape, out var modeldata);
			meshdata = modeldata;
			InitializeAnimator(cacheDictKey, meshdata, shape, rotation);
		}

		public virtual void InitializeAnimator(string cacheDictKey, MeshData meshdata, Shape shape, Vec3f rotation, EnumRenderStage renderStage = EnumRenderStage.Opaque)
		{
			if (meshdata == null)
			{
				throw new ArgumentException("meshdata cannot be null");
			}
			animator = GetAnimator(api, cacheDictKey, shape);
			renderer?.Dispose();
			if (RuntimeEnv.MainThreadId == Environment.CurrentManagedThreadId)
			{
				renderer = new AnimatableRenderer(capi, position, rotation, animator, activeAnimationsByAnimCode, capi.Render.UploadMultiTextureMesh(meshdata), renderStage);
				return;
			}
			renderer = new AnimatableRenderer(capi, position, rotation, animator, activeAnimationsByAnimCode, null, renderStage);
			capi.Event.EnqueueMainThreadTask(delegate
			{
				renderer.mtmeshref = capi.Render.UploadMultiTextureMesh(meshdata);
			}, "uploadmesh");
		}

		[Obsolete("Use MultiTextureMeshRef initialize instead, standard MeshRef does not support multiple texture atlasses")]
		public virtual void InitializeAnimator(string cacheDictKey, MeshRef meshref, Shape blockShape, Vec3f rotation, EnumRenderStage renderStage = EnumRenderStage.Opaque)
		{
			if (api.Side != EnumAppSide.Client)
			{
				throw new NotImplementedException("Server side animation system not implemented yet.");
			}
			animator = GetAnimator(api, cacheDictKey, blockShape);
			renderer = new AnimatableRenderer(capi, position, rotation, animator, activeAnimationsByAnimCode, meshref, RenderTextureId, renderStage);
		}

		public virtual void InitializeAnimator(string cacheDictKey, MultiTextureMeshRef meshref, Shape blockShape, Vec3f rotation, EnumRenderStage renderStage = EnumRenderStage.Opaque)
		{
			if (api.Side != EnumAppSide.Client)
			{
				throw new NotImplementedException("Server side animation system not implemented yet.");
			}
			animator = GetAnimator(api, cacheDictKey, blockShape);
			renderer = new AnimatableRenderer(capi, position, rotation, animator, activeAnimationsByAnimCode, meshref, renderStage);
		}

		public virtual void InitializeAnimatorServer(string cacheDictKey, Shape blockShape)
		{
			animator = GetAnimator(api, cacheDictKey, blockShape);
		}

		public void AnimationTickServer(float deltaTime)
		{
			if (animator != null && (activeAnimationsByAnimCode.Count > 0 || animator.ActiveAnimationCount > 0))
			{
				animator.OnFrame(activeAnimationsByAnimCode, deltaTime);
			}
		}

		public void OnRenderFrame(float deltaTime, EnumRenderStage stage)
		{
			if (animator == null || renderer == null)
			{
				return;
			}
			ICoreClientAPI obj = api as ICoreClientAPI;
			if (obj == null || !obj.IsGamePaused)
			{
				if (activeAnimationsByAnimCode.Count > 0 || animator.ActiveAnimationCount > 0)
				{
					animator.OnFrame(activeAnimationsByAnimCode, deltaTime);
				}
				if (activeAnimationsByAnimCode.Count == 0 && animator.ActiveAnimationCount == 0 && renderer.ShouldRender && !stopRenderTriggered)
				{
					stopRenderTriggered = true;
					OnAnimationsStateChange(animsNowActive: false);
				}
			}
		}

		public virtual bool StartAnimation(AnimationMetaData meta)
		{
			if (!activeAnimationsByAnimCode.ContainsKey(meta.Code))
			{
				stopRenderTriggered = false;
				activeAnimationsByAnimCode[meta.Code] = meta;
				OnAnimationsStateChange(animsNowActive: true);
				return true;
			}
			return false;
		}

		protected virtual void OnAnimationsStateChange(bool animsNowActive)
		{
		}

		public void StopAnimation(string code)
		{
			activeAnimationsByAnimCode.Remove(code);
		}

		public static AnimatorBase GetAnimator(ICoreAPI api, string cacheDictKey, Shape shape)
		{
			if (shape == null)
			{
				return null;
			}
			cacheDictKey = "animutil-" + cacheDictKey;
			Dictionary<string, AnimCacheEntry> dictionary = null;
			api.ObjectCache.TryGetValue("animUtil-animCache", out var value);
			dictionary = value as Dictionary<string, AnimCacheEntry>;
			if (dictionary == null)
			{
				dictionary = (Dictionary<string, AnimCacheEntry>)(api.ObjectCache["animUtil-animCache"] = new Dictionary<string, AnimCacheEntry>());
			}
			AnimatorBase animatorBase;
			if (dictionary.TryGetValue(cacheDictKey, out var value2))
			{
				animatorBase = ((api.Side == EnumAppSide.Client) ? new ClientAnimator(() => 1.0, value2.RootPoses, value2.Animations, value2.RootElems, shape.JointsById) : new ServerAnimator(() => 1.0, value2.RootPoses, value2.Animations, value2.RootElems, shape.JointsById));
			}
			else
			{
				Animation[] animations = shape.Animations;
				if (animations != null)
				{
					for (int num = 0; num < animations.Length; num++)
					{
						animations[num].GenerateAllFrames(shape.Elements, shape.JointsById);
					}
				}
				animatorBase = ((api.Side == EnumAppSide.Client) ? new ClientAnimator(() => 1.0, shape.Animations, shape.Elements, shape.JointsById) : new ServerAnimator(() => 1.0, shape.Animations, shape.Elements, shape.JointsById));
				dictionary[cacheDictKey] = new AnimCacheEntry
				{
					Animations = shape.Animations,
					RootElems = (animatorBase as ClientAnimator).RootElements,
					RootPoses = (animatorBase as ClientAnimator).RootPoses
				};
			}
			return animatorBase;
		}

		public void Dispose()
		{
			renderer?.Dispose();
			(api as ICoreClientAPI)?.Event.UnregisterRenderer(this, EnumRenderStage.Opaque);
		}
	}
	public delegate double WalkSpeedSupplierDelegate();
	public class AnimFrameCallback
	{
		public float Frame;

		public string Animation;

		public Action Callback;
	}
	public abstract class AnimatorBase : IAnimator
	{
		public static readonly float[] identMat = Mat4f.Create();

		public static readonly HashSet<string> logAntiSpam = new HashSet<string>();

		private WalkSpeedSupplierDelegate WalkSpeedSupplier;

		private Action<string> onAnimationStoppedListener;

		protected int activeAnimCount;

		public ShapeElement[] RootElements;

		public List<ElementPose> RootPoses;

		public RunningAnimation[] anims;

		private readonly Dictionary<string, RunningAnimation> animsByCode;

		public float[] TransformationMatrices;

		public float[] TransformationMatricesDefaultPose;

		public Dictionary<string, AttachmentPointAndPose> AttachmentPointByCode = new Dictionary<string, AttachmentPointAndPose>();

		public RunningAnimation[] CurAnims = new RunningAnimation[20];

		private readonly List<RunningAnimation> activeOrRunning = new List<RunningAnimation>(2);

		public Entity entityForLogging;

		private float accum = 0.25f;

		private double walkSpeed;

		public bool CalculateMatrices { get; set; } = true;

		public float[] Matrices
		{
			get
			{
				if (activeAnimCount <= 0)
				{
					return TransformationMatricesDefaultPose;
				}
				return TransformationMatrices;
			}
		}

		public int ActiveAnimationCount => activeAnimCount;

		[Obsolete("Use Animations instead")]
		public RunningAnimation[] RunningAnimations => Animations;

		public RunningAnimation[] Animations => anims;

		public abstract int MaxJointId { get; }

		public RunningAnimation GetAnimationState(string code)
		{
			if (code == null)
			{
				return null;
			}
			animsByCode.TryGetValue(code.ToLowerInvariant(), out var value);
			return value;
		}

		public AnimatorBase(WalkSpeedSupplierDelegate WalkSpeedSupplier, Animation[] Animations, Action<string> onAnimationStoppedListener = null)
		{
			this.WalkSpeedSupplier = WalkSpeedSupplier;
			this.onAnimationStoppedListener = onAnimationStoppedListener;
			RunningAnimation[] array = (anims = ((Animations == null) ? Array.Empty<RunningAnimation>() : new RunningAnimation[Animations.Length]));
			animsByCode = new Dictionary<string, RunningAnimation>(array.Length);
			Dictionary<string, RunningAnimation> dictionary = animsByCode;
			for (int i = 0; i < array.Length; i++)
			{
				Animation animation = Animations[i];
				animation.Code = animation.Code.ToLowerInvariant();
				RunningAnimation value = (array[i] = new RunningAnimation
				{
					Animation = animation
				});
				dictionary[animation.Code] = value;
			}
		}

		public virtual void OnFrame(Dictionary<string, AnimationMetaData> activeAnimationsByAnimCode, float dt)
		{
			activeAnimCount = 0;
			if ((accum += dt) > 0.25f)
			{
				walkSpeed = ((WalkSpeedSupplier == null) ? 1.0 : WalkSpeedSupplier());
				accum = 0f;
			}
			string text = null;
			foreach (string key in activeAnimationsByAnimCode.Keys)
			{
				if (!animsByCode.TryGetValue(key.ToLowerInvariant(), out var value))
				{
					text = key;
				}
				else if (!value.Active)
				{
					AnimNowActive(value, activeAnimationsByAnimCode[key]);
				}
			}
			if (text != null)
			{
				activeAnimationsByAnimCode.Remove(text);
				if (entityForLogging != null)
				{
					string text2 = entityForLogging.Code.ToShortString();
					string item = text2 + "|" + text;
					if (logAntiSpam.Add(item))
					{
						entityForLogging.World.Logger.Debug(text2 + " attempted to play an animation code which its shape does not have: \"" + text + "\"");
					}
				}
			}
			List<RunningAnimation> list = activeOrRunning;
			for (int num = list.Count - 1; num >= 0; num--)
			{
				RunningAnimation runningAnimation = list[num];
				if (runningAnimation.Active && !activeAnimationsByAnimCode.ContainsKey(runningAnimation.Animation.Code))
				{
					runningAnimation.Active = false;
					EnumEntityActivityStoppedHandling onActivityStopped = runningAnimation.Animation.OnActivityStopped;
					if (onActivityStopped == EnumEntityActivityStoppedHandling.Rewind)
					{
						runningAnimation.ShouldRewind = true;
					}
					if (onActivityStopped == EnumEntityActivityStoppedHandling.Stop)
					{
						runningAnimation.Stop();
						onAnimationStoppedListener?.Invoke(runningAnimation.Animation.Code);
					}
					if (onActivityStopped == EnumEntityActivityStoppedHandling.PlayTillEnd)
					{
						runningAnimation.ShouldPlayTillEnd = true;
					}
				}
				if (runningAnimation.Running && !ProgressRunningAnimation(runningAnimation, dt))
				{
					string code = runningAnimation.Animation.Code;
					activeAnimationsByAnimCode.Remove(code);
					onAnimationStoppedListener?.Invoke(code);
				}
				if (!runningAnimation.Active && !runningAnimation.Running)
				{
					list.RemoveAt(num);
				}
			}
			calculateMatrices(dt);
		}

		private bool ProgressRunningAnimation(RunningAnimation anim, float dt)
		{
			EnumEntityAnimationEndHandling onAnimationEnd = anim.Animation.OnAnimationEnd;
			EnumEntityActivityStoppedHandling onActivityStopped = anim.Animation.OnActivityStopped;
			bool flag = false;
			if (anim.Iterations > 0)
			{
				flag = onAnimationEnd == EnumEntityAnimationEndHandling.Stop || (!anim.Active && (onActivityStopped == EnumEntityActivityStoppedHandling.PlayTillEnd || onActivityStopped == EnumEntityActivityStoppedHandling.EaseOut) && anim.EasingFactor < 0.002f) || (onAnimationEnd == EnumEntityAnimationEndHandling.EaseOut && anim.EasingFactor < 0.002f);
			}
			else if (anim.Iterations < 0)
			{
				flag = !anim.Active && onActivityStopped == EnumEntityActivityStoppedHandling.Rewind && anim.EasingFactor < 0.002f;
			}
			if (flag)
			{
				anim.Stop();
				if (onAnimationEnd == EnumEntityAnimationEndHandling.Stop || onAnimationEnd == EnumEntityAnimationEndHandling.EaseOut)
				{
					return false;
				}
				return true;
			}
			CurAnims[activeAnimCount++] = anim;
			if (anim.Iterations != 0 && ((!anim.Active && onAnimationEnd == EnumEntityAnimationEndHandling.Hold) || onAnimationEnd == EnumEntityAnimationEndHandling.EaseOut))
			{
				anim.EaseOut(dt);
			}
			anim.Progress(dt, (float)walkSpeed);
			return true;
		}

		public virtual string DumpCurrentState()
		{
			StringBuilder stringBuilder = new StringBuilder();
			for (int i = 0; i < anims.Length; i++)
			{
				RunningAnimation runningAnimation = anims[i];
				if (runningAnimation.Active && runningAnimation.Running)
				{
					stringBuilder.Append("Active&Running: " + runningAnimation.Animation.Code);
				}
				else if (runningAnimation.Active)
				{
					stringBuilder.Append("Active: " + runningAnimation.Animation.Code);
				}
				else
				{
					if (!runningAnimation.Running)
					{
						continue;
					}
					stringBuilder.Append("Running: " + runningAnimation.Animation.Code);
				}
				stringBuilder.Append(", easing: " + runningAnimation.EasingFactor);
				stringBuilder.Append(", currentframe: " + runningAnimation.CurrentFrame);
				stringBuilder.Append(", iterations: " + runningAnimation.Iterations);
				stringBuilder.Append(", blendedweight: " + runningAnimation.BlendedWeight);
				stringBuilder.Append(", animmetacode: " + runningAnimation.meta.Code);
				stringBuilder.AppendLine();
			}
			return stringBuilder.ToString();
		}

		protected virtual void AnimNowActive(RunningAnimation anim, AnimationMetaData animData)
		{
			anim.Running = true;
			anim.Active = true;
			if (!activeOrRunning.Contains(anim))
			{
				activeOrRunning.Add(anim);
			}
			anim.meta = animData;
			anim.ShouldRewind = false;
			anim.ShouldPlayTillEnd = false;
			anim.CurrentFrame = animData.StartFrameOnce;
			animData.StartFrameOnce = 0f;
		}

		protected abstract void calculateMatrices(float dt);

		public AttachmentPointAndPose GetAttachmentPointPose(string code)
		{
			AttachmentPointByCode.TryGetValue(code, out var value);
			return value;
		}

		public virtual ElementPose GetPosebyName(string name, StringComparison stringComparison = StringComparison.InvariantCultureIgnoreCase)
		{
			throw new NotImplementedException();
		}

		public virtual void ReloadAttachmentPoints()
		{
			throw new NotImplementedException();
		}
	}
	public class ClientAnimator : AnimatorBase
	{
		public Dictionary<int, AnimationJoint> jointsById;

		protected HashSet<int> jointsDone = new HashSet<int>();

		public static int MaxConcurrentAnimations = 16;

		private int maxDepth;

		private List<ElementPose>[][] frameByDepthByAnimation;

		private List<ElementPose>[][] nextFrameTransformsByAnimation;

		private ShapeElementWeights[][][] weightsByAnimationAndElement;

		private float[] localTransformMatrix = Mat4f.Create();

		private float[] tmpMatrix = Mat4f.Create();

		private Action<AnimationSound> onShouldPlaySoundListener;

		private int[] prevFrame = new int[MaxConcurrentAnimations];

		private int[] nextFrame = new int[MaxConcurrentAnimations];

		private static bool EleWeightDebug = false;

		private Dictionary<string, string> eleWeights = new Dictionary<string, string>();

		public override int MaxJointId => jointsById.Count + 1;

		public static ClientAnimator CreateForEntity(Entity entity, List<ElementPose> rootPoses, Animation[] animations, ShapeElement[] rootElements, Dictionary<int, AnimationJoint> jointsById)
		{
			if (entity is EntityAgent)
			{
				EntityAgent entityag = entity as EntityAgent;
				return new ClientAnimator(() => (double)entityag.Controls.MovespeedMultiplier * entityag.GetWalkSpeedMultiplier(), rootPoses, animations, rootElements, jointsById, entity.AnimManager.TriggerAnimationStopped, entity.AnimManager.ShouldPlaySound);
			}
			return new ClientAnimator(() => 1.0, rootPoses, animations, rootElements, jointsById, entity.AnimManager.TriggerAnimationStopped, entity.AnimManager.ShouldPlaySound);
		}

		public static ClientAnimator CreateForEntity(Entity entity, Animation[] animations, ShapeElement[] rootElements, Dictionary<int, AnimationJoint> jointsById)
		{
			if (entity is EntityAgent)
			{
				EntityAgent entityag = entity as EntityAgent;
				return new ClientAnimator(() => (double)entityag.Controls.MovespeedMultiplier * entityag.GetWalkSpeedMultiplier(), animations, rootElements, jointsById, entity.AnimManager.TriggerAnimationStopped, entity.AnimManager.ShouldPlaySound);
			}
			return new ClientAnimator(() => 1.0, animations, rootElements, jointsById, entity.AnimManager.TriggerAnimationStopped, entity.AnimManager.ShouldPlaySound);
		}

		public ClientAnimator(WalkSpeedSupplierDelegate walkSpeedSupplier, Animation[] animations, Action<string> onAnimationStoppedListener = null, Action<AnimationSound> onShouldPlaySoundListener = null)
			: base(walkSpeedSupplier, animations, onAnimationStoppedListener)
		{
			this.onShouldPlaySoundListener = onShouldPlaySoundListener;
			initFields();
		}

		public ClientAnimator(WalkSpeedSupplierDelegate walkSpeedSupplier, List<ElementPose> rootPoses, Animation[] animations, ShapeElement[] rootElements, Dictionary<int, AnimationJoint> jointsById, Action<string> onAnimationStoppedListener = null, Action<AnimationSound> onShouldPlaySoundListener = null)
			: base(walkSpeedSupplier, animations, onAnimationStoppedListener)
		{
			RootElements = rootElements;
			this.jointsById = jointsById;
			RootPoses = rootPoses;
			this.onShouldPlaySoundListener = onShouldPlaySoundListener;
			LoadAttachmentPoints(RootPoses);
			initFields();
			initMatrices(MaxJointId);
		}

		public ClientAnimator(WalkSpeedSupplierDelegate walkSpeedSupplier, Animation[] animations, ShapeElement[] rootElements, Dictionary<int, AnimationJoint> jointsById, Action<string> onAnimationStoppedListener = null, Action<AnimationSound> onShouldPlaySoundListener = null)
			: base(walkSpeedSupplier, animations, onAnimationStoppedListener)
		{
			RootElements = rootElements;
			this.jointsById = jointsById;
			RootPoses = new List<ElementPose>();
			LoadPosesAndAttachmentPoints(rootElements, RootPoses);
			this.onShouldPlaySoundListener = onShouldPlaySoundListener;
			initFields();
			initMatrices(MaxJointId);
		}

		protected virtual void initFields()
		{
			maxDepth = 2 + ((RootPoses != null) ? getMaxDepth(RootPoses, 1) : 0);
			frameByDepthByAnimation = new List<ElementPose>[maxDepth][];
			nextFrameTransformsByAnimation = new List<ElementPose>[maxDepth][];
			weightsByAnimationAndElement = new ShapeElementWeights[maxDepth][][];
			for (int i = 0; i < maxDepth; i++)
			{
				frameByDepthByAnimation[i] = new List<ElementPose>[MaxConcurrentAnimations];
				nextFrameTransformsByAnimation[i] = new List<ElementPose>[MaxConcurrentAnimations];
				weightsByAnimationAndElement[i] = new ShapeElementWeights[MaxConcurrentAnimations][];
			}
		}

		protected virtual void initMatrices(int maxJointId)
		{
			float[] array = AnimatorBase.identMat;
			float[] array2 = new float[16 * maxJointId];
			for (int i = 0; i < array2.Length; i++)
			{
				array2[i] = array[i % 16];
			}
			TransformationMatricesDefaultPose = array2;
			TransformationMatrices = new float[array2.Length];
		}

		public override void ReloadAttachmentPoints()
		{
			LoadAttachmentPoints(RootPoses);
		}

		protected virtual void LoadAttachmentPoints(List<ElementPose> cachedPoses)
		{
			for (int i = 0; i < cachedPoses.Count; i++)
			{
				ElementPose elementPose = cachedPoses[i];
				AttachmentPoint[] attachmentPoints = elementPose.ForElement.AttachmentPoints;
				if (attachmentPoints != null)
				{
					foreach (AttachmentPoint attachmentPoint in attachmentPoints)
					{
						AttachmentPointByCode[attachmentPoint.Code] = new AttachmentPointAndPose
						{
							AttachPoint = attachmentPoint,
							CachedPose = elementPose
						};
					}
				}
				if (elementPose.ChildElementPoses != null)
				{
					LoadAttachmentPoints(elementPose.ChildElementPoses);
				}
			}
		}

		protected virtual void LoadPosesAndAttachmentPoints(ShapeElement[] elements, List<ElementPose> intoPoses)
		{
			foreach (ShapeElement shapeElement in elements)
			{
				ElementPose elementPose;
				intoPoses.Add(elementPose = new ElementPose());
				elementPose.AnimModelMatrix = Mat4f.Create();
				elementPose.ForElement = shapeElement;
				if (shapeElement.AttachmentPoints != null)
				{
					for (int j = 0; j < shapeElement.AttachmentPoints.Length; j++)
					{
						AttachmentPoint attachmentPoint = shapeElement.AttachmentPoints[j];
						AttachmentPointByCode[attachmentPoint.Code] = new AttachmentPointAndPose
						{
							AttachPoint = attachmentPoint,
							CachedPose = elementPose
						};
					}
				}
				if (shapeElement.Children != null)
				{
					elementPose.ChildElementPoses = new List<ElementPose>(shapeElement.Children.Length);
					LoadPosesAndAttachmentPoints(shapeElement.Children, elementPose.ChildElementPoses);
				}
			}
		}

		private int getMaxDepth(List<ElementPose> poses, int depth)
		{
			for (int i = 0; i < poses.Count; i++)
			{
				ElementPose elementPose = poses[i];
				if (elementPose.ChildElementPoses != null)
				{
					depth = getMaxDepth(elementPose.ChildElementPoses, depth);
				}
			}
			return depth + 1;
		}

		public override ElementPose GetPosebyName(string name, StringComparison stringComparison = StringComparison.InvariantCultureIgnoreCase)
		{
			return getPosebyName(RootPoses, name);
		}

		private ElementPose getPosebyName(List<ElementPose> poses, string name, StringComparison stringComparison = StringComparison.InvariantCultureIgnoreCase)
		{
			for (int i = 0; i < poses.Count; i++)
			{
				ElementPose elementPose = poses[i];
				if (elementPose.ForElement.Name.Equals(name, stringComparison))
				{
					return elementPose;
				}
				if (elementPose.ChildElementPoses != null)
				{
					ElementPose posebyName = getPosebyName(elementPose.ChildElementPoses, name);
					if (posebyName != null)
					{
						return posebyName;
					}
				}
			}
			return null;
		}

		protected override void AnimNowActive(RunningAnimation anim, AnimationMetaData animData)
		{
			base.AnimNowActive(anim, animData);
			if (anim.Animation.PrevNextKeyFrameByFrame == null)
			{
				anim.Animation.GenerateAllFrames(RootElements, jointsById);
			}
			anim.LoadWeights(RootElements);
		}

		public override void OnFrame(Dictionary<string, AnimationMetaData> activeAnimationsByAnimCode, float dt)
		{
			for (int i = 0; i < activeAnimCount; i++)
			{
				RunningAnimation runningAnimation = CurAnims[i];
				if (runningAnimation.Animation.PrevNextKeyFrameByFrame == null && runningAnimation.Animation.KeyFrames.Length != 0)
				{
					runningAnimation.Animation.GenerateAllFrames(RootElements, jointsById);
				}
				if (runningAnimation.meta.AnimationSound != null && onShouldPlaySoundListener != null && runningAnimation.CurrentFrame >= (float)runningAnimation.meta.AnimationSound.Frame && runningAnimation.SoundPlayedAtIteration != runningAnimation.Iterations && runningAnimation.Active)
				{
					onShouldPlaySoundListener(runningAnimation.meta.AnimationSound);
					runningAnimation.SoundPlayedAtIteration = runningAnimation.Iterations;
				}
			}
			base.OnFrame(activeAnimationsByAnimCode, dt);
		}

		protected override void calculateMatrices(float dt)
		{
			if (!base.CalculateMatrices)
			{
				return;
			}
			jointsDone.Clear();
			int num = 0;
			for (int i = 0; i < activeAnimCount; i++)
			{
				RunningAnimation runningAnimation = CurAnims[i];
				weightsByAnimationAndElement[0][i] = runningAnimation.ElementWeights;
				num = Math.Max(num, runningAnimation.Animation.Version);
				AnimationFrame[] array = runningAnimation.Animation.PrevNextKeyFrameByFrame[(int)runningAnimation.CurrentFrame % runningAnimation.Animation.QuantityFrames];
				frameByDepthByAnimation[0][i] = array[0].RootElementTransforms;
				prevFrame[i] = array[0].FrameNumber;
				if (runningAnimation.Animation.OnAnimationEnd == EnumEntityAnimationEndHandling.Hold && (int)runningAnimation.CurrentFrame + 1 == runningAnimation.Animation.QuantityFrames)
				{
					nextFrameTransformsByAnimation[0][i] = array[0].RootElementTransforms;
					nextFrame[i] = array[0].FrameNumber;
				}
				else
				{
					nextFrameTransformsByAnimation[0][i] = array[1].RootElementTransforms;
					nextFrame[i] = array[1].FrameNumber;
				}
			}
			calculateMatrices(num, dt, RootPoses, weightsByAnimationAndElement[0], Mat4f.Create(), frameByDepthByAnimation[0], nextFrameTransformsByAnimation[0], 0);
			float[] transformationMatrices = TransformationMatrices;
			if (transformationMatrices != null)
			{
				for (int j = 0; j < transformationMatrices.Length; j += 16)
				{
					if (!jointsById.ContainsKey(j / 16))
					{
						for (int k = 0; k < 16; k++)
						{
							transformationMatrices[j + k] = AnimatorBase.identMat[k];
						}
					}
				}
			}
			foreach (KeyValuePair<string, AttachmentPointAndPose> item in AttachmentPointByCode)
			{
				float[] animModelMatrix = item.Value.CachedPose.AnimModelMatrix;
				float[] animModelMatrix2 = item.Value.AnimModelMatrix;
				for (int l = 0; l < 16; l++)
				{
					animModelMatrix2[l] = animModelMatrix[l];
				}
			}
		}

		private void calculateMatrices(int animVersion, float dt, List<ElementPose> outFrame, ShapeElementWeights[][] weightsByAnimationAndElement, float[] modelMatrix, List<ElementPose>[] nowKeyFrameByAnimation, List<ElementPose>[] nextInKeyFrameByAnimation, int depth)
		{
			depth++;
			List<ElementPose>[] array = frameByDepthByAnimation[depth];
			List<ElementPose>[] array2 = nextFrameTransformsByAnimation[depth];
			ShapeElementWeights[][] array3 = this.weightsByAnimationAndElement[depth];
			for (int i = 0; i < outFrame.Count; i++)
			{
				ElementPose elementPose = outFrame[i];
				ShapeElement forElement = elementPose.ForElement;
				elementPose.SetMat(modelMatrix);
				Mat4f.Identity(localTransformMatrix);
				elementPose.Clear();
				float num = 0f;
				for (int j = 0; j < activeAnimCount; j++)
				{
					RunningAnimation runningAnimation = CurAnims[j];
					ShapeElementWeights shapeElementWeights = weightsByAnimationAndElement[j][i];
					if (shapeElementWeights.BlendMode != EnumAnimationBlendMode.Add)
					{
						num += shapeElementWeights.Weight * runningAnimation.EasingFactor;
					}
				}
				for (int k = 0; k < activeAnimCount; k++)
				{
					RunningAnimation runningAnimation2 = CurAnims[k];
					ShapeElementWeights shapeElementWeights2 = weightsByAnimationAndElement[k][i];
					runningAnimation2.CalcBlendedWeight(num / shapeElementWeights2.Weight, shapeElementWeights2.BlendMode);
					ElementPose elementPose2 = nowKeyFrameByAnimation[k][i];
					ElementPose elementPose3 = nextInKeyFrameByAnimation[k][i];
					int num2 = prevFrame[k];
					int num3 = nextFrame[k];
					float num4 = ((num3 > num2) ? (num3 - num2) : (runningAnimation2.Animation.QuantityFrames - num2 + num3));
					float l = ((runningAnimation2.CurrentFrame >= (float)num2) ? (runningAnimation2.CurrentFrame - (float)num2) : ((float)(runningAnimation2.Animation.QuantityFrames - num2) + runningAnimation2.CurrentFrame)) / num4;
					elementPose.Add(elementPose2, elementPose3, l, runningAnimation2.BlendedWeight);
					array[k] = elementPose2.ChildElementPoses;
					array3[k] = shapeElementWeights2.ChildElements;
					array2[k] = elementPose3.ChildElementPoses;
				}
				forElement.GetLocalTransformMatrix(animVersion, localTransformMatrix, elementPose);
				Mat4f.Mul(elementPose.AnimModelMatrix, elementPose.AnimModelMatrix, localTransformMatrix);
				if (TransformationMatrices != null && forElement.JointId > 0 && !jointsDone.Contains(forElement.JointId))
				{
					Mat4f.Mul(tmpMatrix, elementPose.AnimModelMatrix, forElement.inverseModelTransform);
					int num5 = 16 * forElement.JointId;
					float[] transformationMatrices = TransformationMatrices;
					float[] array4 = tmpMatrix;
					if (num5 + 16 > transformationMatrices.Length)
					{
						float[] transformationMatricesDefaultPose = TransformationMatricesDefaultPose;
						initMatrices(forElement.JointId + 1);
						Array.Copy(transformationMatrices, TransformationMatrices, transformationMatrices.Length);
						Array.Copy(transformationMatricesDefaultPose, TransformationMatricesDefaultPose, transformationMatricesDefaultPose.Length);
						transformationMatrices = TransformationMatrices;
					}
					for (int m = 0; m < 16; m++)
					{
						transformationMatrices[num5 + m] = array4[m];
					}
					jointsDone.Add(forElement.JointId);
				}
				if (elementPose.ChildElementPoses != null)
				{
					calculateMatrices(animVersion, dt, elementPose.ChildElementPoses, array3, elementPose.AnimModelMatrix, array, array2, depth);
				}
			}
		}

		public override string DumpCurrentState()
		{
			EleWeightDebug = true;
			eleWeights.Clear();
			calculateMatrices(1f / 60f);
			EleWeightDebug = false;
			return base.DumpCurrentState() + "\nElement weights:\n" + string.Join("\n", eleWeights.Select((KeyValuePair<string, string> x) => x.Key + ": " + x.Value));
		}
	}
	public class ElementPose
	{
		public ShapeElement ForElement;

		public float[] AnimModelMatrix;

		public List<ElementPose> ChildElementPoses = new List<ElementPose>();

		public float degOffX;

		public float degOffY;

		public float degOffZ;

		public float degX;

		public float degY;

		public float degZ;

		public float scaleX = 1f;

		public float scaleY = 1f;

		public float scaleZ = 1f;

		public float translateX;

		public float translateY;

		public float translateZ;

		public bool RotShortestDistanceX;

		public bool RotShortestDistanceY;

		public bool RotShortestDistanceZ;

		public void Clear()
		{
			degX = 0f;
			degY = 0f;
			degZ = 0f;
			scaleX = 1f;
			scaleY = 1f;
			scaleZ = 1f;
			translateX = 0f;
			translateY = 0f;
			translateZ = 0f;
		}

		public void Add(ElementPose tf, ElementPose tfNext, float l, float weight)
		{
			if (tf.RotShortestDistanceX)
			{
				float num = GameMath.AngleDegDistance(tf.degX, tfNext.degX);
				degX += tf.degX + num * l;
			}
			else
			{
				degX += (tf.degX * (1f - l) + tfNext.degX * l) * weight;
			}
			if (tf.RotShortestDistanceY)
			{
				float num2 = GameMath.AngleDegDistance(tf.degY, tfNext.degY);
				degY += tf.degY + num2 * l;
			}
			else
			{
				degY += (tf.degY * (1f - l) + tfNext.degY * l) * weight;
			}
			if (tf.RotShortestDistanceZ)
			{
				float num3 = GameMath.AngleDegDistance(tf.degZ, tfNext.degZ);
				degZ += tf.degZ + num3 * l;
			}
			else
			{
				degZ += (tf.degZ * (1f - l) + tfNext.degZ * l) * weight;
			}
			scaleX += ((tf.scaleX - 1f) * (1f - l) + (tfNext.scaleX - 1f) * l) * weight;
			scaleY += ((tf.scaleY - 1f) * (1f - l) + (tfNext.scaleY - 1f) * l) * weight;
			scaleZ += ((tf.scaleZ - 1f) * (1f - l) + (tfNext.scaleZ - 1f) * l) * weight;
			translateX += (tf.translateX * (1f - l) + tfNext.translateX * l) * weight;
			translateY += (tf.translateY * (1f - l) + tfNext.translateY * l) * weight;
			translateZ += (tf.translateZ * (1f - l) + tfNext.translateZ * l) * weight;
		}

		internal void SetMat(float[] modelMatrix)
		{
			for (int i = 0; i < 16; i++)
			{
				AnimModelMatrix[i] = modelMatrix[i];
			}
		}

		public override string ToString()
		{
			return $"translate: {translateX}/{translateY}/{translateZ}, rotate: {degX}/{degY}/{degZ}, scale: {scaleX}/{scaleY}/{scaleZ}";
		}
	}
	public class PlayerHeadController : EntityHeadController
	{
		protected IPlayer player;

		private EntityPlayer entityPlayer;

		protected bool turnOpposite;

		protected bool rotateTpYawNow;

		public PlayerHeadController(IAnimationManager animator, EntityPlayer entity, Shape entityShape)
			: base(animator, entity, entityShape)
		{
			entityPlayer = entity;
		}

		public override void OnFrame(float dt)
		{
			if (player == null)
			{
				player = entityPlayer.Player;
			}
			ICoreClientAPI coreClientAPI = entity.Api as ICoreClientAPI;
			if (coreClientAPI.World.Player.Entity.EntityId != entity.EntityId)
			{
				base.OnFrame(dt);
				if (entity.BodyYawServer == 0f)
				{
					entity.BodyYaw = entity.Pos.Yaw;
				}
				return;
			}
			float num = GameMath.AngleRadDistance(entity.BodyYaw, entity.Pos.Yaw);
			if (Math.Abs(num) > 1.8849558f)
			{
				turnOpposite = true;
			}
			if (turnOpposite)
			{
				if (Math.Abs(num) < (float)Math.PI * 9f / 20f)
				{
					turnOpposite = false;
				}
				else
				{
					num = 0f;
				}
			}
			EnumCameraMode cameraMode = (player as IClientPlayer).CameraMode;
			bool flag = coreClientAPI.Settings.Bool["overheadLookAt"] && cameraMode == EnumCameraMode.Overhead;
			if (!flag && coreClientAPI.Input.MouseGrabbed)
			{
				entity.Pos.HeadYaw += (num - entity.Pos.HeadYaw) * dt * 6f;
				entity.Pos.HeadYaw = GameMath.Clamp(entity.Pos.HeadYaw, -0.75f, 0.75f);
				entity.Pos.HeadPitch = GameMath.Clamp((entity.Pos.Pitch - (float)Math.PI) * 0.75f, -1.2f, 1.2f);
			}
			EnumMountAngleMode enumMountAngleMode = EnumMountAngleMode.Unaffected;
			IMountableSeat mountedOn = player.Entity.MountedOn;
			if (player.Entity.MountedOn != null)
			{
				enumMountAngleMode = mountedOn.AngleMode;
			}
			if (player?.Entity == null || enumMountAngleMode == EnumMountAngleMode.Fixate || enumMountAngleMode == EnumMountAngleMode.FixateYaw || cameraMode == EnumCameraMode.Overhead)
			{
				if (coreClientAPI.Input.MouseGrabbed)
				{
					entity.BodyYaw = entity.Pos.Yaw;
					if (flag)
					{
						float num2 = 0f - GameMath.AngleRadDistance((entity.Api as ICoreClientAPI).Input.MouseYaw, entity.Pos.Yaw);
						float num3 = (float)Math.PI + num2;
						float num4 = GameMath.Clamp(0f - entity.Pos.Pitch - (float)Math.PI + (float)Math.PI * 2f, -1f, 0.8f);
						if (num3 > (float)Math.PI)
						{
							num3 -= (float)Math.PI * 2f;
						}
						if (num3 < -1f || num3 > 1f)
						{
							num3 = 0f;
							entity.Pos.HeadPitch += (GameMath.Clamp((entity.Pos.Pitch - (float)Math.PI) * 0.75f, -1.2f, 1.2f) - entity.Pos.HeadPitch) * dt * 6f;
						}
						else
						{
							entity.Pos.HeadPitch += (num4 - entity.Pos.HeadPitch) * dt * 6f;
						}
						entity.Pos.HeadYaw += (num3 - entity.Pos.HeadYaw) * dt * 6f;
					}
				}
			}
			else
			{
				IPlayer obj = player;
				if (obj != null && obj.Entity.Alive)
				{
					float num5 = GameMath.AngleRadDistance(entity.BodyYaw, entity.Pos.Yaw);
					bool flag2 = player.Entity.Controls.TriesToMove || player.Entity.ServerControls.TriesToMove;
					bool flag3 = false;
					float num6 = 1.2f - (flag2 ? 1.19f : 0f) + (float)(flag3 ? 3 : 0);
					if (entity.Controls.Gliding)
					{
						num6 = 0f;
					}
					if (player.PlayerUID == coreClientAPI.World.Player.PlayerUID && !coreClientAPI.Settings.Bool["immersiveFpMode"] && cameraMode != EnumCameraMode.FirstPerson)
					{
						if (Math.Abs(num5) > num6 || rotateTpYawNow)
						{
							float num7 = 0.05f + Math.Abs(num5) * 3.5f;
							entity.BodyYaw += GameMath.Clamp(num5, (0f - dt) * num7, dt * num7);
							rotateTpYawNow = Math.Abs(num5) > 0.01f;
						}
					}
					else
					{
						entity.BodyYaw = entity.Pos.Yaw;
					}
				}
			}
			base.OnFrame(dt);
		}
	}
	public class EntityHeadController
	{
		public ElementPose HeadPose;

		public ElementPose NeckPose;

		public ElementPose UpperTorsoPose;

		public ElementPose LowerTorsoPose;

		public ElementPose UpperFootLPose;

		public ElementPose UpperFootRPose;

		protected EntityAgent entity;

		protected IAnimationManager animManager;

		public float yawOffset;

		public float pitchOffset;

		public EntityHeadController(IAnimationManager animator, EntityAgent entity, Shape entityShape)
		{
			this.entity = entity;
			animManager = animator;
			HeadPose = animator.Animator.GetPosebyName("Head");
			NeckPose = animator.Animator.GetPosebyName("Neck");
			UpperTorsoPose = animator.Animator.GetPosebyName("UpperTorso");
			LowerTorsoPose = animator.Animator.GetPosebyName("LowerTorso");
			UpperFootRPose = animator.Animator.GetPosebyName("UpperFootR");
			UpperFootLPose = animator.Animator.GetPosebyName("UpperFootL");
		}

		public virtual void OnFrame(float dt)
		{
			HeadPose.degOffY = 0f;
			HeadPose.degOffZ = 0f;
			NeckPose.degOffZ = 0f;
			UpperTorsoPose.degOffY = 0f;
			UpperTorsoPose.degOffZ = 0f;
			LowerTorsoPose.degOffZ = 0f;
			UpperFootRPose.degOffZ = 0f;
			UpperFootLPose.degOffZ = 0f;
			if (entity.Pos.HeadYaw != 0f || entity.Pos.HeadPitch != 0f)
			{
				float num = (entity.Pos.HeadYaw + yawOffset) * (180f / (float)Math.PI);
				float num2 = (entity.Pos.HeadPitch + pitchOffset) * (180f / (float)Math.PI);
				HeadPose.degOffY = num * 0.45f;
				HeadPose.degOffZ = num2 * 0.35f;
				NeckPose.degOffY = num * 0.35f;
				NeckPose.degOffZ = num2 * 0.4f;
				ICoreClientAPI obj = entity.World.Api as ICoreClientAPI;
				IPlayer player = (entity as EntityPlayer)?.Player;
				IPlayer obj2 = ((obj?.World.Player.PlayerUID == player?.PlayerUID) ? player : null);
				if (obj2 != null && obj2.ImmersiveFpMode)
				{
					UpperTorsoPose.degOffZ = num2 * 0.3f;
					UpperTorsoPose.degOffY = num * 0.2f;
					float num3 = num2 * 0.1f;
					LowerTorsoPose.degOffZ = num3;
					UpperFootRPose.degOffZ = 0f - num3;
					UpperFootLPose.degOffZ = 0f - num3;
				}
			}
		}
	}
	public class AttachmentPointAndPose
	{
		public float[] AnimModelMatrix;

		public ElementPose CachedPose;

		public AttachmentPoint AttachPoint;

		public AttachmentPointAndPose()
		{
			AnimModelMatrix = Mat4f.Create();
		}

		public Matrixf Mul(Matrixf m)
		{
			AttachmentPoint attachPoint = AttachPoint;
			m.Mul(AnimModelMatrix);
			m.Translate(attachPoint.PosX / 16.0, attachPoint.PosY / 16.0, attachPoint.PosZ / 16.0);
			m.Translate(-0.5f, -0.5f, -0.5f);
			m.RotateX((float)attachPoint.RotationX * ((float)Math.PI / 180f));
			m.RotateY((float)attachPoint.RotationY * ((float)Math.PI / 180f));
			m.RotateZ((float)attachPoint.RotationZ * ((float)Math.PI / 180f));
			m.Translate(0.5f, 0.5f, 0.5f);
			return m;
		}

		public Matrixf MulUncentered(Matrixf m)
		{
			AttachmentPoint attachPoint = AttachPoint;
			m.Mul(AnimModelMatrix);
			m.Translate(attachPoint.PosX / 16.0, attachPoint.PosY / 16.0, attachPoint.PosZ / 16.0);
			m.RotateX((float)attachPoint.RotationX * ((float)Math.PI / 180f));
			m.RotateY((float)attachPoint.RotationY * ((float)Math.PI / 180f));
			m.RotateZ((float)attachPoint.RotationZ * ((float)Math.PI / 180f));
			return m;
		}
	}
