		{
			if (velocity != null)
			{
				return velocity;
			}
			Vec3f vec3f = new Vec3f(1.5f - 3f * (float)rand.NextDouble(), 1.5f - 3f * (float)rand.NextDouble(), 1.5f - 3f * (float)rand.NextDouble());
			if (block.IsLiquid())
			{
				vec3f.Y += 4f;
			}
			return vec3f;
		}

		public override void ToBytes(BinaryWriter writer)
		{
			particlePos.ToBytes(writer);
			blockpos.ToBytes(writer);
			writer.Write(quantity);
			writer.Write(radius);
			writer.Write(scale);
			writer.Write(velocity != null);
			if (velocity != null)
			{
				velocity.ToBytes(writer);
			}
		}

		public override void FromBytes(BinaryReader reader, IWorldAccessor resolver)
		{
			particlePos = Vec3d.CreateFromBytes(reader);
			blockpos = BlockPos.CreateFromBytes(reader);
			quantity = reader.ReadInt32();
			radius = reader.ReadSingle();
			scale = reader.ReadSingle();
			if (reader.ReadBoolean())
			{
				velocity = Vec3f.CreateFromBytes(reader);
			}
		}
	}
