		{
			get
			{
				tmpPos.Set(MinPos.X + AddPos.X * rand.NextDouble(), MinPos.Y + AddPos.Y * rand.NextDouble(), MinPos.Z + AddPos.Z * rand.NextDouble());
				return tmpPos;
			}
		}

