		public virtual bool TryEarlyLoadCollectibleMappings(IWorldAccessor worldForNewMappings, Dictionary<int, AssetLocation> oldBlockIdMapping, Dictionary<int, AssetLocation> oldItemIdMapping, int schematicSeed, bool resolveImports)
		{
			bool flag = false;
			EntityProperties entityType = worldForNewMappings.GetEntityType(Code);
			World = worldForNewMappings;
			List<EntityBehaviorAndConfig> list = entityType?.Server.BehaviorsWithEarlyLoadCollectibleMappings(this, worldForNewMappings);
			if (list != null)
			{
				foreach (EntityBehaviorAndConfig item in list)
				{
					try
					{
						flag |= item.Behavior.TryEarlyLoadCollectibleMappings(worldForNewMappings, oldBlockIdMapping, oldItemIdMapping, resolveImports, entityType, item.BehaviorConfig);
					}
					catch (Exception e)
					{
						worldForNewMappings.Logger.Error($"Error during TryEarlyLoadCollectibleMappings for {item.Behavior.GetType()} on {Code} at {Pos.AsBlockPos}");
						worldForNewMappings.Logger.Error(e);
					}
				}
			}
			return flag;
		}

		public virtual string GetName()
		{
			string text = null;
			foreach (EntityBehavior behavior in SidedProperties.Behaviors)
			{
				EnumHandling handling = EnumHandling.PassThrough;
				string name = behavior.GetName(ref handling);
				switch (handling)
				{
				case EnumHandling.PreventSubsequent:
					return text;
				case EnumHandling.PreventDefault:
					text = name;
					break;
				}
			}
			if (text != null)
			{
				return text;
			}
			if (!Alive)
			{
				return Lang.GetMatching(Code.Domain + ":item-dead-creature-" + Code.Path);
			}
			return Lang.GetMatching(Code.Domain + ":item-creature-" + Code.Path);
		}

		public virtual string GetPrefixAndCreatureName(string languageCode = null)
		{
			if (languageCode == null)
			{
				languageCode = Lang.CurrentLocale;
			}
			string key = Code.Domain + ":prefixandcreature-" + Code.Path;
			string key2 = Code.Domain + ":prefixandcreature-" + Code.Path.Replace("-", "");
			return Lang.AvailableLanguages[languageCode].GetMatchingIfExists(key) ?? Lang.AvailableLanguages[languageCode].GetMatchingIfExists(key2) ?? Lang.GetL(languageCode, "generic-wildanimal");
		}

		public virtual string GetInfoText()
		{
			StringBuilder stringBuilder = new StringBuilder();
			foreach (EntityBehavior behavior in SidedProperties.Behaviors)
			{
				behavior.GetInfoText(stringBuilder);
			}
			int num = WatchedAttributes.GetInt("generation");
			if (num > 0)
			{
				stringBuilder.AppendLine(Lang.Get("Generation: {0}", num));
			}
			if (!Alive && WatchedAttributes.HasAttribute("deathByPlayer"))
			{
				stringBuilder.AppendLine(Lang.Get("Killed by Player: {0}", WatchedAttributes.GetString("deathByPlayer")));
			}
			if (WatchedAttributes.HasAttribute("extraInfoText"))
			{
				foreach (KeyValuePair<string, IAttribute> item in WatchedAttributes.GetTreeAttribute("extraInfoText").SortedCopy())
				{
					stringBuilder.AppendLine(item.Value.ToString());
				}
			}
			if (Api is ICoreClientAPI coreClientAPI && coreClientAPI.Settings.Bool["extendedDebugInfo"])
			{
				stringBuilder.AppendLine("<font color=\"#bbbbbb\">Id:" + EntityId + "</font>");
				stringBuilder.AppendLine(string.Concat("<font color=\"#bbbbbb\">Code: ", Code, "</font>"));
				IEnumerable<string> source = Tags.ToArray().Select(Api.TagRegistry.EntityTagIdToTag).Order();
				if (source.Any())
				{
					StringBuilder stringBuilder2 = stringBuilder;
					StringBuilder.AppendInterpolatedStringHandler handler = new StringBuilder.AppendInterpolatedStringHandler(35, 1, stringBuilder2);
					handler.AppendLiteral("<font color=\"#bbbbbb\">Tags: ");
					handler.AppendFormatted(source.Aggregate((string first, string second) => first + ", " + second));
					handler.AppendLiteral("</font>");
					stringBuilder2.AppendLine(ref handler);
				}
			}
			return stringBuilder.ToString();
		}

