		{
			double num = x - pos.X;
			double num2 = z - pos.Z;
			return GameMath.Sqrt(num * num + num2 * num2);
		}

		public double HorDistanceTo(double x, double z)
		{
			double num = this.x - x;
			double num2 = this.z - z;
			return GameMath.Sqrt(num * num + num2 * num2);
		}

		public double HorDistanceTo(EntityPos pos)
		{
			double num = x - pos.x;
			double num2 = z - pos.z;
			return GameMath.Sqrt(num * num + num2 * num2);
		}

		public float SquareDistanceTo(EntityPos pos)
		{
			double num = x - pos.x;
			double num2 = InternalY - pos.InternalY;
			double num3 = z - pos.z;
			return (float)(num * num + num2 * num2 + num3 * num3);
		}

		public EntityPos Copy()
		{
			return new EntityPos
			{
				X = x,
				y = y,
				z = z,
				yaw = yaw,
				pitch = pitch,
				roll = roll,
				HeadYaw = HeadYaw,
				HeadPitch = HeadPitch,
				Motion = new Vec3d(Motion.X, Motion.Y, Motion.Z),
				Dimension = Dimension
			};
		}

		public Vec3f GetViewVector()
		{
			return GetViewVector(pitch, yaw);
		}

		public static Vec3f GetViewVector(float pitch, float yaw)
		{
			float num = GameMath.Cos(pitch);
			float num2 = GameMath.Sin(pitch);
			float num3 = GameMath.Cos(yaw);
			float num4 = GameMath.Sin(yaw);
			return new Vec3f((0f - num) * num4, num2, (0f - num) * num3);
		}

		public EntityPos AheadCopy(double offset)
		{
			float num = GameMath.Cos(pitch);
			float num2 = GameMath.Sin(pitch);
			float num3 = GameMath.Cos(yaw);
			float num4 = GameMath.Sin(yaw);
			return new EntityPos(x - (double)(num * num4) * offset, y + (double)num2 * offset, z - (double)(num * num3) * offset, yaw, pitch, roll)
			{
				Dimension = Dimension
			};
		}

		public EntityPos HorizontalAheadCopy(double offset)
		{
			float num = GameMath.Cos(yaw);
			float num2 = GameMath.Sin(yaw);
			return new EntityPos(x + (double)num2 * offset, y, z + (double)num * offset, yaw, pitch, roll)
			{
				Dimension = Dimension
			};
		}

		public EntityPos BehindCopy(double offset)
		{
			float num = GameMath.Cos(0f - yaw);
			float num2 = GameMath.Sin(0f - yaw);
			return new EntityPos(x + (double)num2 * offset, y, z + (double)num * offset, yaw, pitch, roll)
			{
				Dimension = Dimension
			};
		}

		public bool BasicallySameAs(EntityPos pos, double epsilon = 0.0001)
		{
			double num = epsilon * epsilon;
			if (GameMath.SumOfSquares(x - pos.x, y - pos.y, z - pos.z) >= num)
			{
				return false;
			}
			if (GameMath.Square(roll - pos.roll) < num && GameMath.Square(yaw - pos.yaw) < num && GameMath.Square(pitch - pos.pitch) < num)
			{
				return GameMath.SumOfSquares(Motion.X - pos.Motion.X, Motion.Y - pos.Motion.Y, Motion.Z - pos.Motion.Z) < num;
			}
			return false;
		}

		public bool BasicallySameAsIgnoreMotion(EntityPos pos, double epsilon = 0.0001)
		{
			double num = epsilon * epsilon;
			if (GameMath.Square(x - pos.x) >= num || GameMath.Square(y - pos.y) >= num || GameMath.Square(z - pos.z) >= num)
			{
				return false;
			}
			if (GameMath.Square(roll - pos.roll) < num && GameMath.Square(yaw - pos.yaw) < num)
			{
				return GameMath.Square(pitch - pos.pitch) < num;
			}
			return false;
		}

		public bool BasicallySameAsIgnoreAngles(EntityPos pos, double epsilon = 0.0001)
		{
			double num = epsilon * epsilon;
			if (GameMath.SumOfSquares(x - pos.x, y - pos.y, z - pos.z) < num)
			{
				return GameMath.SumOfSquares(Motion.X - pos.Motion.X, Motion.Y - pos.Motion.Y, Motion.Z - pos.Motion.Z) < num;
			}
			return false;
		}

		public EntityPos SetFrom(EntityPos pos)
		{
			X = pos.x;
			y = pos.y;
			z = pos.z;
			Dimension = pos.Dimension;
			roll = pos.roll;
			yaw = pos.yaw;
			pitch = pos.pitch;
			Motion.Set(pos.Motion);
			HeadYaw = pos.HeadYaw;
			HeadPitch = pos.HeadPitch;
			return this;
		}

		public EntityPos SetFrom(Vec3d pos)
		{
			X = pos.X;
			y = pos.Y;
			z = pos.Z;
			return this;
		}

		public override string ToString()
		{
			return "XYZ: " + X + "/" + Y + "/" + Z + ", YPR " + Yaw + "/" + Pitch + "/" + Roll + ", Dim " + Dimension;
		}

		public string OnlyPosToString()
		{
			return X.ToString("#.##", GlobalConstants.DefaultCultureInfo) + ", " + Y.ToString("#.##", GlobalConstants.DefaultCultureInfo) + ", " + Z.ToString("#.##", GlobalConstants.DefaultCultureInfo);
		}

		public string OnlyAnglesToString()
		{
			return roll.ToString("#.##", GlobalConstants.DefaultCultureInfo) + ", " + yaw.ToString("#.##", GlobalConstants.DefaultCultureInfo) + pitch.ToString("#.##", GlobalConstants.DefaultCultureInfo);
		}

		public void ToBytes(BinaryWriter writer)
		{
			writer.Write(x);
			writer.Write(InternalY);
			writer.Write(z);
			writer.Write(roll);
			writer.Write(yaw);
			writer.Write(pitch);
			writer.Write(stance);
			writer.Write(Motion.X);
			writer.Write(Motion.Y);
			writer.Write(Motion.Z);
		}

		public void FromBytes(BinaryReader reader)
		{
			x = reader.ReadDouble();
			y = reader.ReadDouble();
			Dimension = (int)y / 32768;
			y -= Dimension * 32768;
			z = reader.ReadDouble();
			roll = reader.ReadSingle();
			yaw = reader.ReadSingle();
			pitch = reader.ReadSingle();
			stance = reader.ReadInt32();
			Motion.X = reader.ReadDouble();
			Motion.Y = reader.ReadDouble();
			Motion.Z = reader.ReadDouble();
		}

		public bool AnyNaN()
		{
			if (double.IsNaN(x + y + z))
			{
				return true;
			}
			if (float.IsNaN(roll + yaw + pitch))
			{
				return true;
			}
			if (double.IsNaN(Motion.X + Motion.Y + Motion.Z))
			{
				return true;
			}
			if (Math.Abs(x) + Math.Abs(y) + Math.Abs(z) > 268435456.0)
			{
				return true;
			}
			return false;
		}
	}
	public class EntityProperties
	{
		public int Id;

		public string Color;

		public AssetLocation Code;

		public OrderedDictionary<string, string> Variant = new OrderedDictionary<string, string>();

		public string Class;

		public EntityTagArray Tags = EntityTagArray.Empty;

		public EnumHabitat Habitat = EnumHabitat.Land;

		public Vec2f CollisionBoxSize = new Vec2f(0.2f, 0.2f);

		public Vec2f DeadCollisionBoxSize = new Vec2f(0.3f, 0.3f);

		public Vec2f SelectionBoxSize;

		public Vec2f DeadSelectionBoxSize;

		public double EyeHeight;

		public double SwimmingEyeHeight;

		public float Weight = 25f;

		public bool CanClimb;

		public bool CanClimbAnywhere;

		public bool FallDamage = true;

		public float FallDamageMultiplier = 1f;

		public float ClimbTouchDistance;

		public bool RotateModelOnClimb;

		public float KnockbackResistance;

		public JsonObject Attributes;

		public EntityClientProperties Client;

		public EntityServerProperties Server;

		public Dictionary<string, AssetLocation> Sounds;

		public Dictionary<string, AssetLocation[]> ResolvedSounds = new Dictionary<string, AssetLocation[]>();

		public float IdleSoundChance = 0.3f;

		public float IdleSoundRange = 24f;

		public BlockDropItemStack[] Drops;

		public byte[] DropsPacket;

		public Cuboidf SpawnCollisionBox => new Cuboidf
		{
			X1 = (0f - CollisionBoxSize.X) / 2f,
			Z1 = (0f - CollisionBoxSize.X) / 2f,
			X2 = CollisionBoxSize.X / 2f,
			Z2 = CollisionBoxSize.X / 2f,
			Y2 = CollisionBoxSize.Y
		};

		public EntityProperties Clone()
		{
			BlockDropItemStack[] array;
			if (Drops == null)
			{
				array = null;
			}
			else
			{
				array = new BlockDropItemStack[Drops.Length];
				for (int i = 0; i < array.Length; i++)
				{
					array[i] = Drops[i].Clone();
				}
			}
			Dictionary<string, AssetLocation> dictionary = new Dictionary<string, AssetLocation>();
			foreach (KeyValuePair<string, AssetLocation> sound in Sounds)
			{
				dictionary[sound.Key] = sound.Value.Clone();
			}
			Dictionary<string, AssetLocation[]> dictionary2 = new Dictionary<string, AssetLocation[]>();
			foreach (KeyValuePair<string, AssetLocation[]> resolvedSound in ResolvedSounds)
			{
				AssetLocation[] value = resolvedSound.Value;
				dictionary2[resolvedSound.Key] = new AssetLocation[value.Length];
				for (int j = 0; j < value.Length; j++)
				{
					dictionary2[resolvedSound.Key][j] = value[j].Clone();
				}
			}
			if (!(Attributes is JsonObject_ReadOnly) && Attributes != null)
			{
				Attributes = new JsonObject_ReadOnly(Attributes);
			}
			return new EntityProperties
			{
				Code = Code.Clone(),
				Tags = Tags,
				Class = Class,
				Color = Color,
				Habitat = Habitat,
				CollisionBoxSize = CollisionBoxSize.Clone(),
				DeadCollisionBoxSize = DeadCollisionBoxSize.Clone(),
				SelectionBoxSize = SelectionBoxSize?.Clone(),
				DeadSelectionBoxSize = DeadSelectionBoxSize?.Clone(),
				CanClimb = CanClimb,
				Weight = Weight,
				CanClimbAnywhere = CanClimbAnywhere,
				FallDamage = FallDamage,
				FallDamageMultiplier = FallDamageMultiplier,
				ClimbTouchDistance = ClimbTouchDistance,
				RotateModelOnClimb = RotateModelOnClimb,
				KnockbackResistance = KnockbackResistance,
				Attributes = Attributes,
				Sounds = new Dictionary<string, AssetLocation>(Sounds),
				IdleSoundChance = IdleSoundChance,
				IdleSoundRange = IdleSoundRange,
				Drops = array,
				EyeHeight = EyeHeight,
				SwimmingEyeHeight = SwimmingEyeHeight,
				Client = (Client?.Clone() as EntityClientProperties),
				Server = (Server?.Clone() as EntityServerProperties),
				Variant = new OrderedDictionary<string, string>(Variant)
			};
		}

		public void Initialize(Entity entity, ICoreAPI api)
		{
			if (api.Side.IsClient())
			{
				if (Client == null)
				{
					return;
				}
				Client.loadBehaviors(entity, this, api.World);
			}
			else if (Server != null)
			{
				Server.loadBehaviors(entity, this, api.World);
			}
			Client?.Init(Code, api.World);
			InitSounds(api.Assets);
		}

		public void InitSounds(IAssetManager assetManager)
		{
			if (Sounds == null)
			{
				return;
			}
			foreach (KeyValuePair<string, AssetLocation> sound in Sounds)
			{
				if (sound.Value.Path.EndsWith('*'))
				{
					List<IAsset> manyInCategory = assetManager.GetManyInCategory("sounds", sound.Value.Path.Substring(0, sound.Value.Path.Length - 1), sound.Value.Domain);
					AssetLocation[] array = new AssetLocation[manyInCategory.Count];
					int num = 0;
					foreach (IAsset item in manyInCategory)
					{
						array[num++] = item.Location;
					}
					ResolvedSounds[sound.Key] = array;
				}
				else
				{
					ResolvedSounds[sound.Key] = new AssetLocation[1] { sound.Value.Clone().WithPathPrefix("sounds/") };
				}
			}
		}

		internal void PopulateDrops(IWorldAccessor worldForResolve)
		{
			using (MemoryStream input = new MemoryStream(DropsPacket))
			{
				BinaryReader binaryReader = new BinaryReader(input);
				BlockDropItemStack[] array = new BlockDropItemStack[binaryReader.ReadInt32()];
				for (int i = 0; i < array.Length; i++)
				{
					array[i] = new BlockDropItemStack();
					array[i].FromBytes(binaryReader, worldForResolve.ClassRegistry);
					array[i].Resolve(worldForResolve, "decode entity drops for ", Code);
				}
				Drops = array;
			}
			DropsPacket = null;
		}
	}
	public abstract class EntitySidedProperties
	{
		public ITreeAttribute Attributes;

		public JsonObject[] BehaviorsAsJsonObj;

		public List<EntityBehavior> Behaviors = new List<EntityBehavior>();

		public EntitySidedProperties(JsonObject[] behaviors, Dictionary<string, JsonObject> commonConfigs)
		{
			BehaviorsAsJsonObj = new JsonObject[behaviors.Length];
			int num = 0;
			foreach (JsonObject jsonObject in behaviors)
			{
				if (!jsonObject["enabled"].AsBool(defaultValue: true))
				{
					continue;
				}
				string text = jsonObject["code"].AsString();
				if (text != null)
				{
					JsonObject original = jsonObject;
					if (commonConfigs != null && commonConfigs.ContainsKey(text))
					{
						JToken obj = commonConfigs[text].Token.DeepClone();
						JToken obj2 = ((obj is JObject) ? obj : null);
						? val = obj2;
						JToken token = jsonObject.Token;
						((JContainer)val).Merge((object)((token is JObject) ? token : null));
						original = new JsonObject(obj2);
					}
					BehaviorsAsJsonObj[num++] = new JsonObject_ReadOnly(original);
				}
			}
			if (num < behaviors.Length)
			{
				Array.Resize(ref BehaviorsAsJsonObj, num);
			}
		}

		public void loadBehaviors(Entity entity, EntityProperties properties, IWorldAccessor world)
		{
			if (BehaviorsAsJsonObj == null)
			{
				return;
			}
			Behaviors.Clear();
			for (int i = 0; i < BehaviorsAsJsonObj.Length; i++)
			{
				JsonObject jsonObject = BehaviorsAsJsonObj[i];
				string text = jsonObject["code"].AsString();
				if (world.ClassRegistry.GetEntityBehaviorClass(text) != null)
				{
					EntityBehavior entityBehavior = world.ClassRegistry.CreateEntityBehavior(entity, text);
					Behaviors.Add(entityBehavior);
					entityBehavior.FromBytes(isSync: false);
					entityBehavior.Initialize(properties, jsonObject);
				}
				else
				{
					world.Logger.Notification("Entity behavior {0} for entity {1} not found, will not load it.", text, properties.Code);
				}
			}
		}

		public abstract EntitySidedProperties Clone();
	}
	public class EntityClientProperties : EntitySidedProperties
	{
		public EntityRenderer Renderer;

		public string RendererName;

		public IDictionary<string, CompositeTexture> Textures = new FastSmallDictionary<string, CompositeTexture>(0);

		public int TexturesAlternatesCount;

		public int GlowLevel;

		public bool PitchStep = true;

		public CompositeShape Shape;

		public Shape LoadedShape;

		public Shape[] LoadedAlternateShapes;

		public Shape LoadedShapeForEntity;

		public CompositeShape ShapeForEntity;

		public float Size = 1f;

		public float SizeGrowthFactor;

		public AnimationMetaData[] Animations;

		public Dictionary<string, AnimationMetaData> AnimationsByMetaCode = new Dictionary<string, AnimationMetaData>(StringComparer.OrdinalIgnoreCase);

		public Dictionary<uint, AnimationMetaData> AnimationsByCrc32 = new Dictionary<uint, AnimationMetaData>();

		public virtual CompositeTexture Texture
		{
			get
			{
				if (Textures != null && Textures.Count != 0)
				{
					return Textures.First().Value;
				}
				return null;
			}
		}

		public CompositeTexture FirstTexture
		{
			get
			{
				if (Textures != null && Textures.Count != 0)
				{
					return Textures.First().Value;
				}
				return null;
			}
		}

		public EntityClientProperties(JsonObject[] behaviors, Dictionary<string, JsonObject> commonConfigs)
			: base(behaviors, commonConfigs)
		{
		}

		public void DetermineLoadedShape(long forEntityId)
		{
			if (LoadedAlternateShapes != null && LoadedAlternateShapes.Length != 0)
			{
				int num = GameMath.MurmurHash3Mod(0, 0, (int)forEntityId, 1 + LoadedAlternateShapes.Length);
				if (num == 0)
				{
					LoadedShapeForEntity = LoadedShape;
					ShapeForEntity = Shape;
				}
				else
				{
					LoadedShapeForEntity = LoadedAlternateShapes[num - 1];
					ShapeForEntity = Shape.Alternates[num - 1];
				}
			}
			else
			{
				LoadedShapeForEntity = LoadedShape;
				ShapeForEntity = Shape;
			}
		}

		public void Init(AssetLocation entityTypeCode, IWorldAccessor world)
		{
			if (Animations != null)
			{
				for (int i = 0; i < Animations.Length; i++)
				{
					AnimationMetaData animationMetaData = Animations[i];
					animationMetaData.Init();
					if (animationMetaData.Animation != null)
					{
						AnimationsByMetaCode[animationMetaData.Code] = animationMetaData;
					}
					if (animationMetaData.Animation != null)
					{
						AnimationsByCrc32[animationMetaData.CodeCrc32] = animationMetaData;
					}
				}
			}
			if (world != null)
			{
				EntityClientProperties entityClientProperties = world.EntityTypes.FirstOrDefault((EntityProperties et) => et.Code.Equals(entityTypeCode))?.Client;
				LoadedShape = entityClientProperties?.LoadedShape;
				LoadedAlternateShapes = entityClientProperties?.LoadedAlternateShapes;
			}
		}

		public override EntitySidedProperties Clone()
		{
			Dictionary<string, AnimationMetaData> dictionary = new Dictionary<string, AnimationMetaData>(StringComparer.OrdinalIgnoreCase);
			Dictionary<uint, AnimationMetaData> dictionary2 = new Dictionary<uint, AnimationMetaData>();
			AnimationMetaData[] array = null;
			if (Animations != null)
			{
				AnimationMetaData[] animations = Animations;
				array = new AnimationMetaData[animations.Length];
				for (int i = 0; i < array.Length; i++)
				{
					AnimationMetaData animationMetaData = (array[i] = animations[i].Clone());
					if (AnimationsByMetaCode.ContainsKey(animationMetaData.Code))
					{
						dictionary[animationMetaData.Code] = animationMetaData;
						dictionary2[animationMetaData.CodeCrc32] = animationMetaData;
					}
				}
			}
			return new EntityClientProperties(BehaviorsAsJsonObj, null)
			{
				Textures = ((Textures == null) ? null : new FastSmallDictionary<string, CompositeTexture>(Textures)),
				TexturesAlternatesCount = TexturesAlternatesCount,
				RendererName = RendererName,
				GlowLevel = GlowLevel,
				PitchStep = PitchStep,
				Size = Size,
				SizeGrowthFactor = SizeGrowthFactor,
				Shape = Shape?.Clone(),
				LoadedAlternateShapes = LoadedAlternateShapes,
				Animations = array,
				AnimationsByMetaCode = dictionary,
				AnimationsByCrc32 = dictionary2
			};
		}

		public virtual void FreeRAMServer()
		{
			CompositeTexture[] array = FirstTexture?.Alternates;
			TexturesAlternatesCount = ((array != null) ? array.Length : 0);
			Textures = null;
			if (Animations != null)
			{
				AnimationMetaData[] animations = Animations;
				for (int i = 0; i < animations.Length; i++)
				{
					animations[i].DeDuplicate();
				}
			}
		}
	}
	public class EntityServerProperties : EntitySidedProperties
	{
		public SpawnConditions SpawnConditions;

		public EntityServerProperties(JsonObject[] behaviors, Dictionary<string, JsonObject> commonConfigs)
			: base(behaviors, commonConfigs)
		{
		}

		public override EntitySidedProperties Clone()
		{
			return new EntityServerProperties(BehaviorsAsJsonObj, null)
			{
				Attributes = Attributes,
				SpawnConditions = SpawnConditions
			};
		}

		public List<EntityBehaviorAndConfig> BehaviorsWithEarlyLoadCollectibleMappings(Entity entity, IWorldAccessor world)
		{
			if (BehaviorsAsJsonObj == null)
			{
				return null;
			}
			List<EntityBehaviorAndConfig> list = new List<EntityBehaviorAndConfig>();
			for (int i = 0; i < BehaviorsAsJsonObj.Length; i++)
			{
				JsonObject jsonObject = BehaviorsAsJsonObj[i];
				string entityBehaviorName = jsonObject["code"].AsString();
				if (world.ClassRegistry.GetEntityBehaviorClass(entityBehaviorName) != null)
				{
					EntityBehavior entityBehavior = world.ClassRegistry.CreateEntityBehavior(entity, entityBehaviorName);
					if (entityBehavior.ShouldEarlyLoadCollectibleMappings())
					{
						entityBehavior.FromBytes(isSync: false);
						list.Add(new EntityBehaviorAndConfig(entityBehavior, jsonObject));
					}
				}
			}
			return list;
		}
	}
