	public class PModuleGravity : PModule
	{
		private double gravityPerSecond = GlobalConstants.GravityPerSecond;

		public override void Initialize(JsonObject config, Entity entity)
		{
			if (config != null)
			{
				gravityPerSecond = GlobalConstants.GravityPerSecond * (float)config["gravityFactor"].AsDouble(1.0);
			}
		}

		public override bool Applicable(Entity entity, EntityPos pos, EntityControls controls)
		{
			switch (entity.Properties.Habitat)
			{
			case EnumHabitat.Air:
				return false;
			case EnumHabitat.Sea:
			case EnumHabitat.Underwater:
				if (entity.Swimming)
				{
					return false;
				}
				break;
			}
			if (controls.IsFlying && !controls.Gliding)
			{
				return false;
			}
			if (!controls.IsClimbing)
			{
				return entity.ApplyGravity;
			}
			return false;
		}

		public override void DoApply(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if ((!entity.Swimming || !controls.TriesToMove || !entity.Alive) && pos.Y > -100.0)
			{
				double num = (gravityPerSecond + Math.Max(0.0, -0.014999999664723873 * pos.Motion.Y)) * (double)(entity.FeetInLiquid ? 0.33f : 1f) * (double)dt;
				pos.Motion.Y -= num * GameMath.Clamp(1.0 - 50.0 * controls.GlideSpeed * controls.GlideSpeed, 0.0, 1.0);
			}
		}
	}
	public class PModuleInAir : PModule
	{
		public float AirMovingStrength = 0.05f;

		public double WallDragFactor = 0.30000001192092896;

		public override void Initialize(JsonObject config, Entity entity)
		{
			if (config != null)
			{
				WallDragFactor = 0.3 * (double)(float)config["wallDragFactor"].AsDouble(1.0);
				AirMovingStrength = (float)config["airMovingStrength"].AsDouble(0.05);
			}
		}

		public override bool Applicable(Entity entity, EntityPos pos, EntityControls controls)
		{
			if ((!entity.Collided && !entity.FeetInLiquid) || controls.IsFlying)
			{
				return entity.Alive;
			}
			return false;
		}

		public override void DoApply(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if (controls.IsFlying)
			{
				ApplyFlying(dt, entity, pos, controls);
			}
			else
			{
				ApplyFreeFall(dt, entity, pos, controls);
			}
		}

		public virtual void ApplyFreeFall(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if (controls.IsClimbing)
			{
				pos.Motion.Add(controls.WalkVector);
				pos.Motion.Scale(Math.Pow(1.0 - WallDragFactor, dt * 60f));
			}
			else
			{
				float num = AirMovingStrength * dt * 60f;
				Vec3d walkVector = controls.WalkVector;
				pos.Motion.Add(walkVector.X * (double)num, walkVector.Y * (double)num, walkVector.Z * (double)num);
			}
		}

		public virtual void ApplyFlying(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			Vec3d flyVector = controls.FlyVector;
			double num = flyVector.Y;
			if (controls.Up || controls.Down)
			{
				float num2 = Math.Min(0.2f, dt) * GlobalConstants.BaseMoveSpeed * controls.MovespeedMultiplier / 2f;
				num = (controls.Up ? num2 : 0f) + (controls.Down ? (0f - num2) : 0f);
			}
			if (num > 0.0 && pos.Y % 32768.0 > 24576.0)
			{
				num = 0.0;
			}
			pos.Motion.Add(flyVector.X, num, flyVector.Z);
		}
	}
	public class PModuleInLiquid : PModule
	{
		public float Push;

		public float Swimspeed = 1f;

		public override void Initialize(JsonObject config, Entity entity)
		{
			if (!(entity is EntityPlayer))
			{
				Swimspeed = (float)entity.World.Config.GetDecimal("creatureSwimSpeed", 1.0);
			}
		}

		public override bool Applicable(Entity entity, EntityPos pos, EntityControls controls)
		{
			return entity.FeetInLiquid;
		}

		public override void DoApply(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if (entity.Swimming && entity.Alive)
			{
				HandleSwimming(dt, entity, pos, controls);
			}
			Block blockRaw = entity.World.BlockAccessor.GetBlockRaw((int)pos.X, (int)pos.InternalY, (int)pos.Z, 2);
			if (blockRaw.PushVector != null && (blockRaw.PushVector.Y >= 0.0 || !entity.World.BlockAccessor.IsSideSolid((int)pos.X, (int)pos.InternalY - 1, (int)pos.Z, BlockFacing.UP)))
			{
				pos.Motion.Add(blockRaw.PushVector);
			}
		}

		public virtual void HandleSwimming(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			Push = Math.Max(1f, Push - 0.1f * dt * 60f);
			int x = (int)pos.X;
			int num = (int)pos.InternalY;
			int z = (int)pos.Z;
			Block blockRaw = entity.World.BlockAccessor.GetBlockRaw(x, num, z, 2);
			Block blockRaw2 = entity.World.BlockAccessor.GetBlockRaw(x, num + 1, z, 2);
			Block blockRaw3 = entity.World.BlockAccessor.GetBlockRaw(x, num + 2, z, 2);
			float num2 = GameMath.Clamp((float)(int)pos.Y + (float)blockRaw.LiquidLevel / 8f + (blockRaw2.IsLiquid() ? 1.125f : 0f) + (blockRaw3.IsLiquid() ? 1.125f : 0f) - (float)pos.Y - (float)entity.SwimmingOffsetY, 0f, 1f);
			num2 = Math.Min(1f, num2 + 0.075f);
			double num3 = ((!controls.Jump) ? (controls.FlyVector.Y * (double)(1f + Push) * 0.029999999329447746 * (double)num2) : ((double)(0.005f * num2 * dt * 60f)));
			if (entity.Properties.Habitat == EnumHabitat.Underwater && blockRaw.IsLiquid() && !blockRaw2.IsLiquid())
			{
				float num4 = (float)(int)pos.Y + (float)blockRaw.LiquidLevel / 8f - entity.CollisionBox.Y2;
				if (pos.Y > (double)num4)
				{
					num3 = 0.0 - GameMath.Clamp(pos.Y - (double)num4, 0.0, 0.05);
				}
			}
			pos.Motion.Add((double)Swimspeed * controls.FlyVector.X * (double)(1f + Push) * 0.029999999329447746, (double)Swimspeed * num3, (double)Swimspeed * controls.FlyVector.Z * (double)(1f + Push) * 0.029999999329447746);
		}
	}
	public class PModuleKnockback : PModule
	{
		public override void Initialize(JsonObject config, Entity entity)
		{
		}

		public override bool Applicable(Entity entity, EntityPos pos, EntityControls controls)
		{
			return true;
		}

		public override void DoApply(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if (entity.Attributes.GetInt("dmgkb") == 1)
			{
				double num = entity.WatchedAttributes.GetDouble("kbdirX");
				double num2 = entity.WatchedAttributes.GetDouble("kbdirY");
				double num3 = entity.WatchedAttributes.GetDouble("kbdirZ");
				pos.Motion.X += num;
				pos.Motion.Y += num2;
				pos.Motion.Z += num3;
				entity.Attributes.SetInt("dmgkb", 0);
			}
		}
	}
	public class PModuleMotionDrag : PModule
	{
		private double waterDragValue = GlobalConstants.WaterDrag;

		private double airDragValue = GlobalConstants.AirDragAlways;

		public override void Initialize(JsonObject config, Entity entity)
		{
			if (config != null)
			{
				waterDragValue = 1f - (1f - GlobalConstants.WaterDrag) * (float)config["waterDragFactor"].AsDouble(1.0);
				airDragValue = 1f - (1f - GlobalConstants.AirDragAlways) * (float)config["airDragFallingFactor"].AsDouble(1.0);
			}
		}

		public override bool Applicable(Entity entity, EntityPos pos, EntityControls controls)
		{
			return true;
		}

		public override void DoApply(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if (entity.FeetInLiquid || entity.Swimming)
			{
				pos.Motion.Scale((float)Math.Pow(waterDragValue, dt * 33f));
			}
			else
			{
				pos.Motion.Scale((float)Math.Pow(airDragValue, dt * 33f));
			}
			if (controls.IsFlying && !controls.Gliding)
			{
				pos.Motion.Scale((float)Math.Pow(GlobalConstants.AirDragFlying, dt * 33f));
			}
		}
	}
	public class PModuleOnGround : PModule
	{
		private const long MinimumJumpInterval = 500L;

		private long lastJump;

		private double groundDragFactor = 0.30000001192092896;

		private float accum;

		private float coyoteTimer;

		private float antiCoyoteTimer;

		private double motionDeltaX;

		private double motionDeltaZ;

		public override void Initialize(JsonObject config, Entity entity)
		{
			if (config != null)
			{
				groundDragFactor = 0.3 * (double)(float)config["groundDragFactor"].AsDouble(1.0);
			}
		}

		public override bool Applicable(Entity entity, EntityPos pos, EntityControls controls)
		{
			bool flag = entity.OnGround && !entity.Swimming;
			if (flag && antiCoyoteTimer <= 0f)
			{
				coyoteTimer = 0.15f;
			}
			if (coyoteTimer > 0f)
			{
				if (entity.Attributes.GetInt("dmgkb") > 0)
				{
					coyoteTimer = 0f;
					antiCoyoteTimer = 0.16f;
					return flag;
				}
				return true;
			}
			return flag;
		}

		public override void DoApply(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			coyoteTimer -= dt;
			if (antiCoyoteTimer > 0f)
			{
				antiCoyoteTimer = Math.Max(0f, antiCoyoteTimer - dt);
			}
			float dragMultiplier = entity.World.BlockAccessor.GetBlockRaw((int)pos.X, (int)(pos.InternalY - 0.05000000074505806), (int)pos.Z).DragMultiplier;
			float num = Math.Min(1f, accum + dt);
			float num2 = 1f / 60f;
			double walkSpeedMultiplier = (entity as EntityAgent).GetWalkSpeedMultiplier(groundDragFactor);
			double num3 = controls.WalkVector.X * walkSpeedMultiplier;
			double num4 = controls.WalkVector.Z * walkSpeedMultiplier;
			Vec3d motion = pos.Motion;
			double num5 = 1.0 - groundDragFactor;
			while (num > num2)
			{
				num -= num2;
				if (entity.Alive)
				{
					motionDeltaX += (num3 - motionDeltaX) * (double)dragMultiplier;
					motionDeltaZ += (num4 - motionDeltaZ) * (double)dragMultiplier;
					motion.Add(motionDeltaX, 0.0, motionDeltaZ);
				}
				motion.X *= num5;
				motion.Z *= num5;
			}
			accum = num;
			if (controls.Jump && entity.World.ElapsedMilliseconds - lastJump > 500 && entity.Alive)
			{
				EntityPlayer entityPlayer = entity as EntityPlayer;
				lastJump = entity.World.ElapsedMilliseconds;
				float num6 = MathF.Sqrt(MathF.Max(1f, entityPlayer?.Stats.GetBlended("jumpHeightMul") ?? 1f));
				pos.Motion.Y = GlobalConstants.BaseJumpForce * 1f / 60f * num6;
				IPlayer dualCallByPlayer = entityPlayer?.World.PlayerByUid(entityPlayer.PlayerUID);
				entity.PlayEntitySound("jump", dualCallByPlayer, randomizePitch: false);
			}
		}
	}
	public class PModuleWind : PModule
	{
		private readonly Vec3d windForce = new Vec3d();

		private bool applyWindForce;

		private float accum;

		public override void Initialize(JsonObject config, Entity entity)
		{
			applyWindForce = entity.World.Config.GetBool("windAffectedEntityMovement");
		}

		public override bool Applicable(Entity entity, EntityPos pos, EntityControls controls)
		{
			if (controls.TriesToMove)
			{
				if (entity.OnGround)
				{
					return !entity.Swimming;
				}
				return false;
			}
			return false;
		}

		public override void DoApply(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if ((accum += dt) > 5f)
			{
				accum = 0f;
				UpdateWindForce(entity);
			}
			pos.Motion.Add(windForce);
		}

		public virtual void UpdateWindForce(Entity entity)
		{
			if (!entity.Alive || !applyWindForce)
			{
				windForce.Set(0.0, 0.0, 0.0);
				return;
			}
			if ((double)entity.World.BlockAccessor.GetRainMapHeightAt((int)entity.Pos.X, (int)entity.Pos.Z) > entity.Pos.Y)
			{
				windForce.Set(0.0, 0.0, 0.0);
				return;
			}
			Vec3d windSpeedAt = entity.World.BlockAccessor.GetWindSpeedAt(entity.Pos.XYZ);
			windForce.X = Math.Max(0.0, Math.Abs(windSpeedAt.X) - 0.8) / 40.0 * (double)Math.Sign(windSpeedAt.X);
			windForce.Y = Math.Max(0.0, Math.Abs(windSpeedAt.Y) - 0.8) / 40.0 * (double)Math.Sign(windSpeedAt.Y);
			windForce.Z = Math.Max(0.0, Math.Abs(windSpeedAt.Z) - 0.8) / 40.0 * (double)Math.Sign(windSpeedAt.Z);
		}
	}
	public class PModulePlayerInAir : PModuleInAir
	{
		private float airMovingStrengthFalling;

		public override void Initialize(JsonObject config, Entity entity)
		{
			base.Initialize(config, entity);
			airMovingStrengthFalling = AirMovingStrength / 4f;
		}

		public override void ApplyFreeFall(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if (controls.IsClimbing)
			{
				base.ApplyFreeFall(dt, entity, pos, controls);
				return;
			}
			float num = AirMovingStrength * Math.Min(1f, ((EntityPlayer)entity).walkSpeed) * dt * 60f;
			if (!controls.Jump)
			{
				num = airMovingStrengthFalling;
				pos.Motion.X *= (float)Math.Pow(0.9800000190734863, dt * 33f);
				pos.Motion.Z *= (float)Math.Pow(0.9800000190734863, dt * 33f);
			}
			pos.Motion.Add(controls.WalkVector.X * (double)num, controls.WalkVector.Y * (double)num, controls.WalkVector.Z * (double)num);
		}

		public override void ApplyFlying(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if (controls.Gliding)
			{
				double num = Math.Cos(pos.Pitch);
				double num2 = Math.Sin(pos.Pitch);
				double num3 = Math.Cos(pos.Yaw);
				double num4 = Math.Sin(pos.Yaw);
				double num5 = num2 + 0.15;
				controls.GlideSpeed = GameMath.Clamp(controls.GlideSpeed - num5 * (double)dt * 0.25, 0.004999999888241291, 0.75);
				double num6 = GameMath.Clamp(max: (double)entity.Stats.GetBlended("gliderSpeedMax") - 0.8, val: controls.GlideSpeed, min: 0.004999999888241291);
				float blended = entity.Stats.GetBlended("gliderLiftMax");
				double y = Math.Min(num2 * num6, blended);
				pos.Motion.Add((0.0 - num) * num4 * num6, y, (0.0 - num) * num3 * num6);
				pos.Motion.Mul(GameMath.Clamp(1.0 - pos.Motion.Length() * 0.12999999523162842, 0.0, 1.0));
			}
			else
			{
				base.ApplyFlying(dt, entity, pos, controls);
			}
		}
	}
	public class PModulePlayerInLiquid : PModuleInLiquid
	{
		private long lastPush;

		private readonly IPlayer player;

		private BlockPos tmpPos = new BlockPos();

		public PModulePlayerInLiquid(EntityPlayer entityPlayer)
		{
			player = entityPlayer.World.PlayerByUid(entityPlayer.PlayerUID);
		}

		public override void HandleSwimming(float dt, Entity entity, EntityPos pos, EntityControls controls)
		{
			if ((controls.TriesToMove || controls.Jump) && entity.World.ElapsedMilliseconds - lastPush > 2000)
			{
				Push = 6f;
				lastPush = entity.World.ElapsedMilliseconds;
				entity.PlayEntitySound("swim", player);
			}
			else
			{
				Push = Math.Max(1f, Push - 0.1f * dt * 60f);
			}
			tmpPos.dimension = pos.Dimension;
			tmpPos.Set((int)pos.X, (int)pos.Y, (int)pos.Z);
			Block block = entity.World.BlockAccessor.GetBlock(tmpPos, 2);
			Block blockAbove = entity.World.BlockAccessor.GetBlockAbove(tmpPos, 1, 2);
			Block blockAbove2 = entity.World.BlockAccessor.GetBlockAbove(tmpPos, 2, 2);
			float num = GameMath.Clamp((float)(int)pos.Y + (float)block.LiquidLevel / 8f + (blockAbove.IsLiquid() ? 1.125f : 0f) + (blockAbove2.IsLiquid() ? 1.125f : 0f) - (float)pos.Y - (float)entity.SwimmingOffsetY, 0f, 1f);
			num = Math.Min(1f, num + 0.075f);
			double y = 0.0;
			if (controls.Jump)
			{
				if (num > 0.1f || !controls.TriesToMove)
				{
					y = 0.005f * num * dt * 60f;
				}
			}
			else
			{
				y = controls.FlyVector.Y * (double)(1f + Push) * 0.029999999329447746 * (double)num;
			}
			pos.Motion.Add(controls.FlyVector.X * (double)(1f + Push) * 0.029999999329447746, y, controls.FlyVector.Z * (double)(1f + Push) * 0.029999999329447746);
		}
	}
